window.SR_CARDS = [{"id": "gen:fc:0", "deck": "General Pharmacology", "dk": "gen", "type": "flashcard", "front": "A drug has a volume of distribution of 500 L in a 70 kg patient. What does this tell you about its distribution, and how does it affect overdose management?", "back": "A Vd of 500 L far exceeds total body water (~42 L), meaning the drug is extensively sequestered in tissues (lipophilic or tissue-bound). High Vd → low plasma concentration per dose, long half-life, and activated charcoal / haemodialysis are <em>ineffective</em> for overdose (most drug is in tissues, not blood). Examples: amiodarone (~60 L/kg), chlorpromazine (~20 L/kg).<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Loading dose = Vd × target plasma concentration ÷ bioavailability. Critical when rapid therapeutic levels are needed (digoxin, amiodarone, phenytoin).</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Warfarin has LOW Vd (~0.15 L/kg) because it is 99% albumin-bound — it stays in plasma. Yet dialysis is still ineffective because the protein-bound fraction is not filterable.</div>"}, {"id": "gen:fc:1", "deck": "General Pharmacology", "dk": "gen", "type": "flashcard", "front": "Ethanol is eliminated at ~10 mL/hour regardless of blood level. What kinetic model describes this, and which other clinically important drugs share it?", "back": "Zero-order (saturation) kinetics — alcohol dehydrogenase is saturated at typical drinking levels, so elimination rate is constant (independent of concentration). Blood alcohol falls linearly, not exponentially. Other zero-order drugs at clinical/toxic concentrations: <strong>phenytoin</strong> (Michaelis–Menten / mixed-order — switches to zero-order at therapeutic levels), <strong>high-dose salicylates</strong>.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Phenytoin follows first-order kinetics at low doses but switches to zero-order at therapeutic/supratherapeutic levels. This means small dose increases cause disproportionately large rises in plasma levels — the key reason phenytoin toxicity is common.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Zero-order drugs have NO constant half-life. Elimination time increases with dose. This makes toxic dose estimation unreliable from standard half-life calculations.</div>"}, {"id": "gen:fc:2", "deck": "General Pharmacology", "dk": "gen", "type": "flashcard", "front": "A drug has 5% oral bioavailability. The IV dose is 10 mg. What oral dose achieves equivalent systemic exposure, and what factors reduce bioavailability?", "back": "Oral dose = IV dose ÷ F = 10 mg ÷ 0.05 = <strong>200 mg</strong>. Bioavailability is reduced by: poor GI absorption, first-pass hepatic metabolism, intestinal CYP3A4 metabolism, P-glycoprotein efflux (returns drug to gut lumen), formulation factors, and gut motility.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Nitroglycerin (F ~1%) and lidocaine (F ~35%) are almost entirely destroyed on first pass — must be given sublingually/transdermally/IV. Morphine F ~30% — oral doses must be 3× the IV dose for equivalent effect.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> IV bioavailability is always 100% by definition. When converting oral → IV opioids, always use an equianalgesic chart — do not simply halve the dose.</div>"}, {"id": "gen:fc:3", "deck": "General Pharmacology", "dk": "gen", "type": "flashcard", "front": "A patient on warfarin is started on rifampin for TB. Her INR drops from 2.8 to 1.2 over two weeks despite taking the same warfarin dose. Explain.", "back": "Rifampin is a potent inducer of <strong>CYP2C9, CYP3A4, and P-glycoprotein</strong>. Warfarin (especially the active S-enantiomer) is a CYP2C9 substrate. Enzyme induction → accelerated warfarin metabolism → lower plasma levels → subtherapeutic anticoagulation. Induction develops over 1–2 weeks and reverses 1–2 weeks after stopping rifampin (both windows require close INR monitoring).<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Major CYP inducers (RIPS): <strong>R</strong>ifampin, <strong>I</strong>soniazid (mild), <strong>P</strong>henytoin/Phenobarbital, <strong>S</strong>t. John's Wort, carbamazepine. All also reduce OCP efficacy — counsel on contraception.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Clarithromycin is a CYP3A4 <em>inhibitor</em>, not an inducer. Erythromycin is also an inhibitor. Azithromycin does NOT significantly inhibit CYP — preferred when drug interactions are a concern.</div>"}, {"id": "gen:fc:4", "deck": "General Pharmacology", "dk": "gen", "type": "flashcard", "front": "Grapefruit juice is taken with simvastatin. The patient develops severe myalgia and dark urine. Which statins are safest, and what is the mechanism?", "back": "Grapefruit contains <strong>furanocoumarins</strong> that irreversibly inhibit <em>intestinal</em> CYP3A4 → increased first-pass bioavailability of CYP3A4-metabolised statins (lovastatin, simvastatin, atorvastatin) → elevated plasma levels → myopathy / rhabdomyolysis. One glass can inhibit CYP3A4 for 24–72 hours.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Safest statins with CYP3A4 inhibitors or grapefruit: <strong>rosuvastatin</strong> (primarily renal excretion, not CYP3A4) and <strong>pravastatin</strong> (not a CYP substrate). Fluvastatin is CYP2C9.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Grapefruit affects intestinal CYP3A4 primarily, not hepatic — so IV drugs given the same day are not affected. The interaction persists even if grapefruit was consumed hours before the drug.</div>"}, {"id": "gen:fc:5", "deck": "General Pharmacology", "dk": "gen", "type": "flashcard", "front": "A competitive antagonist is added to an agonist preparation — the dose–response curve shifts right but Emax is unchanged. An irreversible antagonist is then used. What happens to Emax?", "back": "<strong>Competitive antagonist:</strong> shifts EC₅₀ right (requires more agonist for the same effect) but Emax is preserved because, at high enough agonist concentrations, all binding sites can be occupied. <strong>Irreversible (non-competitive, covalent) antagonist:</strong> permanently reduces the number of available receptors → Emax falls even at maximum agonist concentration — cannot be overcome by increasing agonist dose.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Aspirin is the classic irreversible inhibitor — covalently acetylates COX-1 serine. Platelet COX-1 is permanently blocked for the platelet's lifespan (~10 days). Ibuprofen is competitive/reversible — antiplatelet effect lasts only while drug is present.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Non-competitive allosteric antagonists also reduce Emax WITHOUT shifting EC₅₀ — distinguish from irreversible antagonists by reversibility. Some allosteric antagonists are fully reversible.</div>"}, {"id": "gen:fc:6", "deck": "General Pharmacology", "dk": "gen", "type": "flashcard", "front": "A patient on warfarin is newly prescribed a full-dose NSAID. The INR rises from 2.5 to 4.9 within a week. Identify both the pharmacokinetic and pharmacodynamic mechanisms.", "back": "<strong>Pharmacokinetic:</strong> NSAIDs displace warfarin from albumin binding sites → transient rise in free warfarin → increased anticoagulant effect. Some NSAIDs (phenylbutazone) also inhibit CYP2C9 → reduced warfarin metabolism → sustained elevation. <strong>Pharmacodynamic:</strong> NSAIDs inhibit COX-1 in platelets → antiplatelet effect, synergising with anticoagulation; also cause gastric mucosal injury → bleeding risk multiplied.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Protein displacement is usually transient — free drug redistributes and elimination re-equilibrates. The more dangerous, sustained interaction is CYP2C9 inhibition (metronidazole, fluconazole, amiodarone are stronger inhibitors than most NSAIDs).</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Even topical diclofenac has measurable systemic absorption sufficient to interact with warfarin. Celecoxib (COX-2 selective) is safer for GI bleeding risk but still inhibits CYP2C9 — warfarin interaction persists.</div>"}, {"id": "gen:fc:7", "deck": "General Pharmacology", "dk": "gen", "type": "flashcard", "front": "A patient on codeine for post-operative pain develops respiratory depression and pinpoint pupils despite a 'standard' dose. Genetic testing shows she is an ultrarapid CYP2D6 metaboliser. Explain.", "back": "Codeine is a prodrug; <strong>CYP2D6</strong> converts codeine → morphine (the active opioid). Ultrarapid metabolisers (gene duplication, common in North African/Ethiopian populations: ~10–29%) convert codeine to morphine very rapidly → dangerously elevated morphine levels → respiratory depression, even fatal. The FDA has black-box warnings and restricts codeine use in children and breast-feeding mothers for this reason.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Tramadol is also a CYP2D6 prodrug (→ O-desmethyltramadol). Same ultrarapid metaboliser danger applies. Poor metabolisers (~7–10% Caucasians) derive no benefit from codeine — they cannot produce morphine.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> CYP2D6 inhibitors (fluoxetine, paroxetine, bupropion) convert extensive metabolisers into phenotypic poor metabolisers — codeine is ineffective in these patients and increases codeine toxicity from unconverted parent drug.</div>"}, {"id": "gen:fc:8", "deck": "General Pharmacology", "dk": "gen", "type": "flashcard", "front": "A child develops haemolytic anaemia with Heinz bodies after starting dapsone for dermatitis herpetiformis. What enzyme deficiency explains this?", "back": "<strong>G6PD deficiency</strong> (X-linked). G6PD is essential for the hexose monophosphate shunt → NADPH production → reduced glutathione → protection against oxidative stress in RBCs. Oxidant drugs (dapsone, primaquine, nitrofurantoin, rasburicase) generate reactive oxygen species → Hb oxidation → Heinz body formation (denatured Hb) → haemolysis. G6PD testing is mandatory before prescribing oxidant drugs.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> G6PD activity should be tested during a quiescent (non-haemolytic) period — during active haemolysis, older deficient RBCs are destroyed first; remaining young RBCs have more G6PD, giving a falsely normal result.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> G6PD deficiency protects against Plasmodium falciparum malaria (infected RBCs lyse more easily, limiting parasite spread) — this explains its high prevalence in malaria-endemic regions. The same feature that confers malaria resistance causes drug-induced haemolysis.</div>"}, {"id": "gen:fc:9", "deck": "General Pharmacology", "dk": "gen", "type": "flashcard", "front": "A patient on phenelzine (MAOI) for depression eats aged blue cheese at dinner and develops sudden severe headache, BP 220/130, and diaphoresis. What is happening and how is it treated?", "back": "<strong>Hypertensive crisis from tyramine ('cheese effect').</strong> MAO-A normally deaminates dietary tyramine in the gut wall and liver before it reaches systemic circulation. MAO inhibition → tyramine absorbed → displaces noradrenaline from sympathetic terminals → massive catecholamine surge → hypertensive crisis. Risk of intracerebral haemorrhage. Treatment: IV phentolamine (alpha-blocker) or labetalol; avoid beta-blockers alone (unopposed alpha → worsens hypertension).<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> High-tyramine foods: aged cheeses, cured/smoked meats, fermented foods (soy sauce, Marmite), broad beans, Chianti wine. Patients on MAOIs require strict dietary restriction throughout therapy and for 2 weeks after stopping.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> MAOI + serotonergic drugs (SSRIs, SNRIs, tramadol, pethidine/meperidine) → <strong>serotonin syndrome</strong> (NOT hypertensive crisis). Wash-out: 14 days after stopping MAOI before starting serotonergic drug; 5 weeks after stopping fluoxetine (long t½) before starting MAOI.</div>"}, {"id": "gen:fc:10", "deck": "General Pharmacology", "dk": "gen", "type": "flashcard", "front": "Phenytoin is started for epilepsy. A serum level of 16 µg/mL is reported in a patient with albumin of 2.0 g/dL (normal 4.0). Is dose adjustment needed?", "back": "Yes. Phenytoin is 90% albumin-bound; total drug level measures bound + free, but only free drug is active. In hypoalbuminaemia, a normal 'total' level actually represents a higher free (active) fraction. Use the <strong>Sheiner–Tozer correction</strong>: Corrected level = measured level ÷ [(0.2 × albumin) + 0.1]. Here: 16 ÷ [(0.2 × 2.0) + 0.1] = 16 ÷ 0.5 = 32 µg/mL → already toxic range. Reduce dose; ideally measure free phenytoin directly.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Phenytoin toxicity is dose-related: nystagmus (20–30 µg/mL) → ataxia (30–40 µg/mL) → mental status changes (&gt;40 µg/mL) → paradoxical seizures. Saturable (Michaelis–Menten) kinetics mean small dose increases can cause large level spikes.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> IV phenytoin must be infused ≤50 mg/min with ECG monitoring — the propylene glycol vehicle causes cardiac conduction block and hypotension. Fosphenytoin (water-soluble prodrug) can be infused at 150 mg PE/min and given IM.</div>"}, {"id": "gen:fc:11", "deck": "General Pharmacology", "dk": "gen", "type": "flashcard", "front": "A drug has a therapeutic index of 2. Compare this to penicillin and explain why monitoring is required.", "back": "Therapeutic index (TI) = TD₅₀ ÷ ED₅₀. TI of 2 means the toxic dose is only twice the effective dose — a very narrow safety margin. Classic narrow TI drugs requiring therapeutic drug monitoring: <strong>lithium, digoxin, warfarin, aminoglycosides, vancomycin, theophylline, phenytoin, cyclosporine</strong>. Penicillins have an extremely wide TI (essentially no upper toxicity limit from direct drug effects at achievable doses) — monitoring is unnecessary.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Narrow TI drugs are sensitive to: renal/hepatic impairment (reduced clearance), age extremes, drug interactions, protein binding changes, and pharmacogenomic variation. Always check TI before prescribing a new interacting drug.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> TI is a population-derived ratio, not a guarantee for an individual patient. A patient with CKD, elderly age, or TPMT deficiency may reach toxic levels well within the 'therapeutic' population range.</div>"}, {"id": "gen:fc:12", "deck": "General Pharmacology", "dk": "gen", "type": "flashcard", "front": "Isoniazid is given to two patients with latent TB: a slow NAT2 acetylator and a fast NAT2 acetylator. How does acetylator status affect each patient's risk profile?", "back": "<strong>Slow acetylators</strong> (common in Caucasians/Egyptians): higher isoniazid plasma levels → more effective bactericidal activity, but higher risk of <strong>peripheral neuropathy</strong> (pyridoxine-responsive) and drug–drug interactions (inhibits CYP2C9/CYP2E1 more). <strong>Fast acetylators</strong> (common in East Asians): lower isoniazid levels → potential treatment failure; acetylhydrazine metabolite accumulates → higher <strong>hepatotoxicity</strong> risk. Pyridoxine (B6) 25–50 mg/day is co-prescribed for all patients to prevent neuropathy.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Hydralazine (antihypertensive) and procainamide (antiarrhythmic) are also NAT2 substrates. Slow acetylators on hydralazine or procainamide are at higher risk for <strong>drug-induced lupus</strong> (DIL) — check ANA and anti-histone antibodies.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> 'Fast' acetylators of isoniazid have more hepatotoxicity, not less — the acetylhydrazine intermediate is the hepatotoxin. Slow acetylators have more neuropathy. This counter-intuitive relationship is a classic exam question.</div>"}, {"id": "gen:fc:13", "deck": "General Pharmacology", "dk": "gen", "type": "flashcard", "front": "A patient is at steady state on a drug taken every 8 hours. The dose is doubled. When does the new steady state occur?", "back": "Steady state is reached after ~5 × t½, regardless of dose. Doubling the dose doubles the steady-state plasma concentration but does <strong>NOT change when steady state is reached</strong> — only the half-life determines that. If t½ = 8 h, new steady state occurs ~40 h after the dose change whether the dose is 1× or 100×.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> A <strong>loading dose</strong> shortens the time to therapeutic concentrations without waiting 5 × t½. Practical example: digoxin (t½ 36–48 h) — without a loading dose, therapeutic levels take 7–10 days to develop.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Changing the dosing interval (not dose) changes the peak–trough fluctuation. Same total daily dose given more frequently → smoother, less fluctuating plasma levels → same average steady-state concentration.</div>"}, {"id": "gen:fc:14", "deck": "General Pharmacology", "dk": "gen", "type": "flashcard", "front": "Phase I vs Phase II metabolism: which phase more commonly produces reactive toxic intermediates, and give a clinical example.", "back": "<strong>Phase I</strong> (CYP450-mediated oxidation, reduction, hydrolysis) introduces/exposes polar functional groups — often generating reactive electrophilic intermediates. Example: <strong>paracetamol (acetaminophen)</strong> → CYP2E1/CYP3A4 → NAPQI (N-acetyl-p-benzoquinone imine) → normally conjugated with glutathione (Phase II). In overdose, glutathione depletes → NAPQI accumulates → covalent binding to hepatocytes → necrosis. <strong>Phase II</strong> (glucuronidation, sulphation, acetylation, glutathione conjugation) produces water-soluble, pharmacologically inactive metabolites — generally harmless.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> N-acetylcysteine (NAC) replenishes glutathione stores in paracetamol overdose. Works best if given within 8–10 hours. Give empirically if &gt;150 µg/mL at 4 h on the Rumack–Matthew nomogram.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Lorazepam and oxazepam bypass Phase I — they only require Phase II glucuronidation. They are the 'safe' benzodiazepines in severe liver disease (no Phase I enzymes needed). Remember 'LOT' — Lorazepam, Oxazepam, Temazepam.</div>"}, {"id": "gen:fc:15", "deck": "General Pharmacology", "dk": "gen", "type": "flashcard", "front": "Enterohepatic recirculation prolongs the effect of some drugs. Explain the mechanism and give two clinical implications.", "back": "Parent drug or its glucuronide conjugate is excreted into bile → reaches the intestine → gut bacteria express β-glucuronidase → deconjugate the drug → free drug reabsorbed → recirculates through the liver → prolonged half-life. Clinical implications: (1) <strong>Drug prolongation</strong>: morphine-6-glucuronide, oestrogens, some NSAIDs, colchicine have prolonged action via EHC; (2) <strong>Drug interaction</strong>: cholestyramine sequesters drugs in bile, interrupting EHC and reducing their efficacy/level (relevant for levothyroxine, digoxin, warfarin if taken simultaneously).<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Cholestyramine is used therapeutically to interrupt EHC of leflunomide (active metabolite) during 'washout' in patients who need rapid drug elimination (e.g., before pregnancy or hepatotoxicity).</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> The claimed 'antibiotic disrupts gut flora → reduces EHC of OCP oestrogens → contraceptive failure' has very weak evidence. The FDA does not require OCP warnings with most antibiotics (exception: rifampin — but this works via CYP induction, not EHC).</div>"}, {"id": "gen:fc:16", "deck": "General Pharmacology", "dk": "gen", "type": "flashcard", "front": "A receptor is exposed to a high agonist concentration for 48 hours. Describe the molecular sequence of desensitisation and downregulation.", "back": "<strong>Acute (minutes):</strong> GRK (G-protein-coupled receptor kinase) phosphorylates the agonist-occupied receptor → β-arrestin recruitment → uncoupling from G-protein → desensitisation (reduced signalling despite continued agonist). <strong>Hours:</strong> β-arrestin mediates receptor internalisation (endocytosis) → sequestration in endosomes. <strong>Days:</strong> Internalised receptors directed to lysosomes for degradation → receptor downregulation (reduced total receptor number). Net result: <strong>tachyphylaxis/tolerance</strong> — diminished response to same drug concentration.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> <strong>Upregulation</strong> occurs with prolonged antagonist exposure. Example: chronic beta-blocker use upregulates β-adrenoceptors → abrupt withdrawal → supersensitivity to catecholamines → rebound tachycardia, hypertension, angina. Always taper beta-blockers; never abruptly stop in cardiac patients.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Nitrate tolerance (ISDN/nitroglycerin patches) involves receptor-level and downstream desensitisation of guanylate cyclase. Requires a 'nitrate-free interval' (8–12 h/day) to restore sensitivity.</div>"}, {"id": "gen:fc:17", "deck": "General Pharmacology", "dk": "gen", "type": "flashcard", "front": "A 70-year-old patient with HF and CKD (eGFR 18) needs gentamicin for Gram-negative bacteraemia. How should dosing be adjusted?", "back": "Two strategies for renal impairment: (1) <strong>Extend the dosing interval</strong> (preferred): maintain same dose, lengthen interval proportional to CrCl reduction → maintains high peak (efficacy — aminoglycosides are concentration-dependent killers) while reducing trough accumulation (toxicity is trough-driven). (2) Reduce dose per interval (less preferred — low peaks may compromise efficacy). Monitor trough &lt;1 µg/mL (traditional dosing) or use Hartford nomogram for extended-interval dosing.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> <strong>Nephrotoxicity</strong> is usually reversible (proximal tubule regenerates). <strong>Ototoxicity</strong> (cochleotoxicity and vestibulotoxicity) is often irreversible — damaged inner ear hair cells cannot regenerate. Never resume an aminoglycoside that caused confirmed ototoxicity.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> TDM for aminoglycosides: peak (30 min after infusion end) measures efficacy; trough (just before next dose) measures toxicity risk. Extended-interval dosing uses a single 6–14 h post-dose level plotted on a nomogram — do NOT use traditional peak/trough targets.</div>"}, {"id": "gen:fc:18", "deck": "General Pharmacology", "dk": "gen", "type": "flashcard", "front": "Two drugs, each 90% protein-bound, are given together. Drug A is displaced from albumin by Drug B. Describe the immediate effect and the long-term equilibrium.", "back": "<strong>Immediately:</strong> Free (active) Drug A rises → increased pharmacological effect and potential toxicity, increased Vd. <strong>Long-term:</strong> The additional free drug is available for hepatic metabolism and renal filtration → clearance increases → free drug concentration gradually returns toward baseline (new equilibrium). For most drugs, the net clinical effect is modest, but for <strong>narrow TI drugs</strong>, the initial spike is clinically dangerous (e.g., phenytoin displaced by valproate → transient phenytoin toxicity).<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Valproate both displaces phenytoin from albumin (transient free drug ↑) AND inhibits CYP2C9 (persistent total drug ↑). The combination creates a complex, biphasic interaction that can be severely misleading if total phenytoin level is used alone.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Protein displacement is clinically significant only when: (1) the displaced drug has a narrow TI, (2) &gt;90% protein-bound, and (3) clearance cannot immediately compensate (e.g., saturated hepatic metabolism). Most displacement interactions are transient and of limited clinical significance.</div>"}, {"id": "gen:fc:19", "deck": "General Pharmacology", "dk": "gen", "type": "flashcard", "front": "A patient is on a prodrug that requires hepatic CYP2C19 for activation. She is also prescribed omeprazole. What problem arises, and name the drug.", "back": "<strong>Clopidogrel</strong> (antiplatelet prodrug for ACS/stent). CYP2C19 converts clopidogrel → active thiol metabolite that irreversibly blocks P2Y12 receptors on platelets. Omeprazole (and esomeprazole) are CYP2C19 <strong>inhibitors</strong> → reduced clopidogrel activation → up to 45% reduction in antiplatelet effect → increased risk of stent thrombosis and MACE. <strong>Use pantoprazole instead</strong> (weakest CYP2C19 inhibition among PPIs).<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> CYP2C19 poor metabolisers (10–15% Caucasians, 15–25% Asians) have inherently reduced clopidogrel activation — consider genotyping or switch to ticagrelor/prasugrel (direct-acting P2Y12 inhibitors, no CYP activation needed).</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Ticagrelor and prasugrel do NOT require metabolic activation — they are direct-acting P2Y12 inhibitors. They are NOT affected by CYP2C19 status or PPIs. Prasugrel is contraindicated in prior TIA/stroke and age &gt;75 (excess bleeding risk).</div>"}, {"id": "gen:q:0", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "What does ADME stand for?", "back": "Absorption, Distribution, Metabolism, Elimination."}, {"id": "gen:q:1", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Which physicochemical form of a weak electrolyte crosses membranes by passive diffusion?", "back": "The non-ionised (uncharged, lipid-soluble) form."}, {"id": "gen:q:2", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Write the Henderson–Hasselbalch relationship for an ionisable drug.", "back": "log([protonated]/[unprotonated]) = pKₐ − pH."}, {"id": "gen:q:3", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "On which side of a membrane does a weak acid accumulate?", "back": "On the more basic (alkaline) side — it becomes more ionised and is trapped there."}, {"id": "gen:q:4", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Why does alkalinising the urine help in aspirin overdose?", "back": "Aspirin is a weak acid; alkaline urine ionises (traps) it in the tubule, preventing reabsorption and enhancing excretion."}, {"id": "gen:q:5", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Name the two transporter superfamilies and their direction.", "back": "SLC (solute carriers) — mostly uptake; ABC (ATP-binding cassette) — efflux."}, {"id": "gen:q:6", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Distinguish facilitated diffusion from active transport.", "back": "Facilitated diffusion is carrier-mediated but needs no energy and moves down the gradient; active transport needs energy and can move against the gradient."}, {"id": "gen:q:7", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Give an example of a primary active transporter relevant to drugs.", "back": "P-glycoprotein (ABCB1/MDR1) — hydrolyses ATP to export drugs such as digoxin."}, {"id": "gen:q:8", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "What drives secondary active transport?", "back": "An ion electrochemical gradient (usually Na⁺), established by Na⁺/K⁺-ATPase."}, {"id": "gen:q:9", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Why are second-generation antihistamines (e.g., loratadine) non-sedating?", "back": "They are more ionised/hydrophilic, so they poorly cross the blood-brain barrier."}, {"id": "gen:q:10", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "What is paracellular transport?", "back": "Passage of solutes through gaps between cells; large in most capillaries but tight at the BBB."}, {"id": "gen:q:11", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Define bioavailability (F).", "back": "The fraction of an administered dose that reaches the systemic circulation in unchanged form."}, {"id": "gen:q:12", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "What is the bioavailability of an intravenous drug?", "back": "1 (100%) by definition."}, {"id": "gen:q:13", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "What is the first-pass effect?", "back": "Metabolism of an orally absorbed drug by gut/liver before it reaches the systemic circulation, reducing bioavailability."}, {"id": "gen:q:14", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "How is oral bioavailability calculated relative to IV?", "back": "F = AUC(oral)/AUC(IV) for equal doses."}, {"id": "gen:q:15", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Which transporter in the enterocyte limits oral absorption of some drugs?", "back": "P-glycoprotein, by exporting drug back into the gut lumen."}, {"id": "gen:q:16", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Name a major tissue reservoir for lipophilic drugs.", "back": "Adipose tissue (fat); also plasma proteins and bone."}, {"id": "gen:q:17", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Only what kind of drug is pharmacologically active and able to distribute/clear?", "back": "Free (unbound) drug."}, {"id": "gen:q:18", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "What plasma protein chiefly binds acidic drugs vs basic drugs?", "back": "Albumin binds acidic drugs; α₁-acid glycoprotein binds basic drugs."}, {"id": "gen:q:19", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Over what pH range can urine vary, enabling pH-dependent excretion?", "back": "Approximately 4.5 to 8.0."}, {"id": "gen:q:20", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Name the four key pharmacokinetic parameters.", "back": "Bioavailability (F), volume of distribution (Vd), clearance (CL), half-life (t½)."}, {"id": "gen:q:21", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Define volume of distribution.", "back": "The apparent volume relating the amount of drug in the body to its plasma concentration: Vd = amount/Cp."}, {"id": "gen:q:22", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Why is Vd called \"apparent\"?", "back": "It is a mathematical proportionality constant, not a real anatomical volume; lipophilic, tissue-bound drugs can have Vd far exceeding total body water."}, {"id": "gen:q:23", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Define clearance.", "back": "The volume of plasma completely cleared of drug per unit time; the body's efficiency at eliminating drug."}, {"id": "gen:q:24", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Write systemic clearance as a sum.", "back": "CL = CL(renal) + CL(hepatic) + CL(other)."}, {"id": "gen:q:25", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Give the equation linking half-life to Vd and CL.", "back": "t½ ≈ 0.693 × Vd/CL."}, {"id": "gen:q:26", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Why is half-life called a \"derived\" parameter?", "back": "Because it depends on the two independent variables CL and Vd; it changes when either changes."}, {"id": "gen:q:27", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "If clearance falls (e.g., renal disease) but Vd is constant, what happens to t½?", "back": "t½ increases (lengthens)."}, {"id": "gen:q:28", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Define first-order kinetics.", "back": "A constant fraction of drug is eliminated per unit time; rate is proportional to concentration; t½ is constant."}, {"id": "gen:q:29", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Define zero-order kinetics.", "back": "A constant amount of drug is eliminated per unit time (saturable); rate is independent of concentration."}, {"id": "gen:q:30", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Name three drugs showing zero-order kinetics.", "back": "Ethanol, phenytoin, high-dose aspirin (also theophylline at high dose)."}, {"id": "gen:q:31", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Roughly how fast is ethanol metabolised?", "back": "About 10 g per hour (a fixed amount — zero-order)."}, {"id": "gen:q:32", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "After how many half-lives is steady state essentially reached?", "back": "~4–5 half-lives (≈94% after 4 t½)."}, {"id": "gen:q:33", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Does the dose affect the <em>time</em> to reach steady state?", "back": "No — time to steady state depends only on half-life, not on dose."}, {"id": "gen:q:34", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Write the steady-state concentration equation for oral dosing.", "back": "Css = (F × Dose)/(CL × τ), where τ is the dosing interval."}, {"id": "gen:q:35", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "How is a maintenance dosing rate calculated?", "back": "Dosing rate = CL × target Css (÷ F for oral)."}, {"id": "gen:q:36", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "How is a loading dose calculated, and why give one?", "back": "LD = Vd × target Cp / F; given to reach therapeutic levels rapidly when the half-life is long (e.g., digoxin)."}, {"id": "gen:q:37", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "For a high-extraction-ratio drug, hepatic clearance approaches what?", "back": "Hepatic blood flow — clearance is flow-limited."}, {"id": "gen:q:38", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Which type of drug (high vs low extraction) is more sensitive to enzyme induction/inhibition?", "back": "Low-extraction (capacity-limited) drugs."}, {"id": "gen:q:39", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "What is AUC and what does it relate to?", "back": "Area under the concentration–time curve; for F=1, CL = Dose/AUC, so it reflects total drug exposure."}, {"id": "gen:q:40", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Name the four main receptor superfamilies.", "back": "GPCRs, ligand-gated ion channels, enzyme-linked (catalytic, e.g., RTK) receptors, and nuclear (intracellular) receptors."}, {"id": "gen:q:41", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Which receptor type acts fastest, and on what time scale?", "back": "Ligand-gated ion channels — milliseconds."}, {"id": "gen:q:42", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Which receptor type acts slowest and why?", "back": "Nuclear receptors — hours to days, because they alter gene transcription."}, {"id": "gen:q:43", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Define affinity.", "back": "The tightness with which a drug binds its receptor; quantified by Kd (lower Kd = higher affinity)."}, {"id": "gen:q:44", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Define potency.", "back": "The amount of drug needed to produce a given effect; measured by EC₅₀/ED₅₀ (horizontal position of the curve)."}, {"id": "gen:q:45", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Define efficacy.", "back": "The maximal effect a drug can produce (Emax) — the ceiling, reflecting intrinsic activity."}, {"id": "gen:q:46", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Which matters more clinically, potency or efficacy?", "back": "Efficacy (and therapeutic index); potency mainly determines the dose."}, {"id": "gen:q:47", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "What is a full agonist?", "back": "A ligand that produces the maximal response a receptor population can give (full intrinsic activity)."}, {"id": "gen:q:48", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "What is a partial agonist?", "back": "A ligand that activates the receptor but cannot produce the maximal response even at full occupancy (submaximal Emax)."}, {"id": "gen:q:49", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "What can a partial agonist do in the presence of a full agonist?", "back": "Act as a functional antagonist — competing for receptor and lowering the overall response."}, {"id": "gen:q:50", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "What is an inverse agonist?", "back": "A ligand that reduces constitutive (basal) receptor activity below the no-drug baseline."}, {"id": "gen:q:51", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "How does an inverse agonist behave when there is no basal activity?", "back": "It appears to act as a neutral antagonist."}, {"id": "gen:q:52", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "In the two-state model, full vs partial agonists differ in what?", "back": "Their efficacy — i.e., how far they shift the receptor equilibrium toward the active (Ra) state."}, {"id": "gen:q:53", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Effect of a competitive (reversible) antagonist on the agonist curve?", "back": "Parallel rightward shift; Emax unchanged (surmountable by more agonist)."}, {"id": "gen:q:54", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Effect of a non-competitive/irreversible antagonist?", "back": "Reduced Emax; not surmountable."}, {"id": "gen:q:55", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Define a physiological antagonist with an example.", "back": "A drug producing an opposite effect via a different receptor — e.g., adrenaline vs histamine in anaphylaxis."}, {"id": "gen:q:56", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Define a chemical antagonist with an example.", "back": "A drug that inactivates another by binding it directly — e.g., protamine + heparin, or chelators."}, {"id": "gen:q:57", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "What are spare receptors?", "back": "Receptors in excess of those needed for maximal response — maximal effect occurs before 100% occupancy (EC₅₀ &lt; Kd)."}, {"id": "gen:q:58", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "What is an allosteric modulator?", "back": "A ligand binding a site distinct from the orthosteric (agonist) site to enhance (PAM) or reduce (NAM) receptor function — e.g., benzodiazepines on GABAA."}, {"id": "gen:q:59", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "What does \"orthosteric\" mean?", "back": "Binding at the same site as the endogenous agonist."}, {"id": "gen:q:60", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Difference between graded and quantal dose-response curves?", "back": "Graded = continuous magnitude of effect in one system; quantal = all-or-none response across a population (fraction responding)."}, {"id": "gen:q:61", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "What does ED₅₀ mean on a quantal curve?", "back": "The dose producing the specified effect in 50% of the population."}, {"id": "gen:q:62", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "What does LD₅₀ mean?", "back": "The dose lethal to 50% of the (experimental) population."}, {"id": "gen:q:63", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Write the therapeutic index.", "back": "TI = LD₅₀ / ED₅₀."}, {"id": "gen:q:64", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Why can two drugs with identical LD₅₀ differ in safety?", "back": "Curve slope differs — a steeper curve gives less separation between effective and toxic doses."}, {"id": "gen:q:65", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "What is the certain safety factor and why is it stricter?", "back": "LD₁/ED₉₉; it accounts for the extremes of the curves rather than the midpoints."}, {"id": "gen:q:66", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Name four narrow-therapeutic-index drugs.", "back": "Warfarin, digoxin, lithium, phenytoin (also theophylline, aminoglycosides)."}, {"id": "gen:q:67", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "What is the therapeutic window?", "back": "The concentration range between minimum effective and minimum toxic concentrations."}, {"id": "gen:q:68", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Effector and second messenger for Gs?", "back": "Activates adenylyl cyclase → raises cAMP → activates PKA."}, {"id": "gen:q:69", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Effector for Gi?", "back": "Inhibits adenylyl cyclase (lowers cAMP); also opens K⁺ and inhibits Ca²⁺ channels."}, {"id": "gen:q:70", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Effector and messengers for Gq?", "back": "Activates phospholipase C-β → IP₃ (releases Ca²⁺) + DAG (activates PKC)."}, {"id": "gen:q:71", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Which G-protein do β-adrenergic receptors couple to?", "back": "Gs."}, {"id": "gen:q:72", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Which G-proteins for M₁, M₂, M₃ muscarinic receptors?", "back": "M₁ and M₃ → Gq; M₂ → Gi."}, {"id": "gen:q:73", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Which G-protein for α₁ and α₂ adrenergic receptors?", "back": "α₁ → Gq; α₂ → Gi."}, {"id": "gen:q:74", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Who discovered cAMP as a second messenger?", "back": "Earl Sutherland (Nobel Prize, 1972)."}, {"id": "gen:q:75", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "What degrades cAMP, and name a drug class that inhibits it?", "back": "Phosphodiesterases (PDEs); inhibitors include caffeine, sildenafil, milrinone, theophylline."}, {"id": "gen:q:76", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Define tachyphylaxis.", "back": "Rapid loss of response on repeated/continuous dosing (acute desensitisation)."}, {"id": "gen:q:77", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Molecular basis of GPCR desensitisation?", "back": "GRK phosphorylates the agonist-occupied receptor → β-arrestin binds → uncouples it from the G-protein and promotes internalisation."}, {"id": "gen:q:78", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Why does chronic β-blockade cause rebound on abrupt withdrawal?", "back": "Receptor up-regulation/supersensitivity → exaggerated response (rebound tachycardia/hypertension) when the drug is stopped."}, {"id": "gen:q:79", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "What does down-regulation of receptors underlie clinically?", "back": "Tolerance to chronic agonist exposure (reduced receptor number)."}, {"id": "gen:q:80", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "What is the overall purpose of drug metabolism?", "back": "To convert lipophilic drugs into more water-soluble, excretable metabolites."}, {"id": "gen:q:81", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "What do Phase 1 reactions do?", "back": "Introduce or expose a functional group (–OH, –NH₂, –SH) via oxidation, reduction or hydrolysis (functionalisation)."}, {"id": "gen:q:82", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "What do Phase 2 reactions do?", "back": "Conjugate the drug (or its Phase 1 product) with an endogenous molecule, greatly increasing water solubility."}, {"id": "gen:q:83", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Name the major Phase 2 conjugation reactions.", "back": "Glucuronidation, sulfation, acetylation, methylation, glutathione conjugation, glycine conjugation."}, {"id": "gen:q:84", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Which is the most common Phase 2 reaction and its enzyme?", "back": "Glucuronidation, by UDP-glucuronosyltransferases (UGTs)."}, {"id": "gen:q:85", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Must Phase 1 always precede Phase 2?", "back": "No — some drugs are conjugated directly (e.g., directly glucuronidated)."}, {"id": "gen:q:86", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Where in the cell are CYPs and UGTs located?", "back": "In the endoplasmic reticulum (microsomal fraction)."}, {"id": "gen:q:87", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Decode the name CYP3A4.", "back": "Cytochrome P450, family 3, subfamily A, gene 4."}, {"id": "gen:q:88", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Which CYP subfamilies are most important in drug metabolism?", "back": "CYP2C, CYP2D, and CYP3A."}, {"id": "gen:q:89", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "What fraction of clinical drugs does CYP3A4 metabolise?", "back": "Over 50%."}, {"id": "gen:q:90", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Which CYP is most abundant in the liver?", "back": "CYP3A4."}, {"id": "gen:q:91", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Which CYP metabolises codeine to morphine?", "back": "CYP2D6."}, {"id": "gen:q:92", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Which CYP activates clopidogrel?", "back": "CYP2C19."}, {"id": "gen:q:93", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Which CYP metabolises S-warfarin?", "back": "CYP2C9."}, {"id": "gen:q:94", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Which CYP is induced by cigarette smoking?", "back": "CYP1A2 (affecting theophylline, caffeine, clozapine)."}, {"id": "gen:q:95", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Which CYP generates the toxic paracetamol metabolite, and what is it?", "back": "CYP2E1 generates NAPQI (N-acetyl-p-benzoquinone imine)."}, {"id": "gen:q:96", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "List the commonly polymorphic CYPs.", "back": "CYP2A6, CYP2C9, CYP2C19, CYP2D6."}, {"id": "gen:q:97", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "What is a prodrug?", "back": "An inactive (or less active) compound that is metabolised into its active form."}, {"id": "gen:q:98", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Give three prodrug examples and their active forms.", "back": "Codeine→morphine, clopidogrel→active thiol metabolite, enalapril→enalaprilat (also levodopa, valacyclovir)."}, {"id": "gen:q:99", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "What enzyme class besides CYP carries out Phase 1 oxidations?", "back": "Flavin-containing monooxygenases (FMOs) and epoxide hydrolases; esterases for hydrolysis."}, {"id": "gen:q:100", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "What is enzyme induction?", "back": "Increased synthesis of a metabolising enzyme, raising metabolic capacity over days to weeks."}, {"id": "gen:q:101", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "What is enzyme inhibition, and how fast does it act?", "back": "Blockade of enzyme activity (often competitive at the active site); near-immediate (hours)."}, {"id": "gen:q:102", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Effect of induction on a normal (active) drug's level and effect?", "back": "Lower drug level → loss of efficacy."}, {"id": "gen:q:103", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Effect of inhibition on a normal drug's level?", "back": "Higher drug level → risk of toxicity."}, {"id": "gen:q:104", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "How do induction/inhibition effects invert for a prodrug?", "back": "Induction increases active metabolite (more effect/toxicity); inhibition decreases activation (reduced effect)."}, {"id": "gen:q:105", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "List five classic CYP inducers.", "back": "Rifampin, carbamazepine, phenytoin, phenobarbital, St John's wort (also chronic alcohol, smoking, griseofulvin)."}, {"id": "gen:q:106", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "List five classic CYP inhibitors.", "back": "Ketoconazole, erythromycin/clarithromycin, cimetidine, ritonavir, grapefruit juice (also valproate, isoniazid, fluconazole)."}, {"id": "gen:q:107", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Which component of grapefruit juice inhibits CYP3A4?", "back": "Furanocoumarins (and flavonoids like naringin) — chiefly intestinal CYP3A4."}, {"id": "gen:q:108", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Why is rifampin + oral contraceptive a classic interaction?", "back": "Rifampin induces CYP3A4 → faster OCP metabolism → contraceptive failure."}, {"id": "gen:q:109", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "How does chronic alcohol increase paracetamol hepatotoxicity?", "back": "It induces CYP2E1 → more NAPQI formed → greater glutathione depletion."}, {"id": "gen:q:110", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "What does St John's wort induce, and a consequence?", "back": "CYP3A4 (and P-gp) → lowers levels of cyclosporine, OCPs, many drugs."}, {"id": "gen:q:111", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Why was terfenadine withdrawn?", "back": "It is a prodrug; CYP3A4 inhibitors (erythromycin, grapefruit) raised the parent level → fatal QT prolongation/arrhythmia."}, {"id": "gen:q:112", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "What does an inducer mnemonic \"CRAP GPS\" stand for?", "back": "Carbamazepine, Rifampin, Alcohol(chronic), Phenytoin, Griseofulvin/Phenobarbital, Smoking, St John's wort."}, {"id": "gen:q:113", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "What enzyme detoxifies NAPQI?", "back": "Glutathione (conjugation via glutathione-S-transferase)."}, {"id": "gen:q:114", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "How does N-acetylcysteine treat paracetamol toxicity?", "back": "It replenishes hepatic glutathione (provides cysteine), allowing NAPQI detoxification."}, {"id": "gen:q:115", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "What enzyme acetylates isoniazid, and why does it matter?", "back": "N-acetyltransferase 2 (NAT2); slow acetylators accumulate INH → neuropathy/hepatotoxicity."}, {"id": "gen:q:116", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "What does TPMT metabolise?", "back": "Thiopurines (azathioprine, 6-mercaptopurine); low activity → myelosuppression."}, {"id": "gen:q:117", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "What is the first-pass effect in relation to metabolism?", "back": "Pre-systemic metabolism by gut wall and liver that reduces oral bioavailability."}, {"id": "gen:q:118", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Generally, do Phase 1 reactions activate or inactivate drugs?", "back": "Usually inactivate — but they can activate prodrugs or create reactive/toxic metabolites."}, {"id": "gen:q:119", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Which Phase 2 reaction can produce reactive electrophiles linked to toxicity?", "back": "Some conjugations (and Phase 1 oxidations) yield reactive metabolites; the classic toxic intermediate is NAPQI from paracetamol."}, {"id": "gen:q:120", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Whose principle is \"the dose makes the poison\"?", "back": "Paracelsus."}, {"id": "gen:q:121", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "What does an LD₅₀ value describe?", "back": "The dose lethal to 50% of a test population."}, {"id": "gen:q:122", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "What is a U-shaped (hormetic) dose-response curve?", "back": "Both deficiency and excess are harmful — typical of essential metals and hormones."}, {"id": "gen:q:123", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "What does a hockey-stick curve indicate?", "back": "No effect until a saturable removal process is overwhelmed, then effect appears (zero-order saturation)."}, {"id": "gen:q:124", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "List the five steps of poisoning management.", "back": "Stabilise (ABCs), decontaminate, give antidote, enhance elimination, supportive care/monitoring."}, {"id": "gen:q:125", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "What does activated charcoal NOT bind well?", "back": "Metals (iron, lithium), alcohols, hydrocarbons, and caustics."}, {"id": "gen:q:126", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "What does multiple-dose activated charcoal achieve?", "back": "Interrupts enterohepatic recirculation (e.g., theophylline, carbamazepine, dapsone, phenobarbital)."}, {"id": "gen:q:127", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Antidote for paracetamol?", "back": "N-acetylcysteine."}, {"id": "gen:q:128", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Antidote for opioids?", "back": "Naloxone (μ-opioid antagonist)."}, {"id": "gen:q:129", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Antidote for benzodiazepines, and main caution?", "back": "Flumazenil; can precipitate seizures (especially in dependence or co-ingested proconvulsants)."}, {"id": "gen:q:130", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Antidotes for organophosphate poisoning?", "back": "Atropine (blocks muscarinic effects) + pralidoxime (reactivates acetylcholinesterase)."}, {"id": "gen:q:131", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Antidote for methanol/ethylene glycol?", "back": "Fomepizole (or ethanol) — inhibits alcohol dehydrogenase."}, {"id": "gen:q:132", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Antidote for iron overdose?", "back": "Deferoxamine (chelation)."}, {"id": "gen:q:133", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Antidote for digoxin toxicity?", "back": "Digoxin-specific antibody fragments (Fab)."}, {"id": "gen:q:134", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Antidote for heparin?", "back": "Protamine sulfate (chemical antagonist)."}, {"id": "gen:q:135", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Antidote for warfarin over-anticoagulation?", "back": "Vitamin K, plus FFP or prothrombin complex concentrate for active bleeding."}, {"id": "gen:q:136", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Antidote for cyanide?", "back": "Hydroxocobalamin and/or sodium thiosulfate (± nitrites)."}, {"id": "gen:q:137", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Which drug properties favour removal by haemodialysis?", "back": "Low Vd, low protein binding, low molecular weight, water-soluble."}, {"id": "gen:q:138", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Name dialysable toxins.", "back": "Lithium, salicylate, methanol, ethylene glycol, theophylline, valproate, metformin, barbiturates."}, {"id": "gen:q:139", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Why is acetaminophen overdose the classic \"saturated pathway\" example?", "back": "Conjugation pathways saturate in overdose, diverting metabolism via CYP2E1 to toxic NAPQI and depleting glutathione → hepatic necrosis."}, {"id": "gen:q:140", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "What do SLC transporters generally do?", "back": "Mediate uptake (facilitated or secondary active transport) into cells."}, {"id": "gen:q:141", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "What do ABC transporters do, and what powers them?", "back": "Efflux drugs out of cells, powered by ATP hydrolysis."}, {"id": "gen:q:142", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Give the alternative names for P-glycoprotein.", "back": "ABCB1 / MDR1."}, {"id": "gen:q:143", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Name three sites where P-gp is clinically important.", "back": "Gut enterocytes (limits absorption), the BBB (limits brain entry), and tumour cells (multidrug resistance)."}, {"id": "gen:q:144", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Which classic cardiac drug is a P-gp substrate?", "back": "Digoxin (P-gp inhibitors like verapamil/quinidine raise its level)."}, {"id": "gen:q:145", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "What does OATP1B1 transport, and a consequence of inhibition?", "back": "Hepatic uptake of statins; inhibition/variants → higher statin levels → myopathy."}, {"id": "gen:q:146", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Which transporter secretes metformin renally?", "back": "OCT2 (organic cation transporter)."}, {"id": "gen:q:147", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "How does probenecid prolong penicillin action?", "back": "It inhibits OAT-mediated tubular secretion of penicillin, reducing renal clearance."}, {"id": "gen:q:148", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Define a poor metabolizer (PM).", "back": "An individual with little/no functional enzyme activity (e.g., two no-function CYP2D6 alleles)."}, {"id": "gen:q:149", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Define an ultrarapid metabolizer (UM).", "back": "Someone with increased enzyme activity, often from gene duplication."}, {"id": "gen:q:150", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Codeine in an ultrarapid CYP2D6 metabolizer — risk?", "back": "Excess morphine → respiratory depression/toxicity (infant deaths via breast milk reported)."}, {"id": "gen:q:151", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Codeine in a CYP2D6 poor metabolizer — effect?", "back": "Little or no analgesia (cannot form morphine)."}, {"id": "gen:q:152", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "CYP2C19 poor metabolizer on clopidogrel — risk?", "back": "Reduced activation → reduced antiplatelet effect → stent thrombosis risk."}, {"id": "gen:q:153", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "TPMT deficiency with thiopurines — danger?", "back": "Severe, potentially fatal myelosuppression."}, {"id": "gen:q:154", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "UGT1A1*28 with irinotecan — risk?", "back": "Increased neutropenia and diarrhoea."}, {"id": "gen:q:155", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "G6PD deficiency — which drugs cause haemolysis?", "back": "Primaquine, rasburicase, sulfonamides, dapsone, nitrofurantoin."}, {"id": "gen:q:156", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Which genes guide warfarin dosing?", "back": "VKORC1 (target) and CYP2C9 (metabolism)."}, {"id": "gen:q:157", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Which HLA allele predicts abacavir hypersensitivity?", "back": "HLA-B*57:01."}, {"id": "gen:q:158", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Which HLA allele predicts carbamazepine SJS/TEN, and in whom?", "back": "HLA-B*15:02, particularly in people of Southeast/East Asian ancestry."}, {"id": "gen:q:159", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Why does CYP3A5 expression vary by ancestry?", "back": "Allele frequencies differ; many individuals carry no-function alleles, affecting drugs like tacrolimus dosing."}, {"id": "gen:q:160", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "What is target validation?", "back": "Confirming that modulating a chosen molecular target produces the desired therapeutic effect."}, {"id": "gen:q:161", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "What does \"druggable\" mean?", "back": "A target that can be modulated by a small molecule or biologic to therapeutic benefit."}, {"id": "gen:q:162", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "What is high-throughput screening?", "back": "Rapid automated testing of large compound libraries against a target to find hits/leads."}, {"id": "gen:q:163", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "What document must be filed before first-in-human trials?", "back": "An Investigational New Drug (IND) application."}, {"id": "gen:q:164", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "What is studied in Phase I trials?", "back": "Safety, tolerability and pharmacokinetics, usually in healthy volunteers."}, {"id": "gen:q:165", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "What is the focus of Phase II?", "back": "Efficacy and dose-finding in patients."}, {"id": "gen:q:166", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "What does Phase III establish?", "back": "Confirmatory efficacy and safety in large patient numbers vs standard therapy."}, {"id": "gen:q:167", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "What is filed for marketing approval?", "back": "A New Drug Application (NDA) — or BLA for biologics."}, {"id": "gen:q:168", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "What is a biosimilar?", "back": "A biologic highly similar to an approved reference biologic — not an identical generic, due to manufacturing complexity."}, {"id": "gen:q:169", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Which bacterial enzyme drives enterohepatic recycling of drugs?", "back": "Bacterial β-glucuronidase (deconjugates glucuronides, regenerating active drug)."}, {"id": "gen:q:170", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Which gut bacterium inactivates digoxin?", "back": "Eggerthella lenta."}, {"id": "gen:q:171", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "How do gut bacteria activate sulfasalazine?", "back": "They cleave it into 5-aminosalicylate (active) and sulfapyridine."}, {"id": "gen:q:172", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "What types of reactions does the microbiome predominantly perform?", "back": "Reductions, hydrolyses and deconjugations."}, {"id": "gen:q:173", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Why is postmarketing surveillance necessary?", "back": "Premarketing trials are short and small, missing rare or delayed adverse effects."}, {"id": "gen:q:174", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Distinguish Type A from Type B adverse drug reactions.", "back": "Type A = augmented, dose-related, predictable, common; Type B = bizarre, idiosyncratic, dose-independent, rare."}, {"id": "gen:q:175", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Give an example of a Type B reaction.", "back": "Penicillin anaphylaxis or Stevens-Johnson syndrome."}, {"id": "gen:q:176", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "What is a spontaneous reporting system, with an example?", "back": "Voluntary ADR reporting that generates safety signals — e.g., FDA FAERS, India's PvPI/IPC."}, {"id": "gen:q:177", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "What is a black box warning?", "back": "The FDA's strongest labelling warning about a serious or life-threatening risk."}, {"id": "gen:q:178", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Name two drugs withdrawn for safety postmarketing.", "back": "Rofecoxib (CV events), cerivastatin (rhabdomyolysis); also terfenadine, troglitazone."}, {"id": "gen:q:179", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Give an example of a genetic ADR risk factor recognised in pharmacovigilance.", "back": "TPMT variants predisposing to thiopurine myelosuppression."}, {"id": "gen:q:180", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "A drug has a very large Vd — is it more likely lipophilic or hydrophilic?", "back": "Lipophilic (it partitions widely into tissues, leaving little in plasma)."}, {"id": "gen:q:181", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Doubling clearance, with Vd unchanged, does what to half-life?", "back": "Halves it (t½ ∝ Vd/CL)."}, {"id": "gen:q:182", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Why give sodium bicarbonate in salicylate poisoning?", "back": "It alkalinises urine, ionising and trapping the weak-acid salicylate → enhanced renal excretion."}, {"id": "gen:q:183", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "A patient on clopidogrel has recurrent stent thrombosis — name a pharmacogenetic cause.", "back": "CYP2C19 poor-metaboliser status (failed prodrug activation)."}, {"id": "gen:q:184", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Starting rifampin lowers a patient's cyclosporine level — mechanism?", "back": "CYP3A4 (and P-gp) induction increases cyclosporine metabolism/efflux."}, {"id": "gen:q:185", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Why is IV the only reliable route for a drug with ~100% first-pass metabolism?", "back": "Oral bioavailability is near zero because the liver/gut clear it before systemic entry."}, {"id": "gen:q:186", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "A β-blocker is stopped abruptly and the patient has rebound tachycardia — why?", "back": "Chronic blockade up-regulated β-receptors (supersensitivity)."}, {"id": "gen:q:187", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Which is more dangerous to overdose: a high-TI or low-TI drug?", "back": "Low-TI drug (narrow margin between effective and toxic doses)."}, {"id": "gen:q:188", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Naloxone reverses opioid overdose by acting as what?", "back": "A competitive μ-opioid receptor antagonist."}, {"id": "gen:q:189", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "A chronic alcoholic takes a modest paracetamol overdose and develops severe hepatotoxicity — why?", "back": "CYP2E1 induction increases NAPQI formation, overwhelming glutathione."}, {"id": "gen:q:190", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Which receptor superfamily do steroids act on, and how fast?", "back": "Nuclear receptors — slow (hours–days), via gene transcription."}, {"id": "gen:q:191", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Salbutamol acts on β₂ receptors coupled to which G-protein/messenger?", "back": "Gs → adenylyl cyclase → cAMP."}, {"id": "gen:q:192", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "A partial agonist given with a full agonist reduces the response — what is it acting as?", "back": "A competitive (functional) antagonist."}, {"id": "gen:q:193", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Grapefruit juice raises a statin's level — mechanism and risk?", "back": "Inhibits intestinal CYP3A4 → higher statin exposure → myopathy/rhabdomyolysis risk."}, {"id": "gen:q:194", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Why is digoxin given with a loading dose?", "back": "Its long half-life would otherwise delay therapeutic levels for days; LD fills the large Vd quickly."}, {"id": "gen:q:195", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "A drug is highly protein-bound with small Vd — is it dialysable?", "back": "Poorly — most drug is bound/in plasma compartment but protein binding limits free drug removal; large Vd also reduces dialysability. (Best dialysed: low binding + low Vd.)"}, {"id": "gen:q:196", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "An irreversible antagonist does what to Emax?", "back": "Reduces it (non-surmountable)."}, {"id": "gen:q:197", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Phenytoin shows a sudden jump from therapeutic to toxic levels with small dose increases — why?", "back": "It follows zero-order (saturable) kinetics at therapeutic doses."}, {"id": "gen:q:198", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "A test for HLA-B*57:01 is ordered before which drug?", "back": "Abacavir (to prevent hypersensitivity)."}, {"id": "gen:q:199", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "State the master equation linking maintenance dose to clearance and target level.", "back": "Dosing rate = CL × Css(target); equivalently Css = F·Dose/(CL·τ)."}, {"id": "neuro:fc:0", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "flashcard", "front": "A patient on phenelzine (MAOI) for depression eats aged cheese at a party and collapses with a hypertensive crisis, severe headache, and diaphoresis. Explain the full pharmacological chain of events.", "back": "The <strong>cheese reaction</strong> (tyramine crisis): aged cheese is rich in <strong>tyramine</strong> — normally metabolised by MAO-A in intestinal epithelium and liver (first-pass), preventing systemic absorption. Phenelzine irreversibly inhibits MAO-A and MAO-B → tyramine bypasses first-pass metabolism → enters systemic circulation → taken up into presynaptic terminals by NET → displaces noradrenaline from vesicles → massive NA release into synapse → intense α1/β1 adrenoceptor stimulation → <strong>hypertensive crisis</strong> (NA + adrenaline surge), tachycardia, severe occipital headache, diaphoresis, risk of intracerebral haemorrhage. Treatment: IV phentolamine (non-selective α-blocker) or nitroprusside.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Moclobemide is a reversible MAO-A inhibitor (RIMA) — tyramine competitively displaces it, making the cheese reaction far less severe. Dietary restrictions less strict than irreversible MAOIs. Selegiline (low dose) is a selective MAO-B inhibitor — does NOT require tyramine dietary restriction at standard doses (MAO-B does not metabolise tyramine in the gut).</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> MAOIs + SSRIs/SNRIs/tramadol/pethidine → <strong>serotonin syndrome</strong> (not cheese reaction). MAOIs + sympathomimetics (pseudoephedrine, amphetamine) → tyramine-like crisis. Minimum 14-day washout after stopping an irreversible MAOI before starting any serotonergic drug; 5 weeks after fluoxetine (long half-life) before starting an MAOI.</div>"}, {"id": "neuro:fc:1", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "flashcard", "front": "A 70-year-old man with Parkinson's disease on levodopa/carbidopa develops sudden uncontrollable leg movements, fluctuating responsiveness, and periods of freezing. What are these phenomena called and what causes them?", "back": "These are <strong>motor complications of long-term levodopa therapy</strong>: (1) <strong>Dyskinesias</strong> — involuntary choreiform movements, typically at peak levodopa plasma levels (peak-dose dyskinesia). Caused by sensitisation of dopamine receptors (especially D1) in the striatum from pulsatile dopamine stimulation → aberrant corticostriatal plasticity. (2) <strong>Wearing off</strong> — return of Parkinsonian symptoms before next dose (as levodopa plasma levels fall) — due to progressive loss of striatal dopaminergic neuron terminals that previously buffered dopamine levels. (3) <strong>On-off fluctuations</strong> — unpredictable switches between mobile (on) and frozen (off) states. Management: continuous dopaminergic stimulation — COMT inhibitors (entacapone), MAO-B inhibitors (selegiline, rasagiline), dopamine agonists, controlled-release levodopa, deep brain stimulation.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Carbidopa is a peripheral DOPA decarboxylase inhibitor — it does NOT cross the blood-brain barrier, preventing peripheral conversion of levodopa to dopamine (reducing nausea, vomiting, hypotension) and allowing lower levodopa doses. The standard ratio is 4:1 or 10:1 levodopa:carbidopa.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Dietary protein competes with levodopa for transport across the gut (via LAT1 amino acid transporter) — a high-protein meal significantly delays levodopa absorption and onset. Advise patients to take levodopa 30–60 minutes before meals and consider low-protein diet during daytime.</div>"}, {"id": "neuro:fc:2", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "flashcard", "front": "A patient with schizophrenia on haloperidol develops severe muscle rigidity, hyperthermia (40.5°C), altered consciousness, and autonomic instability with diaphoresis over 24 hours. What is this and how is it managed?", "back": "<strong>Neuroleptic malignant syndrome (NMS)</strong> — a life-threatening idiosyncratic reaction to dopamine antagonists (antipsychotics, metoclopramide). Mechanism: abrupt central D2 receptor blockade → disruption of dopaminergic pathways in hypothalamus (thermoregulation) and basal ganglia (motor control) → hyperthermia, lead-pipe muscle rigidity (causing rhabdomyolysis → AKI), altered consciousness, autonomic instability. Tetrad: <strong>Hyperthermia + Rigidity + Altered consciousness + Autonomic instability</strong>. Management: (1) <strong>Stop the offending drug immediately</strong>; (2) Aggressive cooling, IV fluids, supportive care; (3) <strong>Dantrolene</strong> (directly blocks SR Ca²⁺ release → reduces muscle rigidity and heat generation); (4) <strong>Bromocriptine</strong> (D2 agonist → restores dopaminergic tone).<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> NMS is NOT dose-dependent — it can occur after a single dose or after years of stable treatment. CK is dramatically elevated (rhabdomyolysis). Distinguish from serotonin syndrome: NMS has lead-pipe rigidity + slower onset (days) + hyporeflexia; serotonin syndrome has hyperreflexia + clonus + faster onset (hours) + myoclonus. Both can have hyperthermia and autonomic instability.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Antipsychotic rechallenge after NMS: wait ≥2 weeks after full resolution; switch to a lower-potency or atypical antipsychotic (e.g., quetiapine — lowest D2 affinity among atypicals). Clozapine has the lowest NMS risk. Avoid high-potency typical antipsychotics (haloperidol, fluphenazine) in patients with prior NMS.</div>"}, {"id": "neuro:fc:3", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "flashcard", "front": "A 35-year-old woman with generalised tonic-clonic epilepsy takes phenytoin. She is started on oral contraceptives. Six months later she has a breakthrough seizure. What happened?", "back": "Phenytoin is a potent inducer of <strong>CYP3A4, CYP2C9, and P-glycoprotein</strong>. Combined oral contraceptives (COC) contain ethinylestradiol and progestogen — both metabolised by CYP3A4. Phenytoin induction → dramatically accelerated oestrogen/progestogen metabolism → sub-therapeutic OCP levels → <strong>contraceptive failure</strong> (unwanted pregnancy OR, as here, a hormonal trigger for catamenial epilepsy). Additionally, phenytoin itself has narrow therapeutic index — drug interactions can alter seizure control. Management: use non-hormonal contraception (copper IUD — not affected by enzyme induction) or a combined pill with higher oestrogen dose (50 µg EE). Do NOT use progestogen-only pill or implant (too reliant on progestogen levels).<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Enzyme-inducing AEDs (phenytoin, carbamazepine, phenobarbital, primidone, topiramate at high doses, oxcarbazepine) all reduce effectiveness of hormonal contraception. Non-enzyme-inducing AEDs (lamotrigine, levetiracetam, valproate, gabapentin, pregabalin) are safe with hormonal contraception. Lamotrigine itself is affected by OCP — OCP induces lamotrigine glucuronidation → lamotrigine levels fall 50% when OCP started.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Phenytoin has <strong>zero-order (saturable) kinetics</strong> at therapeutic doses — small dose changes cause disproportionately large changes in plasma levels. Phenytoin also causes concentration-dependent toxicity: nystagmus (early), ataxia, diplopia (intermediate), altered consciousness (high). Monitor levels carefully, especially with any drug interaction.</div>"}, {"id": "neuro:fc:4", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "flashcard", "front": "An elderly man with Alzheimer's disease is started on donepezil. His wife calls 2 weeks later reporting vivid nightmares and the patient waking with bradycardia (HR 48). Explain both effects.", "back": "Donepezil is a <strong>reversible acetylcholinesterase inhibitor (AChEI)</strong> — inhibits AChE in CNS synapses → increased synaptic acetylcholine → enhances cholinergic transmission in the hippocampus and cortex (modest cognitive benefit). Both effects are cholinergic: (1) <strong>Vivid dreams/nightmares</strong> — increased central ACh during REM sleep → intensified dreaming (parasympathetic CNS effects on sleep architecture). Mitigate by taking donepezil in the morning (not at night). (2) <strong>Bradycardia</strong> — increased peripheral ACh → enhanced M2 muscarinic receptor activation at the SA node → reduced heart rate. Other GI effects: nausea, diarrhoea, urinary urgency (all cholinergic).<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> AChEIs for Alzheimer's: donepezil (all stages), rivastigmine (mild-moderate, also available as patch — fewer GI side effects), galantamine (mild-moderate). Memantine (NMDA receptor antagonist) is used for moderate-severe AD — can be combined with an AChEI. None modify disease progression — they provide modest symptomatic benefit.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> AChEIs are contraindicated in patients with <strong>sick sinus syndrome or heart block</strong> — severe bradycardia risk. They worsen <strong>peptic ulcers</strong> (cholinergic → increased gastric acid secretion) and should be used cautiously with NSAIDs. AChEIs also lower the seizure threshold — caution in epilepsy.</div>"}, {"id": "neuro:fc:5", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "flashcard", "front": "A patient with bipolar disorder on lithium presents with coarse tremor, vomiting, diarrhoea, and confusion. Lithium level is 2.8 mmol/L (therapeutic range 0.6–1.0). What precipitated toxicity and what is the treatment?", "back": "Lithium toxicity — therapeutic range is very narrow (0.6–1.0 mmol/L). Likely precipitant: <strong>volume depletion</strong> → increased proximal tubular reabsorption of Na⁺ and Li⁺ together (Li⁺ is handled like Na⁺ in the kidney — reabsorbed proximally, competes with Na⁺). Volume depletion → avid proximal Na⁺ reabsorption → Li⁺ reabsorption rises → toxicity. Common causes: vomiting/diarrhoea (this patient), dehydration, <strong>NSAIDs</strong> (reduce GFR → reduce Li⁺ excretion — most common drug interaction), <strong>thiazide diuretics</strong> (proximal Na⁺ loss → compensatory proximal Li⁺ retention), <strong>ACE inhibitors/ARBs</strong> (reduce GFR → reduce Li⁺ clearance). Treatment: IV normal saline (restore volume → increase Li⁺ clearance), hold lithium, consider <strong>haemodialysis</strong> if level &gt;2.5 mmol/L or severe symptoms.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Lithium toxicity signs by level: 1.0–1.5 (fine tremor, thirst, polyuria — therapeutic range upper limit); 1.5–2.0 (coarse tremor, nausea, confusion); &gt;2.0 (severe tremor, ataxia, seizures, coma, arrhythmias). Chronic toxicity can occur at lower levels than acute toxicity. Neurological effects (cerebellar ataxia, cognitive impairment) can be irreversible.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Loop diuretics (furosemide) do NOT significantly increase lithium levels — they increase distal Na⁺ delivery which does NOT enhance proximal Li⁺ reabsorption. In fact, furosemide with adequate Na⁺ replacement is relatively safe. <strong>Thiazides</strong> are the dangerous diuretic for lithium (proximal tubule effect). Amiloride is used to treat lithium-induced nephrogenic DI — by blocking ENaC in collecting duct, it reduces aquaporin-2 downregulation.</div>"}, {"id": "neuro:fc:6", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "flashcard", "front": "A 25-year-old woman presents with absence seizures. Sodium valproate is started. After 3 months she has gained 8 kg, has tremor, and reports hair loss. Explain each adverse effect.", "back": "All three are well-recognised valproate adverse effects: (1) <strong>Weight gain</strong> — valproate increases appetite and reduces fatty acid β-oxidation (inhibits mitochondrial carnitine transport) → adipogenesis; also stimulates neuropeptide Y. Common (~50% of patients). (2) <strong>Tremor</strong> — valproate-induced postural/action tremor (dose-related) — due to GABA-A enhancement → inhibition of cerebellar pathways that stabilise limb movement. (3) <strong>Hair loss (alopecia)</strong> — zinc/selenium chelation by valproate → impaired hair follicle enzyme function → telogen effluvium. Supplementation with zinc and selenium may help; hair often regrows even with continued therapy.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Most important valproate adverse effects to know: <strong>hepatotoxicity</strong> (idiosyncratic, most common in children &lt;2 on polytherapy — monitor LFTs; mitochondrial disease is a contraindication); <strong>teratogenicity</strong> — highest rate of any AED (neural tube defects, neurodevelopmental impairment, cardiac/limb defects — avoid in women of childbearing age; requires PREVENT programme registration in UK). <strong>Hyperammonaemia</strong> — valproate inhibits carbamoyl phosphate synthetase → raised ammonia even with normal LFTs.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Valproate is <strong>highly teratogenic</strong> — highest rates of neural tube defects (2–3% vs 0.1% background) AND neurodevelopmental harm (autism, reduced IQ). Despite this, valproate remains the most effective AED for idiopathic generalised epilepsy (absence, myoclonic, tonic-clonic). High-dose folic acid (5 mg/day) before conception reduces NTD risk but does NOT eliminate it. Consider lamotrigine or levetiracetam as alternatives in women of reproductive age.</div>"}, {"id": "neuro:fc:7", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "flashcard", "front": "A patient with treatment-resistant depression on clomipramine (TCA) takes an overdose of 30 tablets. In A&amp;E, ECG shows QRS duration 160 ms, QTc 550 ms, and BP 80/50. What is the immediate treatment?", "back": "TCA overdose — the major life-threatening effects are: (1) <strong>QRS widening</strong> (fast Na⁺ channel blockade → slowed ventricular conduction → risk of VT/VF); (2) <strong>QTc prolongation</strong> (K⁺ channel blockade → Torsades de Pointes risk); (3) <strong>Hypotension</strong> (α1-blockade → vasodilation + negative inotropy). Immediate treatment: <strong>IV sodium bicarbonate</strong> (1–2 mmol/kg bolus, repeat to maintain pH 7.45–7.55) — two mechanisms: (a) alkalinisation increases the fraction of Na⁺ channels in the non-ionised state, reducing TCA binding; (b) increased plasma Na⁺ concentration increases the Na⁺ gradient across the cardiac membrane → partially reverses Na⁺ channel blockade → narrows QRS. Target: QRS &lt;120 ms. Vasopressors for hypotension (noradrenaline — avoid adrenaline which can worsen arrhythmias).<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> QRS &gt;100 ms in TCA overdose predicts significant toxicity; &gt;160 ms predicts risk of seizures and VT. Seizures in TCA overdose → IV benzodiazepines (GABA-A agonist — first-line). Do NOT use flumazenil in TCA overdose (can precipitate seizures by removing any benzodiazepine-mediated seizure protection).</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Do NOT use class Ia or class Ic antiarrhythmics (procainamide, flecainide) in TCA overdose — they also block Na⁺ channels → additive toxicity. Amiodarone is also contraindicated (QT prolongation). The antidote is sodium bicarbonate — the only pharmacological intervention with proven benefit in TCA-induced QRS widening.</div>"}, {"id": "neuro:fc:8", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "flashcard", "front": "A 55-year-old with Parkinson's disease starts pramipexole (dopamine agonist). His wife reports he has developed compulsive gambling, hypersexuality, and binge eating. What is this syndrome?", "back": "<strong>Impulse control disorders (ICDs)</strong> — a class effect of <strong>dopamine agonists</strong> (pramipexole, ropinirole, rotigotine) acting on <strong>D3 receptors</strong> in the mesolimbic reward circuit (nucleus accumbens, ventral striatum). D3 receptor stimulation in the reward pathway → dysregulated reward-seeking behaviour → pathological gambling, hypersexuality, compulsive shopping, binge eating, dopamine dysregulation syndrome. Risk factors: male sex, younger age at PD diagnosis, prior history of addictive behaviour, higher dopamine agonist doses. Management: <strong>reduce or stop the dopamine agonist</strong> — ICDs generally resolve. Switch to levodopa (lower ICD risk) if dopaminergic replacement still required.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Dopamine agonists are also used for: restless legs syndrome (RLS) — first-line; hyperprolactinaemia (cabergoline, bromocriptine — D2 agonists reduce prolactin secretion from pituitary lactotrophs); acromegaly (cabergoline as adjunct). ICD risk applies across all these uses, though highest in PD patients on long-term high-dose therapy.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Dopamine agonist <strong>withdrawal syndrome</strong> — abrupt cessation after long-term use → dopamine agonist withdrawal syndrome (DAWS): severe anxiety, depression, diaphoresis, nausea, fatigue — resembles opioid withdrawal. Taper slowly. Also: <strong>daytime somnolence and sudden-onset sleep</strong> (sleep attacks) are class effects of dopamine agonists — warn patients not to drive until established on stable dose.</div>"}, {"id": "neuro:fc:9", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "flashcard", "front": "An 18-year-old with generalised anxiety disorder is prescribed diazepam. After 6 weeks she has developed tolerance and wants to stop abruptly. Explain why this is dangerous and the correct approach.", "back": "Benzodiazepines (BZDs) act as <strong>positive allosteric modulators of GABA-A receptors</strong> — they bind the α/γ subunit interface → increase frequency of Cl⁻ channel opening in response to GABA → enhanced inhibitory tone. Chronic BZD use → <strong>downregulation of GABA-A receptors</strong> (reduced receptor number and sensitivity) AND upregulation of excitatory systems (glutamate/NMDA). Abrupt cessation → rebound CNS hyperexcitability → <strong>BZD withdrawal syndrome</strong>: anxiety, insomnia, tremor, diaphoresis, tachycardia → <strong>seizures</strong> (potentially fatal, as in alcohol withdrawal — both target GABA-A). Correct approach: <strong>gradual tapering</strong> over weeks to months — switch to diazepam (long-acting) if on short-acting BZD, reduce by 5–10% every 1–2 weeks.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Flumazenil (BZD antagonist — competitive antagonist at the BZD binding site on GABA-A) reverses BZD sedation acutely. BUT: in BZD-dependent patients, flumazenil can precipitate acute withdrawal seizures. Also: flumazenil has a short half-life (1 hour) — re-sedation occurs with long-acting BZDs. NOT a substitute for supportive care in BZD overdose.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> BZDs are relatively SAFE in overdose alone (respiratory depression is rare unless combined with other CNS depressants). The dangerous combinations are BZD + alcohol, BZD + opioid, BZD + other sedatives — synergistic respiratory depression. Z-drugs (zolpidem, zopiclone) act at the same BZD binding site (α1-selective) — same dependence risk, same flumazenil reversal.</div>"}, {"id": "neuro:fc:10", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "flashcard", "front": "A patient is given suxamethonium for rapid-sequence intubation. After 15 minutes they have not recovered from paralysis and are still apnoeic. What genetic condition explains this, and how is it managed?", "back": "<strong>Pseudocholinesterase (butyrylcholinesterase) deficiency</strong> — suxamethonium (succinylcholine) is a depolarising neuromuscular blocker (activates nAChRs at NMJ → persistent depolarisation → flaccid paralysis). Normally hydrolysed within 3–5 minutes by plasma pseudocholinesterase (BChE) → action terminates. In BChE deficiency (autosomal recessive, dibucaine-resistant variants) → suxamethonium is not hydrolysed → prolonged apnoea (hours). Management: <strong>continue mechanical ventilation</strong> until paralysis resolves naturally (BChE-independent metabolism via spontaneous Hofmann elimination is minimal for suxamethonium — must wait). Fresh frozen plasma (contains BChE) can accelerate recovery. Test with dibucaine number (BChE activity assay) after recovery; genetic testing; screen family members.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Suxamethonium also causes <strong>hyperkalaemia</strong> (K⁺ released from depolarised muscle — usually mild) — dangerous (cardiac arrest) in burns &gt;24h old, crush injuries, prolonged immobilisation, upper motor neuron injuries (proliferation of extrajunctional nAChRs → massive K⁺ release). Contraindicated in these conditions. Also causes <strong>malignant hyperthermia</strong> in susceptible individuals (RYR1 mutation — suxamethonium ± volatile anaesthetics → uncontrolled SR Ca²⁺ release → hyperthermia, rigidity).</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Suxamethonium is NOT reversed by neostigmine (AChEI) — it is a <strong>depolarising</strong> blocker; AChEI would worsen or prolong paralysis by increasing ACh at the already-depolarised NMJ. Non-depolarising blockers (rocuronium, vecuronium, atracurium) ARE reversed by neostigmine (or sugammadex for rocuronium/vecuronium — encapsulates the drug).</div>"}, {"id": "neuro:fc:11", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "flashcard", "front": "A patient with acute alcohol withdrawal is treated with chlordiazepoxide. He also receives thiamine before any glucose. Why is thiamine given first, and what syndrome does glucose-before-thiamine risk precipitating?", "back": "Glucose administration in a thiamine-deficient patient → rapidly consumes the remaining cellular thiamine stores (thiamine pyrophosphate is an essential cofactor for pyruvate dehydrogenase, α-KG dehydrogenase, and transketolase — all required for glucose metabolism). Depleting thiamine further → acute <strong>Wernicke's encephalopathy</strong> (thiamine-deficient neurons cannot oxidise pyruvate → lactate accumulates → selective necrosis of high-metabolic-rate areas: mammillary bodies, medial thalamus, periaqueductal grey). Triad: <strong>Confusion + Ophthalmoplegia/nystagmus + Ataxia</strong>. Treatment: parenteral thiamine (Pabrinex IV). Untreated → <strong>Korsakoff's psychosis</strong> (irreversible anterograde amnesia + confabulation — mammillary body and thalamic damage).<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> In any malnourished, alcohol-dependent, or vomiting patient presenting to A&amp;E — give IV thiamine (Pabrinex) BEFORE glucose. Always. This is a critical clinical reflex. Oral thiamine supplementation is insufficient if there is any suspicion of Wernicke's — GI absorption is unreliable in malnourished patients.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Wernicke's can also occur in: <strong>hyperemesis gravidarum</strong>, prolonged TPN without thiamine supplementation, bariatric surgery patients, cancer patients with poor oral intake, dialysis patients. Not exclusively an alcohol-related diagnosis. Any patient with unexplained ophthalmoplegia + confusion should receive empirical IV thiamine immediately.</div>"}, {"id": "neuro:fc:12", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "flashcard", "front": "A 65-year-old man is on warfarin post-AF ablation. He is prescribed carbamazepine for trigeminal neuralgia. His INR drops from 2.5 to 1.3. Explain, and what alternative AED would be safer?", "back": "Carbamazepine is a potent <strong>CYP3A4, CYP2C9, and CYP1A2 inducer</strong>. Warfarin (S-warfarin primarily CYP2C9; R-warfarin CYP3A4/1A2) → dramatically accelerated metabolism → reduced warfarin plasma levels → reduced anticoagulant effect → subtherapeutic INR → increased stroke risk. This is one of the most important drug interactions in clinical practice. Safer AED alternatives for trigeminal neuralgia: <strong>oxcarbazepine</strong> (weaker CYP inducer — less effect on warfarin), <strong>gabapentin, pregabalin</strong> (not CYP inducers — renally excreted — no significant warfarin interaction), <strong>lamotrigine</strong> (not a CYP inducer). Carbamazepine also induces its own metabolism (<strong>autoinduction</strong>) — requires dose escalation over the first 4–6 weeks as CYP3A4 is induced.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Carbamazepine mechanism of action: blocks voltage-gated Na⁺ channels (use-dependent — preferentially blocks rapidly firing neurons) → reduces repetitive neuronal firing. Effective in: focal epilepsy, trigeminal neuralgia (drug of choice), bipolar disorder (mood stabiliser). Carbamazepine also causes <strong>SIADH</strong> (hyponatraemia — enhances ADH action at V2 receptor — especially in elderly).</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Carbamazepine hypersensitivity: Stevens-Johnson syndrome (SJS) and toxic epidermal necrolysis (TEN) — strongly associated with HLA-B*1502 allele (Han Chinese, South-East Asian populations). Screen for HLA-B*1502 before prescribing carbamazepine in these ethnic groups. Cross-reactivity with oxcarbazepine and phenytoin exists but is incomplete.</div>"}, {"id": "neuro:fc:13", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "flashcard", "front": "A patient is started on clozapine for treatment-resistant schizophrenia. After 3 weeks, she develops a sore throat and fever. FBC shows neutrophils 0.3 ×10⁹/L. What must happen immediately?", "back": "<strong>Clozapine-induced agranulocytosis</strong> — occurs in ~1–3% of patients. Clozapine's metabolite (norclozapine) is believed to directly damage neutrophil precursors in bone marrow (immune-mediated and/or direct toxicity). Agranulocytosis is potentially fatal (sepsis) but is prevented by mandatory blood monitoring. Immediate action: (1) <strong>STOP CLOZAPINE IMMEDIATELY</strong> — neutrophils &lt;0.5 ×10⁹/L = absolute contraindication; (2) Infective screening (blood cultures, CXR); (3) Broad-spectrum antibiotics for febrile neutropenia; (4) <strong>G-CSF</strong> to stimulate neutrophil recovery; (5) Report to the clozapine monitoring service (mandatory). <strong>Clozapine is permanently contraindicated</strong> in this patient after agranulocytosis.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Clozapine monitoring schedule (UK): weekly FBC for 18 weeks → fortnightly for 12 months → monthly thereafter. Must be registered with the CPMS (Clozapine Patient Monitoring Service). Dispensing is linked to blood results — pharmacy will not dispense if overdue monitoring. Clozapine is the only antipsychotic with proven superior efficacy in treatment-resistant schizophrenia.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Clozapine's other serious adverse effects: <strong>myocarditis</strong> (1st 4–8 weeks — check troponin and ECG at baseline and if symptoms); <strong>metabolic syndrome</strong> (weight gain, dyslipidaemia, T2DM — greatest metabolic risk of any antipsychotic); <strong>seizures</strong> (dose-dependent — plasma level monitoring crucial); <strong>hypersalivation</strong> (M4 muscarinic agonism paradoxically → excess saliva); <strong>constipation/bowel obstruction</strong> (anticholinergic).</div>"}, {"id": "neuro:fc:14", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "flashcard", "front": "A patient with severe chronic pain on morphine 30 mg/day develops constipation despite laxatives. What opioid-specific drug should be added, and what is the mechanism?", "back": "<strong>Methylnaltrexone</strong> (or naloxegol) — peripherally-acting mu-opioid receptor antagonists (PAMORAs). Morphine activates μ-opioid receptors in myenteric plexus → reduced propulsive peristalsis, increased sphincter tone, delayed gastric emptying → opioid-induced constipation (OIC). PAMORAs block peripheral GI μ-receptors to reverse OIC WITHOUT crossing the BBB → do not reverse central analgesia. Methylnaltrexone is a quaternary ammonium compound (charged → cannot cross BBB). Naloxegol is a PEGylated naloxone derivative (PEGylation makes it a P-gp substrate → actively excluded from CNS). Both specifically treat OIC while preserving pain control.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Standard laxatives should be prescribed with every opioid prescription — lactulose, senna, or macrogol. However, unlike most opioid side effects, <strong>tolerance does NOT develop to opioid constipation</strong> (peripheral GI receptors do not desensitise like CNS receptors) — OIC persists indefinitely and requires ongoing laxative/PAMORA treatment.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Naloxone (oral) in naloxegol/Targinact (oxycodone/naloxone combination) undergoes extensive first-pass hepatic metabolism → very low systemic bioavailability (2%) → blocks GI opioid receptors without reversing analgesia. This first-pass mechanism fails if liver function is severely impaired → systemic naloxone absorption → opioid withdrawal. Avoid oral naloxone-containing formulations in severe hepatic impairment.</div>"}, {"id": "neuro:fc:15", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "flashcard", "front": "A 45-year-old with migraine takes sumatriptan and within 30 minutes has complete relief. Two days later she takes another dose but develops chest tightness during the dose. Explain the mechanism and contraindication.", "back": "Sumatriptan is a <strong>5-HT1B/1D agonist</strong>. 5-HT1D agonism → inhibits trigeminal nerve terminal release of CGRP and substance P → reduces neurogenic inflammation around meningeal blood vessels → aborts migraine. 5-HT1B agonism → <strong>vasoconstriction of intracranial blood vessels</strong> (the therapeutic target — reverses meningeal vasodilation of migraine). However, 5-HT1B receptors are also present on <strong>coronary artery smooth muscle</strong> → coronary vasoconstriction → chest tightness, and in patients with underlying CAD, risk of myocardial ischaemia or MI. Contraindications: ischaemic heart disease, Prinzmetal angina, uncontrolled hypertension, stroke/TIA history, peripheral vascular disease.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> CGRP is now the major therapeutic target in preventive migraine treatment: <strong>erenumab</strong> (anti-CGRP receptor monoclonal antibody), <strong>fremanezumab, galcanezumab</strong> (anti-CGRP monoclonal antibodies) — monthly SC injections. Also: gepants (CGRP receptor antagonists — rimegepant, ubrogepant) for acute treatment — do NOT cause vasoconstriction, safe in cardiovascular disease, no overuse headache risk.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Triptans + SSRIs/SNRIs → theoretical serotonin syndrome risk (5-HT1 agonism + serotonin reuptake inhibition). However, FDA advisory (2006) was largely based on weak case reports — major neurological societies state the actual risk of clinically significant serotonin syndrome from this combination is very low. More clinically relevant serotonin syndrome risks: MAOIs + any serotonergic drug.</div>"}, {"id": "neuro:fc:16", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "flashcard", "front": "A patient with myasthenia gravis is treated with pyridostigmine. Despite adequate doses, she remains weak. What would happen if you accidentally gave too much pyridostigmine?", "back": "Pyridostigmine is a reversible AChE inhibitor → increases ACh at the NMJ → enhances transmission in MG (where autoantibodies against nAChRs reduce functional receptor numbers). Excessive pyridostigmine → too much ACh at NMJ → <strong>depolarisation block</strong> (same mechanism as suxamethonium — persistent receptor depolarisation → flaccid paralysis = cholinergic crisis). Both myasthenic crisis (too little AChE inhibitor) and cholinergic crisis (too much) cause muscle weakness. Distinguish by <strong>muscarinic signs</strong>: cholinergic crisis → DUMBELS (Diarrhoea, Urination, Miosis, Bradycardia/Bronchospasm, Emesis, Lacrimation, Salivation/Sweating) — present in cholinergic crisis, absent in myasthenic crisis. <strong>Edrophonium (Tensilon) test</strong>: brief improvement → myasthenic crisis; worsening → cholinergic crisis.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> MG treatment pyramid: (1) Pyridostigmine (symptomatic); (2) Prednisolone (immunosuppression); (3) Azathioprine or mycophenolate (steroid-sparing); (4) Rituximab or eculizumab (anti-C5, for MuSK-Ab or complement-mediated MG); (5) Thymectomy (if thymoma present — mandatory; also improves outcomes in generalised AChR-Ab MG even without thymoma in patients &lt;65).</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Drugs that can precipitate or worsen myasthenic crisis: aminoglycosides (block pre-synaptic Ca²⁺ channels → reduced ACh release), fluoroquinolones, macrolides, neuromuscular blocking agents, beta-blockers, iodinated contrast, magnesium (blocks NMJ transmission — caution in eclampsia treatment). Avoid or use with extreme caution in MG patients.</div>"}, {"id": "neuro:fc:17", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "flashcard", "front": "A patient with treatment-resistant depression fails three SSRIs and one SNRI. She is started on ketamine infusions. What is the rapid antidepressant mechanism, distinct from all other antidepressants?", "back": "Ketamine (and its S-enantiomer esketamine/Spravato) produces rapid antidepressant effects within hours — compared to weeks for conventional antidepressants. Mechanism: <strong>NMDA receptor antagonism</strong> (non-competitive, open-channel block of glutamate NMDA receptors). This rapidly increases synaptic glutamate (by blocking inhibitory interneuron NMDA receptors → disinhibition) → activates AMPA receptors → BDNF (brain-derived neurotrophic factor) release → TrkB receptor activation → <strong>mTOR signalling → rapid synaptogenesis</strong> in prefrontal cortex and hippocampus. Depression is associated with synaptic loss in these areas; ketamine reverses this within hours. This mechanism is completely distinct from monoamine-based antidepressants (SSRIs/SNRIs/TCAs/MAOIs).<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Esketamine (Spravato) nasal spray is FDA/EMA-approved for treatment-resistant depression (+ standard antidepressant) and for major depression with acute suicidal ideation. It must be administered in a certified medical setting with 2-hour post-dose monitoring (dissociation, haemodynamic effects, abuse potential). Effects are NOT permanent — repeated dosing required (twice-weekly × 4 weeks, then weekly, then fortnightly).</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Ketamine at anaesthetic doses causes the 'dissociative anaesthesia' state: profound analgesia + amnesia + cataleptic immobility, but patient maintains airway reflexes and spontaneous breathing — unlike other general anaesthetics. Ketamine increases sympathetic tone (raises BP and HR) — useful in haemodynamically compromised patients but avoid in hypertensive emergencies. Contraindicated in psychosis (can worsen psychotic symptoms through NMDA blockade in schizophrenia-relevant pathways).</div>"}, {"id": "neuro:fc:18", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "flashcard", "front": "A 72-year-old man with Parkinson's disease on levodopa develops acute prostatic symptoms (urinary retention, dry mouth, blurred vision). The A&amp;E doctor gives him procyclidine for his tremor. Was this appropriate?", "back": "No — procyclidine is a <strong>centrally-acting antimuscarinic (anticholinergic)</strong> drug used for drug-induced parkinsonism (D2 blockade from antipsychotics → relative cholinergic excess in basal ganglia → tremor/rigidity — corrected by anticholinergic). In <strong>idiopathic Parkinson's disease</strong>, antimuscarinics are now largely avoided — poor evidence in PD, and they worsen: (1) <strong>urinary retention</strong> (this patient's presenting symptom — M3 block → detrusor relaxation); (2) Cognitive impairment/delirium (elderly are especially sensitive to central anticholinergic effects); (3) Glaucoma (M3 block → reduced aqueous humour drainage); (4) Constipation, dry mouth, tachycardia. Procyclidine is contraindicated here — the appropriate management of this patient's PD tremor would be adjustment of levodopa or addition of a beta-blocker for tremor.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> The <strong>anticholinergic burden</strong> concept is important in elderly patients — many drugs have anticholinergic activity (TCAs, antihistamines, oxybutynin, procyclidine, promethazine, some antipsychotics) and their combined effect → confusion, falls, urinary retention, constipation. Use the Anticholinergic Cognitive Burden (ACB) scale to identify polypharmacy anticholinergic risk.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Distinguish: procyclidine/benztropine (anticholinergics) are used for DRUG-INDUCED parkinsonism (antipsychotic-induced), NOT for idiopathic PD. For idiopathic PD: levodopa, dopamine agonists, MAO-B inhibitors, COMT inhibitors, amantadine. Amantadine (NMDA antagonist + anticholinergic + dopamine-releasing) is used for levodopa-induced dyskinesias — effective but causes livedo reticularis and ankle oedema.</div>"}, {"id": "neuro:fc:19", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "flashcard", "front": "A patient with severe Alzheimer's develops agitation. A colleague proposes haloperidol. What specific risk in this population makes all antipsychotics a serious concern, and what is the only MHRA/FDA-approved non-antipsychotic alternative?", "back": "Antipsychotics (both typical and atypical) carry a <strong>black-box warning for increased mortality</strong> in elderly patients with dementia — primarily from <strong>cerebrovascular events</strong> (stroke, TIA) and cardiovascular death (arrhythmia, heart failure). Risk is ~1.6–1.7× higher than placebo. Additionally, antipsychotics worsen <strong>extrapyramidal symptoms in DLB (Lewy body dementia)</strong> — where dopamine neurons are depleted even more than in Parkinson's — potentially causing severe, life-threatening antipsychotic sensitivity reactions (rigidity, aspiration, rapid cognitive decline). <strong>Non-antipsychotic alternative</strong>: <strong>brexpiprazole</strong> is now approved (FDA 2023) for agitation in Alzheimer's — partial D2 agonist with lower EPS risk. Also: citalopram/escitalopram for agitation, non-pharmacological approaches (structured activity, sensory stimulation, caregiver training) are first-line.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> In DLB specifically: antipsychotics (especially typicals and risperidone) are <strong>absolutely contraindicated</strong> — severe antipsychotic sensitivity in ~50% → acute parkinsonism, autonomic instability, impaired consciousness → death in some cases. If an antipsychotic is unavoidable in DLB, quetiapine or clozapine (lowest D2 affinity) are relatively safer options.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Memantine (NMDA antagonist) has some evidence for agitation in moderate-severe AD. Donepezil/rivastigmine may reduce BPSD (behavioural and psychological symptoms of dementia) modestly. Valproate is sometimes used for agitation off-label but evidence is weak and toxicity risk (falls, hepatotoxicity, cognitive effects) is significant in this population.</div>"}, {"id": "neuro:q:0", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "What transmitter is released by ALL preganglionic autonomic fibers, onto which receptor?", "back": "Acetylcholine, onto nicotinic receptors."}, {"id": "neuro:q:1", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "What transmitter/receptor do parasympathetic postganglionic fibers use?", "back": "Acetylcholine onto muscarinic receptors."}, {"id": "neuro:q:2", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "What transmitter/receptor do most sympathetic postganglionic fibers use?", "back": "Norepinephrine onto adrenergic (α/β) receptors."}, {"id": "neuro:q:3", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Which spinal levels give rise to sympathetic outflow?", "back": "Thoracolumbar — T1 to L2."}, {"id": "neuro:q:4", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Which sites give rise to parasympathetic outflow?", "back": "Craniosacral — cranial nerves III, VII, IX, X and sacral segments S2–S4."}, {"id": "neuro:q:5", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Name the two exceptions to the \"sympathetic = adrenergic\" rule.", "back": "Sweat glands (cholinergic/muscarinic sympathetic) and the adrenal medulla (cholinergic nicotinic, releases epinephrine)."}, {"id": "neuro:q:6", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Why is the adrenal medulla considered a modified sympathetic ganglion?", "back": "A preganglionic cholinergic (nicotinic) fiber stimulates it directly; it has no second neuron and secretes epinephrine into the blood."}, {"id": "neuro:q:7", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "What enzyme synthesises acetylcholine, and from what?", "back": "Choline acetyltransferase (ChAT), from choline + acetyl-CoA."}, {"id": "neuro:q:8", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "How is acetylcholine action terminated?", "back": "Rapid hydrolysis by acetylcholinesterase into choline + acetate."}, {"id": "neuro:q:9", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "What is the rate-limiting step of norepinephrine synthesis?", "back": "Conversion of tyrosine to DOPA by tyrosine hydroxylase."}, {"id": "neuro:q:10", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "What enzyme converts dopamine to norepinephrine?", "back": "Dopamine β-hydroxylase (inside the vesicle)."}, {"id": "neuro:q:11", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "How is norepinephrine action mainly terminated?", "back": "Reuptake into the nerve terminal via the norepinephrine transporter (NET) — not by enzymatic breakdown."}, {"id": "neuro:q:12", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Which two enzymes degrade catecholamines?", "back": "Monoamine oxidase (MAO) and catechol-O-methyltransferase (COMT)."}, {"id": "neuro:q:13", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Which drug blocks NE reuptake at NET, intensifying its effect?", "back": "Cocaine (also tricyclic antidepressants)."}, {"id": "neuro:q:14", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "What does botulinum toxin block?", "back": "Acetylcholine release (vesicle fusion) at the nerve terminal."}, {"id": "neuro:q:15", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "What does reserpine block?", "back": "Vesicular storage of monoamines (VMAT), depleting NE."}, {"id": "neuro:q:16", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Receptor type and speed: nicotinic receptors are…?", "back": "Ligand-gated ion channels — fast (millisecond) signalling."}, {"id": "neuro:q:17", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Receptor type: muscarinic and adrenergic receptors are…?", "back": "G-protein-coupled receptors (slower)."}, {"id": "neuro:q:18", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Why does a ganglionic blocker abolish both divisions of the ANS?", "back": "Both use nicotinic receptors at the ganglion — the shared component."}, {"id": "neuro:q:19", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Which transmitter do some parasympathetic nerves use besides ACh (nitrergic)?", "back": "Nitric oxide (NO)."}, {"id": "neuro:q:20", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "What does the mnemonic SLUDGE-M stand for?", "back": "Salivation, Lacrimation, Urination, Defecation, GI motility, Emesis, Miosis — the muscarinic agonist effects."}, {"id": "neuro:q:21", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Clinical use of pilocarpine?", "back": "Glaucoma (and xerostomia/dry mouth)."}, {"id": "neuro:q:22", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Clinical use of bethanechol?", "back": "Urinary retention and GI atony (\"bethanechol = bladder/bowel\")."}, {"id": "neuro:q:23", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Prototype antimuscarinic drug?", "back": "Atropine."}, {"id": "neuro:q:24", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Recite the antimuscarinic toxidrome.", "back": "Dry as a bone, red as a beet, blind as a bat, mad as a hatter, hot as a hare."}, {"id": "neuro:q:25", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Antimuscarinic used in COPD/asthma by inhalation?", "back": "Ipratropium / tiotropium."}, {"id": "neuro:q:26", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Antimuscarinic for motion sickness?", "back": "Scopolamine."}, {"id": "neuro:q:27", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Which muscarinic subtype slows the heart, via which G-protein?", "back": "M2, via Gi."}, {"id": "neuro:q:28", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Which muscarinic subtypes act on smooth muscle/glands, via which G-protein?", "back": "M3 (and M1/M5), via Gq."}, {"id": "neuro:q:29", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Do anticholinesterases add ACh or prevent its breakdown?", "back": "They prevent breakdown by inhibiting acetylcholinesterase, so ACh accumulates."}, {"id": "neuro:q:30", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Which reversible anticholinesterase treats myasthenia gravis and does NOT cross the BBB?", "back": "Neostigmine."}, {"id": "neuro:q:31", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Which crosses the BBB and treats antimuscarinic (atropine) toxicity?", "back": "Physostigmine."}, {"id": "neuro:q:32", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Name an anticholinesterase used in Alzheimer's disease.", "back": "Donepezil (or rivastigmine, galantamine)."}, {"id": "neuro:q:33", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "How do organophosphates inhibit AChE?", "back": "They phosphorylate it covalently (irreversibly after \"aging\")."}, {"id": "neuro:q:34", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "What is enzyme \"aging\" in organophosphate poisoning?", "back": "Loss of an alkyl group makes the phosphorylated enzyme permanently inactive, so pralidoxime can no longer reactivate it."}, {"id": "neuro:q:35", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "What two-drug antidote treats organophosphate poisoning, and what does each do?", "back": "Atropine (blocks muscarinic effects) + pralidoxime/2-PAM (reactivates AChE, addresses nicotinic effects)."}, {"id": "neuro:q:36", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Name the non-depolarising neuromuscular blockers' suffixes.", "back": "\"-curium\" / \"-curonium\" (e.g., rocuronium, vecuronium, atracurium)."}, {"id": "neuro:q:37", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "How is a non-depolarising block reversed?", "back": "Neostigmine (↑ACh out-competes it) or sugammadex (for rocuronium/vecuronium)."}, {"id": "neuro:q:38", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Why must succinylcholine NOT be reversed with neostigmine?", "back": "It is a depolarising blocker; more ACh sustains the depolarisation and worsens the block."}, {"id": "neuro:q:39", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Three major adverse effects of succinylcholine?", "back": "Hyperkalemia, malignant hyperthermia, and prolonged apnea in pseudocholinesterase deficiency."}, {"id": "neuro:q:40", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "α1 receptor: G-protein and signature effect?", "back": "Gq → vasoconstriction (↑BP, mydriasis, sphincter contraction)."}, {"id": "neuro:q:41", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "α2 receptor: G-protein and main action?", "back": "Gi → presynaptic inhibition of NE release; centrally lowers sympathetic outflow."}, {"id": "neuro:q:42", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "β1 receptor: G-protein and signature effect?", "back": "Gs → increased heart rate, contractility, AV conduction, renin release."}, {"id": "neuro:q:43", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "β2 receptor: G-protein and signature effect?", "back": "Gs → bronchodilation, vasodilation, uterine relaxation."}, {"id": "neuro:q:44", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Which receptors does epinephrine act on?", "back": "α1, α2, β1, β2 (and β3)."}, {"id": "neuro:q:45", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Which receptors does norepinephrine act on (weak at which)?", "back": "α1, α2, β1 — weak at β2."}, {"id": "neuro:q:46", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Drug of choice for anaphylaxis, and why?", "back": "Epinephrine — α1 raises BP, β2 opens airways, β1 supports the heart, all at once."}, {"id": "neuro:q:47", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Selective α1 agonist used as a decongestant/pressor?", "back": "Phenylephrine."}, {"id": "neuro:q:48", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "α2 agonist used for hypertension — and why does an α2 <em>agonist</em> lower BP?", "back": "Clonidine; central α2 stimulation reduces sympathetic outflow."}, {"id": "neuro:q:49", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Selective β1 agonist used as an inotrope?", "back": "Dobutamine."}, {"id": "neuro:q:50", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Selective β2 agonists for asthma?", "back": "Salbutamol/albuterol, terbutaline."}, {"id": "neuro:q:51", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Describe dopamine's dose-dependent receptor profile.", "back": "Low → dopamine receptors (renal); medium → β1; high → α1."}, {"id": "neuro:q:52", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Which receptors does isoproterenol act on?", "back": "β1 and β2 only."}, {"id": "neuro:q:53", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "How do indirect sympathomimetics like tyramine/amphetamine work?", "back": "They promote release of stored norepinephrine."}, {"id": "neuro:q:54", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "β3 agonist used for overactive bladder?", "back": "Mirabegron."}, {"id": "neuro:q:55", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Compare effects of NE vs isoproterenol on heart rate (direct vs reflex).", "back": "Isoproterenol directly raises HR (β1); NE raises BP via α1, triggering reflex bradycardia that can offset its direct β1 effect."}, {"id": "neuro:q:56", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "What structural change shifts a sympathomimetic toward β activity?", "back": "Adding bulky/methyl substituents on the amino group (e.g., EPI's N-methyl gives β2 activity vs NE)."}, {"id": "neuro:q:57", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Which receptor mediates skeletal-muscle vasodilation from epinephrine?", "back": "β2."}, {"id": "neuro:q:58", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Why are catecholamines ineffective orally?", "back": "Rapid inactivation by COMT/MAO in gut and liver (first-pass)."}, {"id": "neuro:q:59", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Which receptor relaxes the uterus (tocolysis)?", "back": "β2 (e.g., terbutaline)."}, {"id": "neuro:q:60", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Suffix for selective α1 blockers, and a key use?", "back": "\"-zosin\" (prazosin); hypertension and BPH."}, {"id": "neuro:q:61", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Characteristic adverse effect of the first prazosin dose?", "back": "First-dose orthostatic (postural) hypotension."}, {"id": "neuro:q:62", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Irreversible vs reversible α-blocker used in pheochromocytoma?", "back": "Phenoxybenzamine (irreversible) and phentolamine (reversible)."}, {"id": "neuro:q:63", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Non-selective β-blocker prototype?", "back": "Propranolol."}, {"id": "neuro:q:64", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Two β1-selective (\"cardioselective\") blockers?", "back": "Metoprolol and atenolol."}, {"id": "neuro:q:65", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Combined α+β blockers, and a use of labetalol?", "back": "Carvedilol and labetalol; labetalol for hypertension in pregnancy."}, {"id": "neuro:q:66", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Why are β-blockers risky in asthmatics?", "back": "Blocking β2 can cause bronchoconstriction/bronchospasm."}, {"id": "neuro:q:67", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Why can β-blockers mask hypoglycemia?", "back": "They blunt the adrenergic warning signs (tremor, tachycardia) of low blood sugar."}, {"id": "neuro:q:68", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Explain \"epinephrine reversal.\"", "back": "After α-blockade, epinephrine's α1 pressor effect is lost, leaving β2 vasodilation, so BP falls instead of rising."}, {"id": "neuro:q:69", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Why must you α-block before β-block in pheochromocytoma?", "back": "β-blockade first removes β2 vasodilation, leaving unopposed α1 vasoconstriction → hypertensive crisis."}, {"id": "neuro:q:70", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "How does a β-blocker lower blood pressure (two mechanisms)?", "back": "↓Cardiac output (β1 on heart) and ↓renin release (β1 on kidney)."}, {"id": "neuro:q:71", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Non-cardiac uses of propranolol?", "back": "Essential tremor, migraine prophylaxis, performance/anxiety, thyrotoxicosis symptoms."}, {"id": "neuro:q:72", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "What happens to β1 selectivity at high doses?", "back": "It is lost — the drug also blocks β2."}, {"id": "neuro:q:73", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Which adrenergic blocker relaxes the prostate/bladder neck in BPH?", "back": "α1 blockers (e.g., tamsulosin, prazosin)."}, {"id": "neuro:q:74", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Why does abrupt β-blocker withdrawal cause rebound?", "back": "Chronic blockade up-regulates β-receptors → supersensitivity → rebound tachycardia/hypertension."}, {"id": "neuro:q:75", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Which α2 agonist is used in opioid/alcohol withdrawal?", "back": "Clonidine."}, {"id": "neuro:q:76", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Effect of an α1 blocker on pupil?", "back": "Miosis/ptosis tendency (blocks pupillary dilator and Müller's muscle tone)."}, {"id": "neuro:q:77", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "What reflex commonly accompanies α-blocker-induced vasodilation?", "back": "Reflex tachycardia."}, {"id": "neuro:q:78", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Which β-blocker property helps in heart failure despite negative inotropy?", "back": "Long-term reduction in harmful sympathetic remodeling (e.g., carvedilol, metoprolol succinate improve survival)."}, {"id": "neuro:q:79", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Cocaine potentiates adrenergic effects by what mechanism?", "back": "Blocking NET reuptake of norepinephrine, prolonging its synaptic action."}, {"id": "neuro:q:80", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Main excitatory and inhibitory CNS transmitters?", "back": "Glutamate (excitatory) and GABA (inhibitory)."}, {"id": "neuro:q:81", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Which receptor do benzodiazepines, barbiturates and alcohol all enhance?", "back": "GABA<sub>A</sub> (the chloride channel)."}, {"id": "neuro:q:82", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Benzodiazepines vs barbiturates at GABA<sub>A</sub>?", "back": "Benzos increase frequency of Cl⁻ channel opening (ceiling, safer); barbiturates increase duration (no ceiling, lethal)."}, {"id": "neuro:q:83", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Antidote for benzodiazepine overdose?", "back": "Flumazenil."}, {"id": "neuro:q:84", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "First-line antidepressant class and prototype?", "back": "SSRIs — fluoxetine (safest in overdose)."}, {"id": "neuro:q:85", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Why do antidepressants take weeks to work?", "back": "Receptor adaptation/downregulation, not just immediate reuptake blockade."}, {"id": "neuro:q:86", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Dietary danger with MAO inhibitors?", "back": "Tyramine-rich foods → hypertensive (\"cheese\") crisis."}, {"id": "neuro:q:87", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Primary receptor blocked by antipsychotics?", "back": "D₂ dopamine receptors."}, {"id": "neuro:q:88", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Why do typical antipsychotics cause extrapyramidal effects?", "back": "Strong D₂ blockade in the nigrostriatal pathway."}, {"id": "neuro:q:89", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Which atypical antipsychotic requires blood monitoring, and for what?", "back": "Clozapine — agranulocytosis."}, {"id": "neuro:q:90", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Three antiepileptic mechanisms?", "back": "Block Na⁺ channels, enhance GABA, or block (T-type) Ca²⁺ channels."}, {"id": "neuro:q:91", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Drug for absence seizures and its target?", "back": "Ethosuximide — T-type calcium channels."}, {"id": "neuro:q:92", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Cornerstone of Parkinson's therapy, and why add carbidopa?", "back": "Levodopa; carbidopa blocks peripheral conversion, reducing side effects and increasing CNS delivery."}, {"id": "neuro:q:93", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Opioid receptor mediating analgesia, and its G-protein?", "back": "μ (mu) receptor, coupled to Gi."}, {"id": "neuro:q:94", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Classic opioid overdose triad?", "back": "Coma, pinpoint pupils, respiratory depression."}, {"id": "neuro:q:95", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Opioid antidote?", "back": "Naloxone."}, {"id": "neuro:q:96", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "What does MAC measure for inhaled anaesthetics?", "back": "Potency — lower MAC means more potent."}, {"id": "neuro:q:97", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Mechanism of local anaesthetics?", "back": "Block voltage-gated Na⁺ channels from inside the axon."}, {"id": "neuro:q:98", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Why do local anaesthetics work poorly in infected (acidic) tissue?", "back": "Acidic pH keeps more drug ionised, so less crosses the membrane to reach its intracellular site (ion trapping)."}, {"id": "neuro:q:99", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Which pathway underlies addiction/reward?", "back": "The mesolimbic dopamine pathway."}, {"id": "cvs:fc:0", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "flashcard", "front": "A 62-year-old man with hypertension develops a dry, persistent cough 3 weeks after starting lisinopril. What is the mechanism and the correct management?", "back": "ACE inhibitors block the breakdown of <strong>bradykinin</strong> (normally degraded by ACE/kininase II). Accumulating bradykinin stimulates pulmonary sensory C-fibres → dry, non-productive cough in ~15–20% of patients (higher in Asian populations). Management: switch to an <strong>ARB</strong> (e.g., losartan, valsartan) — ARBs block the AT₁ receptor without affecting bradykinin metabolism, so no cough.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> ACE inhibitor cough is the #1 reason patients discontinue the drug. Always document it as 'ACE-inhibitor cough' (not 'allergy') — the patient can safely receive an ARB.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Do NOT switch to antihistamines — the cough is bradykinin-mediated, not histaminergic. Do NOT re-challenge with a different ACE inhibitor — the cough will recur with any ACE inhibitor.</div>"}, {"id": "cvs:fc:1", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "flashcard", "front": "A patient with HFrEF (EF 28%) on furosemide and digoxin has K⁺ 2.9 mEq/L. He reports nausea, yellow-green halos, and a heart rate of 44 bpm. Diagnose and explain the mechanism.", "back": "<strong>Digoxin toxicity precipitated by hypokalaemia.</strong> K⁺ and digoxin compete for the same binding site on Na⁺/K⁺-ATPase; hypokalaemia enhances digoxin binding and inhibition of the pump → intracellular Na⁺ rises → Na⁺/Ca²⁺ exchanger reversal → ↑ intracellular Ca²⁺ → increased automaticity + AV node block. Classic triad: GI (nausea/vomiting), visual (yellow-green halos/xanthopsia), and cardiac (bradycardia, heart block, VT).<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Therapeutic digoxin range in HF is 0.5–0.9 ng/mL (lower than old toxicity threshold). Loop diuretics cause hypokalaemia which dramatically lowers the toxic threshold. Add a K⁺-sparing agent (spironolactone) or supplement K⁺.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Treatment of digoxin toxicity: correct K⁺, give Digibind (digoxin immune Fab) for life-threatening toxicity. However, if the patient is already hyperkalaemic (digoxin blocks Na⁺/K⁺-ATPase → K⁺ exits cells), giving Digibind releases K⁺ back into cells — monitor carefully.</div>"}, {"id": "cvs:fc:2", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "flashcard", "front": "A 55-year-old woman with gout is started on hydrochlorothiazide for hypertension. Three weeks later she has an acute gout flare. Explain the mechanism.", "back": "Thiazide diuretics competitively inhibit uric acid secretion at the proximal tubule via the OAT1/OAT3 transporters → reduced renal urate excretion → hyperuricaemia → gout flare. Thiazides are relatively contraindicated in gout. Preferred alternatives: <strong>losartan</strong> (ARB with mild uricosuric effect) or <strong>amlodipine</strong> (CCB, uric-acid neutral).<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Loop diuretics also raise uric acid (less consistently than thiazides). Among antihypertensives, losartan uniquely lowers uric acid (blocks URAT1 reabsorption transporter) — ideal for hypertensive patients with gout or hyperuricaemia.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Low-dose aspirin also inhibits uric acid secretion (same OAT transporters) and can precipitate gout. Do NOT use aspirin to treat gout-associated pain — use colchicine or a full-dose NSAID (noting that NSAIDs raise BP and impair renal function in HTN).</div>"}, {"id": "cvs:fc:3", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "flashcard", "front": "A post-MI patient (EF 35%) is started on carvedilol 3.125 mg BID, but her BP drops to 88/58 mmHg and she feels dizzy. Why is carvedilol used, and how do you manage the hypotension?", "back": "Carvedilol blocks <strong>β1, β2, AND α1 receptors</strong> → negative inotropy + chronotropy + vasodilation. Short-term it can worsen haemodynamics; long-term (weeks–months) it reverses adverse cardiac remodelling and reduces mortality in HFrEF. Management: start at the lowest dose (3.125 mg BID), up-titrate slowly every 2 weeks. Do NOT stop — abrupt withdrawal causes rebound adrenergic surge. Ensure patient is euvolaemic (not overloaded or dehydrated) before starting.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Only three beta-blockers have proven mortality benefit in HFrEF: <strong>carvedilol, bisoprolol, metoprolol succinate</strong> (CR/XL). Atenolol and metoprolol tartrate are NOT proven for HF mortality reduction.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Short-term drop in EF after beta-blocker initiation in HF is EXPECTED and does NOT mean the drug is harmful. The long-term effect is EF improvement ('reverse remodelling'). Never stop a beta-blocker in HF just because the EF appears worse at 4 weeks.</div>"}, {"id": "cvs:fc:4", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "flashcard", "front": "A patient on amiodarone for AF is also taking warfarin (INR 2.5). Her INR rises to 5.8 over six weeks without any warfarin dose change. Explain.", "back": "Amiodarone and its active metabolite desethylamiodarone are potent inhibitors of <strong>CYP2C9</strong> (which metabolises S-warfarin, the more potent enantiomer) and CYP3A4 → increased warfarin plasma levels → supratherapeutic INR. The interaction is delayed because amiodarone has an extremely long half-life (~40–55 days) and takes weeks to reach steady-state inhibitory levels in plasma.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> When initiating amiodarone in a warfarin patient, reduce warfarin dose by 30–50% prophylactically and monitor INR weekly for 4–6 weeks. The interaction persists for months after stopping amiodarone due to its very long t½ and massive tissue distribution.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Amiodarone also inhibits CYP3A4 → increases levels of digoxin, statins, and cyclosporine. It inhibits the renal elimination of digoxin — digoxin dose must be halved when amiodarone is started.</div>"}, {"id": "cvs:fc:5", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "flashcard", "front": "The CAST trial showed that flecainide and encainide increased mortality in post-MI patients despite suppressing PVCs. What class are these, and why are they harmful?", "back": "Class IC agents (Na⁺ channel blockers with <em>slow</em> dissociation kinetics). They reduce conduction velocity markedly in ischaemic/scarred myocardium → create unidirectional block in reentrant circuits → promote sustained VT/VF. The lesson: suppressing an arrhythmia surrogate (PVCs) ≠ mortality benefit. Post-MI arrhythmia prophylaxis: use <strong>Class II (beta-blockers)</strong> — the only antiarrhythmic class proven to reduce post-MI mortality.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Class IC drugs (flecainide, propafenone) ARE safe for AF termination or rhythm control in patients with structurally normal hearts — they are NOT contraindicated in all patients, only in structural heart disease and post-MI.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Class IA (quinidine) prolongs QT → Torsades. Class IB (lidocaine, mexiletine) — fast dissociation, safe post-MI. Class IC — slow dissociation, proarrhythmic in structural disease. Class III (amiodarone, sotalol) — prolong action potential duration (QT risk). Class IV (verapamil, diltiazem) — AV node block.</div>"}, {"id": "cvs:fc:6", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "flashcard", "front": "A patient develops a polymorphic VT with twisting of the QRS complex around the isoelectric line on ECG. Labs show K⁺ 3.0 and Mg²⁺ 0.5 mg/dL. What is the immediate treatment?", "back": "<strong>Torsades de pointes</strong> (TdP) — triggered by QT prolongation + electrolyte derangement. Immediate treatment: <strong>IV magnesium sulphate 2 g over 5–10 minutes</strong>, regardless of serum Mg²⁺ level. Then correct K⁺ (target &gt;4.5 mEq/L). If refractory: overdrive pacing or isoproterenol infusion (increases heart rate → shortens QT). Identify and remove QT-prolonging drugs.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> TdP is <strong>pause-dependent</strong> — it initiates after a long RR interval (bradycardia or post-ectopic pause extends QT). Acquired (drug-induced) QT prolongation is more common and dangerous than congenital long-QT syndrome.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Do NOT treat TdP with amiodarone, sotalol, or other Class III agents — they further prolong QT. Magnesium is the answer even in normomagnesaemic patients. Lidocaine (Class IB) is relatively safe if a Na-channel blocker is absolutely needed.</div>"}, {"id": "cvs:fc:7", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "flashcard", "front": "Nitroglycerin tolerance develops after 24 hours of continuous transdermal patch use. Explain the mechanism and how to prevent it.", "back": "Nitrate tolerance (Needleman effect): continuous nitroglycerin exposure depletes mitochondrial aldehyde dehydrogenase 2 (ALDH2), which converts GTN to its active NO-releasing form. Additionally, reactive oxygen species generated by nitrate metabolism inactivate guanylate cyclase. Result: loss of vasodilatory effect with continuous exposure. Prevention: maintain an <strong>8–12 hour nitrate-free interval</strong> daily (e.g., remove patch at night). Oral ISDN: twice-daily asymmetric dosing (e.g., 8 AM and 2 PM).<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> During the nitrate-free interval, angina risk increases — use a beta-blocker or CCB for background protection. Never rely on nitrates alone for angina prevention without a nitrate-free period.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Nitrates + PDE5 inhibitors (sildenafil, tadalafil, vardenafil) = absolute contraindication. Both increase cGMP → synergistic, potentially fatal hypotension. Sildenafil t½ ~4 h (hold nitrates 24 h); tadalafil t½ ~17 h (hold nitrates 48 h).</div>"}, {"id": "cvs:fc:8", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "flashcard", "front": "IV sodium nitroprusside is infused for 72 hours in a hypertensive emergency. The patient develops confusion and a rising lactate. What toxic metabolite is responsible, and how is it treated?", "back": "<strong>Cyanide toxicity.</strong> Nitroprusside releases nitric oxide (vasodilation) + <strong>cyanide ions (CN⁻)</strong> which accumulate during prolonged/high-dose infusions. CN⁻ binds cytochrome c oxidase → blocks mitochondrial respiration → tissue hypoxia + lactic acidosis (high anion gap). Treatment: <strong>hydroxocobalamin</strong> (binds CN⁻ to form cyanocobalamin — excreted renally) or sodium thiosulphate (converts CN⁻ to thiocyanate).<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Nitroprusside must be light-protected (foil-wrapped bag). Cyanide risk increases with: doses &gt;2 µg/kg/min, infusion &gt;72 h, hepatic failure (impaired conversion to thiocyanate), and renal failure (thiocyanate accumulation). Limit to ≤3 days.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Thiocyanate (from CN⁻ detoxification) also accumulates in renal failure → thiocyanate toxicity: nausea, tremor, psychosis, seizures. Monitor thiocyanate levels in prolonged infusions or CKD. The antidote for thiocyanate toxicity is dialysis.</div>"}, {"id": "cvs:fc:9", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "flashcard", "front": "Sacubitril/valsartan (Entresto) is superior to enalapril in HFrEF. A trainee asks why you can't just add sacubitril to the patient's existing ACE inhibitor. What is the critical safety concern?", "back": "Sacubitril inhibits <strong>neprilysin</strong>, which degrades bradykinin (among other peptides). ACE inhibitors ALSO impair bradykinin degradation. Combining both → profound bradykinin accumulation → <strong>life-threatening angioedema</strong>. Therefore: never combine sacubitril/valsartan with an ACE inhibitor. A mandatory <strong>36-hour washout</strong> after stopping ACE inhibitor before starting Entresto is required.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> PARADIGM-HF trial: sacubitril/valsartan reduced CV death + HF hospitalisation by 20% vs enalapril. Indicated for HFrEF (EF ≤40%). Also the first therapy to show benefit in HFpEF (PARAGON-HF — modest effect at EF ~45–57%).</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> The 36-hour washout is from ACE inhibitor → Entresto (bradykinin danger). No washout is needed when switching from an ARB to Entresto (ARBs don't affect bradykinin metabolism). Entresto IS an ARB-containing product (valsartan).</div>"}, {"id": "cvs:fc:10", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "flashcard", "front": "A 70-year-old man with AF on warfarin switches to apixaban. Two months later he needs an urgent colonoscopy. How long should apixaban be held?", "back": "Apixaban (direct factor Xa inhibitor) t½ ≈ 12 hours. For low-bleeding-risk procedures: hold ≥24 h before. For high-bleeding-risk procedures (colonoscopy with polypectomy): hold <strong>≥48 hours</strong> before. No bridging anticoagulation needed (unlike warfarin). Restart 24–48 h after procedure depending on haemostasis. Reversal if urgent: <strong>andexanet alfa</strong> (specific reversal agent for factor Xa inhibitors).<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> DOAC monitoring: no routine INR equivalent. Renal function determines dosing — apixaban dose-reduce if 2 of 3: age ≥80, weight ≤60 kg, creatinine ≥1.5 mg/dL. Dabigatran relies most on renal excretion (~80%) — most affected by CKD, and uniquely dialysable.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> DOACs do NOT show reliably on standard coagulation tests (PT/aPTT can be normal despite therapeutic anticoagulation). Anti-Xa levels (for Xa inhibitors) or dilute thrombin time (for dabigatran) are used in emergency situations.</div>"}, {"id": "cvs:fc:11", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "flashcard", "front": "Spironolactone is added to an HFrEF patient already on ACE inhibitor and furosemide. Three days later K⁺ is 6.2 mEq/L. Why, and what factors predict this?", "back": "Spironolactone (aldosterone receptor antagonist) blocks K⁺ excretion at the collecting duct. Combined with ACE inhibitor (which reduces angiotensin II → reduces aldosterone → reduces K⁺ excretion), the additive K⁺-sparing effect causes <strong>hyperkalaemia</strong>. Risk factors: CKD (reduced K⁺ excretion), high-dose spironolactone (&gt;25 mg/day in HF), concurrent NSAIDs, trimethoprim, or potassium supplements.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> RALES trial proved spironolactone 25 mg/day reduces HF mortality by 30% in NYHA III–IV. Eplerenone (selective aldosterone antagonist) has fewer anti-androgenic side effects (gynaecomastia, breast pain — from spironolactone's cross-reactivity with androgen receptors).</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Spironolactone also inhibits testosterone synthesis and blocks androgen receptors → gynaecomastia (10%), erectile dysfunction in men. This is NOT seen with eplerenone (selective for aldosterone receptor). Ask about breast tenderness in male HF patients on spironolactone.</div>"}, {"id": "cvs:fc:12", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "flashcard", "front": "Furosemide 80 mg is infused rapidly over 2 minutes to a patient in pulmonary oedema. Twenty minutes later she complains of tinnitus and cannot hear clearly. What happened?", "back": "<strong>Loop diuretic ototoxicity</strong> from rapid IV infusion. Furosemide inhibits Na⁺/K⁺/2Cl⁻ co-transporter (NKCC2) in the stria vascularis of the cochlea → disrupts endolymph ionic gradient → hearing loss and tinnitus. Usually reversible with loop diuretics (vs permanent with aminoglycosides). Risk: rapid infusion, high doses, concurrent aminoglycosides, renal failure.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Safe infusion rate: ≤4 mg/min for furosemide. <strong>Ethacrynic acid</strong> has the highest ototoxicity risk of all loop diuretics and is the only non-sulfonamide loop diuretic (use in true sulfa allergy, though rare — cross-reactivity with furosemide/bumetanide is very low).</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Furosemide and bumetanide are sulfonamide derivatives. In a true sulfa allergy, ethacrynic acid is the alternative. However, cross-reactivity between sulfonamide diuretics and sulphonamide antibiotics is NOT well established — withholding furosemide based on antibiotic sulfa allergy is often unnecessary.</div>"}, {"id": "cvs:fc:13", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "flashcard", "front": "ACE inhibitor is started for a patient with undiagnosed bilateral renal artery stenosis. Creatinine jumps from 1.1 to 3.2 mg/dL in 5 days. Explain.", "back": "In bilateral RAS (or RAS in a solitary kidney), glomerular filtration is maintained by <strong>angiotensin II–mediated efferent arteriolar constriction</strong> (maintains intraglomerular pressure despite reduced perfusion). ACE inhibitor blocks this → efferent arteriolar dilation → sharp fall in intraglomerular pressure → acute decline in GFR → AKI. Same risk with ARBs.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> A modest creatinine rise (&lt;30%) after starting ACE inhibitor is expected and acceptable in most patients — it reflects reduced intraglomerular hypertension (the renoprotective mechanism). Halt if rise &gt;30–35% or K⁺ rises significantly. Investigate for RAS if rise is severe or bilateral.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Unilateral RAS: the contralateral kidney compensates → ACE inhibitor is safe and actually beneficial (reduces proteinuria). Bilateral RAS: ACE inhibitor can precipitate AKI — this is a contraindication (relative in unilateral, absolute in bilateral/single kidney with RAS).</div>"}, {"id": "cvs:fc:14", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "flashcard", "front": "A patient on clopidogrel after coronary stenting is also started on omeprazole for GI protection. The cardiologist requests a change. Why?", "back": "Clopidogrel is a prodrug requiring <strong>CYP2C19</strong> for activation to its active thiol metabolite (irreversible P2Y12 blocker). Omeprazole and esomeprazole are CYP2C19 <strong>inhibitors</strong> → reduced clopidogrel activation → reduced antiplatelet effect by up to 45% → potential risk of stent thrombosis. Switch to <strong>pantoprazole</strong> (weakest CYP2C19 inhibition among PPIs).<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> CYP2C19 poor metabolisers (10–15% Caucasians, 15–25% Asians) have inherently poor clopidogrel response — consider genotype-guided therapy. Ticagrelor and prasugrel are direct P2Y12 inhibitors that do NOT require metabolic activation — unaffected by CYP2C19 or PPIs.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Prasugrel is contraindicated in patients with prior TIA or stroke (increased intracranial bleeding risk) and age &gt;75 years or weight &lt;60 kg (excess bleeding). Ticagrelor is contraindicated if prior haemorrhagic stroke or severe hepatic impairment.</div>"}, {"id": "cvs:fc:15", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "flashcard", "front": "A patient with combined hypertension and stable angina is started on amlodipine. Another patient with the same conditions is given verapamil. Weeks later, the verapamil patient develops ankle swelling AND bradycardia. Explain the differences between these two CCBs.", "back": "Both block L-type Ca²⁺ channels, but differ in tissue selectivity: <strong>Amlodipine</strong> (dihydropyridine) → predominantly vascular smooth muscle → arteriolar vasodilation (↓ afterload) + reflex tachycardia; no significant cardiac conduction effects. Ankle oedema from arteriolar vasodilation (not fluid retention). <strong>Verapamil</strong> (non-dihydropyridine, phenylalkylamine) → predominantly cardiac (SA node, AV node) → bradycardia, AV block, negative inotropy; less potent vasodilation.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Verapamil and diltiazem are CONTRAINDICATED in HFrEF (negative inotropy worsens systolic function) and with beta-blockers (additive AV block risk → complete heart block). Dihydropyridines (amlodipine, nifedipine) can be used in HFrEF.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Nifedipine (short-acting DHP) causes reflex tachycardia — contraindicated in stable angina without a beta-blocker. Amlodipine (long-acting DHP) has minimal reflex tachycardia due to its very slow onset — safe as monotherapy for angina and HTN.</div>"}, {"id": "cvs:fc:16", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "flashcard", "front": "A patient with HFrEF and NYHA Class II symptoms is started on digoxin. Six months later, an echo shows unchanged EF. Has digoxin failed?", "back": "No. Digoxin does NOT improve EF or reverse cardiac remodelling in HF. Its benefits: (1) positive inotropy (inhibits Na⁺/K⁺-ATPase → ↑ intracellular Na⁺ → Na⁺/Ca²⁺ exchanger reversal → ↑ Ca²⁺ → increased contractility); (2) reduces neurohormonal activation (increases parasympathetic tone → reduces HR). DIG trial: digoxin reduces HF hospitalisations and symptoms but does NOT reduce mortality. Current indication: symptom control in patients remaining symptomatic on optimal therapy, and rate control in AF with HF.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Digoxin has a very narrow therapeutic index (therapeutic: 0.5–0.9 ng/mL for HF; toxic: &gt;2 ng/mL). Factors increasing toxicity: hypokalaemia, hypomagnesaemia, hypercalcaemia, hypothyroidism, amiodarone, verapamil (reduce dose by 50% with each).</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Digoxin is renally cleared — dose-reduce in CKD. Hypothyroidism reduces digoxin clearance → toxicity. Hyperthyroidism increases clearance → subtherapeutic levels. Always check TSH when digoxin is not working as expected.</div>"}, {"id": "cvs:fc:17", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "flashcard", "front": "A patient with dyslipidaemia on simvastatin 40 mg is started on gemfibrozil for elevated triglycerides. Two weeks later he has severe myalgia and CK &gt;10× ULN. What interaction caused this?", "back": "<strong>Rhabdomyolysis</strong> from statin + gemfibrozil combination. Gemfibrozil inhibits <strong>UGT1A3</strong> (glucuronidation of statin acid forms) and <strong>OATP1B1</strong> (hepatic uptake transporter) → reduced statin clearance → elevated plasma statin levels → myotoxicity. Gemfibrozil is the most dangerous fibrate for statin interactions. <strong>Fenofibrate</strong> is the preferred fibrate when combination with a statin is necessary.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> The statin most prone to rhabdomyolysis: simvastatin &gt; lovastatin &gt; atorvastatin. Pravastatin and rosuvastatin have lower myopathy risk. Risk also increased by: CYP3A4 inhibitors (azoles, macrolides), high statin doses, hypothyroidism, renal failure, Asian ethnicity.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Dark urine in this context = myoglobinuria → risk of acute tubular necrosis. Stop statin immediately; aggressive IV hydration; monitor CK, creatinine, and urine output. Even if creatinine normalises, do NOT restart the same statin + gemfibrozil combination.</div>"}, {"id": "cvs:fc:18", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "flashcard", "front": "Adenosine is given as a rapid IV push for SVT. The patient immediately feels flushing, chest tightness, and dyspnoea — then converts to sinus rhythm in 15 seconds. Explain the mechanism and the required administration technique.", "back": "Adenosine activates <strong>A₁ receptors</strong> on AV nodal cells → activates IK,ACh → membrane hyperpolarisation → transient AV block → interrupts AV-nodal reentrant tachycardia (most SVTs). Half-life &lt;10 seconds (inactivated by adenosine deaminase in erythrocytes and vascular endothelium). <strong>Technique:</strong> rapid IV bolus via a large antecubital vein (6 mg first, then 12 mg if no response), immediately followed by a fast normal saline flush to propel drug to the heart before degradation.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Dipyridamole (blocks adenosine uptake) potentiates its effect — reduce dose. Methylxanthines (caffeine, theophylline) are competitive adenosine antagonists — higher doses may be needed in caffeine users. The transient symptoms (chest tightness, dyspnoea) are universal and self-limiting.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Adenosine is CONTRAINDICATED in WPW with pre-excited AF — preferential AV nodal block may accelerate conduction down the accessory pathway → VF. In WPW, use procainamide (IV) or electrical cardioversion.</div>"}, {"id": "cvs:fc:19", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "flashcard", "front": "A patient with bilateral leg oedema is on amlodipine 10 mg for hypertension. The GP adds furosemide. Three months later the oedema persists. What is the most likely reason?", "back": "Amlodipine-induced pedal oedema is caused by <strong>arteriolar vasodilation without corresponding venodilation</strong> → increased hydrostatic pressure in capillaries → fluid shift into interstitium. This is a <strong>haemodynamic (non-fluid-retention) mechanism</strong> — not due to excess total body fluid. Therefore, diuretics are largely ineffective. Correct approach: reduce amlodipine dose or switch to another antihypertensive class. Adding an ACE inhibitor or ARB can also attenuate CCB-induced oedema (venodilatory effect).<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> DHP CCB oedema is dose-dependent and position-dependent (worse at end of day, improves with leg elevation). It is NOT a sign of worsening cardiac or renal function — reassure the patient and address the mechanism.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Do not assume new oedema in a cardiac patient = HF decompensation without checking the medication list. Amlodipine-induced oedema is the most common cause of new ankle oedema in hypertensive patients on CCBs.</div>"}, {"id": "cvs:fc:20", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "flashcard", "front": "A woman with bilateral renal artery stenosis, T2DM, and chronic HF is being optimised for hypertension. Her medications include lisinopril and metformin. Which of her existing drugs is potentially most dangerous, and why?", "back": "<strong>Lisinopril</strong> (ACE inhibitor) in bilateral RAS: blocks angiotensin II–mediated efferent arteriolar tone → precipitous GFR fall → AKI. <strong>Metformin</strong> in AKI: if ACE inhibitor triggers AKI, creatinine rises → metformin accumulates (renally cleared) → lactic acid clearance impaired → metformin-associated lactic acidosis (MALA). Both drugs interact dangerously in this vascular anatomy. Image the renal arteries; if bilateral RAS confirmed, stop ACE inhibitor and consider revascularisation.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Suspected bilateral RAS: duplex ultrasound (screening), then CT angiography or MR angiography (definitive). Classic presentation: flash pulmonary oedema (bilateral RAS + ACE inhibitor or diuretic), resistant hypertension, or bilateral small kidneys on imaging.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> The ACE inhibitor itself causes the AKI that then makes metformin dangerous — it is an indirect metformin risk, not a direct drug–drug interaction. Hold metformin whenever AKI risk is high (contrast, surgery, dehydration, ACEI initiation in high-risk patients).</div>"}, {"id": "cvs:q:0", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Which transporter do loop diuretics block, and where?", "back": "Na⁺-K⁺-2Cl⁻ (NKCC2) in the thick ascending limb of the loop of Henle."}, {"id": "cvs:q:1", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Why are loop diuretics the most powerful (\"high-ceiling\")?", "back": "The thick ascending limb reabsorbs ~25% of filtered Na⁺ — the largest accessible fraction."}, {"id": "cvs:q:2", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "From which side of the tubule does furosemide act, and what's the practical implication?", "back": "The luminal (urine) side — it must be secreted into the tubule to reach NKCC2, which is why urinary (not plasma) furosemide reflects delivery to its site."}, {"id": "cvs:q:3", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Which transporter carries furosemide into the tubular lumen?", "back": "Organic anion transporters (OATs) in the proximal tubule."}, {"id": "cvs:q:4", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Name four mechanisms of diuretic resistance in heart failure.", "back": "Reduced renal perfusion/secretion, post-diuretic Na⁺ retention (\"braking\"), distal tubule hypertrophy, and reduced/erratic oral absorption."}, {"id": "cvs:q:5", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "What is sequential nephron blockade?", "back": "Adding a diuretic acting at a different segment (e.g., a thiazide) to overcome distal compensation for loop blockade."}, {"id": "cvs:q:6", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Furosemide-to-torsemide dose conversion ratio?", "back": "Approximately 2:1 (not 4:1)."}, {"id": "cvs:q:7", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Why is torsemide sometimes preferred over furosemide?", "back": "Higher and more predictable oral bioavailability and a longer half-life."}, {"id": "cvs:q:8", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Which transporter do thiazides block, and where?", "back": "Na⁺-Cl⁻ cotransporter (NCC) in the distal convoluted tubule."}, {"id": "cvs:q:9", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Effect of loops vs thiazides on serum calcium?", "back": "Loops cause hypocalcemia (↑Ca²⁺ excretion); thiazides cause hypercalcemia (↑Ca²⁺ reabsorption)."}, {"id": "cvs:q:10", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Shared electrolyte/acid-base disturbance of loops and thiazides?", "back": "Hypokalemia and metabolic alkalosis."}, {"id": "cvs:q:11", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Mechanism and example of a potassium-sparing diuretic acting on ENaC?", "back": "Amiloride blocks the epithelial Na⁺ channel in the collecting duct."}, {"id": "cvs:q:12", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Mechanism of spironolactone?", "back": "Competitive mineralocorticoid (aldosterone) receptor antagonist in the collecting duct."}, {"id": "cvs:q:13", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Main risk of potassium-sparing diuretics?", "back": "Hyperkalemia (especially with ACE-I/ARB)."}, {"id": "cvs:q:14", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Where do carbonic anhydrase inhibitors act, and a clinical use?", "back": "Proximal tubule; used in glaucoma, altitude sickness, metabolic alkalosis."}, {"id": "cvs:q:15", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Mechanism of mannitol?", "back": "Osmotic diuretic — holds water in the tubule by osmosis; used for ↑ICP/cerebral edema."}, {"id": "cvs:q:16", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Why does chronic loop use lose potency at the same dose (\"braking\")?", "back": "Compensatory distal tubule hypertrophy and post-diuretic sodium retention."}, {"id": "cvs:q:17", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Why do loops cause metabolic alkalosis?", "back": "Increased distal Na⁺ delivery enhances H⁺ and K⁺ secretion; volume contraction concentrates bicarbonate."}, {"id": "cvs:q:18", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "What does a spot urinary sodium at 2 hours assess (your protocol)?", "back": "Natriuretic response to the diuretic — a marker of diuretic efficacy/resistance."}, {"id": "cvs:q:19", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Why might plasma furosemide look adequate while the drug fails?", "back": "It is highly protein-bound and acts from the lumen; if tubular secretion is impaired, plasma levels don't reflect delivery to NKCC2."}, {"id": "cvs:q:20", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Trace the RAAS cascade from renin to aldosterone.", "back": "Renin → angiotensinogen to Ang I → ACE converts to Ang II → AT1 receptor → vasoconstriction + aldosterone release."}, {"id": "cvs:q:21", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Two actions of ACE (and why it matters for side effects)?", "back": "It forms Ang II and degrades bradykinin; inhibiting it raises bradykinin → cough/angioedema."}, {"id": "cvs:q:22", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Suffix and example of ACE inhibitors?", "back": "\"-pril\" — enalapril, ramipril, lisinopril."}, {"id": "cvs:q:23", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Why do ARBs cause less cough than ACE inhibitors?", "back": "They block the AT1 receptor without affecting bradykinin metabolism."}, {"id": "cvs:q:24", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Why can ACE-I/ARBs raise serum potassium?", "back": "Reduced aldosterone → less renal K⁺ excretion."}, {"id": "cvs:q:25", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Why are ACE-I/ARBs contraindicated in pregnancy?", "back": "Fetal renal damage/teratogenicity."}, {"id": "cvs:q:26", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Why are they risky in bilateral renal artery stenosis?", "back": "Ang II maintains glomerular filtration via efferent constriction there; blocking it drops GFR → AKI."}, {"id": "cvs:q:27", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "What is an ARNI, and a key example?", "back": "Angiotensin receptor–neprilysin inhibitor — sacubitril/valsartan."}, {"id": "cvs:q:28", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "The first-line antihypertensive classes?", "back": "Thiazide diuretics, ACE-I/ARBs, and calcium-channel blockers."}, {"id": "cvs:q:29", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Equation that frames all antihypertensive action?", "back": "BP = cardiac output × systemic vascular resistance."}, {"id": "cvs:q:30", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Preferred antihypertensive in diabetic kidney disease, and why?", "back": "ACE-I/ARB — lowers intraglomerular pressure (efferent dilation) → renoprotection."}, {"id": "cvs:q:31", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Antihypertensives of choice in pregnancy?", "back": "Labetalol, methyldopa, nifedipine."}, {"id": "cvs:q:32", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "4th-line add-on for resistant hypertension?", "back": "Spironolactone."}, {"id": "cvs:q:33", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Dihydropyridine vs non-dihydropyridine CCB — key difference?", "back": "Dihydropyridines (amlodipine) act on vessels; non-DHPs (verapamil, diltiazem) also slow the heart/AV node."}, {"id": "cvs:q:34", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Why avoid rapid BP correction in hypertensive emergency?", "back": "Auto-regulation has shifted; a sudden drop risks cerebral/renal hypoperfusion (stroke, AKI)."}, {"id": "cvs:q:35", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "\"CAPTOPRIL\" — name three ACE-I adverse effects.", "back": "Cough, Angioedema, Potassium ↑, Taste disturbance, hypotension, Pregnancy contraindication, Renal impairment."}, {"id": "cvs:q:36", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Why combine antihypertensives from different classes?", "back": "Greater efficacy with fewer dose-related side effects than maximising one drug."}, {"id": "cvs:q:37", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Mechanism of aliskiren?", "back": "Direct renin inhibitor."}, {"id": "cvs:q:38", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Why does a thiazide's long-term antihypertensive effect persist beyond its diuresis?", "back": "Chronically it reduces peripheral vascular resistance, not just volume."}, {"id": "cvs:q:39", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Why avoid routine ACE-I + ARB combination?", "back": "Double RAAS blockade increases hyperkalemia and AKI risk without added benefit."}, {"id": "cvs:q:40", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Angina is fundamentally what kind of imbalance?", "back": "A myocardial oxygen supply–demand mismatch."}, {"id": "cvs:q:41", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "How do nitrates relieve angina?", "back": "Release NO → venodilation → ↓preload → ↓myocardial oxygen demand."}, {"id": "cvs:q:42", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Why must nitrates be dosed with a nitrate-free interval?", "back": "Continuous exposure causes tolerance."}, {"id": "cvs:q:43", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Lethal nitrate interaction?", "back": "PDE5 inhibitors (sildenafil) → severe hypotension."}, {"id": "cvs:q:44", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "How do β-blockers reduce angina?", "back": "↓Heart rate and contractility → ↓oxygen demand."}, {"id": "cvs:q:45", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Why avoid verapamil + β-blocker together?", "back": "Both depress the AV node → risk of severe bradycardia/heart block."}, {"id": "cvs:q:46", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Core principle of modern heart-failure therapy?", "back": "Interrupt the neurohormonal vicious cycle (RAAS + sympathetic overactivity)."}, {"id": "cvs:q:47", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Name the four mortality-reducing pillars in HFrEF.", "back": "ACE-I/ARB/ARNI, β-blockers, MR antagonists, and SGLT2 inhibitors."}, {"id": "cvs:q:48", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Do loop diuretics improve survival in heart failure?", "back": "No — they relieve congestion/symptoms but don't reduce mortality."}, {"id": "cvs:q:49", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Which HF drugs are symptom-only?", "back": "Loop diuretics and digoxin."}, {"id": "cvs:q:50", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Why can a strong positive inotrope worsen long-term survival?", "back": "It increases myocardial oxygen demand and arrhythmia risk, accelerating decline."}, {"id": "cvs:q:51", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Why start β-blockers low and slow in HF?", "back": "Acute negative inotropy can transiently worsen failure before long-term benefit."}, {"id": "cvs:q:52", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Three evidence-based β-blockers in HF?", "back": "Carvedilol, bisoprolol, metoprolol succinate."}, {"id": "cvs:q:53", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Mechanism of SGLT2 inhibitors relevant to HF?", "back": "Glucosuric/natriuretic with cardiorenal protection (e.g., dapagliflozin)."}, {"id": "cvs:q:54", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Mechanism of digoxin?", "back": "Inhibits Na⁺/K⁺-ATPase → ↑intracellular Ca²⁺ → positive inotropy; also vagotonic (↓AV conduction)."}, {"id": "cvs:q:55", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Why is hypokalemia dangerous with digoxin?", "back": "Low K⁺ potentiates digoxin binding → increased toxicity."}, {"id": "cvs:q:56", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Two thesis rescue agents and their classes?", "back": "Dapagliflozin (SGLT2 inhibitor) and spironolactone (MR antagonist)."}, {"id": "cvs:q:57", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Why does spironolactone help HF beyond diuresis?", "back": "Aldosterone blockade reduces cardiac remodeling/fibrosis → mortality benefit."}, {"id": "cvs:q:58", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "What compensatory systems does the failing heart switch on?", "back": "RAAS and the sympathetic nervous system."}, {"id": "cvs:q:59", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Why is diuretic resistance clinically critical even though diuretics don't cut mortality?", "back": "They are the main tool for relieving congestion; resistance → fluid overload and hospitalisation."}, {"id": "cvs:q:60", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Name the Vaughan-Williams classes and their targets.", "back": "I = Na⁺ channels, II = β-receptors, III = K⁺ channels, IV = Ca²⁺ channels."}, {"id": "cvs:q:61", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Which phase of the action potential does Class I affect?", "back": "Phase 0 (the Na⁺ upstroke)."}, {"id": "cvs:q:62", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Subclass and example of a Na⁺ blocker used for post-MI ventricular arrhythmias?", "back": "Class Ib — lidocaine."}, {"id": "cvs:q:63", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Why does lidocaine prefer ischemic tissue?", "back": "It binds preferentially to depolarised/inactivated Na⁺ channels, common in ischemia."}, {"id": "cvs:q:64", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Class Ia example and its dual channel effect?", "back": "Quinidine — blocks Na⁺ and K⁺ channels (prolongs QT)."}, {"id": "cvs:q:65", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "What did the CAST trial show about Class Ic drugs?", "back": "They increased mortality post-MI (proarrhythmia)."}, {"id": "cvs:q:66", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Class III mechanism and main risk?", "back": "Block K⁺ channels → prolong repolarisation/QT → risk of torsades de pointes."}, {"id": "cvs:q:67", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Why is amiodarone uniquely effective?", "back": "It has properties of all four classes."}, {"id": "cvs:q:68", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "List five organ toxicities of amiodarone.", "back": "Thyroid (hypo/hyper), pulmonary fibrosis, hepatotoxicity, corneal/skin deposits, neuropathy."}, {"id": "cvs:q:69", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Class IV drugs and their nodal effect?", "back": "Verapamil, diltiazem — slow AV-node conduction."}, {"id": "cvs:q:70", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Drug used to terminate SVT by transient AV block?", "back": "Adenosine."}, {"id": "cvs:q:71", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "What predisposes to torsades with QT-prolonging drugs?", "back": "Hypokalemia, hypomagnesemia, bradycardia, congenital long QT."}, {"id": "cvs:q:72", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Which class flattens the phase-4 pacemaker slope?", "back": "Class II (β-blockers)."}, {"id": "cvs:q:73", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Which ion drives the plateau (phase 2)?", "back": "Calcium (inward Ca²⁺)."}, {"id": "cvs:q:74", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Treatment of torsades de pointes?", "back": "IV magnesium (correct K⁺; stop offending drug)."}, {"id": "cvs:q:75", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Why are antiarrhythmics described as \"proarrhythmic\"?", "back": "By altering conduction/repolarisation they can themselves provoke new arrhythmias."}, {"id": "cvs:q:76", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Class II benefit beyond rhythm control?", "back": "Mortality reduction post-MI and in heart failure."}, {"id": "cvs:q:77", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Which classes reuse mechanisms from earlier chapters?", "back": "II = β-blockade (adrenergic), IV = Ca²⁺ blockade (also antihypertensive/anti-anginal)."}, {"id": "cvs:q:78", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "How does hypokalemia from a loop diuretic interact with antiarrhythmic safety?", "back": "It heightens torsades risk with QT-prolonging drugs."}, {"id": "cvs:q:79", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Why monitor thyroid and lung function on long-term amiodarone?", "back": "It commonly causes thyroid dysfunction and pulmonary fibrosis."}, {"id": "cvs:q:80", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Name the three drug-targeted pathways in PAH.", "back": "Nitric oxide (cGMP), prostacyclin (cAMP), and endothelin."}, {"id": "cvs:q:81", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "How do PDE5 inhibitors help PAH?", "back": "They prevent cGMP breakdown → sustained pulmonary vasodilation."}, {"id": "cvs:q:82", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Mechanism of bosentan?", "back": "Endothelin receptor antagonist (blocks a vasoconstrictor)."}, {"id": "cvs:q:83", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Key monitoring on endothelin antagonists?", "back": "Liver function (hepatotoxicity); also teratogenic."}, {"id": "cvs:q:84", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Prostacyclin analogue example?", "back": "Epoprostenol (or iloprost)."}, {"id": "cvs:q:85", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "The three jobs of clot-directed drugs?", "back": "Antiplatelet, anticoagulant, fibrinolytic."}, {"id": "cvs:q:86", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Mechanism of aspirin as an antiplatelet?", "back": "Irreversibly inhibits COX-1 → blocks thromboxane A₂ for the platelet's lifespan."}, {"id": "cvs:q:87", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Mechanism of clopidogrel?", "back": "Blocks the platelet ADP P2Y12 receptor (prodrug activated by CYP2C19)."}, {"id": "cvs:q:88", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "How does heparin work, and how fast?", "back": "Activates antithrombin to inhibit thrombin (IIa) and Xa; acts within minutes."}, {"id": "cvs:q:89", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Lab test to monitor unfractionated heparin?", "back": "aPTT (activated partial thromboplastin time)."}, {"id": "cvs:q:90", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Reversal agent for heparin?", "back": "Protamine sulfate."}, {"id": "cvs:q:91", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Mechanism of warfarin?", "back": "Inhibits vitamin-K epoxide reductase → ↓functional factors II, VII, IX, X."}, {"id": "cvs:q:92", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Lab test and reversal for warfarin?", "back": "INR; reverse with vitamin K (± PCC/FFP)."}, {"id": "cvs:q:93", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Why does warfarin take days to act?", "back": "Existing clotting factors must decay; effect depends on reduced new synthesis."}, {"id": "cvs:q:94", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Why bridge warfarin with heparin initially?", "back": "Early fall in proteins C and S causes transient hypercoagulability (warfarin skin necrosis risk)."}, {"id": "cvs:q:95", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Direct thrombin inhibitor (DOAC) example and reversal?", "back": "Dabigatran; reversed by idarucizumab."}, {"id": "cvs:q:96", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Direct factor Xa inhibitors and their reversal?", "back": "Rivaroxaban/apixaban; reversed by andexanet alfa."}, {"id": "cvs:q:97", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Mechanism of alteplase (tPA)?", "back": "Activates plasminogen to plasmin, which dissolves fibrin."}, {"id": "cvs:q:98", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Drug that opposes fibrinolysis (antifibrinolytic)?", "back": "Tranexamic acid."}, {"id": "cvs:q:99", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Why might clopidogrel fail in some patients?", "back": "CYP2C19 poor metabolisers cannot activate the prodrug."}, {"id": "cvs:q:100", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Enzyme inhibited by statins?", "back": "HMG-CoA reductase (rate-limiting step of cholesterol synthesis)."}, {"id": "cvs:q:101", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "How do statins lower blood LDL indirectly?", "back": "Low hepatic cholesterol upregulates LDL receptors, which clear LDL from blood."}, {"id": "cvs:q:102", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Main adverse effect of statins?", "back": "Myopathy/rhabdomyolysis (and ↑LFTs)."}, {"id": "cvs:q:103", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Mechanism of ezetimibe?", "back": "Blocks intestinal cholesterol absorption (NPC1L1)."}, {"id": "cvs:q:104", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Mechanism of PCSK9 inhibitors?", "back": "Prevent LDL-receptor degradation → more receptors → potent LDL lowering."}, {"id": "cvs:q:105", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Fibrates' main lipid effect and mechanism?", "back": "Lower triglycerides via PPAR-α activation."}, {"id": "cvs:q:106", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Why does statin + fibrate raise myopathy risk?", "back": "Additive muscle toxicity (especially gemfibrozil, which also impairs statin clearance)."}, {"id": "cvs:q:107", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Which transporter mediates hepatic statin uptake?", "back": "OATP1B1."}, {"id": "cvs:q:108", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Why does clarithromycin raise statin toxicity risk?", "back": "It inhibits CYP3A4, raising statin levels."}, {"id": "cvs:q:109", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Which \"crossover\" drug appears in diuretics, RAAS, HTN and HF chapters?", "back": "Spironolactone (and broadly, ACE-I/ARBs and thiazides)."}, {"id": "cvs:q:110", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Why is spironolactone useful across so many cardiovascular conditions?", "back": "Aldosterone blockade aids diuresis, lowers BP, and reduces cardiac remodeling."}, {"id": "cvs:q:111", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "How does a loop diuretic's hypokalemia tie into antiarrhythmic safety?", "back": "It increases the risk of torsades with QT-prolonging drugs and digoxin toxicity."}, {"id": "cvs:q:112", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Which second messengers underlie the NO and prostacyclin pathways?", "back": "cGMP (NO) and cAMP (prostacyclin)."}, {"id": "cvs:q:113", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "How does a PDE inhibitor amplify a GPCR signal without binding the receptor?", "back": "It blocks breakdown of the second messenger (cAMP/cGMP), prolonging the signal."}, {"id": "cvs:q:114", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Why give short-acting statins at night?", "back": "Cholesterol synthesis peaks overnight."}, {"id": "cvs:q:115", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Which β1 action links β-blocker use in angina, HTN and HF?", "back": "Reduced heart rate/contractility (and renin); the same receptor block serves all three."}, {"id": "cvs:q:116", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Why is the ACE-I/ARB renoprotective effect a double-edged sword?", "back": "Efferent dilation lowers harmful glomerular pressure but can drop GFR in low-flow states (stenosis)."}, {"id": "cvs:q:117", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "How does the same pharmacogenetic concept cause opposite problems for clopidogrel and warfarin?", "back": "CYP2C19 PM → too little active clopidogrel; CYP2C9/VKORC1 variants → too much warfarin effect."}, {"id": "cvs:q:118", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Which classes of antihypertensive overlap with anti-anginal therapy?", "back": "β-blockers and calcium-channel blockers."}, {"id": "cvs:q:119", "deck": "Cardiovascular-Renal", "dk": "cvs", "type": "quiz", "front": "Summarise the deepest 80/20 of this whole section in one line.", "back": "Most cardiovascular drugs either offload volume, block the RAAS/sympathetic cycle, or relax/clear vessels — a handful of levers reused across every chapter."}, {"id": "inflam:fc:0", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "flashcard", "front": "A 28-year-old woman with SLE is found to have anti-dsDNA antibodies, low complement (C3/C4), proteinuria 3.2 g/day, and haematuria. Renal biopsy shows diffuse proliferative lupus nephritis (class IV). Which drug specifically targets the B-cell survival factor implicated in lupus?", "back": "<strong>Belimumab</strong> — a monoclonal antibody targeting <strong>BLyS (B-lymphocyte stimulator / BAFF)</strong>, a cytokine essential for B-cell survival and maturation. In SLE, excess BLyS promotes survival of autoreactive B cells → anti-dsDNA antibody production → immune complex deposition in glomeruli → complement activation → nephritis. Belimumab reduces B-cell counts, lowers anti-dsDNA titres, and reduces flare rates. It is approved as add-on therapy to standard care (hydroxychloroquine ± immunosuppression) for active, autoantibody-positive SLE.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Class IV lupus nephritis (diffuse proliferative) is the most severe and most common — treat aggressively with mycophenolate mofetil (MMF) or cyclophosphamide + high-dose steroids. MMF is now preferred over cyclophosphamide as induction in non-severe cases (comparable efficacy, better toxicity profile). Voclosporin (calcineurin inhibitor) + MMF is a newer combination with faster proteinuria remission.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Anti-dsDNA and anti-Sm antibodies are specific to SLE. Anti-Sm (anti-Smith) is highly specific (~25–30% sensitive but &gt;99% specific) and does NOT fluctuate with disease activity. Anti-dsDNA titres DO fluctuate with disease activity and correlate with lupus nephritis — use to monitor, not diagnose.</div>"}, {"id": "inflam:fc:1", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "flashcard", "front": "Rituximab is given for rheumatoid arthritis. Six months later the patient develops progressive multifocal leukoencephalopathy (PML). Which immune cell did rituximab deplete, and why did this lead to PML?", "back": "Rituximab depletes <strong>CD20+ B cells</strong> via complement-dependent cytotoxicity and ADCC. JC virus (John Cunningham polyomavirus) normally causes asymptomatic latent infection in most adults — kept in check by CD4+ T cells AND B cells (which provide immune surveillance and contribute to anti-JCV humoral immunity). Rituximab-induced profound B-cell depletion (lasting 6–12 months) reduces anti-JCV antibody levels and impairs viral immune control → JC virus reactivation in oligodendrocytes → demyelination → PML.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Anti-JCV antibody serology before rituximab does NOT reliably predict PML risk the way it does with natalizumab. For rituximab, duration of therapy and cumulative B-cell depletion are the main risk factors. Screen for JCV antibodies; monitor for neurological symptoms throughout therapy.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Rituximab does NOT deplete <strong>plasma cells</strong> (which are CD20−) — immunoglobulin levels (IgG) fall slowly over months but existing antibodies persist initially. Do NOT give live vaccines after rituximab (B cells are depleted → no antibody response). Minimum 6-month gap before live vaccine; check B-cell reconstitution first.</div>"}, {"id": "inflam:fc:2", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "flashcard", "front": "A patient on methotrexate for RA develops a dry cough, dyspnoea, and bilateral interstitial infiltrates on CXR after 8 months of therapy. What is the diagnosis and mechanism?", "back": "<strong>Methotrexate pneumonitis</strong> — an idiosyncratic, immune-mediated hypersensitivity reaction (NOT dose-dependent, NOT predictable from folate levels). MTX inhibits dihydrofolate reductase → reduced tetrahydrofolate → impaired purine/thymidylate synthesis. In the lung, MTX may trigger a CD4+ T-cell-mediated granulomatous/hypersensitivity reaction → pneumonitis with BAL showing lymphocytosis. Stop methotrexate immediately; give corticosteroids for moderate-severe cases. MTX cannot be restarted after pneumonitis.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Distinguish MTX pneumonitis from infection before stopping immunosuppression. Key features suggesting MTX pneumonitis: onset 8–18 months (can be earlier), fever + peripheral eosinophilia, bilateral ground-glass opacities, NO infective organism on BAL. Exclude PCP (order beta-D-glucan, BAL PCR) before starting steroids.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> MTX <strong>hepatotoxicity</strong> (fibrosis → cirrhosis) is dose- and duration-dependent and prevented by folate supplementation. Pneumonitis is NOT prevented by folate — these are different toxicity mechanisms. High-dose MTX for cancer can cause acute tubular necrosis (crystallisation in renal tubules) — prevented by urine alkalinisation and leucovorin rescue.</div>"}, {"id": "inflam:fc:3", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "flashcard", "front": "A patient with Crohn's disease on infliximab for 2 years develops fever, night sweats, and a new cavitating upper lobe lung lesion. TB IGRA is positive. What happened, and when was this risk preventable?", "back": "Reactivation of latent tuberculosis (LTBI) due to <strong>TNF-α blockade</strong>. TNF-α is essential for granuloma formation and maintenance — it promotes macrophage activation and containment of mycobacteria within caseating granulomas. Infliximab (anti-TNF-α monoclonal antibody) disrupts this defence → latent TB reactivates, often presenting as extrapulmonary or disseminated disease (pleural, abdominal, miliary). This risk was preventable by LTBI screening before starting infliximab — IGRA or TST + CXR — and treating LTBI with isoniazid for 9 months before beginning biologic therapy.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> All TNF inhibitors (infliximab, adalimumab, etanercept, certolizumab, golimumab) carry TB reactivation risk. Screen ALL patients for LTBI before initiating. Treat LTBI for ≥4 weeks before starting the biologic if possible (some guidelines say 2–4 weeks minimum). Risk is highest with monoclonal antibodies vs etanercept (soluble receptor).</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Etanercept (soluble TNF receptor fusion protein) has a lower TB reactivation risk than anti-TNF monoclonal antibodies — it does not neutralise membrane-bound TNF as efficiently. However, LTBI screening is still mandatory before all TNF blockers including etanercept.</div>"}, {"id": "inflam:fc:4", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "flashcard", "front": "A child with X-linked agammaglobulinaemia (XLA) presents repeatedly with encapsulated bacterial infections (Streptococcus pneumoniae, H. influenzae). What is missing, at what developmental stage, and what is the treatment?", "back": "XLA is caused by mutations in <strong>Bruton's tyrosine kinase (BTK)</strong> — essential for pre-B cell → B cell maturation in the bone marrow. BTK signalling transduces signals downstream of the pre-B cell receptor. Without BTK: B-cell development is arrested at the <strong>pro-B/pre-B cell stage</strong> → no mature B cells → no plasma cells → near-zero serum IgG/IgA/IgM → profound humoral immunodeficiency. Encapsulated bacteria (with polysaccharide capsules) require opsonising antibodies for phagocytic killing — without IgG, patients cannot clear these organisms. Treatment: lifelong <strong>IVIG (intravenous immunoglobulin)</strong> replacement every 3–4 weeks.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> BTK inhibitors (ibrutinib, acalabrutinib) are used to treat B-cell malignancies (CLL, mantle cell lymphoma) — they intentionally exploit BTK's role in B-cell survival. A side effect is immunosuppression with encapsulated bacterial infections — mirroring XLA pathophysiology.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> XLA presents after ~6 months of age when maternal IgG (transplacental) wanes. Boys are affected (X-linked). Distinguish from common variable immunodeficiency (CVID) — which presents in adulthood with low immunoglobulins but B cells ARE present (B-cell function is defective, not absent). Both treated with IVIG.</div>"}, {"id": "inflam:fc:5", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "flashcard", "front": "A 45-year-old patient on long-term prednisolone (15 mg/day for 2 years) for autoimmune hepatitis develops avascular necrosis of the femoral head. What is the mechanism, and what other corticosteroid complications should be monitored?", "back": "Corticosteroid-induced avascular necrosis: chronic GC excess → adipocyte hypertrophy in bone marrow → fat emboli occlude terminal end-arteries of the femoral head (and other susceptible sites) → ischaemic bone death. Mechanism also involves GC-induced coagulopathy. The femoral head, humeral head, and femoral condyle are classic sites. Monitoring for corticosteroid complications: <strong>hyperglycaemia/diabetes</strong> (GCs → gluconeogenesis + insulin resistance); <strong>osteoporosis</strong> (inhibit osteoblasts, increase RANKL, reduce calcium absorption → start bisphosphonate + calcium/vit D if &gt;3 months at &gt;5 mg/day); <strong>Cushingoid features, hypertension, hypokalaemia, posterior subcapsular cataracts, skin atrophy, adrenal suppression</strong>.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Adrenal suppression is a serious GC complication — hypothalamic-pituitary-adrenal (HPA) axis suppressed if prednisolone &gt;5 mg/day for &gt;3 weeks. Abrupt withdrawal can precipitate Addisonian crisis. Taper gradually; cover with stress-dose steroids (hydrocortisone 50–100 mg IV 8-hourly) during surgery or severe illness.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> PCP prophylaxis with TMP-SMX is recommended when prednisolone dose exceeds 20 mg/day for &gt;4 weeks (especially with other immunosuppressants). GC-induced immune suppression particularly affects cell-mediated immunity → increased risk of fungal, TB, PCP, herpes zoster, and strongyloides hyperinfection.</div>"}, {"id": "inflam:fc:6", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "flashcard", "front": "Cyclosporin is given after renal transplantation. Trough levels are maintained at 150–200 ng/mL. What is its mechanism, and what drug would dangerously elevate cyclosporin levels?", "back": "Cyclosporin binds <strong>cyclophilin</strong> → the cyclosporin–cyclophilin complex inhibits <strong>calcineurin</strong> (a serine/threonine phosphatase) → prevents dephosphorylation of NFAT (nuclear factor of activated T cells) → NFAT cannot translocate to the nucleus → <strong>IL-2 gene transcription blocked</strong> → T-cell activation and clonal expansion suppressed. Tacrolimus has the same target (calcineurin) but binds FKBP12 instead of cyclophilin. Drugs that dangerously elevate cyclosporin: <strong>azole antifungals</strong> (fluconazole, voriconazole — CYP3A4 inhibitors), macrolide antibiotics (clarithromycin, erythromycin — CYP3A4 inhibitors), diltiazem, verapamil. All increase cyclosporin AUC → nephrotoxicity, hypertension, neurotoxicity.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Cyclosporin causes <strong>gingival hyperplasia</strong> (also caused by phenytoin and nifedipine — all share this side effect via gingival fibroblast proliferation) and <strong>hirsutism</strong>. Tacrolimus causes neither — instead causes alopecia. Tacrolimus has higher risk of post-transplant diabetes mellitus (PTDM) than cyclosporin.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Rifampin is a potent <strong>CYP3A4 inducer</strong> → dramatically <strong>reduces</strong> cyclosporin levels → acute rejection. St John's Wort (Hypericum perforatum) similarly induces CYP3A4 → major interaction with cyclosporin, tacrolimus, oral contraceptives, and antiretrovirals. Warn transplant patients explicitly about herbal supplements.</div>"}, {"id": "inflam:fc:7", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "flashcard", "front": "A patient with Wegener's granulomatosis (GPA) is PR3-ANCA positive with pulmonary haemorrhage and rapidly progressive GN. Which alkylating agent is used for induction, and what is its most feared long-term complication?", "back": "<strong>Cyclophosphamide</strong> (IV pulse, preferred over oral for ANCA vasculitis induction per CYCLOPS trial — equivalent efficacy, lower cumulative dose). Cyclophosphamide is a prodrug activated by CYP2B6/3A4 to phosphoramide mustard → alkylates DNA → cross-links double strands → inhibits rapidly dividing cells (neutrophils, lymphocytes). Most feared long-term complication: <strong>haemorrhagic cystitis</strong> (acrolein metabolite accumulates in urine → urothelial damage) → prevented with <strong>MESNA</strong> (2-mercaptoethane sulphonate) which reacts with acrolein in the urine, and aggressive IV hydration. Long-term: <strong>transitional cell carcinoma of the bladder</strong> (lifetime monitoring required), gonadal failure (especially in women), secondary malignancies.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Rituximab (anti-CD20) is now equally effective to cyclophosphamide for ANCA vasculitis induction and is preferred in: younger patients, women of childbearing age, those with PR3-ANCA (where rituximab may be superior for preventing relapse), or where cyclophosphamide toxicity is a major concern.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> The ANCA vasculitis maintenance phase uses <strong>rituximab or azathioprine</strong> (NOT cyclophosphamide) — ongoing cyclophosphamide use has unacceptable cumulative toxicity. Switch to maintenance after 3–6 months of induction.</div>"}, {"id": "inflam:fc:8", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "flashcard", "front": "A 35-year-old man with psoriatic arthritis fails methotrexate. He is started on adalimumab (anti-TNF). Before the second dose, he phones with a fever of 39°C, rigors, and looks unwell. What complication do you suspect, and how is it managed?", "back": "Adalimumab-induced <strong>serious infection</strong> — TNF-α blockade predisposes to bacterial sepsis (especially Staphylococcus aureus, Streptococcus pneumoniae), TB reactivation, invasive fungal infections (histoplasmosis, coccidioidomycosis, aspergillosis), and opportunistic infections. In an acutely unwell patient: <strong>hold adalimumab</strong> immediately, obtain blood cultures, broad-spectrum antibiotics empirically, investigate for source. Evaluate for TB (CXR, IGRA), fungal infection if endemic exposure, and viral infections. TNF blockers should not be restarted until the infection is fully resolved and the causative organism identified.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Before starting any biologic: screen for LTBI (IGRA + CXR), hepatitis B (HBsAg, anti-HBc — TNF blockers can reactivate HBV → fulminant hepatitis), HCV status, varicella immunity, and ensure up-to-date vaccinations (live vaccines must be given ≥4 weeks before, not during, biologic therapy).</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Histoplasmosis, coccidioidomycosis, and blastomycosis are endemic fungal infections that may reactivate with TNF blockade — particularly in patients from the Ohio/Mississippi river valley or southwestern US. Serum antigen testing (Histoplasma urine antigen) is the fastest test. These infections can look like miliary TB on CXR — a critical differential.</div>"}, {"id": "inflam:fc:9", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "flashcard", "front": "A patient starting hydroxychloroquine (HCQ) for SLE asks about eye complications. Explain the mechanism of retinal toxicity and the monitoring strategy.", "back": "HCQ accumulates in melanin-containing tissues including the retinal pigment epithelium (RPE). Over years, HCQ binds to RPE melanin → lysosomal enzyme inhibition and mitochondrial damage → RPE cell death → <strong>photoreceptor degeneration</strong>. The characteristic lesion is <strong>bull's-eye maculopathy</strong> (ring of RPE loss around the central macula). Risk factors: cumulative dose &gt;5 mg/kg/day ideal body weight (NOT actual weight — use ideal), duration &gt;5 years, CKD (reduced excretion → accumulation), tamoxifen co-administration (independently toxic to retina). Monitoring: <strong>baseline ophthalmological exam within first year</strong>, then annually after 5 years (or earlier if risk factors).<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> HCQ is the cornerstone of SLE therapy — it reduces flares, nephritis, and cardiovascular mortality, and is safe in pregnancy (low teratogenicity, actually reduces obstetric complications in SLE/antiphospholipid syndrome). The dose threshold for retinal safety is ≤5 mg/kg/day of <strong>ideal body weight</strong>.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> HCQ can cause <strong>QT prolongation</strong> — relevant with concurrent azithromycin or other QT-prolonging drugs. HCQ also inhibits CYP2D6 → may raise plasma levels of codeine, metoprolol, and other CYP2D6 substrates. Do NOT confuse HCQ (safe) with chloroquine (higher retinal toxicity at equivalent doses).</div>"}, {"id": "inflam:fc:10", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "flashcard", "front": "Iron deficiency anaemia is confirmed in a 65-year-old woman with colorectal cancer. Oral iron is poorly tolerated. What is the mechanism of action of IV iron (ferric carboxymaltose), and what acute reaction must be monitored?", "back": "IV iron: ferric carboxymaltose is a colloidal iron complex → taken up by <strong>macrophages in the reticuloendothelial system (liver, spleen, bone marrow)</strong> → iron released from the carbohydrate shell → stored as ferritin → mobilised for erythropoiesis (incorporated into haemoglobin by erythroid precursors in bone marrow). Monitoring: acute <strong>hypophosphataemia</strong> (specific to ferric carboxymaltose — triggers FGF23 release → renal phosphate wasting → severe hypophosphataemia, osteomalacia with repeated dosing). Also monitor for acute hypersensitivity reactions (complement activation by the iron complex → anaphylactoid reaction — NOT IgE-mediated). Pre-medication and slow infusion + resuscitation equipment available.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Intravenous iron is preferred over oral iron for: chemotherapy-induced anaemia, pre-surgical optimisation, IBD patients (poor GI absorption/tolerance), CKD patients on erythropoiesis-stimulating agents (ESA — EPO requires adequate iron for erythropoiesis). Iron sucrose has a lower risk of hypophosphataemia than ferric carboxymaltose.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Oral ferrous sulfate absorption requires an acidic environment — proton pump inhibitors (PPIs) significantly reduce oral iron absorption. Space oral iron and PPI by &gt;2 hours. Oral iron also interacts with antacids, calcium supplements, and fluoroquinolones (chelation). Ascorbic acid (vitamin C) enhances non-haem iron absorption.</div>"}, {"id": "inflam:fc:11", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "flashcard", "front": "A patient develops thrombocytopenia 7 days after starting unfractionated heparin (UFH) post-surgery. Platelet count drops from 220 to 55 ×10⁹/L. Explain the mechanism and immediate management.", "back": "<strong>Heparin-induced thrombocytopenia type II (HIT)</strong> — an immune-mediated thrombotic disorder. Heparin binds <strong>platelet factor 4 (PF4)</strong> → heparin-PF4 complex is immunogenic → IgG antibodies form against the complex → antibody-PF4-heparin complex binds and activates platelets via FcγRIIa → platelet activation → platelet consumption (thrombocytopenia) AND pro-thrombotic state (paradoxical thrombosis despite low platelets). Immediate management: (1) <strong>STOP all heparin immediately</strong> (including heparin flushes, LMWH); (2) Start a <strong>non-heparin anticoagulant</strong> — argatroban (direct thrombin inhibitor, preferred in renal failure), bivalirudin, or fondaparinux; (3) Do NOT start warfarin yet (protein C depletion worsens thrombosis — only start after platelet recovery to &gt;150).<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Use the <strong>4T score</strong> to assess HIT probability: Thrombocytopenia (≥50% drop, nadir &gt;20 = 2 pts), Timing (5–10 days = 2 pts), Thrombosis (new = 2 pts), other causes of Thrombocytopenia (none = 2 pts). Score ≥6 = high probability. Confirm with ELISA (PF4 antibody) + functional assay (serotonin release assay — gold standard).</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> HIT type I is a benign, non-immune direct effect of heparin on platelets — occurs in first 2 days, mild thrombocytopenia (rarely &lt;100), no thrombosis, platelet count normalises spontaneously with continued heparin. HIT TYPE II is the dangerous immune-mediated version — occurs days 5–10 (or earlier if prior heparin exposure within 100 days).</div>"}, {"id": "inflam:fc:12", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "flashcard", "front": "A patient with aplastic anaemia requires immunosuppressive therapy. What is the rationale for combining anti-thymocyte globulin (ATG) with ciclosporin?", "back": "Aplastic anaemia is largely immune-mediated: <strong>autoreactive T cells</strong> (particularly CD8+ cytotoxic T cells releasing IFN-γ and TNF-α) destroy haematopoietic stem cells (HSC) → bone marrow failure. Rationale for combination: <strong>ATG</strong> (equine or rabbit-derived polyclonal antibodies against human thymocytes) depletes T cells via complement-mediated cytotoxicity and ADCC, removing the effector cells attacking the HSC niche. <strong>Ciclosporin</strong> inhibits calcineurin → blocks IL-2 → suppresses residual T-cell activation, preventing recurrence after ATG. Adding <strong>eltrombopag</strong> (TPO receptor agonist) to ATG + ciclosporin triples complete response rates (NEJM 2017) by stimulating HSC proliferation.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> ATG (equine) infusion causes serum sickness 7–14 days later (fever, urticaria, arthralgia, lymphadenopathy) — immune complex deposition. Prevent/treat with corticosteroids. Monitor for anaphylaxis during the first infusion — always administer a test dose first.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Aplastic anaemia must be distinguished from hypocellular MDS (myelodysplastic syndrome) and paroxysmal nocturnal haemoglobinuria (PNH) — both can present similarly. PNH clone (GPI-anchor deficiency → susceptibility to complement → haemolysis + thrombosis) can co-exist with aplastic anaemia. Test with flow cytometry for CD55/CD59 deficiency. Eculizumab (anti-C5) treats PNH haemolysis and thrombosis.</div>"}, {"id": "inflam:fc:13", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "flashcard", "front": "A patient with polycythaemia vera (PV) is at high risk of thrombosis. Beyond aspirin and phlebotomy, what is the cytoreductive drug of choice, and what is the molecular target therapy for patients failing or intolerant of it?", "back": "First-line cytoreduction for high-risk PV (age &gt;60, or prior thrombosis): <strong>hydroxyurea (hydroxycarbamide)</strong> — inhibits ribonucleotide reductase → reduces dNTP pool → impairs DNA synthesis → selectively reduces rapidly dividing haematopoietic cells (RBCs, platelets, WBCs). Molecular target therapy for HU-resistant/intolerant PV: <strong>ruxolitinib</strong> — a JAK1/JAK2 inhibitor. &gt;95% of PV patients carry the <strong>JAK2 V617F mutation</strong> (point mutation in the pseudokinase domain → constitutive JAK2 activation → cytokine-independent haematopoiesis). Ruxolitinib blocks JAK1/2 → reduces cell proliferation, splenomegaly, and symptom burden.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> JAK2 V617F is present in ~95% of PV, ~50% of ET, and ~50% of PMF. Calreticulin (CALR) mutations are found in ~25% of ET and PMF but NOT in PV. MPL mutations in ~5% of ET/PMF. JAK2 exon 12 mutations are PV-specific. Panel testing for JAK2/CALR/MPL is the molecular workup for MPNs.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Hydroxyurea is teratogenic — contraindicated in pregnancy. For PV in pregnancy, use <strong>interferon-alpha</strong> (preferred — non-teratogenic, reduces JAK2 V617F allele burden). Aspirin 75–100 mg daily is given to all PV patients (reduces thrombosis; at low dose avoids paradoxical bleeding from von Willebrand abnormality seen in extreme thrombocytosis).</div>"}, {"id": "inflam:fc:14", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "flashcard", "front": "A 52-year-old man with CLL is started on ibrutinib. Six months later he develops atrial fibrillation and a major gastrointestinal bleed. What is the mechanistic explanation?", "back": "Ibrutinib is a covalent inhibitor of <strong>Bruton's tyrosine kinase (BTK)</strong>. BTK is essential for BCR signalling → B-cell survival (tumour) AND platelet activation (via GPVI collagen receptor signalling). Ibrutinib off-target inhibition of <strong>TEC kinase</strong> and platelet BTK impairs: (1) <strong>Platelet aggregation</strong> (collagen-induced platelet function) → bleeding risk (major bleeding ~6% per year); (2) <strong>Atrial fibrillation</strong> — mechanism involves cardiac BTK/TEC kinase effects on atrial electrical remodelling and inflammation, plus autonomic effects. Overall AF risk ~10–15% (significantly higher than standard therapy). BTK inhibition also causes ibrutinib-specific AF — typically managed by switching to acalabrutinib or zanubrutinib (more selective BTK inhibitors with lower AF and bleeding rates).<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Ibrutinib + warfarin: concurrent anticoagulation dramatically increases bleeding risk. DOAC + ibrutinib: also increases bleeding but may be preferable to warfarin. For AF requiring anticoagulation in a patient on ibrutinib, consider switching to a next-gen BTK inhibitor + DOAC with careful risk-benefit analysis.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Ibrutinib is a CYP3A4 substrate — rifampin dramatically reduces levels; azole antifungals dramatically increase levels. Given the frequency of fungal prophylaxis in CLL patients on ibrutinib, this interaction is clinically critical.</div>"}, {"id": "inflam:fc:15", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "flashcard", "front": "A patient with multiple myeloma undergoes stem cell transplant conditioning with high-dose melphalan. Forty-eight hours later he develops painful oral ulcers, diarrhoea, and neutropaenia. What defines his mucosal recovery, and what drug reduces the duration and severity of mucositis?", "back": "High-dose melphalan → alkylation of rapidly dividing cells → <strong>mucositis</strong> (basal epithelial cell loss in oral mucosa, GI tract) AND <strong>neutropaenia</strong> (bone marrow ablation — cells nadir ~day 10, recover when engraftment occurs). <strong>Palifermin</strong> (recombinant keratinocyte growth factor-1, KGF-1) — given before conditioning → stimulates epithelial cell proliferation and differentiation in the mucosa → thickens mucosal barrier → reduces mucositis severity and duration. Mucosal recovery requires engraftment (WBC recovery) — supported by G-CSF (filgrastim) which stimulates neutrophil production from the transplanted stem cells.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> G-CSF (filgrastim) mechanism: binds G-CSF receptor on neutrophil precursors → JAK2/STAT3 signalling → accelerated granulopoiesis → shorter duration of neutropaenia. Pegfilgrastim is pegylated G-CSF (longer half-life → single dose per chemotherapy cycle). GM-CSF (sargramostim) stimulates both myeloid and monocyte lineages.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Palifermin is contraindicated in solid tumours — KGF receptors on tumour cells (particularly squamous cell cancers) may stimulate tumour growth. Palifermin is approved specifically for haematological malignancies receiving myeloablative conditioning. Do NOT give in head-and-neck cancer or other KGF receptor-expressing malignancies.</div>"}, {"id": "inflam:fc:16", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "flashcard", "front": "A 65-year-old with immune thrombocytopenia (ITP) fails corticosteroids and rituximab. What is the mechanism of eltrombopag and romiplostim, and when would splenectomy be considered?", "back": "<strong>Eltrombopag</strong>: small molecule that binds the <strong>transmembrane domain of the thrombopoietin receptor (c-Mpl/TPO-R)</strong> — activates JAK2/STAT5 signalling → megakaryocyte proliferation and maturation → increased platelet production. Does NOT compete with endogenous TPO. <strong>Romiplostim</strong>: peptibody (Fc-peptide fusion) that mimics TPO → binds extracellular domain of TPO-R → same downstream signalling. Both are TPO receptor agonists — they increase platelet production to compensate for immune-mediated destruction. <strong>Splenectomy</strong> is considered after ≥12 months of ITP (to allow spontaneous remission chance) when 2 lines of therapy fail — the spleen is the primary site of anti-platelet IgG production AND platelet destruction. ~60–70% durable response.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Eltrombopag has an additional off-target effect: chelates non-transferrin-bound iron in hepatocytes and HSCs → stimulates HSC proliferation. This is the basis for its use in aplastic anaemia (iron chelation from HSC niche → promotes HSC self-renewal independent of TPO-R effect).</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Eltrombopag must be taken on an empty stomach — polyvalent cation chelation (calcium, aluminium, iron, magnesium) reduces absorption by up to 70%. Take 2 hours before or 4 hours after dairy, antacids, or mineral supplements. This is a commonly missed pharmacokinetic interaction.</div>"}, {"id": "inflam:fc:17", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "flashcard", "front": "Mycophenolate mofetil (MMF) is used in transplant immunosuppression. What is its mechanism, and why is it specific to lymphocytes?", "back": "MMF is a prodrug hydrolysed to <strong>mycophenolic acid (MPA)</strong> → inhibits <strong>inosine monophosphate dehydrogenase (IMPDH)</strong> — the rate-limiting enzyme in the <em>de novo</em> purine synthesis pathway (converts IMP → xanthine monophosphate → GMP). Specificity to lymphocytes: most cells (hepatocytes, enterocytes, renal tubular cells) can use the <strong>salvage pathway</strong> (recycle purines from nucleoside breakdown) to meet GMP requirements. <strong>T and B lymphocytes lack an effective salvage pathway</strong> and rely almost entirely on de novo synthesis → MMF preferentially suppresses lymphocyte proliferation with relative sparing of other rapidly dividing cells.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> MMF is used in: renal/cardiac/hepatic transplant rejection prophylaxis, lupus nephritis, IgA nephropathy, ANCA vasculitis maintenance. It is safer than azathioprine (less myelosuppression, no thiopurine methyltransferase issue) and has replaced azathioprine in most transplant protocols.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> MMF is a <strong>teratogen (FDA category D/X)</strong> — causes ear malformations (microtia), cleft palate, and cardiac defects. Requires negative pregnancy test before starting and reliable contraception throughout. The FDA issued a specific black-box warning after reports of MMF embryopathy. Switch to azathioprine if pregnancy is planned.</div>"}, {"id": "inflam:fc:18", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "flashcard", "front": "A patient with myelodysplastic syndrome (MDS) with del(5q) is treated with lenalidomide. Explain the mechanism and the unique teratogenicity concern.", "back": "Lenalidomide targets <strong>cereblon (CRBN)</strong>, a substrate-recognition component of the CRL4 E3 ubiquitin ligase complex. Lenalidomide binding to CRBN changes its substrate specificity → the complex now ubiquitinates and degrades <strong>IKZF1 (Ikaros) and IKZF3 (Aiolos)</strong> — transcription factors essential for myeloma and certain lymphoma cell survival. In del(5q) MDS: lenalidomide also degrades <strong>CK1α</strong> (encoded on chromosome 5q) — CK1α haploinsufficiency from del(5q) makes MDS cells exquisitely sensitive to further CK1α degradation → selective cytotoxicity against del(5q) clone. Teratogenicity: lenalidomide is a thalidomide analogue → <strong>phocomelia</strong> (limb defects) and other severe fetal malformations. REMS programme required (RevAssist) — monthly pregnancy tests, male contraception, no blood/semen donation.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Thalidomide was originally a morning sickness drug withdrawn in the 1960s after causing phocomelia in thousands of infants. Its mechanism of teratogenicity is now known: cereblon-mediated degradation of SALL4 (transcription factor essential for limb development). The same cereblon mechanism is its anticancer mechanism — thalidomide is now a bedrock of myeloma therapy.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Lenalidomide + dexamethasone in myeloma: high risk of <strong>venous thromboembolism</strong> (DVT/PE) — prophylactic anticoagulation required (aspirin for low-risk; LMWH or DOAC for high-risk). Also causes peripheral neuropathy (less than thalidomide but still significant) and cytopenias (neutropenia requiring G-CSF support).</div>"}, {"id": "inflam:fc:19", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "flashcard", "front": "A 22-year-old woman with immune thrombocytopenic purpura (ITP) has a platelet count of 8 ×10⁹/L and intracranial haemorrhage. She needs rapid platelet increase. What three interventions would you give simultaneously?", "back": "Life-threatening ITP (ICH) requires rapid multi-modal platelet rescue: (1) <strong>IV methylprednisolone</strong> 1 g/day × 3 days — blocks splenic macrophage FcγR → reduces phagocytosis of opsonised platelets; also reduces anti-platelet antibody synthesis. (2) <strong>IVIG 1 g/kg/day × 2 days</strong> — saturates splenic FcγR (Fc receptor blockade) → reduces platelet destruction; fastest mechanism (platelets rise within 24–48 hours). (3) <strong>Platelet transfusion</strong> — in ITP, transfused platelets are rapidly destroyed (same as native platelets), but in ICH, give anyway: any temporary increase in platelet count buys time for haemostasis. Anti-D immunoglobulin (if Rh-positive, non-splenectomised) is an alternative to IVIG. Consider romiplostim/eltrombopag for sustained response.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> IVIG response is faster than steroids in acute severe ITP. In ICH, the combination of IVIG + steroids achieves higher and faster platelet increments than either alone. Add platelet transfusion despite their rapid destruction — the brief window of platelet activity can slow bleeding.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> IVIG in ITP does NOT block anti-platelet antibody production (that is the role of rituximab, which takes weeks). IVIG works by FcγR blockade — a temporary measure. Platelet counts often fall again after IVIG effect wears off (7–10 days). Plan definitive therapy (rituximab, splenectomy, TPO-RA) simultaneously.</div>"}, {"id": "inflam:q:0", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Which enzyme liberates arachidonic acid from membrane phospholipids?", "back": "Phospholipase A₂."}, {"id": "inflam:q:1", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Which drug class inhibits phospholipase A₂ (indirectly, via annexin-1/lipocortin)?", "back": "Glucocorticoids."}, {"id": "inflam:q:2", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Name the two branches arachidonic acid can take.", "back": "Cyclo-oxygenase (COX) → prostanoids; 5-lipoxygenase (LOX) → leukotrienes."}, {"id": "inflam:q:3", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Which branch do NSAIDs block, and which is left intact?", "back": "They block COX; the leukotriene (LOX) branch is left intact."}, {"id": "inflam:q:4", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Why can an NSAID provoke bronchospasm in a susceptible asthmatic?", "back": "Blocking COX shunts arachidonic acid down the LOX branch → more bronchoconstricting leukotrienes."}, {"id": "inflam:q:5", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Which prostanoid produced by platelets promotes aggregation and vasoconstriction?", "back": "Thromboxane A₂ (TXA₂), via COX-1."}, {"id": "inflam:q:6", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Which endothelial prostanoid opposes it (vasodilator, inhibits aggregation)?", "back": "Prostacyclin (PGI₂)."}, {"id": "inflam:q:7", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Which prostaglandin mediates fever in the hypothalamus?", "back": "PGE₂."}, {"id": "inflam:q:8", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Which prostaglandin protects the gastric mucosa?", "back": "PGE₂ (and PGI₂) — stimulate mucus/bicarbonate."}, {"id": "inflam:q:9", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "What does zileuton inhibit?", "back": "5-Lipoxygenase → ↓ all leukotrienes."}, {"id": "inflam:q:10", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "What receptor do montelukast and zafirlukast block?", "back": "The CysLT₁ (cysteinyl leukotriene) receptor."}, {"id": "inflam:q:11", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Which leukotriene is a potent neutrophil chemoattractant?", "back": "LTB₄."}, {"id": "inflam:q:12", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Which leukotrienes make up the cysteinyl leukotrienes (CysLTs)?", "back": "LTC₄, LTD₄, LTE₄."}, {"id": "inflam:q:13", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Is platelet-activating factor (PAF) an eicosanoid?", "back": "No — it is a separate phospholipid mediator, though it amplifies inflammation."}, {"id": "inflam:q:14", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Why do glucocorticoids suppress more of the inflammatory response than NSAIDs?", "back": "They act upstream at PLA₂, shutting down BOTH the COX and LOX branches."}, {"id": "inflam:q:15", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "What is the shared mechanism of all NSAIDs?", "back": "Inhibition of cyclo-oxygenase (COX) → ↓ prostaglandin synthesis."}, {"id": "inflam:q:16", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Name the four therapeutic effects of NSAIDs.", "back": "Analgesic, antipyretic, anti-inflammatory, antiplatelet."}, {"id": "inflam:q:17", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Why does blocking COX-1 cause peptic ulcers?", "back": "Loss of protective gastric PGE₂ (mucus/bicarbonate)."}, {"id": "inflam:q:18", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Why do NSAIDs cause fluid retention and can precipitate AKI?", "back": "Loss of renal PGE₂/PGI₂ that maintain renal blood flow."}, {"id": "inflam:q:19", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "How does aspirin differ mechanistically from other NSAIDs?", "back": "It IRREVERSIBLY acetylates COX."}, {"id": "inflam:q:20", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Why does aspirin's antiplatelet effect last ~7–10 days?", "back": "Platelets are anucleate and cannot synthesise new COX — effect lasts the platelet lifespan."}, {"id": "inflam:q:21", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "What is the main advantage and the main risk of COX-2-selective agents (coxibs)?", "back": "Advantage: spare gastric COX-1 (fewer ulcers). Risk: increased thrombosis/cardiovascular events."}, {"id": "inflam:q:22", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Why do coxibs increase cardiovascular risk?", "back": "They reduce endothelial PGI₂ (anti-clotting) while platelet TXA₂ (pro-clotting) is preserved."}, {"id": "inflam:q:23", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "How does acetaminophen differ from NSAIDs?", "back": "Analgesic + antipyretic but weak anti-inflammatory; acts centrally; no GI/antiplatelet effects."}, {"id": "inflam:q:24", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "What causes acetaminophen hepatotoxicity in overdose?", "back": "Saturation of conjugation → CYP2E1 forms NAPQI → glutathione depletion."}, {"id": "inflam:q:25", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "First-line drugs for an ACUTE gout flare?", "back": "NSAIDs (e.g. indomethacin), colchicine, or glucocorticoids."}, {"id": "inflam:q:26", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Mechanism of allopurinol/febuxostat?", "back": "Xanthine oxidase inhibition → ↓ uric acid synthesis (chronic urate-lowering)."}, {"id": "inflam:q:27", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Mechanism of colchicine?", "back": "Binds tubulin → inhibits microtubule/neutrophil migration."}, {"id": "inflam:q:28", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Why must aspirin be avoided in children with viral illness?", "back": "Risk of Reye syndrome."}, {"id": "inflam:q:29", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Why does allopurinol potentiate azathioprine/6-MP toxicity?", "back": "Both are inactivated by xanthine oxidase; allopurinol blocks it → drug accumulates → myelosuppression."}, {"id": "inflam:q:30", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "What are the two underlying problems in asthma?", "back": "Acute bronchoconstriction and chronic airway inflammation."}, {"id": "inflam:q:31", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Reliever vs controller — what does each address?", "back": "Relievers (bronchodilators) open the airway fast; controllers (anti-inflammatory) treat the underlying inflammation."}, {"id": "inflam:q:32", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Mechanism of salbutamol?", "back": "Short-acting β₂-agonist → ↑cAMP → smooth muscle relaxation."}, {"id": "inflam:q:33", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "What is the controller cornerstone of asthma therapy?", "back": "Inhaled corticosteroids (ICS)."}, {"id": "inflam:q:34", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Why must a LABA never be used as monotherapy in asthma?", "back": "LABA monotherapy increases asthma deaths — must be combined with an ICS."}, {"id": "inflam:q:35", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Mechanism of tiotropium and where is it most useful?", "back": "Long-acting muscarinic (M₃) antagonist; mainstay in COPD."}, {"id": "inflam:q:36", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Mechanism and role of montelukast?", "back": "CysLT₁ receptor antagonist; add-on controller, useful in allergic/exercise-induced asthma."}, {"id": "inflam:q:37", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Why is theophylline rarely first-line?", "back": "Narrow therapeutic index (nausea, arrhythmia, seizures)."}, {"id": "inflam:q:38", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Theophylline is metabolised by which enzyme, and what happens in smokers?", "back": "CYP1A2; smoking induces it → lower levels (may need higher dose)."}, {"id": "inflam:q:39", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Give two biologic options for severe asthma and their targets.", "back": "Omalizumab (anti-IgE); mepolizumab/benralizumab (anti-IL-5/eosinophils)."}, {"id": "inflam:q:40", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Which second messenger rises when a β₂-agonist binds its receptor?", "back": "cAMP (Gs-coupled GPCR)."}, {"id": "inflam:q:41", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Why does escalating reliever (SABA) use signal poor control?", "back": "It treats only the symptom (spasm), not the inflammation — rising use means the disease is uncontrolled."}, {"id": "inflam:q:42", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Why are anticholinergics relatively more important in COPD than asthma?", "back": "COPD bronchomotor tone is dominantly cholinergic."}, {"id": "inflam:q:43", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "What class is budesonide?", "back": "Inhaled corticosteroid (ICS)."}, {"id": "inflam:q:44", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Formoterol differs from salmeterol how?", "back": "Formoterol is a LABA with a fast onset (can be used in some maintenance-and-reliever regimens with ICS)."}, {"id": "inflam:q:45", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Microcytic anaemia — likely deficiency and treatment?", "back": "Iron deficiency; oral or IV iron."}, {"id": "inflam:q:46", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Macrocytic anaemia — two possible deficiencies?", "back": "Vitamin B₁₂ and/or folate."}, {"id": "inflam:q:47", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Single clinical feature distinguishing B₁₂ from folate deficiency?", "back": "Neurological signs occur with B₁₂ deficiency, not folate."}, {"id": "inflam:q:48", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Why is giving folate alone in B₁₂ deficiency dangerous?", "back": "It corrects the anaemia but lets neurological damage (subacute combined degeneration) progress."}, {"id": "inflam:q:49", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "What causes anaemia in chronic kidney disease?", "back": "Reduced erythropoietin production by the kidney."}, {"id": "inflam:q:50", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Why does erythropoietin fail if iron stores are inadequate?", "back": "Red-cell production needs iron as raw material; EPO alone is insufficient."}, {"id": "inflam:q:51", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Name two erythropoiesis-stimulating agents.", "back": "Epoetin alfa, darbepoetin alfa."}, {"id": "inflam:q:52", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Major risks of ESAs?", "back": "Hypertension and thrombosis/stroke (especially if Hb over-corrected)."}, {"id": "inflam:q:53", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "What does G-CSF (filgrastim) do?", "back": "Stimulates neutrophil production — used for chemotherapy-induced neutropenia."}, {"id": "inflam:q:54", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Where is dietary iron mainly absorbed?", "back": "Duodenum."}, {"id": "inflam:q:55", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Common side effects of oral iron?", "back": "GI upset, constipation, black stools."}, {"id": "inflam:q:56", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "What reduces oral iron absorption?", "back": "PPIs/antacids (raised gastric pH); food."}, {"id": "inflam:q:57", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Vitamin B₁₂ absorption requires what factor, and what disease destroys it?", "back": "Intrinsic factor; pernicious anaemia (give B₁₂ IM)."}, {"id": "inflam:q:58", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Why is folate important periconceptually?", "back": "Prevents neural tube defects."}, {"id": "inflam:q:59", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Name a thrombopoietin-receptor agonist for ITP.", "back": "Romiplostim or eltrombopag."}, {"id": "inflam:q:60", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Mechanism of calcineurin inhibitors?", "back": "↓ calcineurin → ↓ IL-2 transcription → ↓ T-cell activation."}, {"id": "inflam:q:61", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Name two calcineurin inhibitors.", "back": "Ciclosporin and tacrolimus."}, {"id": "inflam:q:62", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Signature toxicity of calcineurin inhibitors?", "back": "Nephrotoxicity (also ↑BP, tremor, hyperglycaemia)."}, {"id": "inflam:q:63", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Why is a rising creatinine ambiguous in a transplant patient on tacrolimus?", "back": "It could be graft rejection OR calcineurin-inhibitor nephrotoxicity — hence drug monitoring."}, {"id": "inflam:q:64", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Mechanism of sirolimus?", "back": "mTOR inhibitor — blocks IL-2 signal transduction/proliferation."}, {"id": "inflam:q:65", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Mechanism of mycophenolate mofetil?", "back": "Inhibits inosine monophosphate dehydrogenase → ↓ purine (guanosine) synthesis in lymphocytes."}, {"id": "inflam:q:66", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Mechanism of azathioprine?", "back": "Pro-drug → 6-mercaptopurine → ↓ purine synthesis; antiproliferative."}, {"id": "inflam:q:67", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Which common gout drug dangerously potentiates azathioprine, and why?", "back": "Allopurinol — it inhibits xanthine oxidase which inactivates the metabolite → toxicity."}, {"id": "inflam:q:68", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Give the target of infliximab.", "back": "TNF-α."}, {"id": "inflam:q:69", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Give the target of rituximab.", "back": "CD20 on B cells."}, {"id": "inflam:q:70", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Why screen for latent TB before an anti-TNF biologic?", "back": "Anti-TNF therapy can reactivate latent tuberculosis (and hepatitis B)."}, {"id": "inflam:q:71", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Calcineurin inhibitors are substrates of which enzyme?", "back": "CYP3A4 (interactions with azoles, macrolides, grapefruit)."}, {"id": "inflam:q:72", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Broadest-acting immunosuppressant class?", "back": "Glucocorticoids."}, {"id": "inflam:q:73", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Universal trade-off of immunosuppression?", "back": "Increased risk of infection and malignancy."}, {"id": "inflam:q:74", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "What does belatacept block?", "back": "T-cell co-stimulation (CTLA-4–Ig fusion blocking CD80/86)."}, {"id": "inflam:q:75", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Which histamine receptor mediates allergic responses and is the antihistamine target?", "back": "H₁."}, {"id": "inflam:q:76", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Which histamine receptor controls gastric acid secretion?", "back": "H₂."}, {"id": "inflam:q:77", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Why are 1st-generation antihistamines sedating?", "back": "They are lipophilic and cross the blood-brain barrier."}, {"id": "inflam:q:78", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Why are 2nd-generation antihistamines non-sedating?", "back": "They are more polar / P-gp substrates and do not cross the BBB significantly."}, {"id": "inflam:q:79", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Name two 1st-generation antihistamines.", "back": "Diphenhydramine, chlorpheniramine (or promethazine)."}, {"id": "inflam:q:80", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Name two 2nd-generation antihistamines.", "back": "Loratadine, cetirizine (or fexofenadine)."}, {"id": "inflam:q:81", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Besides allergy, give two uses of 1st-gen antihistamines.", "back": "Motion sickness/vertigo, nausea, insomnia."}, {"id": "inflam:q:82", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Why do 1st-gen antihistamines cause dry mouth and urinary retention?", "back": "They also block muscarinic (antimuscarinic) receptors."}, {"id": "inflam:q:83", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Why are 1st-gen agents risky in the elderly?", "back": "Antimuscarinic and sedative effects → confusion, falls, retention, glaucoma."}, {"id": "inflam:q:84", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Name two H₂-receptor antagonists.", "back": "Famotidine, ranitidine (cimetidine)."}, {"id": "inflam:q:85", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Which autacoid causes the ACE-inhibitor cough?", "back": "Bradykinin (accumulates when ACE is inhibited)."}, {"id": "inflam:q:86", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "What other ACE-inhibitor adverse effect is bradykinin-mediated?", "back": "Angio-oedema."}, {"id": "inflam:q:87", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Which generation is preferred for daytime allergy control?", "back": "2nd generation (non-sedating)."}, {"id": "inflam:q:88", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "What triggers histamine release from mast cells in Type I hypersensitivity?", "back": "Allergen cross-linking of IgE on mast cells."}, {"id": "inflam:q:89", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Are H₃/H₄ receptors major current drug targets?", "back": "No — largely investigational."}, {"id": "inflam:q:90", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Two arms of the immune system?", "back": "Innate (fast, non-specific, no memory) and adaptive (slow, specific, memory)."}, {"id": "inflam:q:91", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Which arm forms immunological memory?", "back": "Adaptive."}, {"id": "inflam:q:92", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "List the four hypersensitivity types (ACID).", "back": "I Anaphylactic/immediate, II Cytotoxic, III Immune-complex, IV Delayed."}, {"id": "inflam:q:93", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Which hypersensitivity type is IgE-mediated?", "back": "Type I."}, {"id": "inflam:q:94", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Classic example of Type I?", "back": "Anaphylaxis, atopy, allergic rhinitis/asthma."}, {"id": "inflam:q:95", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Which type is antibody-against-cell-surface (e.g. haemolytic anaemia)?", "back": "Type II."}, {"id": "inflam:q:96", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Which type is immune-complex mediated (e.g. SLE, serum sickness)?", "back": "Type III."}, {"id": "inflam:q:97", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Which type is T-cell mediated and delayed?", "back": "Type IV."}, {"id": "inflam:q:98", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Why does a TB skin test take ~48–72 h to read?", "back": "It is a Type IV (delayed, T-cell) reaction."}, {"id": "inflam:q:99", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Which three hypersensitivity types are antibody-mediated?", "back": "Types I, II, and III."}, {"id": "inflam:q:100", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "What is a cytokine storm?", "back": "Excessive cytokine release causing systemic inflammation."}, {"id": "inflam:q:101", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Name two immune checkpoint molecules.", "back": "CTLA-4 and PD-1/PD-L1."}, {"id": "inflam:q:102", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "What do checkpoint inhibitors do in cancer therapy?", "back": "Release the brakes on T cells so they attack tumour cells."}, {"id": "inflam:q:103", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Main toxicity class of checkpoint inhibitors?", "back": "Immune-related adverse events (autoimmune: colitis, hepatitis, thyroiditis, etc.)."}, {"id": "inflam:q:104", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Key innate immune players?", "back": "Neutrophils, macrophages, NK cells, complement."}, {"id": "inflam:q:105", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Active vs passive immunisation — core difference?", "back": "Active = body makes its own antibodies (vaccine); passive = ready-made antibodies given."}, {"id": "inflam:q:106", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Which has faster onset?", "back": "Passive (immediate)."}, {"id": "inflam:q:107", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Which lasts longer?", "back": "Active (durable memory)."}, {"id": "inflam:q:108", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Why give BOTH vaccine and immune globulin after a rabies exposure?", "back": "Globulin protects immediately; the vaccine builds lasting immunity over weeks."}, {"id": "inflam:q:109", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Four broad vaccine types?", "back": "Live-attenuated, inactivated, subunit, mRNA (nucleic acid)."}, {"id": "inflam:q:110", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Which vaccine type is contraindicated in pregnancy/immunocompromise?", "back": "Live-attenuated."}, {"id": "inflam:q:111", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Give two live-attenuated vaccines.", "back": "MMR, varicella (or BCG)."}, {"id": "inflam:q:112", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Why is a live vaccine dangerous in immunocompromise?", "back": "The attenuated organism may cause disease."}, {"id": "inflam:q:113", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Classic passive-immunisation product in pregnancy?", "back": "Anti-D (Rho) immune globulin."}, {"id": "inflam:q:114", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "What does anti-D prevent?", "back": "Rh sensitisation → haemolytic disease of the newborn."}, {"id": "inflam:q:115", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Why does passive immunity fade?", "back": "The transferred antibodies are gradually cleared; no memory is formed."}, {"id": "inflam:q:116", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Which immune arm does a vaccine rely on?", "back": "Adaptive immunity (memory)."}, {"id": "inflam:q:117", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Why can't a transplant patient on tacrolimus get the MMR vaccine?", "back": "It is live-attenuated and they are immunosuppressed → risk of vaccine-strain disease."}, {"id": "inflam:q:118", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Can passive antibody interfere with a simultaneous live vaccine?", "back": "Yes — it can blunt the immune response to it."}, {"id": "inflam:q:119", "deck": "Inflammation, Immunity & Haematopoiesis", "dk": "inflam", "type": "quiz", "front": "Example of post-exposure passive immunisation besides rabies?", "back": "Tetanus immune globulin, hepatitis B immune globulin."}, {"id": "endo:fc:0", "deck": "Endocrine", "dk": "endo", "type": "flashcard", "front": "A 58-year-old woman with T2DM and eGFR 28 mL/min is on metformin. She is admitted for elective contrast CT. What should be done, and why?", "back": "Hold metformin 48 h before and 48 h after IV contrast. Contrast can cause transient AKI; if metformin continues during AKI, lactic acid clearance falls → <strong>metformin-associated lactic acidosis (MALA)</strong>. Also, metformin is contraindicated when eGFR &lt;30 mL/min/1.73m² and should be dose-reduced at eGFR 30–45. Mechanism of metformin: activates AMPK → inhibits hepatic gluconeogenesis + enhances peripheral insulin sensitivity. No hypoglycaemia risk.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> MALA is rare but carries ~50% mortality when it occurs. Classic triad: high anion-gap metabolic acidosis + elevated lactate + metformin use in the setting of CKD, contrast exposure, excessive alcohol, or sepsis.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Metformin does NOT cause hypoglycaemia as monotherapy — it only sensitises to insulin already present. This makes it the preferred first-line agent in T2DM and safe in combination with agents that do cause hypoglycaemia (sulfonylureas).</div>"}, {"id": "endo:fc:1", "deck": "Endocrine", "dk": "endo", "type": "flashcard", "front": "A T2DM patient on glipizide is found unconscious with blood glucose of 36 mg/dL. IV dextrose is given and she wakes, but hypoglycaemia recurs two hours later. Why does this happen, and how long must she be monitored?", "back": "Sulfonylureas (glipizide, gliclazide, glibenclamide) stimulate insulin secretion by blocking <strong>K⁺-ATP channels</strong> on β-cells → depolarisation → Ca²⁺ influx → insulin release, independent of glucose level. Their duration of action (6–24 h) means hypoglycaemia can be <strong>prolonged and recurrent</strong> even after initial dextrose correction. Observe for 24–48 h with continuous glucose infusion; hospital admission is often required.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Long-acting sulfonylureas (glibenclamide/glyburide) are the most dangerous in overdose and in elderly/CKD patients — prefer shorter-acting agents (gliclazide, glipizide) or avoid the class entirely in CKD (accumulation risk).</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Octreotide (somatostatin analogue) is used for refractory sulfonylurea-induced hypoglycaemia — it suppresses insulin secretion directly, reducing the frequency of dextrose infusions needed. This is the specific antidote for SU overdose.</div>"}, {"id": "endo:fc:2", "deck": "Endocrine", "dk": "endo", "type": "flashcard", "front": "A pregnant woman at 8 weeks with Graves' hyperthyroidism is on methimazole. Her obstetrician insists on switching drugs. Why, and to what?", "back": "Methimazole is associated with <strong>embryopathy in the 1st trimester</strong>: aplasia cutis (scalp skin defects), choanal and oesophageal atresia — the 'methimazole embryopathy' syndrome. Switch to <strong>propylthiouracil (PTU)</strong> for the first trimester. After the 1st trimester, switch back to methimazole — PTU carries a risk of severe hepatotoxicity (including fulminant hepatic failure) that outweighs its embryopathy advantage beyond week 14.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> PTU has an additional mechanism absent in methimazole: it inhibits peripheral <strong>5'-deiodinase</strong> → blocks T4 → T3 conversion. This makes PTU the drug of choice in thyroid storm (faster reduction of circulating T3).</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Both thionamides cross the placenta AND enter breast milk. PTU crosses less into breast milk → preferred during breastfeeding. Neither drug is 'safe' — the risk-benefit must be weighed. Target: maternal FT4 in the upper-normal range to avoid foetal hypothyroidism.</div>"}, {"id": "endo:fc:3", "deck": "Endocrine", "dk": "endo", "type": "flashcard", "front": "A patient with thyroid storm is admitted. List the pharmacological steps in the correct order, including why one drug must be given before another.", "back": "<strong>Correct sequence:</strong> (1) <strong>PTU</strong> first — blocks new hormone synthesis AND T4→T3 conversion; (2) Wait ≥1 hour, then <strong>Lugol's iodine / SSKI</strong> — blocks thyroid hormone <em>release</em> (Wolff–Chaikoff). Critical: iodine given before PTU provides substrate for a new surge of hormone synthesis ('escape'). (3) <strong>Propranolol</strong> — controls adrenergic symptoms (tachycardia, tremor) AND inhibits peripheral T4→T3 conversion; (4) <strong>Hydrocortisone</strong> — prevents concurrent adrenal crisis AND reduces peripheral T4→T3 conversion; (5) Supportive care (cooling, fluids).<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Cholestyramine can be added to bind thyroid hormones in the gut (reduces enterohepatic recirculation of T4/T3), accelerating their clearance in severe thyroid storm.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> <strong>Aspirin is contraindicated</strong> in thyroid storm — it displaces T4 from thyroid-binding globulin (TBG) → acutely raises free T4. Use paracetamol (acetaminophen) for fever instead.</div>"}, {"id": "endo:fc:4", "deck": "Endocrine", "dk": "endo", "type": "flashcard", "front": "A T2DM patient on semaglutide loses 12 kg over 6 months. He also reports nausea and early satiety. What are the mechanisms of weight loss and GI side effects?", "back": "<strong>GLP-1 receptor agonists</strong> (semaglutide, liraglutide) activate GLP-1 receptors in: (1) <strong>Pancreas</strong> → glucose-dependent insulin secretion + glucagon suppression; (2) <strong>Hypothalamus/brainstem</strong> → reduced appetite, increased satiety; (3) <strong>Stomach</strong> → slowed gastric emptying → earlier satiety + prolonged nutrient absorption. The same mechanism of gastric slowing causes nausea, vomiting, and early satiety — the most common side effects (start low, titrate slowly).<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> SUSTAIN-6 (semaglutide) and LEADER (liraglutide) trials demonstrated significant reductions in MACE (major adverse cardiovascular events) — cardiovascular benefit independent of glucose lowering. GLP-1 agonists are now first-line add-on in T2DM with established CVD.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> GLP-1 agonists and DPP-4 inhibitors both enhance GLP-1 signalling — but DPP-4 inhibitors (sitagliptin) are weight-neutral, while GLP-1 agonists promote weight loss. GLP-1 agonists are also associated with pancreatitis and theoretical thyroid C-cell tumour risk (contraindicated in MEN2/personal history of MTC).</div>"}, {"id": "endo:fc:5", "deck": "Endocrine", "dk": "endo", "type": "flashcard", "front": "A 45-year-old woman with T2DM is started on empagliflozin. She develops vulvovaginal itching and discharge. What is the mechanism, and what serious adverse effect must also be counselled?", "back": "<strong>Genital mycotic infections</strong>: SGLT2 inhibitors block glucose reabsorption in the proximal tubule → glucosuria → glucose-rich environment in the genital area → Candida overgrowth. Common in women (vulvovaginitis) and uncircumcised men (balanitis). Treat with topical antifungals; reduce/stop if recurrent. Serious adverse effect: <strong>euglycaemic DKA</strong> — normal or near-normal blood glucose (150–200 mg/dL) but ketoacidosis — because SGLT2 inhibitors promote ketonaemia. Must hold drug during illness, fasting, or surgery.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> EMPA-REG OUTCOME trial: empagliflozin reduced CV death by 38% and HF hospitalisation by 35% in T2DM with CVD. DAPA-HF and EMPEROR-Reduced showed benefit even in patients without diabetes. SGLT2 inhibitors are now standard of care in HFrEF regardless of diabetes status.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Fournier's gangrene (necrotising fasciitis of the perineum) is a rare but FDA black-box warning for SGLT2 inhibitors. Also: SGLT2 inhibitors cause a modest rise in LDL (~2–5%) and increase UTI risk slightly (though overall infection rate is low due to urinary glucose washout effect on uropathogens).</div>"}, {"id": "endo:fc:6", "deck": "Endocrine", "dk": "endo", "type": "flashcard", "front": "A T1DM patient in DKA has an initial K⁺ of 5.4 mEq/L. As insulin is infused, K⁺ drops to 3.0 mEq/L in 4 hours. Explain the physiology and the monitoring protocol.", "back": "Despite normal/elevated serum K⁺ at presentation, DKA causes <strong>total body K⁺ depletion</strong> (vomiting, osmotic diuresis, inability to retain K⁺ intracellularly without insulin). Acidosis shifts K⁺ extracellularly, masking the deficit. Insulin therapy: activates Na⁺/K⁺-ATPase → K⁺ rapidly enters cells → serum K⁺ falls precipitously. Protocol: check K⁺ every 2 h; add KCl to IV fluids once K⁺ &lt;5.0; <strong>hold insulin if K⁺ &lt;3.5</strong> until repleted (to prevent life-threatening arrhythmia).<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Phosphate also drops with insulin therapy (enters cells with glucose). If phosphate &lt;1.0 mg/dL or patient has haemolysis/respiratory failure, supplement with potassium phosphate (repletes both K⁺ and PO₄³⁻ simultaneously).</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Never start insulin in DKA without first knowing the K⁺ level. If K⁺ &lt;3.5, giving insulin can precipitate hypokalaemia → VF → death. This is the leading preventable cause of DKA mortality. Glucose-containing fluids (D5W) are NOT used in initial DKA management — use 0.9% NaCl for initial resuscitation.</div>"}, {"id": "endo:fc:7", "deck": "Endocrine", "dk": "endo", "type": "flashcard", "front": "A patient with Cushing's disease awaiting pituitary surgery is prescribed metyrapone. He develops hypertension and acne. Explain both the mechanism and the side effects.", "back": "Metyrapone inhibits <strong>11β-hydroxylase</strong> (CYP11B1) — the final step in cortisol synthesis (11-deoxycortisol → cortisol). Cortisol falls, ACTH rises (pituitary no longer suppressed), and cortisol precursors accumulate. Side effects explained by precursor accumulation: <strong>11-deoxycortisol</strong> has weak glucocorticoid activity; <strong>DHEA and androstenedione</strong> accumulate → androgenic effects (acne, hirsutism, oligomenorrhoea). Precursor mineralocorticoid activity → sodium retention → hypertension.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Metyrapone test: normally the hypothalamic-pituitary axis responds to falling cortisol by secreting more ACTH, raising 11-deoxycortisol. An absent response (low ACTH, low 11-deoxycortisol) implies secondary adrenal insufficiency. Used diagnostically to test the HPA axis integrity.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Ketoconazole (azole antifungal) also inhibits multiple adrenal steroidogenesis enzymes (CYP11A1, CYP17, CYP11B1) → used for Cushing's but limited by hepatotoxicity and extensive CYP3A4 inhibition. Osilodrostat (CYP11B1 inhibitor, newer, more selective) is now preferred over ketoconazole.</div>"}, {"id": "endo:fc:8", "deck": "Endocrine", "dk": "endo", "type": "flashcard", "front": "A patient with primary hypothyroidism is started on levothyroxine. She is also taking ferrous sulphate and calcium carbonate for anaemia and osteoporosis. How should the timing be managed?", "back": "Take levothyroxine on an <strong>empty stomach, 30–60 minutes before any food</strong> and separate from: calcium salts, iron supplements, antacids (Al³⁺/Mg²⁺), cholestyramine, sucralfate, PPIs, and soy products — all reduce levothyroxine absorption by chelation or pH alteration. Separate these by ≥4 hours. Coffee also reduces absorption.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> TSH is the most sensitive monitoring parameter. Aim for TSH 0.5–2.5 mIU/L in most adults; 0.1–1.5 in pregnant women (thyroid hormone critical for foetal neurodevelopment). In subclinical hypothyroidism with TSH 4.5–10, treat if symptomatic, pregnant, or planning pregnancy.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Starting levothyroxine in a patient on warfarin increases thyroid hormone-stimulated clearance of clotting factors → warfarin requirements INCREASE, INR FALLS. Conversely, treating new-onset hypothyroidism in a stable warfarin patient → monitor INR closely and expect to increase warfarin dose.</div>"}, {"id": "endo:fc:9", "deck": "Endocrine", "dk": "endo", "type": "flashcard", "front": "A woman with Addison's disease is admitted in shock with BP 70/40, hyponatraemia (Na⁺ 122), and hyperkalaemia (K⁺ 6.1). What is the immediate management?", "back": "<strong>Addisonian crisis:</strong> acute adrenal insufficiency → deficiency of both cortisol (glucocorticoid) and aldosterone (mineralocorticoid). Immediate treatment: (1) IV <strong>hydrocortisone 100 mg</strong> bolus, then 50–100 mg q6–8h — provides both glucocorticoid and (at high doses) mineralocorticoid activity; (2) <strong>IV 0.9% NaCl</strong> — volume resuscitation + sodium replacement; (3) IV dextrose if hypoglycaemic; (4) Treat hyperkalaemia if K⁺ &gt;6.5 (cardiac risk). Fludrocortisone is not needed acutely (hydrocortisone at stress doses covers mineralocorticoid function).<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Maintenance replacement: hydrocortisone 15–25 mg/day in divided doses (AM-weighted to mimic cortisol diurnal rhythm) + fludrocortisone 50–200 µg/day. Sick day rules: double/triple hydrocortisone dose during illness, injury, or surgery — failure to do so → crisis.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Do NOT delay hydrocortisone while waiting for cortisol or ACTH results in suspected Addisonian crisis. If needed, give dexamethasone 4 mg IV (does not interfere with cortisol assay) → draw cortisol/ACTH → then switch to hydrocortisone. Time is critical.</div>"}, {"id": "endo:fc:10", "deck": "Endocrine", "dk": "endo", "type": "flashcard", "front": "A patient with prostate cancer is started on leuprolide (GnRH agonist) depot injection. His PSA and testosterone initially rise at week 2, worsening bone pain. Explain.", "back": "<strong>Testosterone flare</strong>: continuous GnRH agonist initially stimulates pituitary LH/FSH release ('flare' effect, days 1–14) before causing receptor downregulation → desensitisation → castrate testosterone levels (week 3–4 onwards). The initial testosterone surge can cause disease flare: worsening bone pain, urinary obstruction, spinal cord compression. Prevention: <strong>co-prescribe an anti-androgen</strong> (bicalutamide 50 mg/day) for the first 4 weeks to block AR during the testosterone surge.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> GnRH antagonists (degarelix, relugolix) directly block the GnRH receptor → no initial LH/FSH surge → no testosterone flare → immediate castration levels within 3 days. Preferred over agonists when flare risk is high (impending cord compression, severe bone pain).</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Continuous (non-pulsatile) GnRH agonist = suppression. Pulsatile GnRH (as in physiological secretion) = stimulation. This paradox is the basis of both the therapeutic flare and the ultimate hormonal suppression.</div>"}, {"id": "endo:fc:11", "deck": "Endocrine", "dk": "endo", "type": "flashcard", "front": "Octreotide is prescribed for carcinoid syndrome. Six months later, the patient develops right upper quadrant pain and ultrasound confirms gallstones. Explain the mechanism.", "back": "Octreotide (somatostatin analogue) inhibits <strong>cholecystokinin (CCK)</strong> release and gallbladder smooth muscle contraction → biliary stasis → supersaturation of bile → cholesterol or pigment gallstones in 20–50% of long-term users. Other actions of octreotide: inhibits GH/IGF-1 (acromegaly), serotonin/VIP/substance P (carcinoid/VIPoma), and splanchnic blood flow (variceal bleeding).<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Ursodeoxycholic acid (UDCA) can be given prophylactically during long-term octreotide use to reduce gallstone formation. Lanreotide is a longer-acting somatostatin analogue (monthly depot) with similar efficacy and gallstone risk.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Octreotide improves carcinoid symptoms (flushing, diarrhoea) but does NOT significantly shrink carcinoid tumours. For tumour control, add everolimus (mTOR inhibitor) or sunitinib, or use peptide receptor radionuclide therapy (PRRT) with lutetium-177-DOTATATE.</div>"}, {"id": "endo:fc:12", "deck": "Endocrine", "dk": "endo", "type": "flashcard", "front": "A postmenopausal woman on anastrozole for breast cancer develops wrist and hip fractures after 3 years of therapy. What pharmacological mechanism explains the bone loss?", "back": "Anastrozole (aromatase inhibitor, AI) inhibits CYP19 → blocks peripheral conversion of androgens → oestrogens. In postmenopausal women, peripheral oestrogen production (adrenal androstenedione → oestrone in fat/muscle) is the primary oestrogen source. AI therapy → profound oestrogen deficiency → uncoupled bone remodelling (osteoclasts &gt; osteoblasts) → accelerated bone loss → fractures. AIs cause more bone loss than tamoxifen (which has agonist activity at bone ER).<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> DXA scan before and every 2 years on AI therapy. Prescribe calcium 1200 mg + vitamin D 1000–2000 IU/day to all AI patients. Add bisphosphonate (zoledronic acid, alendronate) or denosumab if T-score ≤ -2.0 or multiple risk factors.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Tamoxifen (SERM) protects bone in postmenopausal women (bone ER agonist) but INCREASES endometrial cancer risk (uterine ER agonist). AIs have NO endometrial cancer risk (no ER stimulation) but worsen bone. Choose AI over tamoxifen in postmenopausal women unless fracture risk is very high.</div>"}, {"id": "endo:fc:13", "deck": "Endocrine", "dk": "endo", "type": "flashcard", "front": "A 70-year-old man is started on teriparatide for severe osteoporosis. His doctor says it can only be given for 2 years. Why is there a time limit?", "back": "Teriparatide (recombinant PTH 1–34) is an <strong>anabolic</strong> bone agent — it stimulates osteoblast proliferation and activity. Animal studies showed dose-dependent <strong>osteosarcoma</strong> in rats with prolonged high-dose exposure. Although not proven in humans, the FDA imposed a 2-year cumulative lifetime limit as a precautionary measure. After stopping teriparatide, bone density rapidly decreases unless followed immediately by an antiresorptive agent (bisphosphonate or denosumab).<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Abaloparatide (PTHrP 1–34 analogue) has the same anabolic mechanism and 2-year limit, with possibly less hypercalcaemia than teriparatide. Romosozumab (anti-sclerostin antibody) — dual anabolic + antiresorptive, 12-month course, but has a cardiovascular safety signal (not in patients with recent MI/stroke).</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Teriparatide is contraindicated in: Paget's disease of bone, prior bone radiation therapy, hypercalcaemia, and paediatric patients (open epiphyses — risk of bone tumours). Do NOT combine with bisphosphonates during teriparatide therapy (bisphosphonates blunt the anabolic response).</div>"}, {"id": "endo:fc:14", "deck": "Endocrine", "dk": "endo", "type": "flashcard", "front": "A patient with type 1 DM uses insulin glargine at night and insulin aspart before meals. She is prescribed propranolol for her new diagnosis of essential tremor. What risk does the beta-blocker introduce?", "back": "Propranolol (non-selective β-blocker) masks the <strong>adrenergic symptoms of hypoglycaemia</strong>: tachycardia, palpitations, tremor — the early warning signs. The patient may not recognise she is hypoglycaemic until she is confused or loses consciousness. Additionally, β-blockade impairs <strong>glycogenolysis</strong> (hepatic glucose release) → prolongs hypoglycaemic episodes. Diaphoresis (sweating) is a parasympathetic-mediated sign — NOT masked by beta-blockers — but this alone is insufficient warning.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> If a beta-blocker is needed in a diabetic patient on insulin, prefer a <strong>cardioselective beta-blocker</strong> (bisoprolol, metoprolol) — β1 selectivity is somewhat less likely to mask glucagon-mediated recovery, but still masks adrenergic warning symptoms. Counsel all insulin patients on this risk.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Beta-blockers do NOT cause hypoglycaemia — they only mask and prolong it. The hypoglycaemia is caused by too much insulin. Diaphoresis is preserved as a warning sign (mediated by sympathetic cholinergic fibres to sweat glands, not β-adrenoceptors).</div>"}, {"id": "endo:fc:15", "deck": "Endocrine", "dk": "endo", "type": "flashcard", "front": "Radioactive iodine (¹³¹I) is given for Graves' disease. The patient calls 3 days later with sore throat and neck pain. Eight months later she is hypothyroid. Are either of these expected?", "back": "<strong>Day 3 symptoms:</strong> Radiation thyroiditis — ¹³¹I damages thyroid tissue → acute inflammatory response → sore throat, neck tenderness, transient worsening of hyperthyroidism (hormone release from damaged follicles). Usually self-limiting; treat with NSAIDs or prednisolone if severe. <strong>Month 8:</strong> Permanent hypothyroidism is the <em>intended</em> outcome of ¹³¹I therapy — occurs in ~80% within 10 years. Replace with levothyroxine lifelong.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> ¹³¹I is absolutely contraindicated in pregnancy (crosses placenta → foetal thyroid ablation) and breastfeeding. It is also avoided in active, moderate-to-severe Graves' ophthalmopathy (TED) — can worsen eye disease; give oral glucocorticoids if ¹³¹I must be used.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Pre-treat with methimazole to render the patient euthyroid before ¹³¹I (especially elderly and cardiac patients) — prevents post-ablation thyroid storm from radiation-induced hormone release. Stop methimazole 3–5 days before ¹³¹I (it reduces iodine uptake).</div>"}, {"id": "endo:fc:16", "deck": "Endocrine", "dk": "endo", "type": "flashcard", "front": "A patient with PCOS presents with irregular cycles and infertility. She declines OCP. What pharmacological options address both the metabolic and reproductive aspects?", "back": "<strong>Metformin:</strong> reduces insulin resistance → lowers androgens (reduces ovarian androgen overproduction driven by hyperinsulinaemia) → may restore ovulatory cycles; first-line for metabolic management of PCOS. <strong>Clomiphene (clomifene):</strong> SERM — blocks oestrogen receptors in hypothalamus → perceived oestrogen deficiency → increased GnRH → LH/FSH surge → ovulation induction; first-line for ovulation induction. <strong>Letrozole</strong> (aromatase inhibitor): now preferred over clomiphene for ovulation induction in PCOS (higher live birth rates per PPCOS-II trial).<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Spironolactone (anti-androgen via aldosterone receptor block + CYP17 inhibition) is added for hirsutism and acne in PCOS. Must use contraception with spironolactone in women of childbearing age — it feminises a male foetus.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Do NOT use clomiphene beyond 6 cycles (increased risk of ovarian cancer with prolonged use). Monitor for ovarian hyperstimulation syndrome (OHSS) during induction cycles — abdominal bloating, ascites, haemoconcentration.</div>"}, {"id": "endo:fc:17", "deck": "Endocrine", "dk": "endo", "type": "flashcard", "front": "Desmopressin (DDAVP) is prescribed for central diabetes insipidus. A patient with nephrogenic DI is mistakenly given the same drug. Why will it fail?", "back": "<strong>Central DI</strong>: ADH deficiency (hypothalamic/pituitary damage). Desmopressin = synthetic ADH V2 receptor agonist → activates renal collecting duct V2 receptors → aquaporin-2 insertion → water reabsorption. Works because the kidney's receptor and response machinery is intact. <strong>Nephrogenic DI</strong>: the kidney <em>cannot respond</em> to ADH (V2 receptor or aquaporin mutations, lithium toxicity, hypercalcaemia, CKD) → desmopressin is ineffective. Treat nephrogenic DI with: thiazide diuretics (paradoxically reduce free water excretion via volume depletion), amiloride (if lithium-induced), low-sodium diet.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Desmopressin also stimulates von Willebrand factor (vWF) release from endothelium (V2 effect) and factor VIII release → used for mild haemophilia A, type 1 von Willebrand disease, and platelet disorders.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Desmopressin can cause severe <strong>hyponatraemia</strong> (dilutional) if patients drink excessive water while on the drug — common in children given desmopressin for nocturnal enuresis. Monitor Na⁺; restrict fluid intake after dosing.</div>"}, {"id": "endo:fc:18", "deck": "Endocrine", "dk": "endo", "type": "flashcard", "front": "A 28-year-old woman is prescribed isotretinoin for severe cystic acne. What monitoring programme is mandated, and what is the teratogenic mechanism?", "back": "Isotretinoin (13-cis-retinoic acid) is a vitamin A (retinol) derivative — activates retinoic acid receptors (RAR) → regulates gene expression critical for cell differentiation and apoptosis in sebaceous glands. Profound teratogenicity: retinoic acid signalling is essential for normal embryonic development; excess → craniofacial defects, CNS malformations, cardiac defects, thymic aplasia. <strong>iPLEDGE programme</strong> (USA): mandatory monthly pregnancy testing, two forms of contraception, prescriber/pharmacy registration, monthly dispensing limits.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Side effects (all reversible except potential teratogenicity): mucocutaneous dryness (cheilitis, epistaxis, xerosis), elevated triglycerides, transient LFT rise, joint/muscle pain, and potential psychiatric effects (depression — monitor, though causality debated).</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Vitamin A supplementation at doses &gt;10,000 IU/day in pregnancy also causes identical birth defects — the same RAR-mediated mechanism. This is why pregnant women are advised to avoid high-dose vitamin A supplements and liver (very high in retinol).</div>"}, {"id": "endo:fc:19", "deck": "Endocrine", "dk": "endo", "type": "flashcard", "front": "Bisphosphonates are prescribed for osteoporosis. After 7 years, a patient develops a mid-shaft femur fracture from a minimal fall. X-ray shows a transverse fracture with cortical thickening. What is the diagnosis, and why does it occur?", "back": "<strong>Atypical femoral fracture (AFF)</strong> — a rare but recognised complication of long-term bisphosphonate therapy (&gt;5 years). Bisphosphonates inhibit osteoclast farnesyl pyrophosphate synthase (mevalonate pathway) → impaired osteoclast activity → suppressed bone turnover. Prolonged suppression prevents normal micro-crack repair (normally osteoclasts resorb damaged bone) → fatigue fractures accumulate → spontaneous transverse fracture at mid-shaft (not osteoporotic compression fracture). Risk increases with &gt;5 years of use.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> AFF is often bilateral (30–40%) and preceded by prodromal thigh or groin pain ('stress reaction' visible on MRI before fracture). A 'drug holiday' after 5 years in lower-risk patients reduces AFF risk while preserving fracture protection (bisphosphonate is stored in bone mineral and continues to be released slowly).</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Also monitor for osteonecrosis of the jaw (ONJ): especially with IV bisphosphonates (zoledronic acid) used for malignancy. Risk factors: dental extraction, poor oral hygiene, corticosteroid use, chemotherapy. ONJ presents as exposed non-healing bone in the jaw. Dental clearance before starting IV bisphosphonates.</div>"}, {"id": "endo:q:0", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "First-line oral drug for type 2 diabetes?", "back": "Metformin."}, {"id": "endo:q:1", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Mechanism of metformin?", "back": "↓ hepatic gluconeogenesis and ↑ peripheral insulin sensitivity."}, {"id": "endo:q:2", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Does metformin cause hypoglycaemia?", "back": "No (when used alone)."}, {"id": "endo:q:3", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Most serious adverse effect of metformin?", "back": "Lactic acidosis (esp. in renal impairment/hypoxia)."}, {"id": "endo:q:4", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "When should metformin be withheld around imaging?", "back": "Before iodinated contrast (and in significant renal impairment)."}, {"id": "endo:q:5", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Mechanism of sulfonylureas?", "back": "Close the β-cell K⁺-ATP channel → depolarisation → insulin release."}, {"id": "endo:q:6", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Why do sulfonylureas cause hypoglycaemia?", "back": "They stimulate insulin release independent of the prevailing glucose level."}, {"id": "endo:q:7", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Give two sulfonylureas.", "back": "Glimepiride, gliclazide (or glipizide)."}, {"id": "endo:q:8", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "How do meglitinides differ from sulfonylureas?", "back": "Same channel target but short-acting — taken with meals for post-prandial control."}, {"id": "endo:q:9", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Mechanism of thiazolidinediones (e.g. pioglitazone)?", "back": "PPAR-γ agonist → ↑ insulin sensitivity."}, {"id": "endo:q:10", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Major adverse effects of pioglitazone?", "back": "Fluid retention (worsens heart failure), weight gain, fractures, bladder-cancer signal."}, {"id": "endo:q:11", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "What do DPP-4 inhibitors do?", "back": "Inhibit DPP-4 → prolong endogenous incretin (GLP-1) → glucose-dependent insulin."}, {"id": "endo:q:12", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Give a DPP-4 inhibitor.", "back": "Sitagliptin (vildagliptin, linagliptin)."}, {"id": "endo:q:13", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Mechanism of GLP-1 receptor agonists?", "back": "Incretin mimetic: ↑ glucose-dependent insulin, ↓ glucagon, slow gastric emptying, ↓ appetite."}, {"id": "endo:q:14", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Give two GLP-1 receptor agonists.", "back": "Semaglutide, liraglutide (dulaglutide, exenatide)."}, {"id": "endo:q:15", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Two major benefits of GLP-1 agonists beyond glucose?", "back": "Weight loss and cardiovascular benefit."}, {"id": "endo:q:16", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Main side effect of GLP-1 agonists?", "back": "Nausea/GI upset."}, {"id": "endo:q:17", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Contraindication to GLP-1 agonists?", "back": "Personal/family history of medullary thyroid carcinoma or MEN2."}, {"id": "endo:q:18", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Mechanism of SGLT2 inhibitors?", "back": "Block renal proximal-tubule glucose reabsorption → glycosuria."}, {"id": "endo:q:19", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Give two SGLT2 inhibitors.", "back": "Dapagliflozin, empagliflozin."}, {"id": "endo:q:20", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Three organ benefits of SGLT2 inhibitors?", "back": "Cardiovascular, renal, and heart-failure benefit."}, {"id": "endo:q:21", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Characteristic adverse effects of SGLT2 inhibitors?", "back": "Genital mycotic infections, volume depletion, euglycaemic DKA."}, {"id": "endo:q:22", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Mechanism of acarbose?", "back": "α-glucosidase inhibition → ↓ intestinal carbohydrate breakdown/absorption."}, {"id": "endo:q:23", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Main side effect of acarbose?", "back": "Flatulence/GI symptoms."}, {"id": "endo:q:24", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Which insulin is used IV in DKA?", "back": "Regular (short-acting) insulin."}, {"id": "endo:q:25", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Name the rapid-acting insulins.", "back": "Lispro, aspart, glulisine."}, {"id": "endo:q:26", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Name the long-acting (basal) insulins.", "back": "Glargine, detemir, degludec."}, {"id": "endo:q:27", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "What is a basal-bolus regimen?", "back": "Long-acting basal insulin + rapid-acting boluses at meals."}, {"id": "endo:q:28", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Which two non-insulin classes cause weight gain?", "back": "Sulfonylureas and thiazolidinediones."}, {"id": "endo:q:29", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Which classes are weight-neutral or cause weight loss?", "back": "Metformin (neutral/loss), DPP-4 (neutral), GLP-1 RA and SGLT2 (loss)."}, {"id": "endo:q:30", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Why is an SGLT2 inhibitor especially relevant in heart failure?", "back": "It reduces heart-failure hospitalisation and is used even in non-diabetics for HF."}, {"id": "endo:q:31", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Type 1 diabetes — mainstay of treatment?", "back": "Exogenous insulin (always required)."}, {"id": "endo:q:32", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Drug of choice for hypothyroidism?", "back": "Levothyroxine (T₄)."}, {"id": "endo:q:33", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Why use T₄ rather than active T₃ for replacement?", "back": "Long, stable half-life; converted peripherally to T₃ as needed."}, {"id": "endo:q:34", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "What lab value do you titrate levothyroxine to?", "back": "TSH."}, {"id": "endo:q:35", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "How should levothyroxine be taken?", "back": "On an empty stomach; separate from calcium, iron, PPIs."}, {"id": "endo:q:36", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Two thionamide antithyroid drugs?", "back": "Methimazole (carbimazole) and propylthiouracil (PTU)."}, {"id": "endo:q:37", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Mechanism of thionamides?", "back": "Inhibit thyroid peroxidase → block organification of iodide."}, {"id": "endo:q:38", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Extra action of PTU beyond synthesis?", "back": "Blocks peripheral conversion of T₄ to T₃."}, {"id": "endo:q:39", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Most feared haematological toxicity of thionamides?", "back": "Agranulocytosis."}, {"id": "endo:q:40", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "What symptom should prompt a patient on a thionamide to stop and get an FBC?", "back": "Sore throat with fever."}, {"id": "endo:q:41", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Preferred thionamide in the first trimester of pregnancy, and why?", "back": "PTU — methimazole is teratogenic (aplasia cutis, embryopathy)."}, {"id": "endo:q:42", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Preferred thionamide after the first trimester?", "back": "Methimazole/carbimazole."}, {"id": "endo:q:43", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Role of β-blockers in hyperthyroidism?", "back": "Rapid control of adrenergic symptoms (tremor, tachycardia); propranolol also ↓ T₄→T₃."}, {"id": "endo:q:44", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Definitive treatment that ablates the thyroid?", "back": "Radioactive iodine (¹³¹I)."}, {"id": "endo:q:45", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Common outcome after radioiodine?", "back": "Hypothyroidism (then replace with levothyroxine)."}, {"id": "endo:q:46", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Effect of high-dose iodide on the thyroid?", "back": "Transiently inhibits hormone release (Wolff-Chaikoff effect)."}, {"id": "endo:q:47", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Use of high-dose iodide (Lugol's)?", "back": "Pre-operative preparation and thyroid storm."}, {"id": "endo:q:48", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Why must iodide be timed carefully relative to radioiodine?", "back": "Iodide blocks radioiodine uptake by the gland."}, {"id": "endo:q:49", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Consequence of over-replacement with levothyroxine?", "back": "Iatrogenic hyperthyroidism — atrial fibrillation, osteoporosis."}, {"id": "endo:q:50", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Which thionamide is preferred in thyroid storm?", "back": "PTU (blocks synthesis and peripheral conversion)."}, {"id": "endo:q:51", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Which receptor type does thyroid hormone act on?", "back": "Nuclear (intracellular) receptors altering gene transcription."}, {"id": "endo:q:52", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "What feedback hormone rises in primary hypothyroidism?", "back": "TSH (raised)."}, {"id": "endo:q:53", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Two drugs that reduce peripheral T₄→T₃ conversion?", "back": "PTU and propranolol (also glucocorticoids)."}, {"id": "endo:q:54", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Three steroid families of the adrenal cortex (outer to inner)?", "back": "Mineralocorticoids, glucocorticoids, androgens (salt, sugar, sex)."}, {"id": "endo:q:55", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Main mineralocorticoid and its action?", "back": "Aldosterone — Na⁺/water retention, K⁺ excretion."}, {"id": "endo:q:56", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Main glucocorticoid?", "back": "Cortisol."}, {"id": "endo:q:57", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Reference glucocorticoid with significant mineralocorticoid activity?", "back": "Hydrocortisone."}, {"id": "endo:q:58", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Most commonly used oral anti-inflammatory glucocorticoid?", "back": "Prednisolone."}, {"id": "endo:q:59", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Potent glucocorticoid with negligible mineralocorticoid effect?", "back": "Dexamethasone."}, {"id": "endo:q:60", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Drug used for pure mineralocorticoid replacement?", "back": "Fludrocortisone."}, {"id": "endo:q:61", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Why do chronic glucocorticoids cause hyperglycaemia?", "back": "They increase gluconeogenesis (and insulin resistance)."}, {"id": "endo:q:62", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Why do they cause muscle wasting and thin skin?", "back": "Protein catabolism."}, {"id": "endo:q:63", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Classic fat-redistribution features?", "back": "Moon face, buffalo hump, central obesity (Cushingoid)."}, {"id": "endo:q:64", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Why do glucocorticoids raise infection risk?", "back": "Immunosuppression."}, {"id": "endo:q:65", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Major skeletal complication of long-term steroids?", "back": "Osteoporosis (also avascular necrosis)."}, {"id": "endo:q:66", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Why can steroids cause hypertension and hypokalaemia?", "back": "Mineralocorticoid activity → Na⁺/water retention, K⁺ loss."}, {"id": "endo:q:67", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Why must chronic glucocorticoids never be stopped abruptly?", "back": "HPA-axis suppression causes adrenal atrophy → risk of adrenal crisis."}, {"id": "endo:q:68", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "How are chronic glucocorticoids discontinued?", "back": "Gradual taper to let the HPA axis recover."}, {"id": "endo:q:69", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "What do patients on long-term steroids need during surgery/illness?", "back": "Stress-dose (increased) glucocorticoid cover."}, {"id": "endo:q:70", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Where in the inflammatory cascade do glucocorticoids act?", "back": "Upstream, inhibiting phospholipase A₂ (via annexin-1) — both COX and LOX branches."}, {"id": "endo:q:71", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Why is this broader than an NSAID's effect?", "back": "NSAIDs block only the COX branch; steroids block the whole cascade."}, {"id": "endo:q:72", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Ophthalmic risks of chronic steroids?", "back": "Cataracts and glaucoma."}, {"id": "endo:q:73", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Effect of glucocorticoids on children's growth?", "back": "Growth suppression."}, {"id": "endo:q:74", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "GI risk when combined with NSAIDs?", "back": "Peptic ulceration/bleeding."}, {"id": "endo:q:75", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Why are most steroid 'side effects' just physiology in excess?", "back": "They are the normal stress/cortisol actions amplified by supraphysiologic dosing."}, {"id": "endo:q:76", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Three hormonal regulators of serum calcium?", "back": "PTH, vitamin D (calcitriol), calcitonin."}, {"id": "endo:q:77", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Net effect of PTH on calcium?", "back": "Raises serum calcium."}, {"id": "endo:q:78", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Net effect of calcitonin?", "back": "Lowers serum calcium (inhibits osteoclasts)."}, {"id": "endo:q:79", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Action of active vitamin D?", "back": "↑ intestinal calcium and phosphate absorption."}, {"id": "endo:q:80", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "First-line drug class for osteoporosis?", "back": "Bisphosphonates."}, {"id": "endo:q:81", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Mechanism of bisphosphonates?", "back": "Inhibit osteoclasts → reduce bone resorption (antiresorptive)."}, {"id": "endo:q:82", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Give two bisphosphonates.", "back": "Alendronate, zoledronate (risedronate)."}, {"id": "endo:q:83", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "How must oral bisphosphonates be taken?", "back": "Upright, empty stomach, full glass of water, stay upright ~30 min."}, {"id": "endo:q:84", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Why those instructions?", "back": "To prevent oesophagitis/oesophageal injury."}, {"id": "endo:q:85", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Two rare but classic bisphosphonate toxicities?", "back": "Osteonecrosis of the jaw and atypical femoral fractures."}, {"id": "endo:q:86", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Mechanism of denosumab?", "back": "Monoclonal antibody against RANKL → blocks osteoclast formation (antiresorptive)."}, {"id": "endo:q:87", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Key danger of stopping denosumab?", "back": "Rebound increase in vertebral fractures — needs follow-on therapy."}, {"id": "endo:q:88", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Which SERM is used as an antiresorptive in osteoporosis?", "back": "Raloxifene."}, {"id": "endo:q:89", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Mechanism of teriparatide?", "back": "PTH analogue given intermittently → anabolic (builds bone)."}, {"id": "endo:q:90", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "The PTH paradox?", "back": "Continuous PTH causes resorption; intermittent PTH builds bone."}, {"id": "endo:q:91", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Mechanism of romosozumab?", "back": "Anti-sclerostin antibody → stimulates bone formation (anabolic)."}, {"id": "endo:q:92", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "What must be co-prescribed with osteoporosis drugs?", "back": "Calcium and vitamin D."}, {"id": "endo:q:93", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "What must be corrected before starting an antiresorptive?", "back": "Vitamin D/calcium deficiency (risk of hypocalcaemia)."}, {"id": "endo:q:94", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Antiresorptive vs anabolic — the conceptual split?", "back": "Antiresorptives slow bone breakdown; anabolics stimulate new bone formation."}, {"id": "endo:q:95", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "A common cause of secondary osteoporosis (drug)?", "back": "Long-term glucocorticoids."}, {"id": "endo:q:96", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Limit on teriparatide duration — why?", "back": "Osteosarcoma signal in animals."}, {"id": "endo:q:97", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Why does denosumab not linger in bone like a bisphosphonate?", "back": "It is a circulating antibody, not incorporated into bone matrix — hence rebound on stopping."}, {"id": "endo:q:98", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Core mechanism of combined oral contraceptives?", "back": "Suppress the HPA-gonadal axis (↓FSH/LH) → no ovulation."}, {"id": "endo:q:99", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Additional contraceptive effect of progestin?", "back": "Thickens cervical mucus, thins endometrium."}, {"id": "endo:q:100", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "When is a progestin-only method preferred?", "back": "When estrogen is contraindicated (e.g. VTE risk, breast feeding, smokers &gt;35)."}, {"id": "endo:q:101", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "What does SERM stand for?", "back": "Selective Estrogen Receptor Modulator."}, {"id": "endo:q:102", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Tamoxifen's effect in breast tissue?", "back": "Estrogen antagonist (treats ER-positive breast cancer)."}, {"id": "endo:q:103", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Tamoxifen's effect on the endometrium?", "back": "Agonist — increases endometrial cancer risk."}, {"id": "endo:q:104", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Tamoxifen's effect on bone?", "back": "Agonist (protective)."}, {"id": "endo:q:105", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Raloxifene's effect on the endometrium?", "back": "Neutral (no increased cancer risk)."}, {"id": "endo:q:106", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Main therapeutic use of raloxifene?", "back": "Osteoporosis (and breast-cancer risk reduction)."}, {"id": "endo:q:107", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Mechanism of aromatase inhibitors?", "back": "Block conversion of androgens to estrogen → ↓ estrogen synthesis."}, {"id": "endo:q:108", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Give two aromatase inhibitors.", "back": "Anastrozole, letrozole."}, {"id": "endo:q:109", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Main population for aromatase inhibitors?", "back": "Postmenopausal women with ER-positive breast cancer."}, {"id": "endo:q:110", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Major skeletal side effect of aromatase inhibitors?", "back": "Osteoporosis (estrogen removed)."}, {"id": "endo:q:111", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Mechanism of mifepristone?", "back": "Progesterone-receptor antagonist."}, {"id": "endo:q:112", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Major vascular risk of estrogen-containing products?", "back": "Venous thromboembolism."}, {"id": "endo:q:113", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Who should avoid estrogen-containing contraception?", "back": "Smokers &gt;35, prior VTE, migraine with aura."}, {"id": "endo:q:114", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Why does a SERM act differently in different tissues?", "back": "Tissue-specific co-regulator expression determines agonist vs antagonist effect."}, {"id": "endo:q:115", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Two cancers/risks associated with tamoxifen?", "back": "Endometrial cancer and VTE."}, {"id": "endo:q:116", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "How do enzyme inducers affect the pill?", "back": "They increase estrogen/progestin metabolism → reduce contraceptive efficacy."}, {"id": "endo:q:117", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Name an enzyme inducer that can cause contraceptive failure.", "back": "Rifampicin (also some anticonvulsants)."}, {"id": "endo:q:118", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "What does the LH surge normally trigger, and what blocks it on the pill?", "back": "Ovulation; suppressed FSH/LH from negative feedback prevents the surge."}, {"id": "endo:q:119", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Estrogen's effect on bone density?", "back": "Maintains/increases it (protective against osteoporosis)."}, {"id": "endo:q:120", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "The three-tier structure of an endocrine axis?", "back": "Hypothalamus → pituitary → target gland."}, {"id": "endo:q:121", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "What stabilises the axis?", "back": "Negative feedback from the target-gland hormone."}, {"id": "endo:q:122", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Drug for growth-hormone deficiency?", "back": "Somatropin (recombinant GH)."}, {"id": "endo:q:123", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Drugs for acromegaly (GH excess)?", "back": "Octreotide (somatostatin analogue), pegvisomant, cabergoline."}, {"id": "endo:q:124", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "What is octreotide?", "back": "A somatostatin analogue that suppresses GH (and other hormones)."}, {"id": "endo:q:125", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "What is pegvisomant?", "back": "A GH-receptor antagonist."}, {"id": "endo:q:126", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Does dopamine stimulate or inhibit prolactin?", "back": "Inhibits prolactin release."}, {"id": "endo:q:127", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Drug class for hyperprolactinaemia/prolactinoma?", "back": "Dopamine agonists (cabergoline, bromocriptine)."}, {"id": "endo:q:128", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Why do dopamine-blocking antipsychotics cause galactorrhoea?", "back": "Loss of dopamine inhibition → rising prolactin."}, {"id": "endo:q:129", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Effect of pulsatile GnRH?", "back": "Stimulates gonadotropin release."}, {"id": "endo:q:130", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Effect of continuous GnRH (analogue)?", "back": "Desensitises receptors → suppresses the gonadal axis."}, {"id": "endo:q:131", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Give a GnRH analogue.", "back": "Leuprolide (goserelin)."}, {"id": "endo:q:132", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Clinical use of continuous GnRH analogues?", "back": "Prostate cancer, endometriosis, central precocious puberty."}, {"id": "endo:q:133", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "What is the initial 'flare' with GnRH analogues?", "back": "A transient rise in sex hormones before suppression."}, {"id": "endo:q:134", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "How is the flare managed in prostate cancer?", "back": "Co-administer an anti-androgen initially."}, {"id": "endo:q:135", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Drug for central diabetes insipidus?", "back": "Desmopressin (ADH/vasopressin analogue)."}, {"id": "endo:q:136", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Other use of desmopressin?", "back": "Nocturnal enuresis (bed-wetting); some bleeding disorders."}, {"id": "endo:q:137", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Main risk of desmopressin?", "back": "Hyponatraemia (water retention)."}, {"id": "endo:q:138", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Hormone used to induce/augment labour?", "back": "Oxytocin."}, {"id": "endo:q:139", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Side effects of dopamine agonists like cabergoline?", "back": "Nausea, postural hypotension, rare valvulopathy, impulse-control disorders."}, {"id": "endo:q:140", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Why does exogenous hormone shut off the axis?", "back": "Negative feedback suppresses hypothalamic/pituitary output."}, {"id": "endo:q:141", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Which earlier modules rely on this feedback principle?", "back": "Thyroid (TSH titration), adrenal (steroid taper), contraception."}, {"id": "endo:q:142", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "What hypothalamic factor stimulates ACTH release?", "back": "CRH (corticotropin-releasing hormone)."}, {"id": "endo:q:143", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Drug for male hypogonadism?", "back": "Testosterone (gel, patch, IM)."}, {"id": "endo:q:144", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Why is oral testosterone problematic?", "back": "Extensive hepatic first-pass metabolism."}, {"id": "endo:q:145", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Enzyme converting testosterone to DHT?", "back": "5α-reductase."}, {"id": "endo:q:146", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Mechanism of finasteride?", "back": "5α-reductase inhibitor → ↓ DHT."}, {"id": "endo:q:147", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Two uses of finasteride?", "back": "Benign prostatic hyperplasia and male-pattern baldness."}, {"id": "endo:q:148", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Why does one drug treat both prostate and scalp?", "back": "Both are DHT-driven; reducing DHT helps both."}, {"id": "endo:q:149", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Difference between finasteride and dutasteride?", "back": "Dutasteride inhibits both 5α-reductase isoenzymes (more complete)."}, {"id": "endo:q:150", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Mechanism of flutamide/bicalutamide?", "back": "Androgen-receptor antagonists."}, {"id": "endo:q:151", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Main use of androgen-receptor antagonists?", "back": "Prostate cancer."}, {"id": "endo:q:152", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Three levels at which androgen action can be blocked?", "back": "Central synthesis (GnRH analogue), DHT conversion (finasteride), receptor (bicalutamide)."}, {"id": "endo:q:153", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Mechanism of abiraterone?", "back": "Inhibits androgen synthesis (CYP17) — used in prostate cancer."}, {"id": "endo:q:154", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Why combine a GnRH analogue with an anti-androgen initially?", "back": "To cover the testosterone flare from the GnRH analogue."}, {"id": "endo:q:155", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Key teratogenic warning for finasteride?", "back": "Pregnant women must not handle crushed/broken tablets (risk to male fetus)."}, {"id": "endo:q:156", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Effect of finasteride on PSA?", "back": "Lowers it — interpret prostate cancer screening accordingly."}, {"id": "endo:q:157", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Why is testosterone contraindicated in prostate cancer?", "back": "It can stimulate androgen-dependent tumour growth."}, {"id": "endo:q:158", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Consequences of anabolic-steroid abuse?", "back": "Suppressed spermatogenesis, cardiovascular and hepatic toxicity, mood effects."}, {"id": "endo:q:159", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "How does exogenous androgen suppress sperm production?", "back": "Negative feedback ↓ LH/FSH → ↓ testicular function."}, {"id": "endo:q:160", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Which hormone does 5α-reductase produce in the prostate?", "back": "Dihydrotestosterone (DHT)."}, {"id": "endo:q:161", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "GnRH analogue example used in prostate cancer?", "back": "Leuprolide (goserelin)."}, {"id": "endo:q:162", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Why is DHT more relevant than testosterone in BPH?", "back": "DHT is the more potent androgen acting on prostate growth."}, {"id": "endo:q:163", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Is the GnRH suppression principle the same in men and women?", "back": "Yes — continuous GnRH suppresses the gonadal axis in both sexes."}, {"id": "endo:q:164", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Ketoconazole's relevance to androgens?", "back": "At high dose it inhibits steroid (androgen) synthesis enzymes."}, {"id": "gi:fc:0", "deck": "Gastrointestinal", "dk": "gi", "type": "flashcard", "front": "A 62-year-old man on long-term omeprazole for GERD sustains a hip fracture after a minor fall. What is the pharmacological link between his PPI and bone loss?", "back": "Long-term PPI use causes <strong>hypochlorhydria</strong> → impaired ionisation and absorption of calcium carbonate (requires acid for dissolution; calcium citrate does not). Additionally, PPIs may inhibit osteoclast vacuolar H⁺-ATPase, disrupting bone remodelling. Net result: reduced bone mineral density and increased fracture risk, especially hip, spine, and wrist with &gt;1 year of continuous use.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Use the lowest effective PPI dose for the shortest duration. If long-term PPI is unavoidable, supplement with <strong>calcium citrate</strong> (acid-independent absorption) and vitamin D rather than calcium carbonate.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> PPIs also cause <strong>hypomagnesaemia</strong> by impairing intestinal Mg²⁺ absorption — can present as refractory hypokalaemia or hyponatraemia (Mg²⁺ depletion impairs K⁺ and Na⁺ regulation). Check Mg²⁺ in long-term PPI patients with arrhythmias or muscle cramps.</div>"}, {"id": "gi:fc:1", "deck": "Gastrointestinal", "dk": "gi", "type": "flashcard", "front": "H. pylori triple therapy (amoxicillin + clarithromycin + PPI × 14 days) fails. Urea breath test remains positive. What is the most likely cause, and what is the next regimen?", "back": "<strong>Clarithromycin resistance</strong> — now 15–40% in many countries, the leading cause of triple therapy failure. Next regimen: <strong>bismuth quadruple therapy</strong> (PPI + bismuth subcitrate + tetracycline + metronidazole × 14 days) — does not rely on clarithromycin. Alternatively, levofloxacin-based triple therapy. Culture and susceptibility testing should guide retreatment when available.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> The urea breath test and stool antigen test are the preferred non-invasive tests for confirming eradication — perform at least 4 weeks after completing antibiotics and 2 weeks after stopping PPI (PPIs suppress H. pylori without eradicating, giving false-negative results).</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Serology (IgG anti-H. pylori antibodies) remains positive for years after eradication — do NOT use serology to confirm cure. Use urea breath test or stool antigen test only.</div>"}, {"id": "gi:fc:2", "deck": "Gastrointestinal", "dk": "gi", "type": "flashcard", "front": "A 32-year-old pregnant woman (12 weeks) with an NSAID-induced gastric ulcer is considered for misoprostol therapy. Why is this absolutely contraindicated?", "back": "Misoprostol is a <strong>PGE1 analogue</strong> that replaces the cytoprotective prostaglandins depleted by NSAID-mediated COX-1 inhibition → protects gastric mucosa. However, PGE1 stimulates <strong>uterine smooth muscle contraction</strong> → uterotonic effect → risk of miscarriage, preterm labour, or uterine rupture. Misoprostol is used therapeutically for medical abortion (with mifepristone) and cervical ripening — thus absolutely contraindicated in ongoing pregnancy for GI indications.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> For NSAID-induced ulcer prophylaxis in pregnancy: use a PPI (omeprazole — Category C, generally considered safe) or switch to paracetamol (acetaminophen). Sucralfate is also safe (minimal systemic absorption).</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Misoprostol IS used intentionally in obstetrics: ripening the cervix before induction of labour, management of postpartum haemorrhage (uterotonic), and missed/incomplete miscarriage — the same uterotonic property that makes it dangerous in early pregnancy is therapeutic in these contexts.</div>"}, {"id": "gi:fc:3", "deck": "Gastrointestinal", "dk": "gi", "type": "flashcard", "front": "An oncology patient develops nausea and vomiting within 2 hours of cisplatin infusion (acute phase) and again on day 3 (delayed phase). What antiemetic targets each phase?", "back": "<strong>Acute phase (0–24 h):</strong> primarily serotonin-mediated — enterochromaffin cells release 5-HT₃ in response to cisplatin → vagal afferent activation → vomiting centre. Target: <strong>5-HT₃ antagonists</strong> (ondansetron, granisetron). <strong>Delayed phase (24–120 h):</strong> primarily substance P/neurokinin-1 mediated. Target: <strong>NK1 antagonists</strong> (aprepitant, fosaprepitant). Both phases benefit from <strong>dexamethasone</strong> (enhances efficacy via unknown mechanism). Triple therapy (5-HT₃ + NK1 + dexamethasone) is standard for highly emetogenic chemotherapy.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Palonosetron (second-generation 5-HT₃ antagonist, t½ ~40 h) has superior activity against delayed emesis compared to ondansetron — it allosterically blocks 5-HT₃ receptors and inhibits SP/NK1 crosstalk signalling.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> <strong>Anticipatory emesis</strong> (before chemotherapy, conditioned response from prior cycles) does NOT respond to 5-HT₃ or NK1 antagonists — it requires <strong>benzodiazepines</strong> (lorazepam) for anxiolysis and behavioural conditioning therapy.</div>"}, {"id": "gi:fc:4", "deck": "Gastrointestinal", "dk": "gi", "type": "flashcard", "front": "A 38-year-old woman with gastroparesis takes metoclopramide for 8 months. She develops involuntary repetitive lip-smacking and tongue protrusion that persists after stopping the drug. What has happened?", "back": "<strong>Tardive dyskinesia (TD)</strong> — caused by chronic central D2 receptor blockade (metoclopramide crosses the BBB). Prolonged D2 blockade → dopamine receptor supersensitivity/upregulation in the nigrostriatal pathway → involuntary stereotyped orofacial movements. May be <strong>irreversible</strong>. FDA black-box warning: metoclopramide should not be used for &gt;12 weeks. Risk is higher in elderly patients and women.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> <strong>Domperidone</strong> is a D2 antagonist that does NOT cross the BBB — effective prokinetic without central extrapyramidal/TD risk. Available in most countries but not FDA-approved in the USA. Preferred over metoclopramide for long-term gastroparesis management.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Acute dystonic reactions (oculogyric crisis, torticollis, jaw spasm) can occur within hours of starting metoclopramide — these are REVERSIBLE and treated with IV diphenhydramine or benztropine. Do not confuse with tardive dyskinesia (weeks–months of exposure, often irreversible).</div>"}, {"id": "gi:fc:5", "deck": "Gastrointestinal", "dk": "gi", "type": "flashcard", "front": "A patient with Crohn's disease on azathioprine develops severe pancytopenia. TPMT genotyping reveals he is a poor metaboliser. Explain the pathway.", "back": "Azathioprine → 6-mercaptopurine (6-MP) → via HPRT → 6-thioguanine nucleotides (6-TGNs, cytotoxic, active). Parallel pathway: 6-MP → via <strong>TPMT</strong> → methylated (inactive) metabolites. In TPMT <strong>poor metabolisers</strong> (homozygous low activity, ~0.3% of population), 6-MP is not methylated → diverted entirely to 6-TGN production → profound myelosuppression. TPMT testing (or NUDT15 in Asian populations) before starting azathioprine/6-MP is now standard of care.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Allopurinol (xanthine oxidase inhibitor) also increases 6-TGN by blocking 6-MP catabolism — combining allopurinol with azathioprine without dose reduction (by 75%) causes life-threatening pancytopenia. This combination can be used therapeutically ('allopurinol shunting') under expert supervision in selected IBD patients.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> TPMT testing predicts <strong>myelosuppression</strong> risk, NOT hepatotoxicity from azathioprine. Hepatotoxicity can occur independently of TPMT status. Monitor CBC monthly for the first 3 months regardless of TPMT genotype.</div>"}, {"id": "gi:fc:6", "deck": "Gastrointestinal", "dk": "gi", "type": "flashcard", "front": "Before starting infliximab for ulcerative colitis, a patient has a positive QuantiFERON-TB Gold test and a normal chest X-ray. What is the management?", "back": "<strong>Latent TB</strong> must be treated before starting any anti-TNF agent. TNF-α is essential for granuloma integrity — anti-TNF therapy reactivates latent TB, often as <strong>extrapulmonary/disseminated</strong> disease. Management: start <strong>isoniazid × 9 months</strong> (or rifampin × 4 months) and wait at least <strong>4 weeks</strong> before initiating infliximab. Also screen for hepatitis B (reactivation risk) and update all live vaccines before starting.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Anti-TNF-induced TB reactivation classically presents as miliary or extrapulmonary TB (lymph nodes, meninges, peritoneum) — different from typical post-primary pulmonary reactivation. A high index of suspicion is needed since chest X-ray may be normal.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> IGRA (QuantiFERON) can be falsely negative in severely immunosuppressed patients (anergy). If clinical suspicion for latent TB is high despite negative IGRA (endemic region, prior exposure), treat empirically for latent TB before starting anti-TNF. Do NOT rely on IGRA alone.</div>"}, {"id": "gi:fc:7", "deck": "Gastrointestinal", "dk": "gi", "type": "flashcard", "front": "A patient with hepatic encephalopathy is started on lactulose. His family asks why a laxative would help his confusion.", "back": "Lactulose is a synthetic, non-absorbable disaccharide cleaved by colonic bacteria → lactic acid + acetic acid → <strong>acidifies the colon</strong> (pH drops from ~7 to ~5). In the acidic colon, ammonia (NH₃) is trapped as ammonium ion (NH₄⁺) which cannot be absorbed → faecal excretion of ammonia. Reduced systemic ammonia → less CNS toxicity → improved hepatic encephalopathy. Secondary effect: osmotic laxation → shorter GI transit → less ammonia production and absorption.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Target: 2–3 soft stools per day. Over-laxation causes dehydration → worsens encephalopathy (pre-renal azotaemia → more ammonia). <strong>Rifaximin</strong> (non-absorbable antibiotic targeting gut ammonia-producing bacteria) is added for recurrent or refractory HE.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Lactulose is NOT lacTOSE. Lactose intolerance is a completely separate condition (brush-border lactase deficiency). Lactulose is synthetic and non-absorbable by design. Also: lactulose enema is used for obtunded patients who cannot take oral medication.</div>"}, {"id": "gi:fc:8", "deck": "Gastrointestinal", "dk": "gi", "type": "flashcard", "front": "A patient with active peptic ulcer has negative H. pylori testing. She takes naproxen daily for rheumatoid arthritis. Explain the dual mechanism of NSAID-induced ulceration.", "back": "<strong>Mechanism 1 (systemic — dominant):</strong> NSAIDs inhibit COX-1 → reduce PGE₂ and PGI₂ (prostacyclin) in gastric mucosa → decreased mucus secretion, decreased bicarbonate secretion, decreased mucosal blood flow → barrier breakdown. <strong>Mechanism 2 (topical/local):</strong> NSAIDs are weak acids; in the acidic stomach they are protonated → lipophilic → penetrate epithelial cells → intracellular acidification → direct cytotoxicity. This is why enteric-coated NSAIDs reduce topical injury but do NOT eliminate systemic (COX-1) damage.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Risk stratification for NSAID GI toxicity — HIGH risk: age &gt;65, H. pylori co-infection, history of ulcer/GI bleed, anticoagulant use, high-dose NSAIDs. In high-risk patients: use COX-2 selective NSAID (celecoxib) + PPI, or switch to paracetamol.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Enteric coating does NOT reduce ulcer risk — it only moves the topical damage from stomach to small intestine. The major mechanism (COX-1 systemic inhibition) is unaffected by formulation. Only a PPI or misoprostol truly reduces ulcer risk in NSAID users.</div>"}, {"id": "gi:fc:9", "deck": "Gastrointestinal", "dk": "gi", "type": "flashcard", "front": "A patient takes bismuth subsalicylate for H. pylori therapy and calls alarmed about black, tarry-looking stools. How do you differentiate this from melaena?", "back": "<strong>Bismuth-black stool</strong>: bismuth reacts with hydrogen sulphide from gut bacteria → bismuth sulphide (jet-black, non-odorous, formed stool). This is expected, harmless, and reversible on stopping the drug. <strong>Melaena</strong>: upper GI bleeding → Hb oxidised by gut bacteria and acid → haematin (black, sticky, tarry, foul-smelling 'coffee-ground' consistency). Key differentiators: melaena has a characteristic foul odour and sticky tarry consistency; also check for concomitant symptoms (haemodynamic instability, vomiting blood, anaemia).<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Bismuth also causes <strong>black tongue</strong> (bismuth sulphide on tongue bacteria) — equally harmless. Bismuth has weak antimicrobial effects against H. pylori (inhibits urease, disrupts bacterial adherence to gastric mucosa), cytoprotective effects, and anti-diarrhoeal (antisecretory) properties.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Bismuth subsalicylate contains <strong>salicylate</strong> — contraindicated in children with viral illness (Reye's syndrome risk) and in patients with aspirin hypersensitivity, bleeding disorders, or taking anticoagulants (additive antiplatelet effect from salicylate).</div>"}, {"id": "gi:fc:10", "deck": "Gastrointestinal", "dk": "gi", "type": "flashcard", "front": "Sucralfate is prescribed alongside a fluoroquinolone antibiotic for a patient with a peptic ulcer. The antibiotic level is undetectable at 2 hours. Explain.", "back": "Sucralfate (aluminium sucrose octasulphate) chelates many drugs in the GI tract: <strong>fluoroquinolones, tetracyclines, digoxin, phenytoin, warfarin, levothyroxine, ketoconazole</strong> — reducing their absorption by 30–90%. Sucralfate must be given at least <strong>2 hours before or after</strong> other medications. Additionally, sucralfate requires an acidic pH to activate (polymerises at pH &lt;4) — simultaneous antacid or PPI use impairs its gastroprotective effect.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Sucralfate works entirely locally — it binds positively charged proteins in the ulcer base (necrotic tissue and albumin) → forms a protective physical barrier over the ulcer surface lasting 4–6 hours. Systemic absorption is &lt;5%. Safe in pregnancy and renal failure (unlike aluminium-containing antacids in CKD).</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Sucralfate contains aluminium — can accumulate in CKD (dialysis patients) → aluminium toxicity (encephalopathy, osteomalacia, anaemia). Use with caution or avoid in advanced CKD.</div>"}, {"id": "gi:fc:11", "deck": "Gastrointestinal", "dk": "gi", "type": "flashcard", "front": "Cholestyramine is prescribed for hypercholesterolaemia. The patient notes that her warfarin is less effective. Explain.", "back": "Cholestyramine is a <strong>bile acid sequestrant</strong> (anion exchange resin) — binds bile acids in the gut → prevents reabsorption → increased hepatic bile acid synthesis from cholesterol → lowers LDL. The same binding mechanism non-selectively traps co-administered drugs including <strong>warfarin, digoxin, levothyroxine, fat-soluble vitamins (A, D, E, K), some statins, and thiazides</strong> → reduced absorption. Give cholestyramine at least <strong>4 hours after</strong> other medications.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Cholestyramine is used therapeutically to interrupt enterohepatic recirculation of drugs that need rapid elimination — e.g., <strong>leflunomide washout</strong> (give cholestyramine 8 g TID × 11 days to accelerate active metabolite elimination, as required before pregnancy).</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Long-term cholestyramine use causes <strong>fat-soluble vitamin malabsorption</strong> (vitamins A, D, E, K) → vitamin K deficiency can independently prolong PT/INR, compounding the warfarin interaction. Supplement fat-soluble vitamins.</div>"}, {"id": "gi:fc:12", "deck": "Gastrointestinal", "dk": "gi", "type": "flashcard", "front": "Erythromycin 125 mg is prescribed at subantimicrobial doses for gastroparesis. The patient asks why an antibiotic is being used for a stomach motility problem.", "back": "At low (sub-antimicrobial) doses, erythromycin and other macrolides are potent <strong>motilin receptor agonists</strong>. Motilin is a gut peptide hormone that triggers the <strong>migrating motor complex (MMC)</strong> — the 'housekeeper' wave that clears the stomach of undigested contents between meals. Erythromycin mimics motilin → stimulates gastric antral contractions → accelerates gastric emptying. The antibiotic effect requires much higher concentrations than the prokinetic effect.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Tachyphylaxis (motilin receptor downregulation) is a major limitation — efficacy typically wanes after 4 weeks of continuous use. Cycling the drug (2 weeks on / 2 weeks off) or using it intermittently may preserve the prokinetic response.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> All macrolides (including azithromycin, clarithromycin) prolong the <strong>QT interval</strong> via hERG K⁺ channel blockade — risk of Torsades de Pointes. Avoid combining erythromycin with other QT-prolonging drugs (ondansetron, haloperidol, antiarrhythmics). This is especially relevant given that erythromycin inhibits CYP3A4, which can raise levels of QT-prolonging co-medications.</div>"}, {"id": "gi:fc:13", "deck": "Gastrointestinal", "dk": "gi", "type": "flashcard", "front": "Mesalamine (5-ASA) is started for mild UC. Two weeks later the patient returns with significantly worse bloody diarrhoea. Could mesalamine be the cause?", "back": "Yes — <strong>paradoxical mesalamine-induced exacerbation of colitis</strong> occurs in approximately 2–3% of patients. Mechanism unclear (possibly hapten-mediated immune reaction). The presentation is indistinguishable from IBD flare, making it a diagnosis of exclusion. Key clue: onset within 2–4 weeks of starting or increasing mesalamine dose, rapid resolution within days of stopping the drug. Do not rechallenge.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Mesalamine mechanism: inhibits NF-κB → reduces TNF-α, IL-6, COX-2 in colonic epithelium; also inhibits 5-lipoxygenase → reduces LTB4. Key long-term toxicity: <strong>interstitial nephritis</strong> → check renal function annually in all patients on mesalamine.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> <strong>Sulfasalazine</strong> (the original 5-ASA prodrug) is split by gut bacteria into 5-ASA (active) + sulphapyridine (largely responsible for side effects): haemolytic anaemia (G6PD-dependent), agranulocytosis, hepatotoxicity, <strong>reversible oligospermia</strong>, folate deficiency, and hypersensitivity. Mesalamine formulations eliminate sulphapyridine and have a much better side-effect profile.</div>"}, {"id": "gi:fc:14", "deck": "Gastrointestinal", "dk": "gi", "type": "flashcard", "front": "Vedolizumab is chosen over infliximab for a 72-year-old woman with Crohn's disease and recurrent pneumonias. What is the mechanism and why is it preferred in this patient?", "back": "Vedolizumab is an anti-<strong>α4β7 integrin</strong> monoclonal antibody. The α4β7 integrin on gut-homing lymphocytes binds <strong>MAdCAM-1</strong> (mucosal addressin cell adhesion molecule-1), expressed exclusively on gut endothelium → lymphocyte trafficking into intestinal mucosa is selectively blocked. Because the target is gut-specific, vedolizumab does not suppress systemic immunity — no increased risk of systemic infections, TB reactivation, or PML. Ideal for elderly patients with recurrent respiratory infections who cannot tolerate systemic immunosuppression.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Vedolizumab has a <strong>slow onset</strong> (weeks–months for Crohn's; faster for UC) — bridge with corticosteroids if rapid control is needed. It does not cross the BBB, so it never causes PML (unlike natalizumab — anti-α4 integrin, NOT gut-selective, associated with JC virus reactivation).</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Natalizumab (anti-α4 integrin) targets BOTH gut α4β7 AND CNS α4β1 (VLA-4) → blocks lymphocyte entry into CNS → risk of <strong>progressive multifocal leukoencephalopathy (PML)</strong> from JC virus. Vedolizumab targets only α4β7 (gut) → NO PML risk. This gut-selectivity is the critical differentiator.</div>"}, {"id": "gi:fc:15", "deck": "Gastrointestinal", "dk": "gi", "type": "flashcard", "front": "A patient is treated with polyethylene glycol (PEG) for constipation. Another patient on long-term opioids is given methylnaltrexone. Explain why PEG would not work for the second patient.", "back": "PEG (osmotic laxative): large polymer draws water osmotically into the colon → softens stool + stimulates peristalsis. This addresses mechanical stool hardening but does NOT address the underlying cause of opioid-induced constipation (OIC), which is <strong>peripheral µ-opioid receptor activation</strong> in the enteric nervous system → decreased GI motility + decreased secretion + increased sphincter tone. <strong>Methylnaltrexone</strong> is a peripherally acting µ-opioid receptor antagonist (PAMORA) — blocks enteric opioid receptors without crossing the BBB, restoring GI motility without reversing analgesia.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Other PAMORAs: <strong>naloxegol</strong> (oral, PEGylated naloxone — too large to cross BBB), <strong>naldemedine</strong> (oral). Lubiprostone (ClC-2 activator) also has an FDA indication specifically for OIC in non-cancer chronic pain patients.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Oral naloxone (unmodified) does have some intestinal effect for OIC, but is absorbed and undergoes partial hepatic first-pass — systemic exposure can occur in liver disease, reversing analgesia. PAMORAs are specifically designed to avoid CNS penetration and are safer for reliable OIC treatment without reversing pain control.</div>"}, {"id": "gi:fc:16", "deck": "Gastrointestinal", "dk": "gi", "type": "flashcard", "front": "Lubiprostone is prescribed for chronic idiopathic constipation. A colleague says it 'works like a laxative.' What is the more precise mechanism?", "back": "Lubiprostone specifically activates <strong>ClC-2 chloride channels</strong> (type-2 chloride channels) in intestinal epithelial cells → Cl⁻ secretion into the lumen → passive Na⁺ and water follow → fluid accumulates in the lumen → softer stool + increased GI transit. Unlike osmotic laxatives (which draw water passively), lubiprostone actively secretes fluid via a targeted channel. It is also approved for IBS-C and OIC (at higher doses).<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> <strong>Linaclotide</strong> activates guanylate cyclase-C (GC-C) receptor → cGMP → CFTR Cl⁻ secretion (different channel) + analgesic effect on subepithelial afferent neurons. Preferred for IBS-C (addresses both constipation AND visceral pain). Plecanatide is a newer GC-C agonist.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Lubiprostone, linaclotide, and plecanatide are contraindicated in patients &lt;6 years old (risk of severe diarrhoea and dehydration). Lubiprostone causes nausea in up to 30% of patients — take with food and water to reduce GI side effects.</div>"}, {"id": "gi:fc:17", "deck": "Gastrointestinal", "dk": "gi", "type": "flashcard", "front": "A 40-year-old woman with primary biliary cholangitis (PBC) is started on ursodeoxycholic acid (UDCA). How does a bile acid treat a liver disease?", "back": "UDCA (ursodiol) is a hydrophilic, non-toxic bile acid that, when given orally, replaces the endogenous pool of hydrophobic, cytotoxic bile acids (chenodeoxycholic, lithocholic, deoxycholic acids) via competitive inhibition of their intestinal reabsorption. Mechanisms in PBC: (1) replaces toxic bile acids → reduces hepatocyte injury; (2) stabilises cholangiocyte membranes; (3) has immunomodulatory and anti-apoptotic effects; (4) stimulates biliary HCO₃⁻ secretion ('bicarbonate umbrella'). Slows disease progression, improves LFTs, reduces need for transplant.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> UDCA is also used for cholesterol gallstone dissolution (takes 6–24 months; only works for small, cholesterol-rich, radiolucent stones in functioning gallbladder) and to prevent gallstones during rapid weight loss or octreotide therapy.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> UDCA does NOT cure PBC — it slows progression. For patients with inadequate response to UDCA, add <strong>obeticholic acid</strong> (FXR agonist → reduces bile acid synthesis, improves cholestasis) — but it can cause dose-dependent pruritus and is contraindicated in decompensated cirrhosis.</div>"}, {"id": "gi:fc:18", "deck": "Gastrointestinal", "dk": "gi", "type": "flashcard", "front": "Ondansetron is given for post-operative nausea in a patient on fluoxetine. The anaesthetist is concerned about a drug interaction. What is it, and how significant is the risk?", "back": "Potential <strong>serotonin syndrome</strong>: fluoxetine (SSRI) increases synaptic serotonin by blocking reuptake; ondansetron is primarily a 5-HT₃ <em>antagonist</em>. The risk is real but low with ondansetron alone — however, in the context of polypharmacy (SSRI + opioids with serotonergic activity like tramadol/fentanyl + antiemetics like metoclopramide), cumulative serotonin burden increases. The more clinically significant concern: ondansetron <strong>QT prolongation</strong> in combination with other QT-prolonging perioperative drugs (haloperidol, droperidol, some antibiotics).<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> True serotonin syndrome risk with ondansetron monotherapy + SSRI is low because ondansetron ANTAGONISES 5-HT₃ (it doesn't activate serotonin receptors). The interaction concern is greatest when multiple serotonergic agents are used simultaneously — applies more to granisetron in some studies.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Max single IV ondansetron dose is <strong>16 mg</strong> (the old 32 mg dose was removed due to QT prolongation risk). FDA warning: avoid in patients with congenital long-QT syndrome and concurrent QT-prolonging drugs. Oral 24 mg single dose for highly emetogenic chemotherapy is still acceptable.</div>"}, {"id": "gi:fc:19", "deck": "Gastrointestinal", "dk": "gi", "type": "flashcard", "front": "A patient with Clostridioides difficile infection (CDI) fails a first course of oral metronidazole. What is the correct treatment escalation, and why has treatment guidance changed?", "back": "Current IDSA/ESCMID guidelines no longer recommend metronidazole as first-line for CDI of any severity. <strong>Vancomycin oral</strong> (125 mg QID × 10 days) or <strong>fidaxomicin</strong> (200 mg BID × 10 days) are now first-line. Fidaxomicin has a narrower spectrum → preserves Bacteroides and Lactobacillus colonisation resistance → significantly lower recurrence rate (~40% reduction vs oral vancomycin). Metronidazole is acceptable only for mild cases when cost is prohibitive.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> For recurrent CDI: second recurrence — fidaxomicin (if first treatment was vancomycin) or vancomycin taper/pulse. Third or more recurrences: <strong>bezlotoxumab</strong> (anti-toxin B monoclonal antibody) as adjunct, or <strong>faecal microbiota transplant (FMT)</strong> — 85–90% cure rate for multiply recurrent CDI.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> IV vancomycin does NOT treat CDI — it does not reach the colon lumen in therapeutic concentrations. Only <strong>oral</strong> vancomycin achieves adequate colonic levels. Fidaxomicin also has minimal systemic absorption — both act locally in the colon.</div>"}, {"id": "gi:q:0", "deck": "Gastrointestinal", "dk": "gi", "type": "quiz", "front": "Which single cell type, via which receptor, is the dominant paracrine amplifier of parietal-cell acid secretion?", "back": "The <b>ECL cell</b> releasing <b>histamine</b>, acting on the parietal-cell <b>H2 receptor</b> (Gs → cAMP). This is why H₂ blockers and PPIs are so effective."}, {"id": "gi:q:1", "deck": "Gastrointestinal", "dk": "gi", "type": "quiz", "front": "Gastrin is the most potent inducer of acid yet acts \"largely indirectly.\" Explain.", "back": "Gastrin (from antral <b>G cells</b>, via CCK2) stimulates acid <b>mainly by releasing histamine from ECL cells</b>; its direct action on parietal cells is comparatively minor."}, {"id": "gi:q:2", "deck": "Gastrointestinal", "dk": "gi", "type": "quiz", "front": "What luminal change triggers somatostatin release, and what is its downstream effect?", "back": "Luminal <b>pH &lt; 3</b> stimulates antral <b>D cells</b> → somatostatin → <b>suppresses gastrin</b> (negative feedback). <i>H. pylori</i> depletes D cells, removing this brake."}, {"id": "gi:q:3", "deck": "Gastrointestinal", "dk": "gi", "type": "quiz", "front": "Why is the PPI's duration of acid suppression (24–48 h) so much longer than its plasma half-life (0.5–3 h)?", "back": "PPIs bind the pump <b>covalently and irreversibly</b>; acid secretion only resumes once the cell <b>synthesises new pumps</b> — decoupling effect duration from plasma clearance."}, {"id": "gi:q:4", "deck": "Gastrointestinal", "dk": "gi", "type": "quiz", "front": "Why should a PPI be taken 30–60 minutes before the first meal of the day?", "back": "Pump numbers are <b>highest after fasting</b>; dosing before the meal means the maximum number of freshly inserted, actively secreting pumps are available to be irreversibly inhibited."}, {"id": "gi:q:5", "deck": "Gastrointestinal", "dk": "gi", "type": "quiz", "front": "Where exactly is a PPI prodrug activated, and into what active species?", "back": "In the acidic <b>secretory canaliculus</b> of the parietal cell, it forms a <b>tetracyclic sulfenamide</b> that covalently binds pump cysteines."}, {"id": "gi:q:6", "deck": "Gastrointestinal", "dk": "gi", "type": "quiz", "front": "Which PPI uniquely inhibits CYP2C19 and may impair clopidogrel activation, and which is the safest co-prescription?", "back": "<b>Omeprazole</b> inhibits CYP2C19 (controversial clopidogrel interaction); <b>pantoprazole</b> is the safest pairing."}, {"id": "gi:q:7", "deck": "Gastrointestinal", "dk": "gi", "type": "quiz", "front": "List four recognised long-term adverse associations of PPIs.", "back": "↓ <b>vitamin B12</b>, <b>hypomagnesaemia</b> (worse with diuretics), <b>↑ fracture</b> risk, and <b>↑ infections</b> (C. difficile, pneumonia, SBP). Also hypergastrinaemia → ECL hyperplasia/rebound."}, {"id": "gi:q:8", "deck": "Gastrointestinal", "dk": "gi", "type": "quiz", "front": "By what type of binding do H₂ antagonists act, and roughly what % acid suppression do they achieve?", "back": "<b>Reversible competitive</b> antagonism at H2; ~<b>70%</b> suppression (especially nocturnal/basal). Tolerance develops within ~3 days."}, {"id": "gi:q:9", "deck": "Gastrointestinal", "dk": "gi", "type": "quiz", "front": "Which H₂ antagonist causes gynaecomastia/impotence and inhibits CYP enzymes? Which two were withdrawn and why?", "back": "<b>Cimetidine</b> (antiandrogen + CYP inhibitor). <b>Ranitidine and nizatidine</b> were largely withdrawn due to <b>NDMA contamination</b>."}, {"id": "gi:q:10", "deck": "Gastrointestinal", "dk": "gi", "type": "quiz", "front": "How do potassium-competitive acid blockers differ mechanistically from PPIs, and what clinical advantages follow?", "back": "P-CABs <b>reversibly</b> block the K⁺ site of the pump, need <b>no acid activation</b>, and bind both active and inactive pump → <b>faster onset (day 1)</b>, longer duration, better nocturnal control, meal-independence, CYP2C19-independence."}, {"id": "gi:q:11", "deck": "Gastrointestinal", "dk": "gi", "type": "quiz", "front": "Misoprostol's mechanism and its single most important contraindication?", "back": "PGE₁ analogue → <b>EP3/Gi → ↓cAMP ↓acid</b> + cytoprotection (prevents NSAID ulcers). <b>Absolutely contraindicated in pregnancy</b> (uterotonic/abortifacient)."}, {"id": "gi:q:12", "deck": "Gastrointestinal", "dk": "gi", "type": "quiz", "front": "Why must sucralfate be taken on an empty stomach, and in whom is it risky?", "back": "It needs <b>acid (pH &lt; 4)</b> to cross-link into its protective gel. Avoid in <b>renal failure</b> (aluminium accumulation); it also binds other drugs (space dosing)."}, {"id": "gi:q:13", "deck": "Gastrointestinal", "dk": "gi", "type": "quiz", "front": "Contrast the bowel effects of magnesium- vs aluminium-containing antacids.", "back": "<b>Mg²⁺ → diarrhoea</b>; <b>Al³⁺ → constipation</b>. Combinations aim to balance the two."}, {"id": "gi:q:14", "deck": "Gastrointestinal", "dk": "gi", "type": "quiz", "front": "State a standard 10–14-day triple therapy for H. pylori.", "back": "<b>PPI + clarithromycin 500 mg + amoxicillin 1 g</b>, all twice daily (metronidazole can replace amoxicillin if penicillin-allergic)."}, {"id": "gi:q:15", "deck": "Gastrointestinal", "dk": "gi", "type": "quiz", "front": "What is the quadruple regimen, and when is it preferred?", "back": "<b>PPI + bismuth + tetracycline + metronidazole</b> — preferred where <b>clarithromycin/metronidazole resistance</b> is common."}, {"id": "gi:q:16", "deck": "Gastrointestinal", "dk": "gi", "type": "quiz", "front": "In GERD during pregnancy, outline the stepwise drug progression.", "back": "Start with <b>antacids / alginates / sucralfate</b> → then <b>H₂ antagonist</b> (cimetidine best track record; avoid nizatidine) → reserve <b>PPI</b> (lansoprazole/pantoprazole) for intractable/complicated disease."}, {"id": "gi:q:17", "deck": "Gastrointestinal", "dk": "gi", "type": "quiz", "front": "Drug of choice for Zollinger-Ellison syndrome, and the rescue if uncontrolled?", "back": "<b>High-dose PPI</b> (≈ twice the usual ulcer dose); if acid still uncontrolled, add the somatostatin analogue <b>octreotide</b>."}, {"id": "gi:q:18", "deck": "Gastrointestinal", "dk": "gi", "type": "quiz", "front": "Name the primary excitatory and inhibitory neurotransmitters of enteric motor neurons.", "back": "Excitatory = <b>acetylcholine</b>; inhibitory = <b>nitric oxide</b> (with VIP, ATP, PACAP as contributors)."}, {"id": "gi:q:19", "deck": "Gastrointestinal", "dk": "gi", "type": "quiz", "front": "Which cell releases serotonin to ignite the peristaltic reflex, and which cells set the gut's electrical pacemaker rhythm?", "back": "<b>Enterochromaffin cells</b> release 5HT; <b>interstitial cells of Cajal</b> set the pacemaker/slow-wave rhythm."}, {"id": "gi:q:20", "deck": "Gastrointestinal", "dk": "gi", "type": "quiz", "front": "Give metoclopramide's full receptor profile and its most feared chronic adverse effect.", "back": "D2 antagonist + 5HT4 agonist + 5HT3 antagonist. Chronic use → <b>tardive dyskinesia (may be irreversible)</b>; also acute dystonia, hyperprolactinaemia, QT. Limit to &lt; 12 weeks."}, {"id": "gi:q:21", "deck": "Gastrointestinal", "dk": "gi", "type": "quiz", "front": "How does domperidone avoid extrapyramidal effects yet still cause prolactin elevation and antiemesis?", "back": "It's a <b>peripheral D2 antagonist that poorly crosses the BBB</b>; but it still acts at sites <b>outside the BBB</b> (CTZ for emesis, pituitary for prolactin). Caution: ventricular arrhythmia/sudden death."}, {"id": "gi:q:22", "deck": "Gastrointestinal", "dk": "gi", "type": "quiz", "front": "Why was cisapride withdrawn?", "back": "Fatal <b>QT prolongation / torsades</b> via blockade of the <b>hERG K⁺ channel</b>."}, {"id": "gi:q:23", "deck": "Gastrointestinal", "dk": "gi", "type": "quiz", "front": "Erythromycin's prokinetic mechanism and why its effect fades within ~28 days.", "back": "It mimics <b>motilin</b> (triggers phase III MMC). <b>Tachyphylaxis</b> from <b>motilin-receptor downregulation</b> after ~28 days."}, {"id": "gi:q:24", "deck": "Gastrointestinal", "dk": "gi", "type": "quiz", "front": "Lactulose has an indication beyond constipation — what, and by what mechanism?", "back": "<b>Hepatic encephalopathy</b>: colonic fermentation drops luminal pH, <b>trapping ammonia as non-absorbable NH₄⁺</b>, plus faster transit lowers blood ammonia."}, {"id": "gi:q:25", "deck": "Gastrointestinal", "dk": "gi", "type": "quiz", "front": "Match each prosecretory laxative to its target: lubiprostone, linaclotide/plecanatide, tenapanor.", "back": "Lubiprostone → <b>ClC-2 chloride channel</b>; linaclotide/plecanatide → <b>guanylate cyclase-C (GC-C)</b>; tenapanor → <b>NHE3 inhibition</b>."}, {"id": "gi:q:26", "deck": "Gastrointestinal", "dk": "gi", "type": "quiz", "front": "Which laxative class should be avoided in renal failure and in patients on diuretics, and why?", "back": "<b>Magnesium (saline) laxatives</b> — risk of <b>hypermagnesaemia</b> and electrolyte disturbance."}, {"id": "gi:q:27", "deck": "Gastrointestinal", "dk": "gi", "type": "quiz", "front": "Why does loperamide relieve diarrhoea without central opioid effects, and what is its black-box warning?", "back": "It's a <b>peripheral MOR agonist</b> that penetrates the CNS poorly (40–50× morphine as an antidiarrhoeal). Black box: <b>cardiac events / torsades at overdose</b> (max 16 mg/day)."}, {"id": "gi:q:28", "deck": "Gastrointestinal", "dk": "gi", "type": "quiz", "front": "Why is atropine co-formulated with diphenoxylate/difenoxin?", "back": "A subtherapeutic atropine dose <b>discourages abuse/overdose</b> (unpleasant anticholinergic effects at high doses)."}, {"id": "gi:q:29", "deck": "Gastrointestinal", "dk": "gi", "type": "quiz", "front": "In which two diarrhoeal scenarios must antibiotics AND antimotility agents be avoided?", "back": "<b>Enterohaemorrhagic E. coli</b> (HUS risk) and <b>C. difficile</b>. Antimotility risks toxic megacolon and prolonged organism clearance."}, {"id": "gi:q:30", "deck": "Gastrointestinal", "dk": "gi", "type": "quiz", "front": "Bismuth subsalicylate: two harmless signs it causes, and one systemic caution.", "back": "<b>Black stools and black tongue</b> (bismuth sulfide). Caution: the absorbed <b>salicylate</b> → Reye's risk, tinnitus, CNS effects."}, {"id": "gi:q:31", "deck": "Gastrointestinal", "dk": "gi", "type": "quiz", "front": "Which IBS drug carries an ischaemic-colitis risk and a REMS, and in whom is it used?", "back": "<b>Alosetron</b> (5HT3 antagonist) — for <b>women with severe diarrhoea-predominant IBS</b>, under a restricted prescribing programme."}, {"id": "gi:q:32", "deck": "Gastrointestinal", "dk": "gi", "type": "quiz", "front": "Eluxadoline's receptor profile and the special dosing rule for patients without a gallbladder.", "back": "<b>MOR agonist / DOR antagonist / KOR agonist</b>. Without a gallbladder use <b>75 mg twice daily</b> (lower) to reduce sphincter-of-Oddi spasm/pancreatitis risk."}, {"id": "gi:q:33", "deck": "Gastrointestinal", "dk": "gi", "type": "quiz", "front": "Why is the CTZ uniquely positioned to detect blood-borne emetics?", "back": "It lies in the <b>area postrema, outside the blood–brain barrier</b>, sampling blood and CSF for toxins."}, {"id": "gi:q:34", "deck": "Gastrointestinal", "dk": "gi", "type": "quiz", "front": "Which antiemetic class is the key addition for delayed-phase chemotherapy emesis, and with what two partners is it given?", "back": "<b>NK1 antagonists</b> (aprepitant/fosaprepitant, rolapitant), given with a <b>5HT3 antagonist + dexamethasone</b>."}, {"id": "gi:q:35", "deck": "Gastrointestinal", "dk": "gi", "type": "quiz", "front": "Best drug classes for motion sickness?", "back": "<b>H1 antihistamines</b> (cyclizine, meclizine) and the <b>antimuscarinic scopolamine</b> (patch). 5HT3 antagonists are ineffective for motion sickness."}, {"id": "gi:q:36", "deck": "Gastrointestinal", "dk": "gi", "type": "quiz", "front": "First-line agent for nausea/vomiting of pregnancy?", "back": "<b>Doxylamine (H1 antihistamine) + pyridoxine (vitamin B6)</b>."}, {"id": "gi:q:37", "deck": "Gastrointestinal", "dk": "gi", "type": "quiz", "front": "Which 5HT3 antagonist helps with delayed emesis and spares the QT interval, and why?", "back": "<b>Palonosetron</b> — long half-life (~40 h) and highest receptor affinity; does not appear to prolong QT."}, {"id": "gi:q:38", "deck": "Gastrointestinal", "dk": "gi", "type": "quiz", "front": "Ursodiol and obeticholic acid both treat primary biliary cholangitis — how do they differ mechanistically, and what is obeticholic acid's black-box risk?", "back": "Ursodiol = hydrophilic bile acid that <b>displaces toxic bile acids</b> &amp; reduces lithogenicity; obeticholic acid = <b>FXR agonist</b> that suppresses bile-acid synthesis. Black box: <b>hepatic decompensation / liver failure</b> if mis-dosed."}, {"id": "gi:q:39", "deck": "Gastrointestinal", "dk": "gi", "type": "quiz", "front": "How is pancreatic enzyme replacement dosed, and on which enzyme is it titrated?", "back": "Titrated on <b>lipase</b> content: start ~<b>500 USP units/kg per meal</b>, up to ~2500 USP units/kg per meal (≤ 10,000 USP units/kg/day)."}, {"id": "gi:q:40", "deck": "Gastrointestinal", "dk": "gi", "type": "quiz", "front": "Contrast the cytokine profiles of Crohn's disease vs ulcerative colitis.", "back": "Crohn's = <b>TH1/TH17</b> (IL-12, IL-23, IFN-γ, TNF-α); UC = <b>TH2-like</b> (IL-4, IL-13). Crohn's is transmural with skip lesions; UC is mucosal and continuous."}, {"id": "gi:q:41", "deck": "Gastrointestinal", "dk": "gi", "type": "quiz", "front": "Which is the active moiety of sulfasalazine, and how is it released specifically in the colon?", "back": "<b>5-ASA (mesalamine)</b>. The <b>azo bond</b> survives stomach/small bowel and is cleaved by <b>colonic bacterial azoreductases</b>; sulfapyridine is the inert (toxic) carrier."}, {"id": "gi:q:42", "deck": "Gastrointestinal", "dk": "gi", "type": "quiz", "front": "Two adverse effects attributable to the sulfapyridine moiety, and the supplement routinely given with sulfasalazine.", "back": "Headache/nausea/fatigue, rash, reversible <b>↓ sperm count/motility</b>, marrow suppression. Give <b>folate</b> (sulfasalazine inhibits folate absorption)."}, {"id": "gi:q:43", "deck": "Gastrointestinal", "dk": "gi", "type": "quiz", "front": "Why are glucocorticoids excellent for induction but not maintenance of IBD remission?", "back": "They rapidly damp inflammation (induction) but chronic use carries <b>serious toxicity</b> (bone, skin, metabolic, HPA suppression). Always <b>taper</b> to avoid adrenal insufficiency/relapse."}, {"id": "gi:q:44", "deck": "Gastrointestinal", "dk": "gi", "type": "quiz", "front": "What makes budesonide gentler systemically than prednisone?", "back": "Extensive <b>first-pass hepatic metabolism</b> (CYP3A4) keeps systemic levels low while delivering steroid locally to ileum/colon."}, {"id": "gi:q:45", "deck": "Gastrointestinal", "dk": "gi", "type": "quiz", "front": "Trace the activation pathway of azathioprine to its active moiety.", "back": "Azathioprine → <b>6-mercaptopurine</b> → (via HGPRT) → <b>6-thioguanine nucleotides</b>, the active immunosuppressive species."}, {"id": "gi:q:46", "deck": "Gastrointestinal", "dk": "gi", "type": "quiz", "front": "Why must TPMT be assessed before azathioprine, and what is the allopurinol interaction rule?", "back": "Low <b>TPMT</b> shunts drug to <b>6-TGN → bone-marrow suppression</b>. Allopurinol blocks <b>xanthine oxidase</b> → more active metabolite → <b>reduce dose to ~25%</b>."}, {"id": "gi:q:47", "deck": "Gastrointestinal", "dk": "gi", "type": "quiz", "front": "Two notable thiopurine toxicities beyond marrow suppression.", "back": "<b>Pancreatitis (~5%)</b> and a <b>4-fold increased risk of (non-Hodgkin) lymphoma</b>."}, {"id": "gi:q:48", "deck": "Gastrointestinal", "dk": "gi", "type": "quiz", "front": "Methotrexate's role in IBD, its main contraindication, and drugs that raise its toxicity.", "back": "Maintenance of <b>Crohn's</b> remission (SC). <b>Absolutely contraindicated in pregnancy</b> (teratogen). <b>NSAIDs, PPIs, penicillins, probenecid, ciprofloxacin</b> reduce its renal clearance → toxicity."}, {"id": "gi:q:49", "deck": "Gastrointestinal", "dk": "gi", "type": "quiz", "front": "Distinguish infliximab from adalimumab/certolizumab in structure and antidrug-antibody risk.", "back": "Infliximab = <b>chimeric</b> (mouse/human), IV, more antidrug antibodies → often combined with azathioprine. Adalimumab/golimumab = humanised; certolizumab = pegylated Fab — both fewer antibodies, given SC."}, {"id": "gi:q:50", "deck": "Gastrointestinal", "dk": "gi", "type": "quiz", "front": "What must be screened for before starting any anti-TNF agent, and which cardiac condition contraindicates infliximab?", "back": "Screen for <b>latent tuberculosis</b> (reactivation risk). Infliximab is contraindicated in <b>severe congestive heart failure</b>."}, {"id": "gi:q:51", "deck": "Gastrointestinal", "dk": "gi", "type": "quiz", "front": "Which biologic is gut-selective by blocking α4β7, and which carries a PML risk under a restricted programme?", "back": "<b>Vedolizumab</b> (anti-α4β7, gut-selective). <b>Natalizumab</b> (anti-α4) → <b>PML/JC virus</b>, available only via the TOUCH programme."}, {"id": "gi:q:52", "deck": "Gastrointestinal", "dk": "gi", "type": "quiz", "front": "Ustekinumab's target, and a practical vaccination caution from its long half-life.", "back": "Targets the <b>p40 subunit of IL-12/IL-23</b>. Half-life up to ~120 days → <b>stop 15 weeks before a live vaccine</b>."}, {"id": "gi:q:53", "deck": "Gastrointestinal", "dk": "gi", "type": "quiz", "front": "Tofacitinib's mechanism, key indication, and boxed warnings.", "back": "<b>JAK1/3 inhibitor</b> (oral) for moderate–severe <b>UC after biologic failure</b>. Boxed warnings: <b>serious cardiac events, thromboembolism, malignancy</b>; teratogenic."}, {"id": "gi:q:54", "deck": "Gastrointestinal", "dk": "gi", "type": "quiz", "front": "Ozanimod's mechanism and the dietary/drug interaction its metabolite creates.", "back": "<b>S1P1/5 receptor modulator</b> — traps lymphocytes in lymph nodes. A metabolite inhibits <b>MAO-B</b> → hypertensive interactions with <b>tyramine, SSRIs/SNRIs, TCAs, MAO inhibitors</b>."}, {"id": "gi:q:55", "deck": "Gastrointestinal", "dk": "gi", "type": "quiz", "front": "In a pregnant IBD patient, name the safest anti-TNF and the three drug categories that are absolutely contraindicated.", "back": "Safest anti-TNF = <b>certolizumab pegol</b> (no placental transfer). Contraindicated: <b>methotrexate</b>, <b>JAK inhibitors (tofacitinib)</b>, and <b>ozanimod</b>."}, {"id": "id:fc:0", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "flashcard", "front": "A 25-year-old woman with penicillin allergy (documented anaphylaxis) needs cefazolin for surgical prophylaxis. Her surgeon says the 10% cross-reactivity rule means she cannot have it. Is this correct?", "back": "No — the oft-cited 10% figure is based on outdated skin-test data using impure penicillin reagents. Modern evidence shows true cross-reactivity between penicillins and cephalosporins is <strong>≤2%</strong>, and cross-reactivity depends on shared <strong>R1 side chains</strong>, not the shared beta-lactam ring. Cefazolin has a unique R1 side chain structurally distinct from penicillins — its cross-reactivity risk is extremely low (&lt;0.01%) even in confirmed penicillin allergy. Most infectious disease guidelines now endorse cefazolin use in penicillin-allergic patients after careful risk assessment.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Ampicillin and cefadroxil share identical R1 side chains — avoid cefadroxil in ampicillin-allergic patients. Amoxicillin and cefprozil/cefaclor also share similar side chains. Side-chain matching (not the beta-lactam ring) predicts true cross-reactivity.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Aztreonam (monobactam) has essentially NO cross-reactivity with penicillins — EXCEPT with <strong>ceftazidime</strong>, which shares an identical R1 side chain. In cystic fibrosis patients allergic to ceftazidime, aztreonam must also be avoided.</div>"}, {"id": "id:fc:1", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "flashcard", "front": "A patient on tobramycin for Pseudomonas pneumonia develops rising creatinine and bilateral high-frequency hearing loss on day 8. Explain why the hearing loss is irreversible while the kidney injury often recovers.", "back": "Both toxicities are trough-level dependent (accumulation-driven). <strong>Nephrotoxicity:</strong> aminoglycosides accumulate in proximal tubule cells → oxidative stress → cell necrosis. Proximal tubule cells can <strong>regenerate</strong> from stem cells at the S3 segment → renal function usually recovers after stopping the drug. <strong>Ototoxicity:</strong> aminoglycosides accumulate in cochlear outer hair cells → oxidative damage → cell death. Cochlear hair cells <strong>cannot regenerate</strong> in humans → permanent high-frequency sensorineural hearing loss.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Once-daily extended-interval aminoglycoside dosing (high peak for concentration-dependent killing, long drug-free interval for toxicity clearance from inner ear/tubules) has lower ototoxicity and nephrotoxicity rates than traditional dosing. Use the Hartford nomogram for monitoring.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Vestibulotoxicity (balance, oscillopsia) may present separately from cochleotoxicity (hearing loss) — both irreversible. Screen with audiometry baseline and periodically for courses &gt;5 days. <strong>Never resume</strong> an aminoglycoside that caused confirmed ototoxicity regardless of the clinical need.</div>"}, {"id": "id:fc:2", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "flashcard", "front": "A 16-year-old football player is prescribed ciprofloxacin for a UTI. Two weeks later he ruptures his Achilles tendon during training. What is the mechanism, and who is at highest risk?", "back": "Fluoroquinolone-induced tendinopathy: fluoroquinolones chelate Mg²⁺ in tenocytes → inhibit mitochondrial function and matrix metalloprotease regulatory pathways → collagen matrix degradation + impaired repair → tendon degeneration. The Achilles tendon is most commonly affected. Risk factors: age &gt;60, concurrent corticosteroids (dramatically increases risk), renal failure, prior tendon injury, solid organ transplant recipients (often on steroids). Fluoroquinolones are generally <strong>avoided in children</strong> (also impair developing cartilage).<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Additional fluoroquinolone black-box warnings: QT prolongation, peripheral neuropathy (may be permanent), CNS effects (seizures, psychosis in elderly), aortic aneurysm/dissection. The FDA emphasises reserving fluoroquinolones for infections with no equally effective alternative.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Ciprofloxacin chelates divalent cations (Ca²⁺, Mg²⁺, Al³⁺, Fe²⁺, Zn²⁺) in the GI tract → reduced absorption by up to 90%. Must be taken 2 hours before or 6 hours after antacids, dairy products, iron, or calcium supplements — a frequently missed cause of treatment failure.</div>"}, {"id": "id:fc:3", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "flashcard", "front": "Vancomycin is infused over 15 minutes and the patient develops diffuse facial and truncal erythema, pruritus, and hypotension — but no urticaria and no wheeze. What is this, and how is it managed?", "back": "<strong>Red man syndrome (RMS)</strong> — a rate-dependent, <strong>non-IgE-mediated</strong> direct mast cell degranulation reaction. Vancomycin (and ciprofloxacin, amphotericin B) directly degranulate mast cells → histamine release → vasodilation, flushing, pruritus, and hypotension. Management: (1) Stop infusion immediately; (2) Give diphenhydramine IV; (3) When resolved, restart infusion at half the rate (≤10 mg/min, standard is 1 g over 60 minutes). Pre-treat with antihistamine if history of RMS.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Document RMS as <strong>'infusion reaction'</strong>, NOT as 'vancomycin allergy' — it is not immune-mediated and the patient can safely receive vancomycin again with slower infusion. Mislabelling it as an allergy leads to unnecessary use of inferior alternatives.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Vancomycin nephrotoxicity is now monitored using <strong>AUC-guided dosing</strong> (target AUC₂₄/MIC ≥400 mg·h/L) rather than trough-only monitoring — trough-only dosing led to over-dosing and nephrotoxicity. Vancomycin + piperacillin-tazobactam combination is associated with synergistic nephrotoxicity.</div>"}, {"id": "id:fc:4", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "flashcard", "front": "Linezolid is started for VRE bacteraemia. The patient is also on sertraline for depression. Two days later she develops fever, agitation, diaphoresis, tremor, and bilateral lower limb clonus. What happened?", "back": "<strong>Serotonin syndrome</strong> — linezolid is a weak, reversible <strong>MAO inhibitor</strong> (inhibits MAO-A predominantly). Combined with sertraline (SSRI → blocks 5-HT reuptake), synaptic serotonin levels become dangerously elevated → hyperthermia, autonomic instability, neuromuscular hyperactivity (clonus, hyperreflexia, tremor). Serotonin syndrome triad: <strong>altered mental status + autonomic instability + neuromuscular abnormalities</strong>. Management: stop both drugs; cyproheptadine (5-HT antagonist); supportive care; benzodiazepines for agitation.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> If VRE infection requires linezolid and a serotonergic drug cannot be stopped, use <strong>daptomycin</strong> as an alternative for non-pulmonary VRE (daptomycin is NOT an MAOI). Note: daptomycin is inactivated by surfactant → ineffective for VRE pneumonia.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Linezolid long-term toxicity (beyond 4 weeks): <strong>myelosuppression</strong> (monitor CBC weekly), <strong>lactic acidosis</strong> (mitochondrial protein synthesis inhibition — same mechanism as bacteria but affects mitochondrial ribosomes), peripheral and optic neuropathy. These are NOT serotonin-related.</div>"}, {"id": "id:fc:5", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "flashcard", "front": "A TB patient on rifampin/isoniazid/pyrazinamide/ethambutol (RIPE) develops jaundice, AST 12× ULN, and nausea at week 6. What do you do?", "back": "Drug-induced hepatitis from RIPE therapy — <strong>hold ALL four anti-TB drugs immediately</strong> when AST/ALT &gt;3× ULN with symptoms, or &gt;5× ULN without symptoms. Determine which drug is responsible (usually INH, PZA, or rifampin). After LFTs normalise to &lt;2× ULN, reintroduce sequentially: start with <strong>rifampin</strong> (least hepatotoxic) → add isoniazid after 1 week → consider omitting pyrazinamide if it was the culprit. Monitor LFTs after each reintroduction.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> <strong>Pyrazinamide</strong> is the most hepatotoxic first-line TB drug and the most likely cause if hepatitis occurs in the first 2 months. If PZA cannot be reintroduced, extend treatment duration (9–12 months instead of 6). Baseline LFTs before RIPE therapy and monthly monitoring are essential.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> A mild transient rise in bilirubin in the first 2 weeks of rifampin therapy is common — rifampin competes with bilirubin for hepatic excretion (not true hepatotoxicity). This alone does NOT require stopping treatment. Only a rise in transaminases indicates hepatocellular damage.</div>"}, {"id": "id:fc:6", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "flashcard", "front": "Acyclovir is infused for herpes simplex encephalitis. On day 3, creatinine rises from 0.9 to 2.8 mg/dL. Explain the nephrotoxicity mechanism and how to prevent it.", "back": "Acyclovir crystallises in renal tubules at high concentrations — <strong>crystal nephropathy</strong>. Acyclovir is poorly soluble at physiological urine pH; if the drug concentrates (dehydration, rapid infusion, CKD) it precipitates in the distal tubule and collecting duct → tubular obstruction → AKI. Prevention: <strong>adequate IV hydration</strong> (ensure urine output ≥1 mL/kg/h), infuse each dose over ≥1 hour, avoid concurrent nephrotoxins. Usually reversible with hydration and dose reduction.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Acyclovir resistance in HSV/VZV: most commonly due to mutations in viral <strong>thymidine kinase (TK)</strong> gene → TK-deficient strains cannot phosphorylate acyclovir. Treatment: <strong>foscarnet</strong> (directly inhibits viral DNA polymerase — does not require TK activation) or cidofovir.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Valacyclovir is the oral prodrug of acyclovir (L-valyl ester → acyclovir after first-pass hydrolysis) with ~55% oral bioavailability vs acyclovir's ~10–20%. Same mechanism and toxicity profile — the same dose (in mg of acyclovir equivalent) carries the same crystal nephropathy risk if patient is dehydrated.</div>"}, {"id": "id:fc:7", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "flashcard", "front": "An HIV-positive patient on tenofovir/emtricitabine/efavirenz starts rifampin for TB. His HIV viral load rebounds 4 weeks later. Explain.", "back": "Rifampin is a potent <strong>CYP3A4 and P-gp inducer</strong>. Efavirenz (NNRTI) is a CYP3A4 substrate — rifampin reduces efavirenz AUC by ~25%, potentially falling below therapeutic levels. However, efavirenz is the most rifampin-tolerant NNRTI; the standard approach is to <strong>increase efavirenz dose to 800 mg</strong> (from 600 mg) in patients ≥60 kg. Alternatively, switch to a <strong>double-dose dolutegravir (50 mg BID)</strong> regimen — dolutegravir is induced by rifampin but the higher dose compensates and is currently preferred.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Rifampin + protease inhibitors (PIs): <strong>absolutely contraindicated</strong> — rifampin reduces PI levels by 75–90%, leading to virological failure and resistance. Use <strong>rifabutin</strong> (weaker CYP inducer) instead of rifampin when PI-based ART cannot be changed.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Rifabutin is NOT rifampin — it is a distinct drug with much weaker CYP3A4 induction and can be used alongside most PIs (with rifabutin dose adjustment to 150 mg 3×/week when boosted with ritonavir). Never substitute rifabutin for rifampin in TB treatment without infectious disease input.</div>"}, {"id": "id:fc:8", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "flashcard", "front": "Amphotericin B deoxycholate is started for cryptococcal meningitis. On day 4, K⁺ = 2.6, Mg²⁺ = 0.5, creatinine = 2.9 mg/dL. Explain all three abnormalities.", "back": "All three result from amphotericin B's mechanism: it binds <strong>ergosterol</strong> in fungal membranes forming pores → fungal cell lysis. It also (less avidly) binds <strong>cholesterol</strong> in mammalian cell membranes: (1) Distal tubule pores → <strong>K⁺ and Mg²⁺ wasting</strong> (renal tubular acidosis type 1, distal); (2) Afferent arteriolar vasoconstriction → reduced GFR → <strong>nephrotoxicity</strong>. Prevention: aggressive saline pre-hydration (1 L 0.9% NaCl before each dose), daily electrolyte replacement, consider switching to liposomal amphotericin B (AmBisome) — 5–10× less nephrotoxic.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Liposomal amphotericin B (L-AmB) preferentially distributes to sites of fungal infection (where ergosterol-rich membranes attract liposomes) vs healthy tissues — significantly reduced renal and infusion-related toxicity. Use L-AmB when nephrotoxicity risk is high or CrCl falls below 25 mL/min.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Amphotericin B infusion reactions (fever, chills, rigors 1–3 h after infusion start) are very common (~80%) and NOT the same as nephrotoxicity. Pre-medicate with paracetamol, diphenhydramine, and hydrocortisone. Meperidine (pethidine) is used for severe rigors. These reactions lessen after the first few infusions.</div>"}, {"id": "id:fc:9", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "flashcard", "front": "A patient with P. vivax malaria is treated with chloroquine. To prevent relapse from liver hypnozoites, primaquine is prescribed. Before giving it, you must check one specific test. What and why?", "back": "Check <strong>G6PD activity</strong> before primaquine. Primaquine is an oxidant drug that generates reactive oxygen species — in G6PD-deficient RBCs (unable to replenish NADPH via hexose monophosphate shunt), oxidative stress → Heinz body formation → haemolytic anaemia, potentially severe or fatal. G6PD deficiency is most prevalent in malaria-endemic regions (Africa, Mediterranean, SE Asia, Middle East) — exactly the populations who need radical cure.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Tafenoquine (single-dose 8-aminoquinoline for radical cure) requires <strong>quantitative G6PD testing</strong> (not just qualitative) before use — it causes more severe haemolysis than primaquine at borderline G6PD levels. Tafenoquine is contraindicated if G6PD activity &lt;70% of normal.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> P. falciparum has <strong>NO hypnozoites</strong> — radical cure with primaquine is NOT needed for falciparum malaria. Primaquine is required only for P. vivax and P. ovale (hypnozoite-forming species). Confusing this is a classic exam error.</div>"}, {"id": "id:fc:10", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "flashcard", "front": "A patient on metronidazole for Trichomonas vaginalis infection has a glass of wine at dinner and develops severe flushing, tachycardia, nausea, and headache within 30 minutes. Explain.", "back": "Metronidazole inhibits <strong>aldehyde dehydrogenase (ALDH)</strong> — the enzyme that converts acetaldehyde (from ethanol oxidation) to acetic acid. Acetaldehyde accumulates → causes the <strong>disulfiram-like reaction</strong>: vasodilation, flushing, tachycardia, nausea, headache, hypotension. This is the same mechanism as disulfiram (Antabuse) used in alcohol aversion therapy. Patients must avoid alcohol during metronidazole therapy AND for <strong>48 hours</strong> after the last dose (48–72 h with tinidazole).<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Metronidazole has a broad anaerobic spectrum: C. difficile, Bacteroides fragilis, Giardia, Entamoeba, Trichomonas. It is also the drug of choice for bacterial vaginosis. Long-term use risks peripheral neuropathy and cerebellar ataxia.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Metronidazole + warfarin: metronidazole inhibits <strong>CYP2C9</strong> → reduces warfarin (S-enantiomer) metabolism → significantly elevated INR. This is a genuine and dangerous pharmacokinetic interaction — always check INR and consider reducing warfarin dose when starting metronidazole.</div>"}, {"id": "id:fc:11", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "flashcard", "front": "TMP-SMX is prescribed for Pneumocystis jirovecii pneumonia prophylaxis. The patient develops megaloblastic anaemia and leucopenia after 3 weeks. Explain.", "back": "TMP-SMX doubly blocks folate synthesis: <strong>SMX</strong> inhibits dihydropteroate synthase (DHPS — blocks PABA incorporation into folate); <strong>TMP</strong> inhibits dihydrofolate reductase (DHFR — blocks folate reduction to THF). In bacteria, this is selective because bacterial DHFR has much higher affinity for TMP than human DHFR. However, at high doses or in folate-deficient patients, human DHFR inhibition occurs → impaired thymidylate and purine synthesis → megaloblastic anaemia, neutropenia. Treatment: <strong>folinic acid (leucovorin)</strong> — provides pre-reduced folate, bypassing the DHFR block.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> TMP also blocks K⁺ secretion in the distal nephron (mimics amiloride, an ENaC blocker) → <strong>hyperkalaemia</strong> in CKD patients. Additionally, TMP inhibits renal creatinine secretion (via OCT2 transporter) → <strong>apparent creatinine rise</strong> without true GFR change. Know these renal effects — commonly confused with true AKI.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Use <strong>folinic acid (leucovorin)</strong> — NOT folic acid — to treat TMP-induced megaloblastic anaemia. Folic acid still requires DHFR to be activated (reduced to THF) — blocked by TMP. Folinic acid (5-formyl-THF) bypasses DHFR entirely and directly enters the folate pool.</div>"}, {"id": "id:fc:12", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "flashcard", "front": "Fluconazole fails to clear a Candida krusei bloodstream infection. Why, and what should be used instead?", "back": "Candida krusei is <strong>intrinsically resistant to fluconazole</strong> — it has reduced expression of the azole target enzyme (14α-demethylase/CYP51) and altered membrane composition reducing azole binding. Fluconazole cannot achieve adequate activity regardless of dose. Use: <strong>echinocandin</strong> (caspofungin, micafungin, anidulafungin) — inhibits β-1,3-glucan synthase → cell wall synthesis disruption → fungicidal. Echinocandins are first-line for all invasive candidiasis per IDSA guidelines, particularly for azole-resistant species and critically ill patients.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Candida glabrata (now reclassified as Nakaseomyces glabrata) also has reduced azole susceptibility (acquired resistance via ERG11 mutations and efflux pumps) — echinocandin preferred. Candida auris is resistant to fluconazole AND often to echinocandins — a major emerging pathogen requiring specialist input.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Echinocandins have poor CNS and urine penetration — do NOT use for Candida meningitis or urinary tract candidiasis. Use fluconazole (if susceptible) for UTI candidiasis; liposomal amphotericin B for Candida meningitis.</div>"}, {"id": "id:fc:13", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "flashcard", "front": "Voriconazole is started for invasive aspergillosis. The patient, who is a CYP2C19 poor metaboliser (East Asian ethnicity), develops adverse effects at standard dosing. Why?", "back": "Voriconazole is primarily metabolised by <strong>CYP2C19</strong> (and to a lesser extent CYP3A4, CYP2C9). CYP2C19 <strong>poor metabolisers</strong> (~15–25% of Asians, 3–5% of Caucasians) have ~4× higher voriconazole AUC compared to extensive metabolisers at the same dose → supratherapeutic levels → toxicity (visual disturbances, hepatotoxicity, QT prolongation, periostitis with chronic use, photosensitivity). Therapeutic drug monitoring (TDM) is essential — target trough 1–5.5 µg/mL.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Voriconazole is also a potent inhibitor of CYP3A4, CYP2C9, and CYP2C19 — causing multiple drug interactions. Isavuconazole (newer triazole) has less pharmacokinetic variability, fewer drug interactions, better tolerability, and no QT prolongation (actually mildly shortens QT — watch in patients with short QT syndrome).</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Voriconazole causes transient, reversible visual disturbances (photopsia, altered colour perception, blurred vision) in up to 30% of patients — typically occur within 30 minutes of dosing and resolve spontaneously. These are caused by voriconazole inhibiting retinal CYP enzymes — NOT optic neuritis, and NOT a reason to stop therapy unless severe or persistent.</div>"}, {"id": "id:fc:14", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "flashcard", "front": "A patient with HIV, CD4 count 45 cells/µL, develops fever, headache, neck stiffness, and photophobia. CSF India ink stain is positive. What antibiotic is given, and what specific monitoring parameter prevents a key complication?", "back": "Cryptococcal meningitis — treat with <strong>liposomal amphotericin B + flucytosine (5-FC)</strong> induction × 2 weeks (IDSA/WHO guidelines), then fluconazole consolidation and maintenance. Key complication: <strong>raised intracranial pressure (ICP)</strong> from CSF outflow obstruction by Cryptococcus capsular polysaccharide. Monitor opening pressure at each lumbar puncture — if &gt;25 cmH₂O, perform therapeutic LP (drain 10–30 mL CSF) daily until pressure normalises. Mortality from cryptococcal meningitis is largely driven by uncontrolled elevated ICP, not antifungal failure.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Flucytosine (5-FC) mechanism: enters fungal cells via cytosine permease → converted to 5-fluorouracil (5-FU) → inhibits thymidylate synthase → impairs fungal DNA synthesis. Monitor flucytosine levels (target 25–100 µg/mL peak) and CBC (bone marrow suppression risk, especially with renal failure).</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Do NOT give acetazolamide, steroids, or mannitol for cryptococcal meningitis ICP — only therapeutic LPs reduce fungal burden-related ICP effectively. Steroids are not indicated in cryptococcal meningitis (unlike bacterial meningitis where dexamethasone reduces mortality).</div>"}, {"id": "id:fc:15", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "flashcard", "front": "Oseltamivir is given 24 hours after influenza symptom onset. A colleague says it is too late. Is this correct?", "back": "Only partially. Oseltamivir (neuraminidase inhibitor → prevents viral release from infected cells) reduces illness duration by ~1 day and severity if started <strong>within 48 hours</strong> of symptom onset in otherwise healthy adults — modest benefit after 48 h. However, in <strong>high-risk patients</strong> (hospitalised, immunocompromised, elderly, pregnant, severe obesity, underlying cardiopulmonary disease) oseltamivir provides benefit beyond 48 hours and should be given regardless of symptom duration. At 24 hours, it is definitely appropriate to treat.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Oseltamivir covers influenza A AND B. <strong>Baloxavir marboxil</strong> (cap-dependent endonuclease inhibitor, single dose) — novel mechanism, non-inferior to oseltamivir, active against oseltamivir-resistant strains. Amantadine/rimantadine (M2 ion channel blockers) — only influenza A, high resistance rates, essentially obsolete.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Oseltamivir does NOT treat RSV, SARS-CoV-2, or other respiratory viruses — it is influenza-specific. Also: oseltamivir resistance (H275Y mutation in H1N1 neuraminidase) → use zanamivir (inhaled) or baloxavir for oseltamivir-resistant strains.</div>"}, {"id": "id:fc:16", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "flashcard", "front": "Doxycycline is prescribed for community-acquired pneumonia in a 10-year-old child. The parent objects citing 'teeth damage.' How do you respond?", "back": "The concern about tetracycline and teeth applies to <strong>children under 8 years</strong> — during active dentinogenesis, tetracyclines chelate calcium → incorporated into developing teeth and bone → permanent yellow-brown discolouration and enamel hypoplasia. <strong>Doxycycline</strong> chelates calcium far less avidly than older tetracyclines (oxytetracycline, demeclocycline) → significantly lower risk of dental staining. The <strong>AAP revised its guidance in 2012</strong>: doxycycline is acceptable in children ≥8 years and permissible even in younger children for short courses (&lt;21 days) when benefits outweigh risks (e.g., Rocky Mountain spotted fever — where delay is fatal).<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Doxycycline covers atypical CAP pathogens (Mycoplasma, Chlamydophila, Legionella) as well as typical bacteria — a key advantage over beta-lactams (which miss atypicals). For walking pneumonia in outpatients, doxycycline is a preferred agent.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Tetracyclines cause <strong>photosensitivity</strong> — advise sunscreen. They are contraindicated in pregnancy throughout (foetal bone/teeth effects). Doxycycline also causes oesophageal ulceration if taken without adequate water — remain upright for 30 min after dosing.</div>"}, {"id": "id:fc:17", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "flashcard", "front": "A 68-year-old woman with bacteraemic UTI due to ESBL-producing E. coli is on ciprofloxacin empirically, but sensitivity testing shows resistance. What antibiotic class is now first-line for ESBL infections?", "back": "<strong>Carbapenems</strong> (meropenem, ertapenem, imipenem-cilastatin) are the treatment of choice for serious ESBL-producing Enterobacteriaceae infections. ESBL (extended-spectrum beta-lactamases) hydrolyse penicillins, cephalosporins (including 3rd and 4th generation), and aztreonam — but NOT carbapenems. For less severe ESBL-UTI without bacteraemia, pivmecillinam or fosfomycin may be options based on susceptibility, but carbapenems remain gold standard for systemic infections.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Carbapenemase-producing Enterobacteriaceae (CPE/CRE) — resistant to ALL carbapenems. Treatment options: ceftazidime-avibactam (KPC, OXA-48, some MBLs), ceftolozane-tazobactam (Pseudomonas), meropenem-vaborbactam (KPC), aztreonam-avibactam (MBL). These combinations are increasingly needed — requires microbiology and ID input.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Piperacillin-tazobactam (PTZ) is often reported as 'sensitive' against ESBL producers in vitro — but clinical outcomes are significantly worse than carbapenems in ESBL bacteraemia (MERINO trial: PTZ inferior to meropenem, higher mortality). Do NOT use PTZ as definitive therapy for ESBL bacteraemia even if sensitive in vitro.</div>"}, {"id": "id:fc:18", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "flashcard", "front": "A patient with HIV (CD4 50 cells/µL) develops progressive weakness, visual loss, and cognitive decline over 3 months. Brain MRI shows multifocal demyelinating white matter lesions with no mass effect. What is the diagnosis and its pharmacological association?", "back": "<strong>Progressive multifocal leukoencephalopathy (PML)</strong> — caused by reactivation of <strong>JC virus</strong> (John Cunningham polyomavirus) in the CNS of profoundly immunocompromised patients. Associated with: (1) Advanced HIV (low CD4); (2) <strong>Natalizumab</strong> (anti-α4 integrin, used for MS/Crohn's) — blocks lymphocyte CNS entry → JC virus reactivation in brain; (3) Rituximab, efalizumab, other immunosuppressants. Treatment: <strong>immune reconstitution</strong> is the only effective therapy — start or optimise ART for HIV-PML. For natalizumab-PML: stop the drug; immune reconstitution inflammatory syndrome (IRIS) may paradoxically worsen before improving.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> JC virus serology (anti-JCV antibody index) is used for risk stratification before natalizumab initiation. High antibody index + natalizumab &gt;24 months + prior immunosuppressant = very high PML risk → consider switching to a safer alternative (ocrelizumab, ofatumumab).</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> PML lesions on MRI are non-enhancing (no blood-brain barrier breakdown, no mass effect) — unlike CNS lymphoma (ring-enhancing) or toxoplasmosis (ring-enhancing, mass effect). Toxoplasmosis in HIV is ring-enhancing, responds to empirical pyrimethamine + sulfadiazine + folinic acid.</div>"}, {"id": "id:fc:19", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "flashcard", "front": "Nitrofurantoin is prescribed for a UTI in a woman with eGFR 25 mL/min. The pharmacist contacts you to discuss the prescription. What is the concern?", "back": "Nitrofurantoin requires renal excretion to achieve <strong>therapeutic urinary concentrations</strong>. In significant CKD (eGFR &lt;30 mL/min): (1) Urinary nitrofurantoin levels fall below therapeutic range → <strong>treatment failure</strong>; (2) Systemic metabolites accumulate → toxicity: pulmonary fibrosis, peripheral neuropathy, hepatotoxicity, haemolytic anaemia. Nitrofurantoin is therefore <strong>contraindicated when eGFR &lt;30 mL/min</strong> (some guidelines say &lt;45 for prophylaxis). Use fosfomycin trometamol (single dose) or trimethoprim (with K⁺ monitoring) as alternatives.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Nitrofurantoin ONLY treats <em>lower</em> UTI (cystitis) — it does NOT achieve therapeutic levels in renal parenchyma, blood, or tissues. Never use for pyelonephritis, bacteraemia, or any upper urinary tract infection. Resistance rates remain low (&lt;3%) because resistance requires simultaneous loss of multiple nitroreductase enzymes.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Nitrofurantoin can cause acute (type I hypersensitivity — eosinophilic pneumonitis, rapid onset, reversible) or chronic (fibrotic, insidious, may be irreversible) pulmonary reactions. Monitor for new cough or dyspnoea, especially in patients on long-term prophylaxis.</div>"}, {"id": "id:q:0", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "Name the three PK/PD indices that guide antibiotic efficacy.", "back": "Cmax/MIC (concentration-dependent), T&gt;MIC (time-dependent), and AUC/MIC (exposure-dependent)."}, {"id": "id:q:1", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "Which PK/PD index governs β-lactam efficacy?", "back": "T&gt;MIC (Time above Minimum Inhibitory Concentration)."}, {"id": "id:q:2", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "What is the clinical dosing strategy for concentration-dependent killers like aminoglycosides?", "back": "High-dose, once-daily administration."}, {"id": "id:q:3", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "What does a high Post-Antibiotic Effect (PAE) mean?", "back": "Bacterial growth remains suppressed even after drug levels fall below the MIC."}, {"id": "id:q:4", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "Name the four principal mechanisms of bacterial resistance.", "back": "Enzymatic drug inactivation, target site modification, reduced permeability (porin loss), and active efflux."}, {"id": "id:q:5", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "Why is a bactericidal agent mandatory in endocarditis and meningitis?", "back": "The host immune system cannot assist in clearing the bacteria at these privileged sites."}, {"id": "id:q:6", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "Which enzyme is blocked by Sulfonamides (e.g. Sulfamethoxazole)?", "back": "Dihydropteroate synthase (DHPS)."}, {"id": "id:q:7", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "Which enzyme is blocked by Trimethoprim?", "back": "Dihydrofolate reductase (DHFR)."}, {"id": "id:q:8", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "Why is the combination of TMP and SMX synergistic?", "back": "It causes sequential blockade of the tetrahydrofolate synthesis pathway."}, {"id": "id:q:9", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "Why is Bactrim contraindicated in neonates?", "back": "It displaces bilirubin from albumin, raising free bilirubin and causing kernicterus."}, {"id": "id:q:10", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "What electrolyte abnormality is associated with trimethoprim use?", "back": "Hyperkalemia (TMP blocks renal ENaC channels, mimicking amiloride)."}, {"id": "id:q:11", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "What is the target of fluoroquinolones in Gram-negative bacteria?", "back": "DNA gyrase (blocks relaxation of supercoiled DNA)."}, {"id": "id:q:12", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "What is the target of fluoroquinolones in Gram-positive bacteria?", "back": "Topoisomerase IV (prevents decatenation of sister chromosomes)."}, {"id": "id:q:13", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "Name three major musculoskeletal or cardiovascular side effects of fluoroquinolones.", "back": "Tendonitis/tendon rupture, QTc prolongation, and aortic dissection/aneurysm."}, {"id": "id:q:14", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "Why are fluoroquinolones contraindicated in pediatric patients?", "back": "They cause articular cartilage toxicity (chondrotoxicity)."}, {"id": "id:q:15", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "Mechanism of metronidazole activation?", "back": "Its nitro group is reduced by PFOR in anaerobic cells to form toxic free radicals."}, {"id": "id:q:16", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "Why must patients avoid alcohol while on metronidazole?", "back": "It blocks aldehyde dehydrogenase, causing a severe disulfiram-like reaction."}, {"id": "id:q:17", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "How does sulfamethoxazole interact with warfarin?", "back": "It inhibits CYP2C9, raising warfarin concentrations and INR."}, {"id": "id:q:18", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "Which genetic deficiency puts a patient at risk for hemolytic anemia on Bactrim?", "back": "G6PD deficiency."}, {"id": "id:q:19", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "Why do anaerobes resist aminoglycosides but succumb to metronidazole?", "back": "Aminoglycoside uptake is oxygen-dependent (which anaerobes lack); metronidazole activation requires anaerobic PFOR metabolism."}, {"id": "id:q:20", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "What is the target of all β-lactam antibiotics?", "back": "Penicillin-Binding Proteins (PBPs), inhibiting transpeptidation (cross-linking)."}, {"id": "id:q:21", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "How does MRSA resist β-lactams?", "back": "Acquisition of the mecA gene, which encodes PBP2a (low affinity for β-lactams)."}, {"id": "id:q:22", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "Which cephalosporin generation covers Pseudomonas aeruginosa?", "back": "3rd generation (specifically Ceftazidime) and 4th generation (Cefepime)."}, {"id": "id:q:23", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "Which cephalosporin covers MRSA?", "back": "5th generation Ceftaroline."}, {"id": "id:q:24", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "What is the unique spectrum of Aztreonam?", "back": "Gram-negative aerobic bacteria only (no Gram-positive or anaerobic activity)."}, {"id": "id:q:25", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "Why is aztreonam safe in patients with a penicillin anaphylaxis history?", "back": "It lacks cross-reactivity with other β-lactams due to its monobactam structure (except Ceftazidime)."}, {"id": "id:q:26", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "Mechanism of action of Vancomycin?", "back": "Binds directly to the D-Ala-D-Ala terminus of peptidoglycan monomers, blocking transglycosylation."}, {"id": "id:q:27", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "How do Enterococci resist Vancomycin (VRE)?", "back": "They alter the terminal peptide chain from D-Ala-D-Ala to D-Ala-D-Lac (VanA/B genes)."}, {"id": "id:q:28", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "What is the mechanism of Red Man Syndrome with vancomycin?", "back": "Direct, non-immune degranulation of mast cells, causing histamine release during rapid infusion."}, {"id": "id:q:29", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "Why is Daptomycin inactivated in the lungs?", "back": "It binds to pulmonary surfactant, preventing insertion into bacterial membranes."}, {"id": "id:q:30", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "What laboratory parameter must be monitored weekly in a patient on daptomycin?", "back": "Creatine Phosphokinase (CPK) due to the risk of myopathy."}, {"id": "id:q:31", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "Name two antibiotic classes that bind the 30S ribosomal subunit.", "back": "Aminoglycosides and Tetracyclines."}, {"id": "id:q:32", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "What is the primary mechanism of action of Aminoglycosides?", "back": "Irreversible binding to the 30S subunit, leading to mRNA misreading and protein synthesis termination."}, {"id": "id:q:33", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "List two irreversible toxicities associated with aminoglycosides.", "back": "Ototoxicity (vestibulotoxicity and cochleotoxicity) and neuromuscular blockade."}, {"id": "id:q:34", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "Why must tetracyclines be avoided in pregnant women and children under 8?", "back": "They chelate calcium, depositing in teeth (staining) and inhibiting bone growth."}, {"id": "id:q:35", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "Mechanism of action of macrolides?", "back": "Bind to the 50S ribosomal subunit (23S rRNA), blocking peptidyltransferase and translocation."}, {"id": "id:q:36", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "Which macrolide does NOT inhibit CYP3A4?", "back": "Azithromycin."}, {"id": "id:q:37", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "Why does Clindamycin carry a high-yield warning for pseudomembranous colitis?", "back": "It kills gut anaerobes, facilitating overgrowth of toxigenic Clostridioides difficile."}, {"id": "id:q:38", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "What is the mechanism of Linezolid-induced Serotonin Syndrome?", "back": "Linezolid is a weak, reversible monoamine oxidase inhibitor (MAOI), leading to excess serotonin."}, {"id": "id:q:39", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "What is the target of Polymyxins?", "back": "Lipid A of LPS in the outer membrane of Gram-negative bacteria."}, {"id": "id:q:40", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "How does Amphotericin B damage fungal cell membranes?", "back": "It binds directly to ergosterol, forming transmembrane pores that leak ions."}, {"id": "id:q:41", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "How can amphotericin-induced renal injury be mitigated?", "back": "Pre-infusion saline loading (sodium loading)."}, {"id": "id:q:42", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "What is the target of Flucytosine?", "back": "It is converted to 5-FU in fungal cells, inhibiting thymidylate synthase and DNA synthesis."}, {"id": "id:q:43", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "What enzyme is inhibited by azole antifungals?", "back": "Fungal 14α-demethylase (CYP51), preventing lanosterol to ergosterol conversion."}, {"id": "id:q:44", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "Which azole is notorious for causing transient visual disturbances?", "back": "Voriconazole."}, {"id": "id:q:45", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "What is the mechanism of action of Echinocandins (e.g. Caspofungin)?", "back": "Inhibition of β-(1,3)-D-glucan synthase, disrupting fungal cell wall structure."}, {"id": "id:q:46", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "Which azole is an exception and shortens the QTc interval?", "back": "Isavuconazole."}, {"id": "id:q:47", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "Why is valacyclovir preferred over acyclovir for oral therapy?", "back": "It is a prodrug with significantly higher oral bioavailability."}, {"id": "id:q:48", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "How is acyclovir activated inside host cells?", "back": "It is first phosphorylated by viral thymidine kinase (TK) into acyclovir monophosphate."}, {"id": "id:q:49", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "Why does acyclovir cause renal dysfunction, and how is it prevented?", "back": "It precipitates as crystals in renal tubules; prevent with aggressive IV hydration."}, {"id": "id:q:50", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "Which viral kinase activates ganciclovir in CMV-infected cells?", "back": "UL97 kinase."}, {"id": "id:q:51", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "What is the dose-limiting toxicity of ganciclovir?", "back": "Bone marrow suppression (leukopenia, neutropenia)."}, {"id": "id:q:52", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "What drug is used for acyclovir-resistant HSV, and why does it bypass resistance?", "back": "Foscarnet or Cidofovir; they do not require viral thymidine kinase phosphorylation."}, {"id": "id:q:53", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "What is the mechanism of action of Oseltamivir?", "back": "Inhibits viral neuraminidase, preventing the release of new virions from host cells."}, {"id": "id:q:54", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "What is the target of Baloxavir marboxil?", "back": "Viral cap-dependent endonuclease, blocking viral transcription."}, {"id": "id:q:55", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "How do chronic HBV drugs differ from chronic HCV drugs regarding cure rates?", "back": "HBV therapy is suppressive (due to cccDNA); HCV therapy is curative (DAAs clear viral RNA)."}, {"id": "id:q:56", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "Name the class and target of Glecaprevir.", "back": "NS3/4A protease inhibitor in HCV."}, {"id": "id:q:57", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "Name the class and target of Ledipasvir or Velpatasvir.", "back": "NS5A replication complex inhibitor in HCV."}, {"id": "id:q:58", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "Name the class and target of Sofosbuvir.", "back": "NS5B RNA-dependent RNA polymerase inhibitor in HCV."}, {"id": "id:q:59", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "Why is Sofosbuvir referred to as a \"nuke\" analogue for HCV?", "back": "It acts as a chain terminator during HCV RNA replication."}, {"id": "id:q:60", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "What is the standard configuration of a first-line ART regimen?", "back": "2 NRTIs (nucleoside backbones) + 1 Integrase inhibitor (INSTI)."}, {"id": "id:q:61", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "How do NRTIs cause chain termination of viral DNA?", "back": "They are nucleoside analogues lacking a 3'-OH group, preventing the addition of the next nucleotide."}, {"id": "id:q:62", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "What gene must be tested before starting Abacavir?", "back": "HLA-B*5701 (prevent fatal hypersensitivity)."}, {"id": "id:q:63", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "What is the difference in side effects between Tenofovir Disoproxil Fumarate (TDF) and Tenofovir Alafenamide (TAF)?", "back": "TDF has higher plasma levels and cause more renal impairment and bone density loss; TAF has lower plasma levels (enters cells more efficiently)."}, {"id": "id:q:64", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "What class is Efavirenz, and what is its mechanism?", "back": "NNRTI; binds allosterically to reverse transcriptase."}, {"id": "id:q:65", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "State two major side effects of Efavirenz.", "back": "Neuropsychiatric symptoms (vivid dreams, insomnia, depression) and teratogenicity."}, {"id": "id:q:66", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "Name three integrase strand transfer inhibitors (INSTIs).", "back": "Dolutegravir, Bictegravir, and Raltegravir."}, {"id": "id:q:67", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "What is the target of protease inhibitors?", "back": "The viral protease enzyme (pol), preventing cleavage of Gag-Pol polyproteins."}, {"id": "id:q:68", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "List three metabolic complications of protease inhibitors.", "back": "Hyperlipidemia, insulin resistance, and lipodystrophy (buffalo hump)."}, {"id": "id:q:69", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "Why is Ritonavir or Cobicistat added to protease inhibitor regimens?", "back": "They inhibit host CYP3A4, boosting the levels of the protease inhibitor (e.g. Darunavir)."}, {"id": "id:q:70", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "What is the mechanism of action of Maraviroc?", "back": "It is a CCR5 co-receptor antagonist, preventing viral gp120 binding."}, {"id": "id:q:71", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "What test is required before initiating Maraviroc?", "back": "A tropism assay (to confirm the virus uses the CCR5 receptor)."}, {"id": "id:q:72", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "What is the mechanism of action of Enfuvirtide?", "back": "It binds gp41, blocking the fusion of the viral envelope with the host membrane."}, {"id": "id:q:73", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "Which NRTI is associated with macrocytic anemia?", "back": "Zidovudine (AZT)."}, {"id": "id:q:74", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "What toxicity is common to all NRTIs due to mitochondrial inhibition?", "back": "Lactic acidosis and hepatic steatosis."}, {"id": "id:q:75", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "What class of antiretrovirals is associated with significant clinical weight gain?", "back": "Integrase inhibitors (INSTIs like dolutegravir)."}, {"id": "id:q:76", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "Why should antacids containing divalent cations be separated from INSTIs?", "back": "Divalent cations chelate INSTIs, reducing their absorption and efficacy."}, {"id": "id:q:77", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "Which protease inhibitor is associated with unconjugated hyperbilirubinemia?", "back": "Atazanavir (inhibits UGT1A1 enzyme, mimicking Gilbert syndrome)."}, {"id": "id:q:78", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "Why is dual therapy (like Dolutegravir + Lamivudine) now sometimes used?", "back": "To reduce drug exposure and toxicities, while maintaining efficacy in patients with no baseline resistance."}, {"id": "id:q:79", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "What is the primary role of gp120 vs gp41 in HIV cell entry?", "back": "gp120 binds to CD4 and chemokine co-receptors; gp41 mediates the physical fusion of membranes."}, {"id": "id:q:80", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "How is Isoniazid (INH) activated in Mycobacterium tuberculosis?", "back": "By the bacterial catalase-peroxidase enzyme, KatG."}, {"id": "id:q:81", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "What is the target of activated Isoniazid?", "back": "InhA (enoyl-ACP reductase), inhibiting mycolic acid synthesis."}, {"id": "id:q:82", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "Why is Pyridoxine (Vit B6) co-prescribed with Isoniazid?", "back": "To prevent INH-induced peripheral neuropathy (due to functional B6 depletion)."}, {"id": "id:q:83", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "What is the mechanism of action of Rifampin?", "back": "Inhibition of bacterial DNA-dependent RNA polymerase, blocking transcription."}, {"id": "id:q:84", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "What is a key patient counseling point regarding Rifampin's physical effects?", "back": "It causes benign orange-red discoloration of body fluids (urine, sweat, tears)."}, {"id": "id:q:85", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "Why is rifampin notorious for drug interactions?", "back": "It is a highly potent CYP inducer (speeds up clearance of other drugs)."}, {"id": "id:q:86", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "Where is Pyrazinamide most pharmacologically active?", "back": "In acidic environments (specifically within the phagosomes of host macrophages)."}, {"id": "id:q:87", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "Name a unique metabolic side effect of Pyrazinamide.", "back": "Hyperuricemia, which can precipitate acute gouty arthritis."}, {"id": "id:q:88", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "What is the key side effect of Ethambutol, and how is it monitored?", "back": "Optic neuritis (decreased visual acuity, red-green color blindness); monitor with visual acuity tests."}, {"id": "id:q:89", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "What drugs constitute the standard first-line regimen for leprosy?", "back": "Dapsone, Rifampin, and Clofazimine."}, {"id": "id:q:90", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "What is the mechanism of action of Artemisinins?", "back": "Heme iron cleaves their endoperoxide bridge, generating free radicals that alkylate parasite proteins."}, {"id": "id:q:91", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "How does Chloroquine kill Plasmodium parasites?", "back": "It blocks heme crystallization into hemozoin, letting free heme accumulate and lyse the parasite vacuole."}, {"id": "id:q:92", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "Which drug must be added to cure liver hypnozoites in P. vivax malaria?", "back": "Primaquine or Tafenoquine."}, {"id": "id:q:93", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "Why must G6PD deficiency be ruled out before starting Primaquine?", "back": "It generates oxidative stress in RBCs, causing acute intravascular hemolysis in G6PD-deficient hosts."}, {"id": "id:q:94", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "Name a common anti-malarial used for prophylaxis that has severe neuropsychiatric side effects.", "back": "Mefloquine."}, {"id": "id:q:95", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "What is the mechanism of action of Albendazole?", "back": "Inhibition of parasite β-tubulin polymerization, blocking microtubule assembly."}, {"id": "id:q:96", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "What is the mechanism of action of Ivermectin?", "back": "Activation of glutamate-gated chloride channels, causing hyperpolarization and flaccid paralysis of the parasite."}, {"id": "id:q:97", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "How does Praziquantel act against schistosomes?", "back": "It increases calcium influx, causing spastic muscle contraction and tegumental damage."}, {"id": "id:q:98", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "Why is Metronidazole useful in treating Entamoeba histolytica?", "back": "It is an anaerobic protozoan that contains PFOR to activate metronidazole into DNA-shredding radicals."}, {"id": "id:q:99", "deck": "Infectious Disease & Chemotherapy", "dk": "id", "type": "quiz", "front": "What is the role of Clavulanate or Avibactam when combined with β-lactams?", "back": "They act as β-lactamase inhibitors, protecting the active antibiotic from enzymatic destruction."}, {"id": "neo:fc:0", "deck": "Neoplastic Disease", "dk": "neo", "type": "flashcard", "front": "A patient with CML has a BCR-ABL fusion gene and a white cell count of 280 ×10⁹/L. Imatinib is started. Explain the mechanism and why resistance with T315I mutation renders imatinib ineffective.", "back": "Imatinib is a <strong>tyrosine kinase inhibitor (TKI)</strong> that occupies the ATP-binding pocket of BCR-ABL kinase, locking it in the inactive conformation → prevents phosphorylation of downstream substrates (RAS, PI3K, STAT5) → blocks proliferation and promotes apoptosis in CML cells. <strong>T315I mutation</strong> (threonine → isoleucine at residue 315, the 'gatekeeper' residue): isoleucine adds a bulky side chain that clashes sterically with imatinib and also removes a critical hydrogen bond between imatinib and the kinase → imatinib cannot bind → resistance. T315I also confers resistance to dasatinib and nilotinib. <strong>Ponatinib</strong> (3rd-generation TKI) was specifically designed to accommodate the T315I mutation and is the treatment of choice.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Imatinib also inhibits c-Kit and PDGFR — hence its use in GIST (gastrointestinal stromal tumour, KIT-driven) and dermatofibrosarcoma protuberans (PDGFR-driven). Asciminib is a novel 'STAMP' inhibitor targeting the myristoyl pocket of ABL (not the ATP pocket) — active against T315I.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> CML has three phases: chronic → accelerated → blast crisis. Imatinib in chronic phase achieves major molecular response in ~80%. Philadelphia chromosome (t(9;22)) is present in ~95% of CML AND ~30% of ALL (Ph+ ALL). Ph+ ALL requires TKI + chemotherapy ± stem cell transplant — different management from CML.</div>"}, {"id": "neo:fc:1", "deck": "Neoplastic Disease", "dk": "neo", "type": "flashcard", "front": "A 55-year-old woman with HER2-positive breast cancer is treated with trastuzumab. After 6 months she develops reduced LVEF and heart failure. Explain the mechanism of cardiotoxicity and how it differs from anthracycline cardiotoxicity.", "back": "Trastuzumab (anti-HER2 monoclonal antibody) blocks HER2 signalling. <strong>HER2 (ErbB2)</strong> is essential for cardiomyocyte survival and stress response — it activates PI3K/Akt survival pathways in response to mechanical stress. Trastuzumab-induced HER2 blockade → cardiomyocytes cannot mount adaptive responses to stress → contractile dysfunction. Key distinction from anthracyclines: <strong>Trastuzumab cardiotoxicity</strong> is type II — NOT cumulative dose-dependent, NOT associated with myocyte necrosis or ultrastructural damage, largely <strong>reversible</strong> with cessation and cardiac therapy (usually recovers in 2–4 months). <strong>Anthracycline cardiotoxicity</strong> is type I — cumulative dose-dependent (risk rises sharply above 450 mg/m² doxorubicin), involves ROS-mediated myocyte necrosis, irreversible fibrosis.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Monitor LVEF before trastuzumab, every 3 months during therapy. Hold trastuzumab if LVEF falls ≥10 percentage points or falls below 50%. Restart after recovery. Concurrent use of anthracyclines + trastuzumab (synchronous) is generally avoided — sequential administration is standard.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Pertuzumab (anti-HER2, different epitope from trastuzumab) + trastuzumab is dual HER2 blockade — standard in HER2+ metastatic breast cancer and neoadjuvant HER2+ early breast cancer. Ado-trastuzumab emtansine (T-DM1) is an antibody-drug conjugate delivering DM1 (microtubule inhibitor) specifically to HER2+ cells — active in trastuzumab-resistant disease.</div>"}, {"id": "neo:fc:2", "deck": "Neoplastic Disease", "dk": "neo", "type": "flashcard", "front": "Cisplatin is given for testicular cancer. The patient develops tinnitus and bilateral high-frequency hearing loss after the third cycle. What is the mechanism, and what renal toxicity requires specific prevention?", "back": "<strong>Ototoxicity:</strong> cisplatin accumulates in cochlear outer hair cells and stria vascularis → forms platinum-DNA adducts + generates ROS → irreversible outer hair cell death → permanent high-frequency sensorineural hearing loss (tinnitus is often the first symptom). <strong>Nephrotoxicity:</strong> cisplatin is filtered and concentrated in proximal tubular cells → platinum-DNA adducts + oxidative stress → proximal tubule necrosis → AKI (most common dose-limiting toxicity). Prevention: <strong>aggressive IV hydration</strong> (1–2 L 0.9% NaCl before and after each dose), ensure urine output &gt;100 mL/hr, mannitol diuresis, avoid concurrent NSAIDs/aminoglycosides. Amifostine (free-radical scavenger) can reduce nephrotoxicity and neuropathy — used selectively.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Cisplatin causes a characteristic <strong>hypomagnesaemia</strong> (renal magnesium wasting — tubular damage → impaired Mg²⁺ reabsorption) and hypokalaemia — may persist for months after treatment ends. Check Mg²⁺ and replace aggressively. Cisplatin-induced hypomagnesaemia can itself cause hypocalcaemia (Mg²⁺ required for PTH secretion).</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Carboplatin is a platinum analogue with significantly lower nephrotoxicity and ototoxicity — it is dosed by AUC using the Calvert formula (dose = AUC × [GFR + 25]). Carboplatin's dose-limiting toxicity is <strong>myelosuppression</strong> (thrombocytopenia &gt; neutropenia), not nephrotoxicity. Oxaliplatin causes distinctive cold-triggered peripheral neuropathy and is used in colorectal cancer.</div>"}, {"id": "neo:fc:3", "deck": "Neoplastic Disease", "dk": "neo", "type": "flashcard", "front": "A patient with BRAF V600E-mutant metastatic melanoma is started on vemurafenib (BRAF inhibitor). Three months later, a new squamous cell carcinoma (SCC) appears on her arm. Explain this paradoxical toxicity.", "back": "Paradoxical <strong>cutaneous squamous cell carcinoma</strong> (and keratoacanthoma) is a class effect of BRAF V600E inhibitors (vemurafenib, dabrafenib). Mechanism: in melanoma, BRAF V600E constitutively activates the MAPK pathway (BRAF → MEK → ERK). In normal keratinocytes with wild-type RAS mutations (present in ~60% of pre-malignant keratinocytes), BRAF inhibition paradoxically causes <strong>transactivation of CRAF</strong> → amplified MAPK signalling through the RAS-CRAF axis → accelerated keratinocyte proliferation → SCC induction. Prevention: combining a <strong>MEK inhibitor (trametinib)</strong> with the BRAF inhibitor blocks the downstream paradoxical MAPK activation → reduces cutaneous SCC incidence (and also improves anti-tumour efficacy — dual BRAF+MEK blockade is now standard).<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Dabrafenib + trametinib is the standard BRAF-targeted regimen for BRAF V600E/K metastatic melanoma. Also approved in BRAF V600E NSCLC, anaplastic thyroid cancer, and biliary tract cancer. Encorafenib + binimetinib is an alternative with a better tolerability profile (less pyrexia).</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> BRAF inhibitors ONLY work when the BRAF V600E/K mutation is present — they are INEFFECTIVE (and potentially harmful) in BRAF wild-type tumours or in colorectal cancer with BRAF V600E (due to EGFR-mediated feedback re-activation of MAPK — requires triple combination: BRAF + MEK + EGFR inhibition).</div>"}, {"id": "neo:fc:4", "deck": "Neoplastic Disease", "dk": "neo", "type": "flashcard", "front": "A patient with metastatic NSCLC has an EGFR exon 19 deletion. Osimertinib is started as first-line therapy. What is the mechanism, and why is osimertinib preferred over first-generation EGFR TKIs (erlotinib, gefitinib)?", "back": "Osimertinib is a <strong>3rd-generation, irreversible EGFR TKI</strong> that covalently binds Cys797 in the EGFR kinase domain → permanently inhibits EGFR (including T790M-mutant EGFR). Exon 19 deletions (and exon 21 L858R substitution) are activating EGFR mutations — constitutive EGFR kinase activity drives tumour proliferation. Advantages over 1st-gen TKIs (erlotinib, gefitinib): (1) <strong>T790M resistance mutation</strong> — the most common resistance mechanism to 1st-gen TKIs (70%) — osimertinib retains full activity against T790M; (2) Superior <strong>CNS penetration</strong> (critical given 25–40% of EGFR-mutant NSCLC develop brain metastases); (3) FLAURA trial demonstrated longer PFS and OS vs 1st-gen TKIs as first-line therapy.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Osimertinib resistance mechanisms: C797S mutation (abolishes covalent binding), MET amplification, HER2 amplification, histological transformation to SCLC. For acquired resistance, re-biopsy or liquid biopsy (ctDNA) to identify the mechanism guides next therapy.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> EGFR TKIs cause a characteristic <strong>acneiform rash</strong> (papulopustular, folliculocentric — different from acne vulgaris) on face/chest/back. Paradoxically, rash severity correlates positively with tumour response. Manage with topical clindamycin/tetracycline; severe rash → doxycycline + dose interruption. Also causes diarrhoea and paronychia (nail fold inflammation).</div>"}, {"id": "neo:fc:5", "deck": "Neoplastic Disease", "dk": "neo", "type": "flashcard", "front": "A patient with ALL is receiving high-dose methotrexate. 48 hours after infusion, MTX level is dangerously elevated and creatinine is rising. What is the antidote and its mechanism?", "back": "<strong>Glucarpidase (carboxypeptidase G2)</strong> — a bacterial enzyme that cleaves MTX into inactive metabolites (DAMPA + glutamate) in the plasma. It rapidly reduces plasma MTX levels by &gt;98% within 15 minutes. Mechanism: carboxypeptidase G2 hydrolyses the C-terminal glutamate of MTX → DAMPA (which does not inhibit DHFR and is rapidly cleared). Used when MTX levels are dangerously elevated AND standard leucovorin rescue is insufficient (usually indicated when MTX &gt;1 µmol/L at 42 h in a patient with AKI). <strong>Continue leucovorin (folinic acid)</strong> alongside glucarpidase — leucovorin rescues cells that have taken up MTX by providing pre-reduced folate bypassing the DHFR block.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> High-dose MTX requires <strong>leucovorin rescue</strong> starting 24 hours after MTX infusion — leucovorin (folinic acid, 5-formyl-THF) enters the folate pool directly without requiring DHFR → rescues normal cells. Alkalinise urine (sodium bicarbonate IV) to keep pH &gt;7 — MTX is more soluble at alkaline pH, preventing tubular precipitation and the AKI that delays clearance.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> After glucarpidase, do NOT measure plasma MTX levels for 48 hours — glucarpidase interferes with standard MTX immunoassays (DAMPA cross-reacts) → falsely low readings. Use an alternative assay (HPLC) or wait until glucarpidase is cleared. Continue leucovorin doses based on the pre-glucarpidase level.</div>"}, {"id": "neo:fc:6", "deck": "Neoplastic Disease", "dk": "neo", "type": "flashcard", "front": "A 60-year-old man with multiple myeloma receives bortezomib. He develops a painful vesicular rash in a dermatomal distribution on his trunk. What happened and how is it prevented?", "back": "Bortezomib-induced <strong>herpes zoster (shingles) reactivation</strong>. Bortezomib is a <strong>proteasome inhibitor</strong> (reversible inhibitor of the 26S proteasome's chymotryptic-like activity) → blocks ubiquitin-proteasome degradation of regulatory proteins → accumulation of pro-apoptotic proteins (p21, p27, IκB) → malignant plasma cell death. However, proteasome inhibition also suppresses T-cell immune surveillance → reactivation of latent varicella-zoster virus (VZV) in dorsal root ganglia → shingles. Prevention: <strong>prophylactic antiviral therapy</strong> (acyclovir 400 mg BD or valacyclovir 500 mg OD) is mandatory for ALL patients receiving bortezomib — started before treatment and continued throughout.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Bortezomib also causes <strong>peripheral neuropathy</strong> (painful, predominantly sensory, dose-limiting) — due to proteasome inhibition in sensory neurons leading to ER stress and axonal dysfunction. Subcutaneous administration significantly reduces neuropathy vs IV (same efficacy). Carfilzomib (irreversible proteasome inhibitor) causes less neuropathy but more cardiovascular toxicity (hypertension, HF).</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Bortezomib causes <strong>thrombocytopenia</strong> with a unique cyclical pattern — nadir at day 11 of each cycle, recovery by day 21. This is predictable and manageable; it is NOT cumulative myelosuppression. The mechanism involves proteasome inhibition in megakaryocytes transiently impairing platelet release.</div>"}, {"id": "neo:fc:7", "deck": "Neoplastic Disease", "dk": "neo", "type": "flashcard", "front": "Anthracyclines (doxorubicin) are used for breast cancer and lymphoma. A 45-year-old woman has received 400 mg/m² cumulative doxorubicin. Should her next course be given?", "back": "Standard cumulative dose limit for doxorubicin is <strong>450–550 mg/m²</strong> — above this threshold, cumulative cardiomyopathy risk rises steeply (~7–26% at 550 mg/m²). At 400 mg/m², she is approaching this limit but has not exceeded it. Decision requires baseline and current LVEF assessment — if LVEF is preserved (&gt;50%) and cardiac risk factors are low, one more cycle may be feasible with close monitoring. Mechanism of anthracycline cardiotoxicity: doxorubicin + iron → Fenton reaction → hydroxyl radical formation → ROS → lipid peroxidation of cardiomyocyte membranes → irreversible myocyte necrosis and fibrosis. Also inhibits topoisomerase IIβ in cardiomyocytes (distinct from topoisomerase IIα in cancer cells).<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> <strong>Dexrazoxane</strong> — an iron chelator (EDTA analogue, also a topoisomerase IIβ inhibitor) — is the only FDA-approved cardioprotectant for anthracycline cardiotoxicity. Given before each doxorubicin dose. Cardio-protective liposomal doxorubicin (Doxil/Caelyx) reduces peak plasma concentrations and preferentially accumulates in tumour vasculature → less cardiac exposure at equivalent anti-tumour doses.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Anthracyclines cause two types of cardiotoxicity: (1) Acute — arrhythmias during or immediately after infusion (self-limiting, not dose-dependent); (2) Chronic — cardiomyopathy months-years later (dose-dependent, irreversible). Only chronic cardiotoxicity is cumulative dose-related. Childhood cancer survivors who received anthracyclines require lifelong cardiac surveillance.</div>"}, {"id": "neo:fc:8", "deck": "Neoplastic Disease", "dk": "neo", "type": "flashcard", "front": "A patient with ovarian cancer receives paclitaxel (Taxol). During infusion she develops flushing, urticaria, and bronchospasm within 10 minutes. After recovery, she is rechallenged with a slower infusion and premedication. Why does this work for paclitaxel but is contraindicated in true drug allergy?", "back": "Paclitaxel hypersensitivity reactions are predominantly <strong>non-IgE-mediated</strong> (pseudo-allergic/anaphylactoid) — caused by the <strong>Cremophor EL (polyoxyethylated castor oil)</strong> vehicle that solubilises paclitaxel. Cremophor EL directly activates complement and stimulates mast cell degranulation → histamine release → anaphylactoid reaction. Standard premedication (dexamethasone + diphenhydramine + H2 blocker given the night before and morning of) + slow infusion rate successfully prevents recurrence in ~80%. This is NOT true IgE-mediated allergy to paclitaxel itself — rechallenge with premedication is safe. nab-paclitaxel (Abraxane — albumin-bound nanoparticle paclitaxel, Cremophor-free) eliminates the vehicle-related reactions entirely.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Paclitaxel mechanism: binds β-tubulin and <strong>stabilises polymerised microtubules</strong> → prevents depolymerisation → mitotic spindle cannot disassemble → cell arrested in G2/M → apoptosis. This is the OPPOSITE of vinca alkaloids (vincristine/vinblastine) which <strong>destabilise microtubules</strong> (inhibit polymerisation).</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Docetaxel (also a taxane) uses polysorbate 80 as a vehicle — different from Cremophor EL but also causes hypersensitivity reactions. Docetaxel causes distinctive <strong>fluid retention</strong> (pleural effusion, peripheral oedema, ascites) due to capillary leak syndrome — managed with prophylactic dexamethasone for 3 days around each infusion.</div>"}, {"id": "neo:fc:9", "deck": "Neoplastic Disease", "dk": "neo", "type": "flashcard", "front": "A patient with KRAS wild-type metastatic colorectal cancer is treated with cetuximab. After 4 months, disease progresses. Testing reveals a new KRAS G12C mutation. Explain the resistance mechanism.", "back": "Cetuximab is a chimeric <strong>anti-EGFR monoclonal antibody</strong> (IgG1) that blocks EGF binding → prevents EGFR dimerisation and downstream MAPK/PI3K activation. Efficacy requires <strong>wild-type RAS (KRAS/NRAS)</strong> — mutant KRAS G12C locks RAS in a permanently active GTP-bound state → downstream MAPK pathway is constitutively active regardless of EGFR inhibition → primary resistance. Acquired KRAS G12C mutation represents clonal selection under cetuximab pressure — a minor pre-existing clone with KRAS G12C expands because it survives EGFR blockade. Treatment: <strong>sotorasib</strong> or <strong>adagrasib</strong> (KRAS G12C-specific covalent inhibitors — bind the GDP-bound form of KRAS G12C via Cys12 → lock KRAS in inactive state).<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Before starting anti-EGFR therapy (cetuximab, panitumumab) in colorectal cancer, extended RAS testing (KRAS exons 2/3/4, NRAS exons 2/3/4) AND BRAF V600E must be done. Any RAS mutation → anti-EGFR ineffective. BRAF V600E → poor prognosis, requires BRAF+MEK+EGFR triple inhibition (encorafenib + cetuximab ± binimetinib).</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Cetuximab (IgG1) mediates <strong>ADCC</strong> — antibody-dependent cellular cytotoxicity contributes to its efficacy. Panitumumab (IgG2) does NOT mediate ADCC — no Fc effector function. Cetuximab causes infusion reactions (first dose especially) and acneiform rash. The rash is biomarker of response — patients with severe rash have better outcomes.</div>"}, {"id": "neo:fc:10", "deck": "Neoplastic Disease", "dk": "neo", "type": "flashcard", "front": "Tamoxifen is used for ER-positive breast cancer. A patient on tamoxifen also takes fluoxetine for depression. Her oncologist is concerned. Why?", "back": "Tamoxifen is a <strong>prodrug</strong> requiring CYP2D6-mediated activation to <strong>endoxifen</strong> (the active metabolite with 30–100× higher affinity for ER than tamoxifen). Fluoxetine (and paroxetine) are potent <strong>CYP2D6 inhibitors</strong> → reduce endoxifen plasma levels by ~50–75% → potentially compromised anti-tumour efficacy. Studies suggest CYP2D6 poor metabolisers (or those on CYP2D6 inhibitors) have higher breast cancer recurrence rates. Safe antidepressant alternatives: <strong>venlafaxine, desvenlafaxine, citalopram, escitalopram</strong> — these do not significantly inhibit CYP2D6 and do not reduce endoxifen levels.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Tamoxifen increases risk of <strong>endometrial cancer</strong> (it is an ER agonist in the uterus — selective ER modulator/SERM) and <strong>thromboembolic events</strong> (DVT/PE). Annual gynaecological review and prompt investigation of abnormal uterine bleeding are mandatory during tamoxifen therapy. Postmenopausal patients: aromatase inhibitors (anastrozole, letrozole, exemestane) are preferred — no uterine stimulation.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> CYP2D6 <strong>poor metabolisers</strong> (~7–10% of Caucasians) convert tamoxifen to endoxifen very inefficiently even without inhibitors — consider aromatase inhibitor if postmenopausal. Tamoxifen also undergoes CYP3A4 metabolism — strong CYP3A4 inducers (rifampin, carbamazepine) reduce tamoxifen levels. Avoid concurrent use.</div>"}, {"id": "neo:fc:11", "deck": "Neoplastic Disease", "dk": "neo", "type": "flashcard", "front": "Irinotecan (CPT-11) is given for colorectal cancer. The patient develops severe diarrhoea and neutropenia. A UGT1A1*28 polymorphism is found. Explain.", "back": "Irinotecan is a topoisomerase I inhibitor (prodrug) → converted by carboxylesterases to <strong>SN-38</strong> (active metabolite, 100–1000× more potent). SN-38 is glucuronidated by <strong>UGT1A1</strong> → SN-38-G (inactive, excreted in bile). In the gut, intestinal bacteria deconjugate SN-38-G → SN-38 re-released → damages intestinal epithelium → <strong>late-onset diarrhoea</strong>. <strong>UGT1A1*28 polymorphism</strong> (7 TA repeats in TATA box instead of 6) → reduced UGT1A1 expression → impaired SN-38 glucuronidation → SN-38 accumulates → severe diarrhoea AND neutropenia (SN-38 damages bone marrow). Homozygous *28/*28 patients require dose reduction at the outset.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> The UGT1A1*28 polymorphism is the SAME polymorphism responsible for <strong>Gilbert syndrome</strong> (mild unconjugated hyperbilirubinaemia) — UGT1A1 also glucuronidates bilirubin. Gilbert syndrome patients (benign condition) have elevated bilirubin under fasting/stress — but also have increased irinotecan toxicity. Test UGT1A1 before high-dose irinotecan.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Irinotecan causes TWO types of diarrhoea: (1) <strong>Early</strong> (during or shortly after infusion) — cholinergic (irinotecan inhibits acetylcholinesterase → excess ACh → GI hypermotility, flushing, salivation) — treat with <strong>atropine</strong>; (2) <strong>Late</strong> (≥24h after) — SN-38 mucosal toxicity — treat with <strong>high-dose loperamide</strong> (4 mg immediately then 2 mg every 2h until diarrhoea-free for 12h).</div>"}, {"id": "neo:fc:12", "deck": "Neoplastic Disease", "dk": "neo", "type": "flashcard", "front": "A patient with CLL is given fludarabine + cyclophosphamide + rituximab (FCR). Why is Pneumocystis jirovecii prophylaxis mandatory, and what immunological effect persists for years?", "back": "FCR causes profound and prolonged <strong>lymphocyte depletion</strong>: fludarabine (purine analogue → incorporates into DNA → chain termination, also inhibits DNA polymerase and ribonucleotide reductase) preferentially kills lymphocytes (high deoxynucleotide pools). FCR dramatically depletes <strong>CD4+ T cells</strong> — CD4 counts can fall to &lt;200 cells/µL and remain low for 12–24 months or longer. Below CD4 &lt;200, PCP risk is high → TMP-SMX prophylaxis mandatory. Also: CMV reactivation monitoring, VZV prophylaxis (acyclovir), and avoidance of live vaccines throughout and for 12+ months after. Hypogammaglobulinaemia (from B-cell depletion by rituximab) persists for 6–12 months → IVIG replacement if recurrent infections.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Fludarabine is contraindicated as a single agent in the Coombs-positive setting — it can precipitate or worsen <strong>autoimmune haemolytic anaemia</strong> (AIHA) in CLL by unknown mechanisms (possibly immune dysregulation). Rituximab + chlorambucil is safer in CLL with AIHA.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Fludarabine causes a distinctive <strong>haemolytic transfusion reaction</strong> risk — fludarabine-treated patients must receive only <strong>irradiated blood products</strong> (to prevent transfusion-associated GVHD — residual viable donor T cells can engraft in the profoundly lymphocytopaenic recipient → fatal GVHD). This requirement persists for LIFE after fludarabine.</div>"}, {"id": "neo:fc:13", "deck": "Neoplastic Disease", "dk": "neo", "type": "flashcard", "front": "A patient with chronic myelomonocytic leukaemia (CMML) and IDH2 mutation receives enasidenib. Twelve days later he develops fever, rapidly increasing WBC, and pulmonary infiltrates. What syndrome is occurring?", "back": "<strong>Differentiation syndrome</strong> (DS) — previously called all-trans retinoic acid (ATRA) syndrome or retinoic acid syndrome when described in APL. <strong>IDH2</strong> (isocitrate dehydrogenase 2) mutation produces 2-hydroxyglutarate (2-HG) — an oncometabolite that inhibits TET2 and histone demethylases → DNA hypermethylation → differentiation block → accumulation of immature myeloid blasts. Enasidenib inhibits mutant IDH2 → 2-HG levels fall → epigenetic reprogramming → blasts undergo rapid differentiation into mature neutrophils → massive cytokine release (IL-6, IL-8, MMP) → <strong>capillary leak</strong> → pulmonary infiltrates, pleural/pericardial effusions, fever, leucocytosis, weight gain. Treatment: <strong>dexamethasone</strong> 10 mg IV BD — reduces inflammatory cytokine cascade.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Differentiation syndrome also occurs with: ATRA in APL (classic), arsenic trioxide in APL, ivosidenib (IDH1 inhibitor). The same syndrome is now called differentiation syndrome across all these contexts. APL treatment: ATRA + arsenic trioxide — two agents that together induce PML-RARα fusion protein degradation via distinct mechanisms → higher cure rates (~90%).</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> In APL (AML-M3), <strong>never give cytotoxic chemotherapy without ATRA</strong> — APL blasts have high intracellular t-PA (tissue plasminogen activator) → spontaneous fibrinolysis → catastrophic DIC/bleeding. ATRA must be started immediately on clinical suspicion, before molecular confirmation. The t(15;17) PML-RARα fusion creates the RARA fusion — ATRA bypasses the PML-RARα differentiation block.</div>"}, {"id": "neo:fc:14", "deck": "Neoplastic Disease", "dk": "neo", "type": "flashcard", "front": "A patient with metastatic renal cell carcinoma (RCC) is started on sunitinib. After 4 weeks, blood pressure rises to 165/105 mmHg. Should sunitinib be stopped?", "back": "No — <strong>hypertension is an on-target effect of VEGFR inhibition</strong> and is a pharmacodynamic biomarker of therapeutic activity. Sunitinib inhibits <strong>VEGFR1/2/3, PDGFR, c-Kit, FLT3</strong> (multi-targeted TKI). VEGFR blockade → reduced VEGF signalling in endothelial cells → reduced nitric oxide (NO) production → vasoconstriction → hypertension. This is manageable with antihypertensives — do NOT stop sunitinib. Use: <strong>amlodipine</strong> (CCB — does not inhibit CYP3A4 significantly), or ACE inhibitor/ARB (also may be renoprotective). Paradoxically, patients who develop more severe hypertension have better tumour responses to VEGFR inhibitors.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Other common sunitinib/VEGFR inhibitor toxicities: hand-foot syndrome (palmar-plantar erythrodysaesthesia — painful blistering of palms and soles), hypothyroidism (thyroid VEGF dependency → follicular atrophy — check TFTs every 3 months), QT prolongation, hepatotoxicity. Cabozantinib additionally inhibits MET and AXL — used in sunitinib-refractory RCC and HCC.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> VEGFR inhibitors carry a risk of <strong>arterial thromboembolism</strong> (MI, stroke) — VEGF is normally anti-thrombotic (promotes NO and prostacyclin production). Also: impaired wound healing and GI perforation (VEGF required for mucosal repair) — hold VEGFR inhibitors perioperatively (&gt;2 weeks before elective surgery).</div>"}, {"id": "neo:fc:15", "deck": "Neoplastic Disease", "dk": "neo", "type": "flashcard", "front": "Pembrolizumab (anti-PD-1) is started for NSCLC. Six weeks later the patient develops acute-onset watery diarrhoea 8 times per day. Colonoscopy shows diffuse colonic inflammation. What is this and how is it treated?", "back": "<strong>Immune-related adverse event (irAE) — immune-mediated colitis</strong>. Pembrolizumab blocks PD-1 on T cells → removes inhibitory signal → enhanced T-cell activation against tumour AND self-antigens → loss of peripheral immune tolerance → autoimmune colitis (resembling inflammatory bowel disease, predominantly CD8+ T-cell mediated). Grade 3 colitis (≥7 stools above baseline per day): (1) Hold pembrolizumab permanently; (2) <strong>High-dose IV methylprednisolone</strong> (1–2 mg/kg/day); (3) If no improvement in 2–3 days: add <strong>infliximab</strong> (anti-TNF, 5 mg/kg) — effective in steroid-refractory irAE colitis (vedolizumab is an alternative for infliximab-contraindicated patients).<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Other common irAEs by checkpoint inhibitor: <strong>pneumonitis</strong> (anti-PD-1/PD-L1 — dry cough, dyspnoea, bilateral GGOs), <strong>hepatitis</strong> (anti-CTLA-4 — elevated ALT/AST), <strong>endocrinopathies</strong> (hypophysitis, hypothyroidism, adrenalitis — common with both classes), <strong>dermatitis</strong> (maculopapular rash, vitiligo). Most irAEs respond to corticosteroids; severe/refractory require infliximab (colitis) or mycophenolate (hepatitis).</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Anti-CTLA-4 (ipilimumab) has a higher rate of colitis than anti-PD-1 (pembrolizumab). Combined ipilimumab + nivolumab (dual checkpoint blockade for melanoma) has the highest irAE rate (~59% grade 3–4). Importantly: do NOT use <strong>infliximab</strong> for immune-mediated hepatitis (anti-TNF is hepatotoxic) — use mycophenolate or azathioprine for steroid-refractory hepatitis instead.</div>"}, {"id": "neo:fc:16", "deck": "Neoplastic Disease", "dk": "neo", "type": "flashcard", "front": "Methotrexate 25 mg/week is used for psoriasis. The patient's GP prescribes trimethoprim for a UTI. Two weeks later, the patient presents with mouth ulcers, pancytopenia, and fever. Explain.", "back": "A life-threatening drug interaction: <strong>both methotrexate and trimethoprim inhibit dihydrofolate reductase (DHFR)</strong>. MTX (competitive DHFR inhibitor) + TMP (also inhibits DHFR) → additive folate depletion → impaired thymidylate and purine synthesis → bone marrow failure (pancytopenia), mucositis. Low-dose MTX for psoriasis/RA has a narrow therapeutic window — adding any DHFR inhibitor can push into toxicity. Management: stop both drugs immediately; IV leucovorin (folinic acid) rescue; G-CSF if severe neutropenia; supportive care. Prevention: warn all MTX patients to alert their pharmacist/GP before any new antibiotic — TMP and TMP-SMX are <strong>absolutely contraindicated</strong> with concurrent MTX.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Other drugs that potentiate MTX toxicity: NSAIDs (reduce MTX renal tubular secretion → elevated MTX levels → toxicity — particularly dangerous with high-dose MTX in cancer); penicillins (same mechanism). Probenecid also increases MTX levels by blocking tubular secretion.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Folic acid (1–5 mg/day) is prescribed alongside low-dose MTX for RA/psoriasis to reduce GI and mucosal toxicity WITHOUT reducing anti-inflammatory efficacy. Folate supplementation does NOT prevent MTX hepatotoxicity. For methotrexate toxicity rescue (overdose or impaired clearance), use <strong>leucovorin (folinic acid)</strong> — not folic acid — as it bypasses the DHFR block.</div>"}, {"id": "neo:fc:17", "deck": "Neoplastic Disease", "dk": "neo", "type": "flashcard", "front": "A patient with colorectal cancer on FOLFOX (5-FU + leucovorin + oxaliplatin) develops chest pain and coronary artery spasm during 5-FU infusion. How does 5-FU cause this?", "back": "<strong>5-FU cardiotoxicity</strong> — coronary artery vasospasm is the most common cardiac manifestation, occurring in ~1–19% of patients. Mechanisms: (1) 5-FU metabolites (fluoroacetate, fluorocitrate) inhibit Krebs cycle in cardiomyocytes → impaired energy production → vascular smooth muscle dysfunction; (2) Direct endothelial toxicity → thromboxane A2 release → coronary vasospasm; (3) Protein kinase C activation → vasoconstriction. Management: <strong>stop 5-FU infusion immediately</strong>, sublingual nitrates ± calcium channel blocker for acute spasm. Future: switch to capecitabine (oral prodrug, lower peak plasma levels) — lower cardiotoxicity rate OR substitute raltitrexed in truly 5-FU-intolerant patients.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> 5-FU toxicity is significantly influenced by <strong>dihydropyrimidine dehydrogenase (DPD) deficiency</strong> — DPD metabolises 80% of 5-FU. DPD-deficient patients (DPYD*2A and other variants, ~3–8% of population) have dramatically elevated 5-FU levels → severe mucositis, diarrhoea, myelosuppression, potentially fatal. DPYD genotyping recommended before 5-FU/capecitabine therapy in Europe (FDA guidance in US is evolving).</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Leucovorin (folinic acid) in FOLFOX does NOT rescue folate — it is given to <strong>potentiate</strong> 5-FU. Leucovorin stabilises the ternary complex between 5-FdUMP (active 5-FU metabolite), thymidylate synthase (TS), and the folate cofactor → prolonged TS inhibition → greater anti-tumour effect. This is the opposite of leucovorin's role as MTX antidote.</div>"}, {"id": "neo:fc:18", "deck": "Neoplastic Disease", "dk": "neo", "type": "flashcard", "front": "A patient with Philadelphia-chromosome-positive ALL is on dasatinib. She develops dyspnoea, bilateral pleural effusions, and leg oedema. What is this toxicity and its mechanism?", "back": "<strong>Dasatinib-induced pleural effusion</strong> — occurs in up to 35% of patients. Dasatinib inhibits BCR-ABL (more potently than imatinib) AND SRC kinases. SRC inhibition disrupts vascular endothelial and lymphatic tight junctions → increased vascular permeability and impaired lymphatic drainage → pleural fluid accumulation. Also: dasatinib inhibits <strong>PDGFR</strong> which normally promotes pleural lymphatic drainage. Management: hold dasatinib, diuretics (furosemide), thoracentesis if large/symptomatic, short course of corticosteroids (prednisone 20 mg tapering over 1–2 weeks). Resume at lower dose or switch to ponatinib/bosutinib.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Dasatinib vs imatinib: dasatinib is ~325× more potent against BCR-ABL, penetrates the CNS better (important in Ph+ ALL where CNS prophylaxis/treatment is needed), and is active against most imatinib-resistant mutations (except T315I). However, pleural effusion and pulmonary arterial hypertension are class-specific dasatinib toxicities not seen with imatinib.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Nilotinib (2nd-gen BCR-ABL inhibitor) causes <strong>QT prolongation</strong> and has a black-box warning for sudden cardiac death — avoid in patients with long QT, hypokalaemia, or on other QT-prolonging drugs. Nilotinib also causes hyperglycaemia and is associated with <strong>peripheral arterial occlusive disease</strong> (PAD) — check ABI annually and avoid in patients with established PAD.</div>"}, {"id": "neo:fc:19", "deck": "Neoplastic Disease", "dk": "neo", "type": "flashcard", "front": "Trastuzumab deruxtecan (T-DXd) is given for HER2-positive breast cancer. What makes this antibody-drug conjugate different from standard trastuzumab, and what is the key pulmonary toxicity to monitor?", "back": "T-DXd is an <strong>antibody-drug conjugate (ADC)</strong>: trastuzumab (anti-HER2 antibody) linked via a cleavable linker to <strong>DXd</strong> (an exatecan derivative, topoisomerase I inhibitor — 10× more potent than irinotecan's active metabolite SN-38). Key advantage: <strong>bystander killing effect</strong> — DXd is membrane-permeable; after ADC enters HER2+ tumour cells and the linker is cleaved, free DXd diffuses into adjacent HER2-low or HER2-negative cells → kills heterogeneous tumour populations. This explains efficacy in HER2-low breast cancer (IHC 1+ or 2+/ISH-negative). Key pulmonary toxicity: <strong>interstitial lung disease (ILD)/pneumonitis</strong> — occurs in ~10–15% of patients (grade ≥3 in ~3%). Monitor for new respiratory symptoms; CT chest for any new dyspnoea. Hold for grade 2; permanently discontinue for grade 3–4.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> T-DXd has dramatically expanded the HER2 therapeutic landscape — DESTINY-Breast04 showed efficacy in HER2-LOW breast cancer (previously untreatable with HER2-targeted therapy). T-DXd is also approved for HER2-mutant (not amplified) NSCLC and HER2+ gastric cancer — demonstrating tumour-agnostic HER2 targeting.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Distinguish T-DXd from T-DM1 (ado-trastuzumab emtansine) — both are trastuzumab ADCs but different payloads: T-DM1 uses DM1 (maytansinoid, antimicrotubule) with a non-cleavable linker → NO bystander killing. T-DXd uses DXd (topo I inhibitor) with a cleavable linker → bystander killing → broader efficacy spectrum. T-DXd is significantly more active than T-DM1 in post-trastuzumab HER2+ breast cancer.</div>"}, {"id": "neo:q:0", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "What hypothesis states that chemo kills a constant fraction of cells?", "back": "The Log-Kill Hypothesis."}, {"id": "neo:q:1", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "How do tumors develop resistance via the MDR1 gene?", "back": "MDR1 encodes P-glycoprotein, an ATP-dependent efflux pump that expels drugs from the cell."}, {"id": "neo:q:2", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "What is the rationale for combination chemotherapy?", "back": "Different mechanisms maximize cell kill; non-overlapping toxicities allow full dosing of each drug."}, {"id": "neo:q:3", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "Name the 4 drugs in the CHOP regimen.", "back": "Cyclophosphamide, Hydroxydaunorubicin (Doxorubicin), Oncovin (Vincristine), Prednisone."}, {"id": "neo:q:4", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "What is the dose-limiting toxicity of cyclophosphamide?", "back": "Hemorrhagic cystitis (due to acrolein metabolite)."}, {"id": "neo:q:5", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "What drug prevents cyclophosphamide-induced cystitis?", "back": "Mesna (binds and neutralizes acrolein in the bladder)."}, {"id": "neo:q:6", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "Which resistance mechanism involves gene amplification of DHFR?", "back": "Methotrexate resistance (overproduction of target enzyme)."}, {"id": "neo:q:7", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "What DNA repair enzyme mediates Temozolomide resistance?", "back": "MGMT (O6-methylguanine-DNA methyltransferase)."}, {"id": "neo:q:8", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "Antimetabolites are specific to which cell cycle phase?", "back": "S-phase (DNA synthesis)."}, {"id": "neo:q:9", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "Microtubule inhibitors are specific to which phase?", "back": "M-phase (mitosis)."}, {"id": "neo:q:10", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "What does \"cell-cycle non-specific\" mean?", "back": "The drug damages DNA at any phase, including G0 resting cells (e.g., alkylating agents)."}, {"id": "neo:q:11", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "Why does tumor regrowth occur between chemo cycles?", "back": "Surviving cells continue to divide during the recovery interval needed for normal tissues."}, {"id": "neo:q:12", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "A patient receives 3 cycles of chemo, each achieving a 2-log kill. Starting from 10<sup>9</sup> cells, how many remain?", "back": "10<sup>3</sup> cells (1,000 cells). Each 2-log kill divides by 100."}, {"id": "neo:q:13", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "What mutation in BCR-ABL causes Imatinib resistance?", "back": "T315I (\"gatekeeper\" mutation)."}, {"id": "neo:q:14", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "Name 3 rapidly dividing normal tissues affected by cytotoxic chemo.", "back": "Bone marrow (myelosuppression), GI mucosa (mucositis), hair follicles (alopecia)."}, {"id": "neo:q:15", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "What is the Gompertzian growth model?", "back": "Tumor growth slows as it gets larger (growth fraction decreases). Small tumors grow fastest and are most chemo-sensitive."}, {"id": "neo:q:16", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "Why is adjuvant chemotherapy given after surgery?", "back": "To kill residual micrometastases when tumor burden is low and growth fraction is high."}, {"id": "neo:q:17", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "What is neoadjuvant chemotherapy?", "back": "Chemo given before surgery to shrink the primary tumor, making it resectable."}, {"id": "neo:q:18", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "Name a drug class that is NOT a substrate for P-glycoprotein.", "back": "Alkylating agents and platinum compounds are generally not P-gp substrates."}, {"id": "neo:q:19", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "What is the growth fraction of a tumor?", "back": "The proportion of tumor cells actively dividing. Higher growth fraction = more sensitive to cell-cycle specific drugs."}, {"id": "neo:q:20", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "How does Methotrexate work?", "back": "Inhibits Dihydrofolate Reductase (DHFR), blocking thymidylate and purine synthesis."}, {"id": "neo:q:21", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "What drug rescues Methotrexate toxicity and how?", "back": "Leucovorin (folinic acid). Bypasses the DHFR block by providing reduced folate directly."}, {"id": "neo:q:22", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "How does 5-FU work?", "back": "Pyrimidine analog converted to 5-FdUMP, which inhibits thymidylate synthase."}, {"id": "neo:q:23", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "Why does Leucovorin potentiate 5-FU (but rescue MTX)?", "back": "Leucovorin stabilizes the 5-FdUMP–thymidylate synthase complex, enhancing inhibition."}, {"id": "neo:q:24", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "What is the difference between Vincristine and Paclitaxel?", "back": "Vincristine inhibits microtubule assembly. Paclitaxel stabilizes microtubules (inhibits disassembly). Both halt M-phase."}, {"id": "neo:q:25", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "What is Vincristine's dose-limiting toxicity?", "back": "Peripheral neuropathy (areflexia, paresthesia, foot drop)."}, {"id": "neo:q:26", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "What is the dose-limiting toxicity of Doxorubicin?", "back": "Cumulative, irreversible dilated cardiomyopathy."}, {"id": "neo:q:27", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "How does Dexrazoxane prevent Doxorubicin cardiotoxicity?", "back": "Chelates iron, preventing free radical formation that damages cardiac myocytes."}, {"id": "neo:q:28", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "What is unique about Bleomycin toxicity?", "back": "Pulmonary fibrosis (dose-limiting), with minimal myelosuppression."}, {"id": "neo:q:29", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "What is Cisplatin's dose-limiting toxicity?", "back": "Nephrotoxicity. Requires aggressive IV hydration."}, {"id": "neo:q:30", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "How does Carboplatin differ from Cisplatin in toxicity?", "back": "Carboplatin: myelosuppression (thrombocytopenia) is dose-limiting. Much less nephrotoxic than Cisplatin."}, {"id": "neo:q:31", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "What unique neuropathy does Oxaliplatin cause?", "back": "Cold-triggered peripheral neuropathy (avoid cold drinks/objects)."}, {"id": "neo:q:32", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "Why must 6-MP dose be reduced 75% with Allopurinol?", "back": "6-MP is metabolized by xanthine oxidase. Allopurinol inhibits XO, causing toxic 6-MP accumulation."}, {"id": "neo:q:33", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "Which antimetabolite crosses the blood-brain barrier?", "back": "Temozolomide (used for glioblastoma)."}, {"id": "neo:q:34", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "What is the high-dose Cytarabine toxicity?", "back": "Cerebellar toxicity (ataxia, dysarthria)."}, {"id": "neo:q:35", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "Name the oral prodrug of 5-FU.", "back": "Capecitabine. Converted to 5-FU preferentially in tumor tissue."}, {"id": "neo:q:36", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "What is palmar-plantar erythrodysesthesia (hand-foot syndrome)?", "back": "Painful erythema and desquamation of palms/soles. Seen with Capecitabine and 5-FU."}, {"id": "neo:q:37", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "What is the mechanism of Etoposide?", "back": "Inhibits Topoisomerase II, preventing DNA re-ligation after strand breaks."}, {"id": "neo:q:38", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "What late complication is associated with Etoposide?", "back": "Secondary acute myeloid leukemia (treatment-related AML)."}, {"id": "neo:q:39", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "What are the two types of diarrhea caused by Irinotecan?", "back": "Early: cholinergic (treated with Atropine). Late: secretory (potentially life-threatening, treated with Loperamide)."}, {"id": "neo:q:40", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "What is the target of Imatinib?", "back": "BCR-ABL tyrosine kinase (in CML with Philadelphia chromosome)."}, {"id": "neo:q:41", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "What does the Philadelphia chromosome produce?", "back": "The BCR-ABL fusion protein, a constitutively active tyrosine kinase, from translocation t(9;22)."}, {"id": "neo:q:42", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "What suffix indicates a tyrosine kinase inhibitor?", "back": "-tinib (Imatinib, Erlotinib, Osimertinib)."}, {"id": "neo:q:43", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "What suffix indicates a RAF kinase inhibitor?", "back": "-fenib (Vemurafenib, Dabrafenib)."}, {"id": "neo:q:44", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "What is the target of Erlotinib?", "back": "EGFR (Epidermal Growth Factor Receptor)."}, {"id": "neo:q:45", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "What is the common dermatologic side effect of EGFR inhibitors?", "back": "Acneiform rash (paradoxically correlates with better efficacy)."}, {"id": "neo:q:46", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "What mutation does Vemurafenib target?", "back": "BRAF V600E in melanoma."}, {"id": "neo:q:47", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "Why are BRAF inhibitors combined with MEK inhibitors?", "back": "BRAF inhibitors alone can paradoxically activate MAPK via wild-type RAF, causing squamous cell carcinoma. MEK inhibitors block this paradoxical activation."}, {"id": "neo:q:48", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "What does Bevacizumab target?", "back": "VEGF (Vascular Endothelial Growth Factor) — inhibits tumor angiogenesis."}, {"id": "neo:q:49", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "Name 3 toxicities of VEGF inhibitors.", "back": "Hypertension, GI perforation, bleeding, impaired wound healing."}, {"id": "neo:q:50", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "What is the target of Bortezomib?", "back": "The 26S proteasome. Used in multiple myeloma."}, {"id": "neo:q:51", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "What suffix indicates a proteasome inhibitor?", "back": "-zomib (Bortezomib, Carfilzomib)."}, {"id": "neo:q:52", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "What suffix indicates a CDK4/6 inhibitor?", "back": "-ciclib (Palbociclib, Ribociclib)."}, {"id": "neo:q:53", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "What is Osimertinib used for?", "back": "NSCLC with T790M resistance mutation (after failure of 1st-gen EGFR TKIs)."}, {"id": "neo:q:54", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "Name a 2nd-generation BCR-ABL inhibitor.", "back": "Dasatinib or Nilotinib. Used for Imatinib-resistant CML."}, {"id": "neo:q:55", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "What is Dasatinib's unique toxicity?", "back": "Pleural effusions."}, {"id": "neo:q:56", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "What is the mechanism of Sunitinib?", "back": "Multi-kinase inhibitor (VEGFR, PDGFR, KIT). Used in renal cell carcinoma."}, {"id": "neo:q:57", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "How does Imatinib work at the molecular level?", "back": "Competitively binds the ATP-binding pocket of BCR-ABL, preventing phosphorylation and downstream signaling."}, {"id": "neo:q:58", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "What must be tested before prescribing Cetuximab for CRC?", "back": "KRAS mutation status. Only effective in KRAS wild-type tumors."}, {"id": "neo:q:59", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "Why do targeted therapies inevitably develop resistance?", "back": "Selective pressure drives outgrowth of clones with mutations in the drug target (e.g., T315I, T790M) or activation of bypass signaling pathways."}, {"id": "neo:q:60", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "What do Pembrolizumab and Nivolumab inhibit?", "back": "PD-1 (Programmed Death-1) immune checkpoint."}, {"id": "neo:q:61", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "What does Ipilimumab target?", "back": "CTLA-4. Enhances T-cell priming in lymph nodes."}, {"id": "neo:q:62", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "Why do checkpoint inhibitors cause autoimmune side effects?", "back": "They remove inhibitory signals on T-cells, leading to hyperactivation against normal tissues (irAEs)."}, {"id": "neo:q:63", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "Name 5 immune-related adverse events (irAEs).", "back": "Colitis, pneumonitis, hepatitis, thyroiditis, type 1 DM, hypophysitis, dermatitis."}, {"id": "neo:q:64", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "How are irAEs primarily managed?", "back": "Corticosteroids (and drug discontinuation for severe cases)."}, {"id": "neo:q:65", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "What is the target of Rituximab?", "back": "CD20 on B-cells."}, {"id": "neo:q:66", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "What serious infection risk is associated with Rituximab?", "back": "Hepatitis B reactivation and Progressive Multifocal Leukoencephalopathy (PML, JC virus)."}, {"id": "neo:q:67", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "What is the target and use of Trastuzumab?", "back": "HER2 receptor. HER2-positive breast cancer."}, {"id": "neo:q:68", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "What is the major toxicity of Trastuzumab?", "back": "Cardiotoxicity (reversible, unlike Doxorubicin)."}, {"id": "neo:q:69", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "Why must Trastuzumab never be given concurrently with Doxorubicin?", "back": "Both are cardiotoxic. The combination causes additive/synergistic cardiac damage."}, {"id": "neo:q:70", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "What is an Antibody-Drug Conjugate (ADC)?", "back": "An antibody linked to a cytotoxic payload. The antibody delivers the toxin specifically to tumor cells."}, {"id": "neo:q:71", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "Name an ADC and its components.", "back": "T-DM1 (ado-trastuzumab emtansine): Trastuzumab (anti-HER2) + emtansine (microtubule inhibitor)."}, {"id": "neo:q:72", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "What are the 4 steps of CAR-T cell therapy?", "back": "1) Harvest patient T-cells. 2) Engineer CAR receptor. 3) Expand ex vivo. 4) Infuse after lymphodepletion."}, {"id": "neo:q:73", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "What is the most common target for CAR-T cells?", "back": "CD19 (found on B-cell malignancies)."}, {"id": "neo:q:74", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "What is Cytokine Release Syndrome (CRS)?", "back": "Massive cytokine release (IL-6, TNF-α) from activated CAR-T cells causing fever, hypotension, and multi-organ failure."}, {"id": "neo:q:75", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "How is CRS treated?", "back": "Tocilizumab (anti-IL-6 receptor antibody). Corticosteroids if refractory."}, {"id": "neo:q:76", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "What is ICANS?", "back": "Immune Effector Cell-Associated Neurotoxicity Syndrome. A neurological complication of CAR-T therapy (confusion, seizures, cerebral edema)."}, {"id": "neo:q:77", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "Name two FDA-approved CAR-T products.", "back": "Tisagenlecleucel (Kymriah) and Axicabtagene ciloleucel (Yescarta)."}, {"id": "neo:q:78", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "Where does PD-1 blockade act: lymph node or tumor microenvironment?", "back": "Tumor microenvironment. CTLA-4 blockade acts in the lymph node."}, {"id": "neo:q:79", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "What is Bevacizumab and its mechanism?", "back": "Anti-VEGF monoclonal antibody. Neutralizes VEGF to starve tumors of blood supply (anti-angiogenic)."}, {"id": "neo:q:80", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "How does Tamoxifen act in breast tissue vs uterine tissue?", "back": "Antagonist in breast (blocks ER), agonist in uterus (stimulates endometrium → cancer risk)."}, {"id": "neo:q:81", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "What distinguishes Raloxifene from Tamoxifen?", "back": "Raloxifene is antagonist in both breast and uterus. No endometrial cancer risk. Used for osteoporosis prevention."}, {"id": "neo:q:82", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "What is Fulvestrant?", "back": "A pure ER antagonist (SERD) that causes ER degradation. Used after Tamoxifen failure."}, {"id": "neo:q:83", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "In which patient population are Aromatase Inhibitors effective?", "back": "Postmenopausal women only (they block peripheral aromatase, the sole estrogen source post-menopause)."}, {"id": "neo:q:84", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "Name 2 aromatase inhibitors.", "back": "Anastrozole, Letrozole (non-steroidal). Exemestane (steroidal, irreversible)."}, {"id": "neo:q:85", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "What is the key side effect of aromatase inhibitors?", "back": "Osteoporosis and musculoskeletal pain (due to estrogen depletion)."}, {"id": "neo:q:86", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "What is the mechanism of Leuprolide?", "back": "GnRH agonist. Continuous use downregulates GnRH receptors, decreasing LH/FSH and testosterone."}, {"id": "neo:q:87", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "Why is an antiandrogen co-administered when starting Leuprolide?", "back": "To block the initial testosterone flare (first 1–2 weeks) before receptor downregulation occurs."}, {"id": "neo:q:88", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "What advantage does Degarelix (GnRH antagonist) have over Leuprolide?", "back": "No initial testosterone flare. Directly blocks GnRH receptors."}, {"id": "neo:q:89", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "What is Enzalutamide?", "back": "A next-generation antiandrogen with higher AR affinity. Effective in castration-resistant prostate cancer."}, {"id": "neo:q:90", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "What does Abiraterone inhibit?", "back": "CYP17 — blocks androgen synthesis in testes, adrenals, and tumor."}, {"id": "neo:q:91", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "Why must Abiraterone be given with Prednisone?", "back": "CYP17 blockade causes mineralocorticoid excess (hypertension, hypokalemia). Prednisone suppresses ACTH, preventing this."}, {"id": "neo:q:92", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "What is the role of glucocorticoids in cancer therapy?", "back": "Induce apoptosis in lymphoid malignancies, reduce cerebral edema, manage irAEs, part of many regimens (CHOP)."}, {"id": "neo:q:93", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "What do CDK4/6 inhibitors (Palbociclib) do?", "back": "Block cell cycle G1-to-S transition. Combined with hormonal therapy in ER+ breast cancer."}, {"id": "neo:q:94", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "What is the key toxicity of CDK4/6 inhibitors?", "back": "Neutropenia."}, {"id": "neo:q:95", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "A premenopausal woman with ER+ breast cancer should receive which hormonal therapy?", "back": "Tamoxifen (not an aromatase inhibitor, which won't work in premenopausal women)."}, {"id": "neo:q:96", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "A postmenopausal woman with ER+ breast cancer should receive which hormonal therapy?", "back": "Aromatase inhibitor (Anastrozole, Letrozole) — more effective than Tamoxifen post-menopause."}, {"id": "neo:q:97", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "What is the BEP regimen for testicular cancer?", "back": "Bleomycin, Etoposide, and Platinum (Cisplatin). Highly curative."}, {"id": "neo:q:98", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "What is tumor lysis syndrome and how is it prevented?", "back": "Rapid cell lysis releases K+, phosphate, uric acid → renal failure, arrhythmias. Prevented with hydration, Allopurinol, or Rasburicase."}, {"id": "neo:q:99", "deck": "Neoplastic Disease", "dk": "neo", "type": "quiz", "front": "Match: Doxorubicin, Cisplatin, Bleomycin, Vincristine to their unique toxicities.", "back": "Doxorubicin: cardiomyopathy. Cisplatin: nephrotoxicity. Bleomycin: pulmonary fibrosis. Vincristine: peripheral neuropathy."}, {"id": "special:fc:0", "deck": "Special Systems", "dk": "special", "type": "flashcard", "front": "A 65-year-old man with open-angle glaucoma is started on latanoprost eye drops. After 6 weeks he notices his iris has turned from grey-green to brown, and his eyelashes are longer and darker. Explain.", "back": "Latanoprost is a <strong>prostaglandin F2α (PGF2α) analogue</strong> — it increases uveoscleral outflow (the non-conventional aqueous humour drainage pathway) → reduces intraocular pressure (IOP). Melanocyte stimulation: PGF2α receptors (FP receptors) on iris melanocytes → upregulate melanin synthesis in iris stromal melanocytes → <strong>irreversible iris colour darkening</strong> (heterochromia if one eye treated). Eyelash effects: FP receptors on follicular melanocytes and dermal papilla cells → increased melanogenesis + follicle anagen extension → <strong>hypertrichosis</strong> (longer, thicker, darker lashes — eyelash growth is actually a cosmetic application of bimatoprost, a related prostamide). Both effects are permanent even after stopping the drug.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> First-line IOP-lowering agents for glaucoma: <strong>prostaglandin analogues</strong> (latanoprost, bimatoprost, travoprost — once daily, excellent efficacy) &gt; beta-blockers (timolol) &gt; alpha-2 agonists (brimonidine) &gt; carbonic anhydrase inhibitors (dorzolamide). Prostaglandins are first-line because of once-daily dosing, highest efficacy, and no systemic cardiovascular or pulmonary effects.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Prostaglandin analogues are <strong>contraindicated in uveitis and cystoid macular oedema</strong> — FP receptor stimulation promotes prostaglandin-mediated inflammation. Also contraindicated in aphakic/pseudophakic eyes at risk of CMO. In these patients, use beta-blockers or carbonic anhydrase inhibitors as first-line alternatives.</div>"}, {"id": "special:fc:1", "deck": "Special Systems", "dk": "special", "type": "flashcard", "front": "Timolol eye drops are prescribed for glaucoma in a 70-year-old man with mild COPD. Two weeks later he is admitted with acute bronchospasm. How did topical timolol cause systemic effects?", "back": "Timolol is a non-selective <strong>beta-blocker (β1 + β2 blockade)</strong>. Topical eye drops drain via the nasolacrimal duct into the nasal cavity → absorbed via nasal mucosa → enters systemic circulation, <strong>bypassing first-pass hepatic metabolism</strong> → systemic bioavailability ~80% of topical dose. β2 blockade in bronchial smooth muscle → bronchoconstriction → acute bronchospasm in susceptible patients (COPD, asthma). Systemic effects also include: bradycardia, heart block, hypotension, masking hypoglycaemia, fatigue. Prevention: nasolacrimal occlusion (press the inner corner of the eye after instillation × 1–2 minutes) reduces systemic absorption by ~50%.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Timolol reduces aqueous humour <strong>production</strong> (β2 receptors on ciliary body epithelium → reduced cAMP → reduced aqueous secretion). It lowers IOP but does NOT affect outflow. Contraindications: asthma, severe COPD, heart block, bradycardia, decompensated heart failure. Use betaxolol (β1-selective) as an alternative in mild COPD — lower bronchospasm risk.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Systemic side effects from eye drops are commonly underestimated and under-reported. Always check for eye drop use when evaluating bradycardia, bronchospasm, or fatigue — patients often forget to mention 'just eye drops.' The nasolacrimal drainage route means topical ocular drugs can achieve significant systemic drug levels.</div>"}, {"id": "special:fc:2", "deck": "Special Systems", "dk": "special", "type": "flashcard", "front": "A patient with acute angle-closure glaucoma presents with severe eye pain, vomiting, and IOP of 58 mmHg. After pilocarpine and IV acetazolamide, IOP falls to 35 mmHg. Explain the mechanisms of both drugs.", "back": "<strong>Pilocarpine</strong> (direct M3 muscarinic agonist): stimulates ciliary muscle contraction → pulls on trabecular meshwork → opens Schlemm's canal → increases conventional (trabecular) aqueous outflow. Also causes miosis (sphincter pupillae contraction) → in acute angle-closure, miosis pulls the iris away from the trabecular meshwork → opens the drainage angle. <strong>Acetazolamide IV</strong> (carbonic anhydrase inhibitor): inhibits CA-II and CA-IV in ciliary body epithelium → reduces HCO₃⁻ production → reduces Na⁺ and water secretion into posterior chamber → dramatically reduces aqueous humour formation (→ IOP reduction within 30 minutes). Definitive treatment: <strong>Nd:YAG laser peripheral iridotomy</strong> — creates a hole in the peripheral iris → equalises pressure between posterior and anterior chambers → eliminates pupillary block.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Systemic acetazolamide causes metabolic acidosis (inhibits renal tubular CA → impaired HCO₃⁻ reabsorption → bicarbonate wasting → non-anion gap metabolic acidosis). Also causes sulfonamide-type side effects (nephrolithiasis, paraesthesiae, hypokalaemia). Contraindicated in sulfonamide allergy and severe renal failure.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Pilocarpine causes <strong>miosis</strong> (pupil constriction) — do NOT use in open-angle glaucoma as monotherapy (miosis reduces vision in dim light, causes headache from ciliary spasm). Also: systemic pilocarpine effects (DUMBELS — cholinergic stimulation) — avoid in asthma, bowel obstruction, urinary obstruction. In ACUTE angle-closure, pilocarpine is appropriate; in CHRONIC open-angle glaucoma, prostaglandins and beta-blockers are preferred.</div>"}, {"id": "special:fc:3", "deck": "Special Systems", "dk": "special", "type": "flashcard", "front": "A dermatology patient with severe plaque psoriasis on cyclosporin develops new hypertension and rising creatinine. What is the mechanism, and what topical immunosuppressant avoids these systemic effects?", "back": "Cyclosporin inhibits calcineurin → blocks NFAT → reduces IL-2 → suppresses T-cell activation → reduces the Th1/Th17-driven keratinocyte hyperproliferation in psoriasis. Systemic toxicity: <strong>nephrotoxicity</strong> — cyclosporin causes afferent arteriolar vasoconstriction (via TXA2, ET-1 upregulation, reduced NO/PGI2) → reduced GFR → progressive CKD with chronic use. Also causes hypertension (same vascular mechanism), hyperkalaemia, hypomagnesaemia, gingival hyperplasia, hirsutism. Topical alternative: <strong>tacrolimus</strong> (Protopic) or <strong>pimecrolimus</strong> (Elidel) — topical calcineurin inhibitors. Applied to skin → inhibit T-cell calcineurin locally → reduce cytokine production → reduce inflammation. Negligible systemic absorption from intact skin → minimal nephrotoxicity or immunosuppression.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Topical tacrolimus/pimecrolimus carry a black-box warning about theoretical malignancy risk (lymphoma, skin cancer) — based on systemic immunosuppressive experience. However, topical levels are far below systemic levels achieved with oral tacrolimus, and evidence for actual malignancy risk from topical use is weak. Still, avoid use on malignant/pre-malignant skin lesions.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Cyclosporin nephrotoxicity is <strong>dose-dependent and partially reversible</strong> on dose reduction, but chronic use causes irreversible interstitial fibrosis. Distinguish from tacrolimus nephrotoxicity (same mechanism, same monitoring required). Cyclosporin maximum duration for psoriasis: 2 years (due to cumulative nephrotoxicity). Monitor creatinine, BP, and drug levels throughout.</div>"}, {"id": "special:fc:4", "deck": "Special Systems", "dk": "special", "type": "flashcard", "front": "A 28-year-old woman with acne vulgaris is prescribed isotretinoin. Before dispensing, what pregnancy-related obligations must be fulfilled, and what monitoring is required during therapy?", "back": "Isotretinoin (13-cis-retinoic acid) is <strong>highly teratogenic</strong> — retinoic acid is essential for embryonic development; excess causes characteristic defects: <strong>craniofacial abnormalities, cardiac defects, CNS malformations (hydrocephalus), thymic hypoplasia</strong> — fetal retinoid syndrome. Obligations before dispensing: (1) Two negative pregnancy tests (one at initiation, one 19–37 days later, on day 2–3 of next menstrual cycle); (2) Two forms of contraception for 1 month before, throughout, and 1 month after therapy (UK: iPLEDGE equivalent — Pregnancy Prevention Programme); (3) Signed informed consent; (4) Written prescription valid for 7 days only, no repeat dispensing without re-assessment. Monitoring during therapy: monthly pregnancy tests, LFTs (hepatotoxicity), fasting lipids (triglyceridaemia — severe hypertriglyceridaemia can cause pancreatitis), FBC (leucopenia).<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Isotretinoin works by multiple mechanisms: (1) Reduces sebaceous gland size and sebum production (most important — sebum is the substrate for <em>C. acnes</em>); (2) Normalises follicular keratinisation (reduces comedone formation); (3) Anti-inflammatory; (4) Reduces <em>C. acnes</em> colonisation indirectly. The only acne treatment with the potential for <strong>permanent remission</strong> (~80% never need retreatment).</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Isotretinoin causes <strong>night blindness</strong> (vitamin A analogue → impairs rhodopsin regeneration) — warn patients before starting. Also causes <strong>cheilitis</strong> (most common side effect — dry, cracked lips), dry eyes, myalgia, epistaxis. Tetracyclines + isotretinoin → <strong>benign intracranial hypertension</strong> (pseudotumour cerebri) — this combination is absolutely contraindicated.</div>"}, {"id": "special:fc:5", "deck": "Special Systems", "dk": "special", "type": "flashcard", "front": "A farmer presents with pinpoint pupils, bradycardia, copious secretions, bronchospasm, urinary incontinence, and muscle fasciculations. He has been spraying organophosphate pesticides. What is the treatment sequence?", "back": "Organophosphate (OP) toxidrome — <strong>irreversible acetylcholinesterase inhibition</strong> → ACh accumulates at all cholinergic synapses. Muscarinic effects (DUMBELS): Diarrhoea/Defaecation, Urination, Miosis, Bradycardia/Bronchospasm/Bronchorrhoea, Emesis, Lacrimation, Salivation/Sweating. Nicotinic effects (NMJ): muscle fasciculations → paralysis (including respiratory muscles — the main cause of death). CNS: seizures, coma. Treatment sequence: (1) <strong>Atropine IV</strong> (large doses, titrated to dry secretions — NOT to pupil size) — blocks muscarinic receptors, reverses bronchospasm and secretions; (2) <strong>Pralidoxime (2-PAM) IV</strong> — reactivates AChE by displacing the phosphate group before 'ageing' (irreversible covalent bond maturation) — must be given within hours; (3) Benzodiazepines for seizures; (4) Supportive care, mechanical ventilation if respiratory failure.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Pralidoxime has a narrow time window — OP-AChE bond undergoes 'ageing' (oxime-resistant conformation) within hours (nerve agents: minutes; malathion: hours; chlorpyrifos: days). After ageing, pralidoxime is ineffective — only atropine for muscarinic control. Nerve agents (sarin, VX, novichok) cause the same toxidrome but with faster ageing times.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Atropine dosing in OP poisoning: <strong>massive doses</strong> are required (2–4 mg IV bolus repeated every 5–10 min until secretions dry — total doses of 20–100 mg may be needed). The endpoint is drying of secretions and improving bronchospasm, NOT pupil dilation or tachycardia. Inadequate atropine dosing is a leading cause of death in OP poisoning.</div>"}, {"id": "special:fc:6", "deck": "Special Systems", "dk": "special", "type": "flashcard", "front": "A patient ingests a large quantity of paracetamol (acetaminophen) 4 hours ago. LFTs are normal, INR is 1.0. Should you start N-acetylcysteine (NAC) now, or wait for toxicity?", "back": "Start NAC <strong>immediately</strong> if the paracetamol level at 4 hours is above the treatment threshold on the Rumack-Matthew nomogram (or the UK risk assessment line). Do NOT wait for liver injury — NAC is most effective when given before hepatotoxicity develops. Mechanism of paracetamol toxicity: CYP2E1/CYP3A4 convert paracetamol to <strong>NAPQI</strong> (N-acetyl-p-benzoquinone imine) — a highly reactive hepatotoxic metabolite. Normally conjugated by hepatic glutathione (GSH) → non-toxic mercapturate. Overdose overwhelms GSH stores → free NAPQI → covalent binding to hepatocyte proteins → necrosis (centrilobular — zone 3, highest CYP2E1 activity). NAC mechanism: replenishes cysteine → GSH synthesis → scavenges NAPQI. Also donates cysteine/GSH directly, improves microvascular circulation.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Risk factors that lower the threshold for treatment (shift the nomogram line): enzyme inducers (rifampin, carbamazepine, alcohol — chronic use → more CYP2E1 induction → more NAPQI); malnutrition/anorexia/fasting (depleted baseline GSH stores). These factors increase paracetamol hepatotoxicity at lower doses. UK guidelines now use a single treatment line without risk stratification.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> NAC itself can cause anaphylactoid reactions (flushing, urticaria, bronchospasm — particularly at the start of the IV loading dose) — NOT IgE-mediated. Manage by temporarily stopping infusion and giving antihistamine; restart at slower rate. The reaction is more common in asthmatics. This is NOT a reason to withhold NAC — benefit far outweighs risk of the reaction.</div>"}, {"id": "special:fc:7", "deck": "Special Systems", "dk": "special", "type": "flashcard", "front": "Carbon monoxide poisoning is suspected in a family found unconscious at home. What is the treatment and why is high-flow 100% O₂ the key intervention?", "back": "CO poisoning mechanism: CO binds haemoglobin with 240× the affinity of O₂ → carboxyhaemoglobin (COHb) cannot carry O₂ → functional anaemia. Also binds myoglobin and cytochrome c oxidase (Complex IV) → inhibits cellular respiration → histotoxic hypoxia. SpO₂ pulse oximetry reads COHb as oxyhaemoglobin → falsely normal SpO₂ — measure COHb by co-oximetry (ABG). Treatment: <strong>high-flow 100% O₂ via non-rebreather mask</strong>. Rationale: competitive displacement of CO from haemoglobin. Half-life of COHb: ~5 hours on room air (21% O₂) → ~90 minutes on 100% O₂ → ~20–30 minutes in <strong>hyperbaric O₂ (HBO)</strong> (3 atm). HBO indications: loss of consciousness, neurological deficit, COHb &gt;25%, pregnancy (fetus especially sensitive), cardiac involvement.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> CO poisoning causes a characteristic <strong>cherry-red skin</strong> (COHb is bright red) — but this is a late/post-mortem finding. In acute presentation, patients appear pale or cyanotic. Classic history: multiple family members affected (from a faulty boiler/enclosed car), headache, nausea, confusion (CO causes selective white matter and basal ganglia injury).</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Cyanide toxicity can co-occur with CO in smoke inhalation (burning plastics/upholstery release HCN). Presentation: profound lactic acidosis disproportionate to haemodynamic status + cellular hypoxia despite adequate O₂ delivery. Treatment: <strong>hydroxocobalamin</strong> (binds CN⁻ → cyanocobalamin, excreted renally) — preferred over dicobalt edetate (toxic, causes vomiting/hypotension) or sodium thiosulfate + sodium nitrite regimen.</div>"}, {"id": "special:fc:8", "deck": "Special Systems", "dk": "special", "type": "flashcard", "front": "A patient presents with acute opioid overdose — pinpoint pupils, respiratory rate 4/min, GCS 6. What is given, and what problem arises if the patient is opioid-dependent?", "back": "<strong>Naloxone IV</strong> (or IM/intranasal) — competitive antagonist at μ, κ, δ opioid receptors. Rapid reversal of opioid-induced respiratory depression, sedation, and miosis. Onset within 2 minutes IV. Dose: 0.4–2 mg IV, repeat every 2–3 minutes as needed up to 10 mg. Problem in opioid-dependent patients: naloxone's half-life is <strong>60–90 minutes</strong> — much shorter than most opioids (morphine ~4–6 h, methadone ~24–36 h, buprenorphine ~24–72 h). Reversal wears off → re-narcotisation → patient may re-arrest. Additionally, in opioid-dependent patients, naloxone precipitates <strong>acute opioid withdrawal</strong> — agitation, vomiting, diarrhoea, tachycardia, severe distress. Management: titrate naloxone to restore adequate ventilation (NOT to full wakefulness) — use small incremental doses to avoid precipitating withdrawal.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> <strong>Naltrexone</strong> is a long-acting oral opioid antagonist (half-life ~13 hours, metabolite 6-β-naltrexol active for ~24 hours) — used for opioid use disorder (relapse prevention after detox) and alcohol use disorder (reduces craving/reward). Extended-release IM naltrexone (Vivitrol, monthly injection) improves adherence. Naltrexone + bupropion (Contrave) is an FDA-approved anti-obesity combination.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Buprenorphine (partial μ-agonist, κ-antagonist) used in opioid substitution therapy has a <strong>ceiling effect on respiratory depression</strong> — safer in overdose than full agonists. However, high doses of buprenorphine + benzodiazepines or alcohol → can still cause fatal respiratory depression. Naloxone partially reverses buprenorphine (partial agonist properties mean it is harder to displace than full agonists — may need higher naloxone doses).</div>"}, {"id": "special:fc:9", "deck": "Special Systems", "dk": "special", "type": "flashcard", "front": "A 30-year-old with alcohol use disorder is prescribed disulfiram. He drinks wine at a party and develops severe flushing, nausea, vomiting, hypotension, and palpitations within 10 minutes. Explain the pharmacology.", "back": "Disulfiram irreversibly inhibits <strong>aldehyde dehydrogenase (ALDH)</strong> — the enzyme that converts acetaldehyde → acetic acid. Ethanol → (alcohol dehydrogenase) → <strong>acetaldehyde</strong> → (ALDH — BLOCKED) → acetaldehyde accumulates → <strong>disulfiram-ethanol reaction (DER)</strong>: vasodilation (flushing, hypotension), tachycardia, nausea/vomiting, headache, sweating. Aversion therapy — the unpleasant reaction deters drinking. Duration of inhibition: disulfiram irreversibly inhibits ALDH → effect lasts <strong>1–2 weeks</strong> after stopping the drug (new enzyme must be synthesised). Warn patients to avoid all alcohol-containing products (mouthwash, cooking wine, certain medicines).<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Other pharmacological treatments for alcohol use disorder: <strong>acamprosate</strong> (GABA-A agonist + NMDA antagonist — reduces craving/withdrawal symptoms, best started after detox); <strong>naltrexone</strong> (reduces opioid-mediated reward from alcohol — reduces pleasure and craving); <strong>nalmefene</strong> (opioid partial agonist/antagonist — reduces drinking intensity in non-abstinent patients). Combination naltrexone + acamprosate may be superior to monotherapy.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Disulfiram inhibits multiple enzymes beyond ALDH: also inhibits <strong>dopamine-β-hydroxylase</strong> (reduces conversion of dopamine → noradrenaline), <strong>CYP2E1</strong> (raises blood alcohol levels), and <strong>CYP2C9</strong> (raises warfarin levels → increased INR). Multiple drug interactions — check all concurrent medications. Contraindicated in psychosis (dopamine effects), severe hepatic disease, cardiac disease.</div>"}, {"id": "special:fc:10", "deck": "Special Systems", "dk": "special", "type": "flashcard", "front": "A patient with severe sepsis has lactic acidosis (pH 7.18, lactate 8 mmol/L). The ICU team considers sodium bicarbonate infusion. What does the pharmacology say about this practice?", "back": "Sodium bicarbonate for lactic acidosis is <strong>controversial and generally not recommended</strong> as routine practice. Rationale for NaHCO₃: provides exogenous bicarbonate → buffers H⁺ → raises pH. Problems: (1) Paradoxical intracellular acidosis — HCO₃⁻ + H⁺ → CO₂ + H₂O; CO₂ freely diffuses into cells and mitochondria → intracellular pH may actually fall; (2) Hypokalaemia (H⁺/K⁺ shift — alkalosis drives K⁺ into cells); (3) Hypocalcaemia (alkalosis increases albumin binding of Ca²⁺); (4) Hypernatraemia (sodium load); (5) Does NOT improve haemodynamics or mortality in trials (BICAR-ICU). Exception: bicarbonate indicated in lactic acidosis with severe acidaemia (pH &lt;7.1) AND <strong>AKI</strong> requiring renal replacement — improves haemodynamics in this specific context (BICAR-ICU subgroup).<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Treating the underlying cause of lactic acidosis is the only evidence-based intervention: source control in sepsis (antibiotics, drainage), optimise cardiac output, correct hypovolaemia, stop causative drugs (metformin, linezolid, NRTIs). Dichloroacetate (activates pyruvate dehydrogenase → reduces lactate production) — lowers lactate in trials but does NOT improve mortality.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Type A lactic acidosis (tissue hypoxia — sepsis, cardiogenic shock, ischaemia) vs Type B (no hypoxia — metformin, linezolid, NRTIs, thiamine deficiency, malignancy). Both cause elevated lactate but management differs. Metformin lactic acidosis (MALA) in the context of AKI → withhold metformin, haemodialysis (clears metformin AND corrects acidosis).</div>"}, {"id": "special:fc:11", "deck": "Special Systems", "dk": "special", "type": "flashcard", "front": "A 45-year-old nurse is found to have regular exposure to hazardous chemotherapy drugs without adequate PPE. She asks which chemotherapy agents pose the highest dermal absorption and reproductive toxicity risk.", "back": "Most hazardous chemotherapy drugs for occupational exposure (NIOSH Table 1 hazardous drugs): highest risk drugs include alkylating agents (<strong>cyclophosphamide, ifosfamide, melphalan, busulfan</strong> — direct DNA alkylators, skin absorption, teratogenic, carcinogenic), antimetabolites (<strong>methotrexate, 5-FU</strong> — dermal absorption, reproductive toxicity), anthracyclines (<strong>doxorubicin</strong> — skin sensitiser, vesicant). Reproductive risks: <strong>cyclophosphamide</strong> causes premature ovarian failure and is teratogenic; <strong>methotrexate</strong> is abortifacient. PPE requirements: closed-system drug-transfer devices (CSTDs), double gloves (chemotherapy-rated nitrile, not latex), low-permeability gown, eye/face protection, preparation in certified biological safety cabinet (class II B2 exhaust).<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Vesicant chemotherapy agents (cause tissue necrosis on extravasation): <strong>anthracyclines</strong> (doxorubicin, epirubicin — most severe; treat with dexrazoxane IV within 6 hours), vinca alkaloids (vincristine, vinblastine — treat with warm compresses + hyaluronidase), mechlorethamine. Irritant agents (cause inflammation but not necrosis): oxaliplatin, etoposide, paclitaxel.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Cyclophosphamide for cancer requires <strong>MESNA</strong> to prevent haemorrhagic cystitis (acrolein metabolite). Ifosfamide additionally causes <strong>encephalopathy</strong> (ifosfamide CNS toxicity — confusion, hallucinations, seizures) — treat with methylene blue (alternative electron acceptor — reverses ifosfamide-induced inhibition of mitochondrial electron transport) or supportive care.</div>"}, {"id": "special:fc:12", "deck": "Special Systems", "dk": "special", "type": "flashcard", "front": "A patient is brought in after intentional iron tablet overdose. He has vomiting, diarrhoea, haematemesis, and abdominal X-ray shows radio-opaque tablets. What is the specific chelating antidote and its mechanism?", "back": "<strong>Desferrioxamine (deferoxamine)</strong> — a hexadentate siderophore chelator produced by <em>Streptomyces pilosus</em>. It binds free iron (Fe³⁺) with extremely high affinity → forms <strong>ferrioxamine</strong> complex → renally excreted (produces 'vin rosé' pink-orange urine — indicating chelation is occurring). Desferrioxamine specifically chelates free iron and iron in ferritin/haemosiderin — it does NOT chelate iron in haemoglobin or transferrin (too tightly bound). Iron toxicity phases: GI phase (0–6h, direct GI corrosion) → latent phase (6–24h, apparent improvement) → systemic toxicity (24–72h, acidosis, hepatic failure, coagulopathy, cardiovascular collapse) → late sequelae (2–8 weeks, GI stricture). Treat in ICU with IV desferrioxamine if serum iron &gt;90 µmol/L or severe symptoms.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Other chelating antidotes: <strong>EDTA</strong> (ethylenediaminetetraacetic acid) — lead, heavy metals; <strong>dimercaprol (BAL)</strong> — arsenic, mercury, lead; <strong>DMSA (succimer)</strong> — lead, mercury (oral, safer than BAL); <strong>penicillamine</strong> — Wilson's disease (copper), lead; <strong>prussian blue</strong> — thallium, caesium; <strong>hydroxocobalamin</strong> — cyanide (binds CN⁻ → cyanocobalamin).</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Whole-bowel irrigation (polyethylene glycol at 1–2 L/hour) is used for iron tablet overdose to mechanically flush unabsorbed tablets from the GI tract — particularly if tablets are visible on X-ray. Activated charcoal does NOT bind iron (or lithium, alcohols, acids, bases) — do NOT give activated charcoal in iron overdose.</div>"}, {"id": "special:fc:13", "deck": "Special Systems", "dk": "special", "type": "flashcard", "front": "A 25-year-old with recreational drug use has taken MDMA (ecstasy) at a party. He presents confused, with hyperthermia (40.2°C), tachycardia, and hyponatraemia (Na 121 mmol/L). What is the mechanism of hyponatraemia?", "back": "MDMA causes hyponatraemia via two mechanisms: (1) <strong>SIADH</strong> — MDMA massively releases serotonin from raphe nuclei and serotonergic terminals → serotonin stimulates ADH (AVP) release from hypothalamus → water retention → dilutional hyponatraemia. (2) <strong>Compulsive water drinking</strong> (hyperdipsia) — MDMA users drink excess water to prevent hyperthermia/dehydration, often dramatically overcorrecting → dilutional hyponatraemia. Both mechanisms combine → severe hyponatraemia → cerebral oedema → confusion, seizures, cerebral herniation (particularly in young women — more susceptible due to hormonal effects on brain AQP4 channels). Treatment: controlled hypertonic saline (3%) for symptomatic hyponatraemia; correct at ≤10 mmol/L/day to avoid osmotic demyelination syndrome.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> MDMA toxicity triad: hyperthermia + hyponatraemia + serotonin syndrome features (hyperthermia, clonus, agitation). Management: active cooling, benzodiazepines for agitation/seizures, correct Na⁺ carefully. Avoid dantrolene (used for malignant hyperthermia/NMS — does not address serotonin mechanism). Cyproheptadine (5-HT antagonist) for serotonin syndrome if severe.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Hyponatraemia correction: correct too slowly → ongoing cerebral oedema and death; correct too fast → <strong>osmotic demyelination syndrome (ODS)</strong> — central pontine myelinolysis → quadriplegia, dysarthria, locked-in syndrome. Maximum safe correction rate: 10 mmol/L in first 24 hours, 18 mmol/L in 48 hours. Exception: in acute symptomatic hyponatraemia (&lt;48h), faster initial correction (1–2 mmol/L/hour for first few hours) is safe to stop seizures before slowing.</div>"}, {"id": "special:fc:14", "deck": "Special Systems", "dk": "special", "type": "flashcard", "front": "A 55-year-old taking warfarin for AF is also prescribed broad-spectrum antibiotics for 10 days. Her INR rises to 6.2. Why?", "back": "Broad-spectrum antibiotics (especially those with poor GI absorption — cephalosporins, fluoroquinolones, metronidazole) disrupt gut flora → reduce intestinal bacterial synthesis of <strong>vitamin K2 (menaquinone)</strong> → reduced vitamin K available for hepatic carboxylation of clotting factors (II, VII, IX, X, protein C and S) → enhanced warfarin anticoagulant effect → INR rise. Additionally: some antibiotics (metronidazole, fluconazole) inhibit CYP2C9 → reduced warfarin (S-enantiomer) metabolism → pharmacokinetic interaction also contributes. Management: hold 1–2 warfarin doses, recheck INR, restart at lower dose; if INR &gt;8 or bleeding → vitamin K1 (phytomenadione) orally or IV.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Vitamin K1 (phytomenadione/phytonadione) reverses warfarin anticoagulation. Oral route takes 12–24 hours (wait for hepatic factor synthesis). IV route: faster onset (~6–8h) but risk of anaphylactoid reaction — use slow IV infusion. For life-threatening bleeding: <strong>4-factor prothrombin complex concentrate (4F-PCC)</strong> provides immediate factor replacement (fastest reversal). FFP is second-line (large volume, incomplete reversal).</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> The <strong>hepatic vitamin K cycle</strong>: dietary K1 → reduced by VKOR (vitamin K epoxide reductase) → active form → γ-carboxylation of Glu residues on clotting factors. Warfarin inhibits VKOR → factors produced without γ-carboxylation → non-functional (cannot bind Ca²⁺/phospholipid). This is also why warfarin has a <strong>delayed onset</strong> (~5 days) — must wait for existing carboxylated factors to clear (factor VII shortest half-life, ~6h → INR rises first).</div>"}, {"id": "special:fc:15", "deck": "Special Systems", "dk": "special", "type": "flashcard", "front": "A 70-year-old man taking multiple medications for hypertension, gout, and depression is found confused with a Na⁺ of 118 mmol/L. Review of his medication list reveals hydrochlorothiazide, allopurinol, sertraline, and ramipril. Which drug is most likely responsible?", "back": "Most likely: <strong>SIADH from sertraline</strong> (SSRI) — SSRIs cause SIADH in elderly patients (~0.5–1%), mechanism unclear but involves serotonin-stimulated ADH release and/or direct effect on renal collecting duct aquaporins. However, <strong>hydrochlorothiazide</strong> is also a major cause — thiazides cause hyponatraemia via: (1) Inhibiting distal tubule NaCl cotransporter → impaired diluting ability in the kidney; (2) Indirect ADH stimulation from volume depletion. In elderly patients, thiazide-induced hyponatraemia can be severe. Ramipril rarely causes hyponatraemia. Allopurinol does not. Management: identify culprit drug (stop if possible), fluid restriction for SIADH, demeclocycline or vaptans (tolvaptan — V2 receptor antagonist, aquaretic) for persistent SIADH.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Tolvaptan (and conivaptan) are <strong>vasopressin V2 receptor antagonists</strong> — block ADH action at renal collecting duct → free water excretion (aquaresis — water without Na⁺ → raises serum Na⁺). Used for euvolaemic SIADH and hypervolaemic hyponatraemia (HF, cirrhosis). Risk: overly rapid Na⁺ correction → ODS. Monitoring required; start in hospital.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Hyponatraemia from thiazides is <strong>hypotonic hyponatraemia with low urine Na⁺ if early</strong> (urinary Na⁺ may be high initially then falls as volume depletion activates aldosterone). SIADH has high urine Na⁺ (&gt;40 mmol/L) and concentrated urine. Distinguishing features: thiazide → volume depletion + metabolic alkalosis + hypokalaemia; SIADH → euvolaemia, normal acid-base, variable K⁺.</div>"}, {"id": "special:fc:16", "deck": "Special Systems", "dk": "special", "type": "flashcard", "front": "A patient in a burns unit needs nutritional support. What drug given to burn patients reduces catabolism, and why is glutamine supplementation specifically recommended in critical illness?", "back": "<strong>Oxandrolone</strong> (anabolic steroid, synthetic testosterone analogue) — used in severe burns to counter the massive hypermetabolism and muscle catabolism (cortisol and catecholamine surge → protein breakdown, negative nitrogen balance). Oxandrolone stimulates androgen receptors → enhances nitrogen retention, muscle protein synthesis, wound healing, lean mass preservation. Standard in major burns (&gt;40% TBSA) for 6–12 months. <strong>Glutamine</strong> in critical illness: glutamine is normally a non-essential amino acid but becomes <strong>conditionally essential</strong> in critical illness (endogenous synthesis cannot meet demand). Functions: primary fuel for enterocytes and lymphocytes → maintains gut mucosal integrity (reduces bacterial translocation) and immune function. Supplementation recommended for burns, trauma, and ICU patients on TPN (parenteral glutamine — gut cannot absorb enteral glutamine effectively in severe illness).<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Insulin infusion (targeting glucose 6–10 mmol/L) is used in burns/critical illness ICUs — insulin has anabolic effects beyond glucose control: promotes amino acid uptake into muscle, reduces muscle proteolysis, stimulates GH axis. Tight glucose control (4–6 mmol/L) is no longer recommended after NICE-SUGAR trial — increased mortality from hypoglycaemia.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Enteral nutrition is always preferred over parenteral in critical illness (including burns) — preserves gut mucosal integrity, reduces infection rate, maintains gut-associated lymphoid tissue (GALT). Start enteral nutrition within 24–48 hours. TPN only if enteral route is impossible or contraindicated (high-output fistula, ileus, bowel obstruction).</div>"}, {"id": "special:fc:17", "deck": "Special Systems", "dk": "special", "type": "flashcard", "front": "A patient develops hyperkalaemia (K⁺ 7.1 mmol/L) with peaked T waves and widened QRS on ECG. List the emergency treatment sequence in the correct order with mechanisms.", "back": "Emergency treatment of severe hyperkalaemia (ECG changes): (1) <strong>IV calcium gluconate 10 mL 10%</strong> (or calcium chloride) — immediately stabilises cardiomyocyte membrane potential by raising threshold potential → reduces cardiac excitability. Onset: 1–3 minutes. Does NOT lower K⁺ level — cardiac membrane protection only. (2) <strong>IV insulin (10 units actrapid) + 50 mL 50% dextrose</strong> — insulin activates Na⁺/K⁺-ATPase → drives K⁺ into cells. Onset 20–30 min, lasts 4–6h. (3) <strong>Nebulised salbutamol 10–20 mg</strong> — β2 agonist → activates Na⁺/K⁺-ATPase in muscle → additional K⁺ shift into cells. Additive with insulin. (4) <strong>Calcium resonium (sodium polystyrene sulfonate) or patiromer</strong> — GI K⁺ binders → remove K⁺ from body. Onset hours. (5) <strong>Haemodialysis</strong> — fastest K⁺ removal in refractory cases or oliguria.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Sodium bicarbonate (IV) for hyperkalaemia — causes K⁺ shift via H⁺/K⁺ exchange only in the context of metabolic acidosis. It is NOT reliable as monotherapy for hyperkalaemia without acidosis, and its role in the treatment sequence is now de-emphasised by most guidelines (NICE).</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Calcium gluconate does NOT lower K⁺ — students confuse it with 'treating' the hyperkalaemia. It only protects the heart for ~30–60 minutes. Definitive K⁺ lowering requires insulin-glucose, salbutamol, K⁺ binders, or dialysis. If calcium is given but no K⁺-lowering treatment follows, the patient will deteriorate as the calcium effect wears off.</div>"}, {"id": "special:fc:18", "deck": "Special Systems", "dk": "special", "type": "flashcard", "front": "A 40-year-old woman on long-term phenytoin for epilepsy develops macrocytic anaemia. Her folate level is low. Explain the mechanism and treatment.", "back": "Phenytoin causes folate deficiency via two mechanisms: (1) <strong>Impairs intestinal folate absorption</strong> — phenytoin inhibits intestinal conjugase (pteroylpolyglutamate hydrolase) → dietary polyglutamate folate cannot be hydrolysed to absorbable monoglutamate form → folate malabsorption. (2) Increases folate catabolism. Result: low serum folate → impaired thymidylate synthesis → megaloblastic erythropoiesis → macrocytic anaemia. Treatment: <strong>folic acid supplementation</strong> (5 mg/day). Important caveat: folic acid supplementation in epilepsy can <strong>lower phenytoin levels</strong> (folate may induce CYP2C9/2C19, or compete for enterohepatic recycling) → may increase seizure frequency. Monitor phenytoin levels closely when starting folate.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Other phenytoin-related metabolic effects: <strong>osteomalacia/osteoporosis</strong> — phenytoin induces CYP3A4 → accelerates vitamin D catabolism → reduced 25-OH-D → impaired calcium absorption → secondary hyperparathyroidism → bone demineralisation. Supplement calcium + vitamin D in long-term phenytoin users. Also causes gingival hyperplasia, hirsutism, coarsening of facies (cosmetically distressing, particularly in young women).</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Macrocytic anaemia from phenytoin is <strong>folate-deficiency megaloblastic anaemia</strong> — do NOT confuse with vitamin B12 deficiency (different mechanism, though both cause macrocytosis and megaloblastic changes). Check both folate AND B12 in macrocytosis. Phenytoin also causes a lupus-like syndrome (anti-histone antibodies) — reversible on stopping the drug.</div>"}, {"id": "special:fc:19", "deck": "Special Systems", "dk": "special", "type": "flashcard", "front": "A patient is prescribed warfarin for mechanical heart valve. She is also started on amiodarone for paroxysmal AF. One week later her INR is 7.8. What is the interaction and how should it be managed?", "back": "Amiodarone is a potent inhibitor of <strong>CYP2C9</strong> (the major enzyme metabolising the active S-warfarin enantiomer) and also inhibits CYP3A4 (R-warfarin). Result: dramatically reduced warfarin metabolism → warfarin accumulates → excessive anticoagulation → INR rises. Importantly, amiodarone has a half-life of <strong>40–55 days</strong> (due to massive tissue distribution — adipose tissue, liver, lungs) — the CYP2C9 inhibition PERSISTS for months after stopping amiodarone. Management: (1) Hold 1–2 warfarin doses; (2) Reduce warfarin dose by 30–50% when amiodarone is started; (3) Monitor INR weekly until stable; (4) Remember that warfarin dose requirements will gradually increase again over months if amiodarone is stopped (as CYP2C9 inhibition wanes).<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Amiodarone's extraordinary half-life (40–55 days) means: (1) Weeks to reach therapeutic antiarrhythmic levels (IV loading used for acute arrhythmias); (2) Drug interactions and adverse effects persist long after cessation; (3) Amiodarone pulmonary toxicity, thyroid dysfunction, and hepatotoxicity may appear or worsen months after stopping. Monitor TFTs, LFTs, CXR every 6 months during treatment.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Amiodarone is an iodine-rich drug (~37% iodine by weight) → can cause both <strong>hypo- and hyperthyroidism</strong>. Type 1 amiodarone-induced thyrotoxicosis (AIT) — iodine-induced excess thyroid hormone synthesis in pre-existing thyroid disease (treat with thionamides). Type 2 AIT — destructive thyroiditis from iodine toxicity (treat with corticosteroids). Distinguishing the two requires thyroid imaging and colour flow Doppler.</div>"}, {"id": "special:q:0", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "Which outflow pathway do prostaglandin analogues primarily enhance, and what receptor mediates this?", "back": "<strong>Uveoscleral outflow</strong> (fluid flows through ciliary muscle into suprachoroidal space). Mediated by FP receptors (PGF₂α receptor), linked to Gq/11-PLC-IP3-Ca²⁺ pathway. This is the target exploited because it bypasses the trabecular meshwork."}, {"id": "special:q:1", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "Why is betaxolol less efficacious than timolol for glaucoma, yet preferred in asthma?", "back": "Ocular β receptors (ciliary epithelium/blood vessels) are predominantly <strong>β₂ subtype</strong> (75–90%). Betaxolol is β₁-selective → less blockade of the target receptors → less IOP reduction. However, because it doesn't block pulmonary β₂ receptors, it is safer in asthma."}, {"id": "special:q:2", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "A patient with hazel eyes on latanoprost notes one iris is now brown. Is this reversible?", "back": "<strong>No — it is permanent.</strong> Latanoprost (via FP receptor stimulation) increases melanin production in iris stromal melanocytes. This is a structural change, not a vascular or edematous one. Patients should be warned before starting therapy."}, {"id": "special:q:3", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "Cocaine eye drops fail to dilate a patient's left pupil (right dilates normally). What does this confirm and what drug would localise the lesion?", "back": "<strong>Confirms left Horner syndrome</strong> (sympathetic denervation — no NE to block reuptake, so cocaine can't dilate). Use <strong>hydroxyamphetamine 1%</strong>: if it dilates, the postganglionic neuron is intact (1st/2nd order Horner); if it fails to dilate, the 3rd-order (postganglionic) neuron is damaged."}, {"id": "special:q:4", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "What is the mechanism by which timolol eye drops can cause systemic bradycardia?", "back": "Drainage via nasolacrimal duct → nasal mucosa (highly vascular) → absorption bypasses hepatic first-pass metabolism → <strong>systemically bioavailable timolol</strong> blocks cardiac β₁ receptors → bradycardia. Nasolacrimal occlusion after instillation reduces systemic absorption."}, {"id": "special:q:5", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "What corneal layer structure makes an amphipathic drug ideal for transcorneal penetration?", "back": "The cornea is a <strong>\"fat-water-fat\" trilaminar structure</strong>: hydrophobic epithelium (barrier for hydrophilic drugs) → hydrophilic stroma (barrier for lipophilic drugs) → hydrophobic endothelium. An amphipathic molecule with both lipophilic and hydrophilic properties traverses all three layers. Drug penetration is approximately linearly related to tear film concentration."}, {"id": "special:q:6", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "Echothiophate is an irreversible AChE inhibitor used for glaucoma. Name two serious adverse effects unique to its long-term use.", "back": "<strong>Posterior subcapsular cataracts</strong> (chronic ciliary spasm/zonular tension alters lens metabolism) and <strong>iris cysts</strong>. Also: retinal detachment (risk), punctal stenosis. Systemic toxicity risk exists because organophosphates can be absorbed. Often used with mydriatic to reduce iris cysts."}, {"id": "special:q:7", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "Aflibercept differs structurally from bevacizumab. How, and what is the clinical significance?", "back": "Aflibercept is a <strong>recombinant fusion protein</strong> (decoy receptor: portions of human VEGFR-1 and VEGFR-2 fused to IgG1 Fc). It binds VEGF-A, VEGF-B, AND placental growth factor (PlGF) — broader coverage than bevacizumab (anti-VEGF-A only mAb). Given every 2 months after loading. CATT trial showed similar visual acuity outcomes between aflibercept, ranibizumab, and bevacizumab."}, {"id": "special:q:8", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "A patient on hydroxychloroquine for lupus asks about eye side effects. What is the mechanism, what does it look like, and when does it appear?", "back": "Chloroquine/HCQ accumulates in <strong>retinal pigment epithelium</strong> (melanin binding) → toxic maculopathy called <strong>\"bull's-eye maculopathy\"</strong> (ring of hyperpigmentation around fovea) → central visual acuity loss. Typically requires 5–7 years at therapeutic doses (risk appears after ~6 years with normal dosing of ≤5 mg/kg/day). Annual ophthalmology screening after 5 years. Stopping does NOT reverse damage but prevents further progression."}, {"id": "special:q:9", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "What photoreceptor types exist and what visual function does each serve? What molecule is the chromophore for both?", "back": "<strong>Rods</strong> → dim light vision (low intensity); <strong>Cones</strong> (3 types: red/green/blue) → high-intensity light, colour vision. Both use <strong>11-cis-retinal</strong> as chromophore (bound to opsin proteins — rhodopsin in rods). Photon isomerises 11-cis → all-trans → activates transducin → PDE6 → ↓ cGMP → CNG channels close → hyperpolarisation."}, {"id": "special:q:10", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "Why does PDE5 inhibitor use (sildenafil) sometimes cause visual disturbance?", "back": "PDE5 inhibitors have mild cross-inhibition of <strong>PDE6</strong> (controls cGMP levels in photoreceptors). Inhibiting PDE6 → elevated retinal cGMP → altered photoreceptor signalling → transient bluish haze or light sensitivity (altered colour discrimination). This is why pilots are warned against sildenafil use before flying."}, {"id": "special:q:11", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "What is the preferred route for ocular antifungal therapy and why is treatment prolonged?", "back": "Topical natamycin (5% suspension, only commercially available topical antifungal) is first-line for fungal keratitis. <strong>Treatment is prolonged</strong> because: (1) poor ocular penetration of antifungal drugs through intact/scarred cornea; (2) fungi are intrinsically more resistant than bacteria. Often supplemented with systemic antifungals (e.g. voriconazole) for deep infections."}, {"id": "special:q:12", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "What distinguishes open-angle glaucoma from angle-closure glaucoma anatomically and pharmacologically?", "back": "<strong>Open-angle</strong>: Trabecular meshwork is accessible but dysfunctional (unknown mechanism); 80–95% of cases. Treated with drugs ↓ production or ↑ outflow. <strong>Angle-closure</strong>: Iris physically occludes the trabecular meshwork (pupillary block). Pharmacological dilation (anticholinergics, sympathomimetics, antihistamines) can precipitate acute attack in susceptible eyes. Definitive treatment = laser iridotomy (creates alternate channel)."}, {"id": "special:q:13", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "Rho kinase inhibitors have a unique and distinctive side effect on the cornea. What is it and what is the underlying reason?", "back": "<strong>Cornea verticillata</strong>: gold-brown pigment deposits in the corneal epithelium in a whorl-like pattern. The underlying mechanism is incompletely understood but thought to relate to phospholipidosis or altered lysosomal function in corneal epithelial cells. Also causes subconjunctival hemorrhage (vasodilatory effect). Compare with amiodarone (cardiac drug) which also causes cornea verticillata — a classic shared adverse effect."}, {"id": "special:q:14", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "A neonate is given brimonidine eye drops. What systemic emergency may occur and why?", "back": "<strong>CNS depression and apnea.</strong> Brimonidine is lipophilic (penetrates blood-brain barrier) and a selective α₂ agonist. Nasolacrimal absorption bypasses first-pass → systemically active drug reaches immature CNS. α₂ receptors in brainstem → central hypnotic/apnoeic effect. Brimonidine is absolutely <strong>contraindicated in children under 2 years</strong> of age for this reason."}, {"id": "special:q:15", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "What is the rate-limiting step for percutaneous drug absorption and which body site has the thinnest stratum corneum?", "back": "The <strong>stratum corneum</strong> is the rate-limiting step. Thinnest at eyelid and scrotum (hence highest absorption). Thickest at palms and soles. Thin SC = higher absorption = higher systemic exposure = ↑ HPA suppression risk with potent steroids."}, {"id": "special:q:16", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "What are the two nuclear receptor families that retinoids activate, and which disorders does each treat?", "back": "<strong>RARs (retinoic acid receptors)</strong>: mediate differentiation/proliferation effects → acne, psoriasis, photoaging. <strong>RXRs (retinoid X receptors)</strong>: mediate apoptosis in malignant cells → CTCL (bexarotene), Kaposi sarcoma (alitretinoin). Isotretinoin has no clear receptor affinity."}, {"id": "special:q:17", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "Why does acitretin require 3 years of contraception after stopping, but isotretinoin only 1 month?", "back": "Acitretin + alcohol → esterification in vivo → <strong>etretinate</strong> (stored in adipose tissue, t½ 80–160 days). Etretinate is teratogenic and persists long after acitretin is stopped. Isotretinoin has a t½ of 10–20 hours and no such long-acting metabolite is formed."}, {"id": "special:q:18", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "Name the first-line biologic for moderate-to-severe psoriasis according to most guidelines, and explain its mechanism.", "back": "<strong>Secukinumab or Ixekizumab (IL-17A mAbs)</strong> or IL-23 inhibitors (guselkumab, risankizumab) are now first-line in many guidelines due to high efficacy. PG analogues in ophthalmology correspond here — both displaced older agents by superior efficacy. Secukinumab is human IgG1κ → binds free IL-17A → prevents keratinocyte stimulation → reduces hyperproliferation, barrier dysfunction, and neutrophil recruitment."}, {"id": "special:q:19", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "What is the signature adverse effect of dupilumab and what is its proposed mechanism?", "back": "<strong>Conjunctivitis</strong> (most frequent adverse effect). Proposed mechanism: IL-4 and IL-13 signalling normally maintains conjunctival goblet cell function and tear film mucins. Blocking IL-4Rα with dupilumab disrupts this → goblet cell dysfunction → reduced tear film → conjunctival inflammation. Tralokinumab (IL-13 selective) appears to cause less conjunctivitis."}, {"id": "special:q:20", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "Which topical retinoid is the most irritating and which is the least irritating?", "back": "Most irritating: <strong>Tazarotene (++++ irritancy)</strong>. Least irritating: <strong>Adapalene (+ irritancy)</strong> and Trifarotene (+). Tretinoin is intermediate (++). Irritancy correlates with receptor affinity — tazarotene is pan-RAR, highly potent. This determines patient tolerability and compliance."}, {"id": "special:q:21", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "Why are fluorinated topical steroids contraindicated on the face?", "back": "Face has thin, sebaceous skin with high percutaneous absorption. Fluorinated steroids at this site cause: (1) <strong>perioral dermatitis</strong> (inflammatory follicular eruption), (2) <strong>rosacea-like eruptions</strong>, (3) skin atrophy, telangiectasia. Non-fluorinated agents (hydrocortisone, desonide, alclometasone) are preferred for facial use."}, {"id": "special:q:22", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "What boxed warning is unique to brodalumab (not shared by other IL-17/IL-23 biologics) and why was it added?", "back": "<strong>Suicidal ideation and behaviour</strong>. A signal was detected in phase III trials. Mechanistically: IL-17RA is also expressed in the CNS; blocking all IL-17 isoforms (A, C, D, E, F) may have neuroinflammatory effects. Note: causality has NOT been established — the signal may reflect high baseline depression prevalence in psoriasis. REMS program required before dispensing."}, {"id": "special:q:23", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "Describe the mechanism of action of calcipotriene (a vitamin D analogue) for psoriasis.", "back": "Calcipotriene binds the <strong>vitamin D receptor (VDR)</strong>. The drug-VDR complex associates with RXR-α and binds vitamin D response elements in DNA → increases expression of genes modulating epidermal differentiation and suppressing inflammation → reduces keratinocyte proliferation and normalises differentiation in psoriatic plaques. Limit: 100 g/week → hypercalcemia/hypercalciuria risk if exceeded."}, {"id": "special:q:24", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "What is the mechanism of action of crisaborole for atopic dermatitis, and what is its pharmacokinetic advantage?", "back": "Crisaborole is a <strong>PDE4B inhibitor</strong> (topical) — inhibits phosphodiesterase 4B → ↑ intracellular cAMP → ↓ inflammatory cytokines (TNFα, IFNγ, IL-17, IL-23). Its pharmacokinetic advantage: low molecular weight (251 Da, due to boron-containing benzoxaborole structure) → effective skin penetration despite topical application. This allows effective PDE4 inhibition in the epidermis without significant systemic exposure."}, {"id": "special:q:25", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "Compare the mechanism of isotretinoin vs. topical tretinoin for acne.", "back": "Both are retinoids but differ markedly: <strong>Tretinoin (topical)</strong> → RAR activation in the epidermis → normalises follicular keratinisation, reduces comedones, anti-inflammatory. <strong>Isotretinoin (systemic)</strong> → no clear receptor affinity; markedly suppresses sebaceous gland activity (↓ gland size, ↓ sebum production), normalises follicular keratinisation, reduces C. acnes via hostile follicular environment. Isotretinoin is curative (70%) while tretinoin is suppressive (disease returns on stopping)."}, {"id": "special:q:26", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "A patient using PUVA (psoralen + UVA) asks about combining with isotretinoin for psoriasis. What is your advice?", "back": "<strong>Contraindicated</strong>. Both psoralens and retinoids cause <strong>photosensitivity</strong> (retinoids induce epidermal thinning and reduce the protective keratinised layer). The combination markedly increases the risk of severe phototoxic reactions and sunburn. Additionally, systemic retinoids + tetracyclines (which may be prescribed concurrently for acne) risk pseudotumor cerebri — another combination to avoid."}, {"id": "special:q:27", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "What distinguishes etanercept from other anti-TNFα biologics structurally and functionally?", "back": "Etanercept is a <strong>soluble recombinant TNF receptor fusion protein</strong> (p75 TNF receptor Fc IgG1 fusion) — NOT a monoclonal antibody. It binds both TNFα AND TNFβ. Unlike infliximab/adalimumab/certolizumab (IgG1 mAbs), etanercept lacks complement-dependent cytotoxicity activity because it doesn't bind membrane-bound TNFα as effectively. This explains its lower efficacy in granulomatous conditions (like Crohn's disease) vs. monoclonal antibody TNFα inhibitors, and potentially lower infection risk."}, {"id": "special:q:28", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "Calcipotriene is inactivated by a commonly co-prescribed topical agent. Name it and explain the interaction.", "back": "<strong>Salicylic acid and lactic acid</strong> (acidic topical agents). Calcipotriene is chemically unstable in acidic conditions → inactivated. Since salicylic acid is commonly prescribed for its keratolytic properties in psoriasis, this is a clinically important incompatibility. Space application times or choose different keratolytic."}, {"id": "special:q:29", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "Name the JAK inhibitor approved for alopecia areata and one for atopic dermatitis; what class-wide boxed warning do all oral JAK inhibitors share?", "back": "<strong>Baricitinib (JAK1/2)</strong> is FDA-approved for severe alopecia areata and moderate-severe rheumatoid arthritis. <strong>Abrocitinib (JAK1)</strong> and upadacitinib (JAK1) are approved for atopic dermatitis. Class-wide boxed warning: ↑ risk of serious infections, malignancy, ↑ all-cause mortality (including cardiovascular death), MI, stroke, and thrombosis (DVT/PE). Based on ORAL-SURVEILLANCE study comparing tofacitinib vs. anti-TNF in RA patients ≥50 years with CV risk factors."}, {"id": "special:q:30", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "What is the Reference Dose (RfD) and how is it calculated from animal data?", "back": "<strong>RfD = NOAEL / 100</strong> (standard case). NOAEL = highest dose with no statistically significant adverse effect. Divided by 10 for interspecies variability (animal→human) and 10 for interindividual human variability. Additional uncertainty factors (10 each) may be added for database limitations. This reflects the \"precautionary principle\" — assumes worst-case for each unknown."}, {"id": "special:q:31", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "A child has a blood lead level of 55 μg/dL. What treatment is indicated and what route?", "back": "<strong>Oral succimer (DMSA)</strong> — indicated for children with BLL 45–70 μg/dL as outpatient therapy. Succimer is orally bioavailable, hydrophilic (does not enter CNS → no lead redistribution to brain), selective for heavy metals. BLL &gt;70 μg/dL = medical emergency → IV CaNa₂EDTA ± IM dimercaprol (inpatient)."}, {"id": "special:q:32", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "Why is chelation therapy contraindicated for cadmium poisoning?", "back": "The dimercaprol-cadmium complex (and complexes with other chelators) is <strong>more toxic than free cadmium itself</strong>, particularly to the kidneys. Cadmium's primary target is the renal tubule — chelation redistributes cadmium to the kidney and increases nephrotoxicity. No chelator has demonstrated clinical benefit for cadmium; treatment is supportive only."}, {"id": "special:q:33", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "What is the mechanism of aflatoxin B₁ carcinogenesis and why does co-infection with HBV increase risk 59-fold?", "back": "AFB₁ → CYP1A2/3A4 → 8,9-epoxide → N7-guanine adduct → G→T transversion → <strong>p53 codon 249 mutation</strong> (Arg→Cys) → uncontrolled hepatocyte proliferation. HBV synergy via: (1) HBx protein inhibits p53 → impairs NER of AFB₁ adducts; (2) HBV upregulates CYP3A4 → more AFB₁ activation; (3) HBV causes hepatocyte death → compensatory proliferation → initiated cells expand. Individual risks: AFB₁ = 3.4×, HBV = 7.3×, combined = <strong>59×</strong> (synergistic, not additive)."}, {"id": "special:q:34", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "What enzyme is most sensitive to lead inhibition in heme biosynthesis and what are the downstream effects?", "back": "<strong>Ferrochelatase</strong> (which inserts Fe²⁺ into protoporphyrin IX to form haem) and <strong>ALAD</strong> (δ-aminolevulinate dehydratase, very sensitive at BLL &lt;10 μg/dL). Effects: ↑ erythrocyte protoporphyrin IX (zinc protoporphyrin), ↑ urinary ALA, hypochromic microcytic anaemia morphologically similar to iron deficiency."}, {"id": "special:q:35", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "Why should sodium EDTA (Na₂EDTA) NOT be used instead of calcium EDTA (CaNa₂EDTA) for lead poisoning?", "back": "Na₂EDTA lacks the calcium — it will chelate endogenous Ca²⁺ from the blood → <strong>hypocalcaemic tetany</strong> if administered rapidly IV. CaNa₂EDTA exchanges its calcium for metals with higher EDTA affinity (Pb &gt; Ca) without causing hypocalcaemia — the calcium released is physiologically inconsequential at therapeutic doses."}, {"id": "special:q:36", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "Methyl mercury causes severe fetal brain damage even in asymptomatic mothers. Explain the molecular and physiological basis.", "back": "MeHg⁺-cysteine complex mimics methionine → transported across placenta and blood-brain barrier via amino acid transporters (molecular mimicry). Fetal brain is maximally vulnerable (neurons actively migrating, forming synapses — microtubule-dependent processes). Mercury disrupts tubulin polymerisation → impairs neuronal migration. Adult CNS is mature and far more tolerant. Hence, maternal intake causes fetal Minamata disease (severe CNS damage, cerebral palsy, ID) with only mild maternal symptoms."}, {"id": "special:q:37", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "What distinguishes genotoxic from non-genotoxic carcinogens? Give one example of each.", "back": "<strong>Genotoxic</strong>: directly damage DNA (adducts, strand breaks, oxidation via ROS). Example: benzo[a]pyrene (tobacco) → diol epoxide → DNA adducts. The Ames test detects genotoxins. <strong>Non-genotoxic</strong>: increase cancer incidence without directly damaging DNA; act via receptor-mediated proliferation (phorbol esters → PKC), inflammation (asbestos), compensatory regeneration (ethanol → hepatotoxicity), or epigenetic silencing (arsenic → DNA methylation changes). Lead is a classic non-genotoxic carcinogen (inhibits zinc-finger DNA repair proteins)."}, {"id": "special:q:38", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "A patient with Wilson disease is allergic to penicillin. Can they still take penicillamine?", "back": "Penicillamine cross-reacts with penicillin → up to 1/3 of patients develop allergic reactions (urticaria, maculopapular rash, fever). Penicillin allergy is therefore a relative contraindication. The preferred alternative is <strong>trientine</strong> (triethylenetetramine dihydrochloride) — orally effective copper chelator with a safer profile, though less potent than penicillamine."}, {"id": "special:q:39", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "What is the main route of arsenic excretion and how does biotransformation affect its toxicity?", "back": "Arsenic is excreted primarily in urine (t½ ~1–3 days — faster than most toxic metals). Biotransformation: inorganic arsenate (As⁵⁺) → arsenite (As³⁺) → methylated forms (MMA, DMA) via AS3MT enzyme using SAM as methyl donor. Previously thought to be detoxification; now known that <strong>trivalent methylated intermediates (MMA³⁺)</strong> are actually MORE toxic than inorganic arsenite (higher sulfhydryl affinity). So methylation is a bioactivation pathway, not purely detoxification."}, {"id": "special:q:40", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "Name three IARC Group 1 carcinogens with their target organs and mechanisms.", "back": "(1) <strong>Aflatoxin B₁</strong> → liver (HCC) → metabolic activation (CYP→8,9-epoxide) → N7-guanine adducts → p53 mutation. (2) <strong>Arsenic (inorganic)</strong> → liver, bladder, lung, skin → inhibition of DNA repair, epigenetic changes, oxidative stress. (3) <strong>Hexavalent chromium (Cr⁶⁺)</strong> → lung → absorbed via anion transporters → reduced intracellularly to Cr³⁺ → DNA adducts, oxidative DNA damage, inflammation. Bonus: benzene → leukaemia; asbestos → mesothelioma (non-genotoxic via inflammation)."}, {"id": "special:q:41", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "What is BPA's mechanism of action as an endocrine disruptor and which phase of development is most critical?", "back": "BPA is structurally similar to oestrogen → binds ERα (agonist) and ERβ (antagonist) → acts as a selective oestrogen receptor modulator. At low concentrations: interferes with non-genomic ER signalling (extranuclear complexes, Ca²⁺ release). Also metabolised to BPA-glucuronide (inactive) by CYP2C subfamily. Most critical windows: <strong>embryonic development, gestational stages, neonatal period, peripubertal period</strong>. Developmental exposure (in utero) programs adult metabolic and reproductive outcomes (decreased insulin secretion in offspring of BPA-exposed dams)."}, {"id": "special:q:42", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "Deferoxamine is described as having \"extraordinarily high\" affinity for iron. Quantify this and explain why it doesn't remove iron from haemoglobin.", "back": "Deferoxamine Ka for Fe³⁺ = <strong>10³¹ M⁻¹</strong> vs. Ca²⁺ = 10² M⁻¹ — approximately 10²⁹ greater selectivity for iron. It does NOT remove iron from haemoglobin or cytochromes because these proteins coordinate iron within a specific protein tertiary structure (porphyrin + protein coordination) that is thermodynamically and kinetically stable — haem iron is not \"free\" iron accessible to the chelator. Deferoxamine chelates only iron in its free, transferrin, ferritin, and haemosiderin forms."}, {"id": "special:q:43", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "Describe the immunotoxic mechanism of TCDD and its primary cellular target.", "back": "TCDD (2,3,7,8-tetrachlorodibenzo-p-dioxin) binds the <strong>aryl hydrocarbon receptor (AhR)</strong> with extremely high affinity and is resistant to CYP-mediated metabolism → sustained AhR activation (unlike other AhR ligands). In T cells: promotes newly activated CD4⁺ T cells → regulatory T cell phenotype (immunosuppression). Also inhibits B cell antibody production, induces tolerogenic dendritic cells, alters CD8⁺ antiviral responses. Most consistent human finding: ↓ CD4⁺ T helper cell subsets. TCDD has human half-life of 7–11 years (extremely persistent)."}, {"id": "special:q:44", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "A chemopreventive strategy uses chlorophyllin for aflatoxin-exposed populations. What is its mechanism?", "back": "Chlorophyllin (water-soluble chlorophyll salts) acts as an <strong>\"interceptor molecule\"</strong> — it tightly binds aflatoxin B₁ in the GI tract, forming a complex that is not absorbed (reduces bioavailability of aflatoxin). Additionally: inhibits CYP activity → less metabolic activation; acts as antioxidant (↓ ROS). Phase II clinical trial: 100 mg chlorophyllin with each meal → significant ↓ in urinary aflatoxin-N7-guanine adducts (direct measure of DNA damage reduced). This is a primary prevention strategy for HCC in aflatoxin-endemic regions."}, {"id": "exp:fc:0", "deck": "Experimental & Clinical", "dk": "exp", "type": "flashcard", "front": "A drug is active at 50 mg/kg in mice. What is the approximate human equivalent dose for a 60 kg adult, and why isn't it simply 50 mg/kg?", "back": "Doses scale with <strong>body surface area</strong>, not weight. HED (mg/kg) = 50 × (K<sub>m</sub> mouse ÷ K<sub>m</sub> human) = 50 × (3/37) ≈ <strong>4.05 mg/kg</strong> → × 60 kg ≈ <strong>243 mg</strong>, then ÷10 safety factor for a first-in-human dose (~24 mg).<div class=\"sr-note\">💎 <strong>Practical Pearl:</strong> Small animals have a higher surface-area-to-mass ratio and faster metabolism, so they need a higher dose per kg. K<sub>m</sub> = weight ÷ surface area.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Direct mg/kg scaling massively over-doses humans when scaling up from rodents — a classic cause of first-in-human toxicity.</div>"}, {"id": "exp:fc:1", "deck": "Experimental & Clinical", "dk": "exp", "type": "flashcard", "front": "You must give a 25 g mouse a drug intraperitoneally. What is the approximate maximum safe volume, and why is IP faster than SC but less predictable than IV?", "back": "Roughly <strong>1 mL</strong> IP in a mouse. IP gives a large absorptive peritoneal surface (fast) but the drug drains via the <strong>portal circulation through the liver first</strong> (first-pass), making bioavailability less predictable than IV, which is instant and 100%.<div class=\"sr-note\">💎 <strong>Practical Pearl:</strong> Rough mouse maxima — IV ~0.2 mL, IP ~1 mL, SC ~0.5 mL, IM ~0.05 mL, oral ~0.5 mL.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> A \"negative result\" after an over-volume injection may be a dilution/injury artefact, not a true lack of drug effect.</div>"}, {"id": "exp:fc:2", "deck": "Experimental & Clinical", "dk": "exp", "type": "flashcard", "front": "Which committee must approve an animal protocol in India, and what are the 3Rs it enforces?", "back": "The institutional <strong>IAEC</strong> approves and monitors each protocol under national <strong>CPCSEA</strong> guidelines. The <strong>3Rs</strong> are <strong>Replacement</strong> (use non-animal methods where possible), <strong>Reduction</strong> (fewest animals consistent with valid statistics), and <strong>Refinement</strong> (minimise pain/distress).<div class=\"sr-note\">💎 <strong>Practical Pearl:</strong> Good experimental design and a correct sample-size calculation <em>are</em> ethical acts — they operationalise Reduction.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> No ethics approval = no experiment and no publishable data; approval must precede any procedure.</div>"}, {"id": "exp:fc:3", "deck": "Experimental & Clinical", "dk": "exp", "type": "flashcard", "front": "Define a bioassay. What single feature distinguishes it from a chemical assay?", "back": "A bioassay estimates the <strong>potency/concentration of a substance by the magnitude of the biological response it evokes</strong>, by comparison with a standard of the same substance on the same tissue. Unlike a chemical assay (which measures molecular quantity), it measures <em>biological activity</em>.<div class=\"sr-note\">💎 <strong>Practical Pearl:</strong> Essential when the active principle is unknown, impure, or has no chemical assay (e.g., early hormone/cytokine work).</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Validity demands standard and unknown act by the <em>same mechanism on the same tissue</em> — i.e. parallel log dose–response curves.</div>"}, {"id": "exp:fc:4", "deck": "Experimental & Clinical", "dk": "exp", "type": "flashcard", "front": "Distinguish graded from quantal responses with an example of each and what each yields.", "back": "<strong>Graded:</strong> continuous, dose-dependent in one preparation (e.g., height of ileum contraction) → yields a dose–response curve. <strong>Quantal (all-or-none):</strong> each animal scored yes/no across a population (convulsion, death) → yields <strong>ED₅₀ / LD₅₀</strong> by probit analysis.<div class=\"sr-note\">💎 <strong>Practical Pearl:</strong> The therapeutic index TI = LD₅₀/ED₅₀ comes from two quantal curves.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> A steep quantal curve means a uniform population; it does <em>not</em> mean the drug is safe — a steep LD₅₀ curve can sit dangerously close to the ED₅₀ curve.</div>"}, {"id": "exp:fc:5", "deck": "Experimental & Clinical", "dk": "exp", "type": "flashcard", "front": "Name the four/five matching methods of bioassay and which is most accurate.", "back": "<strong>Matching, bracketing, interpolation, three-point, and four-point (2+2)</strong> assays. The <strong>four-point assay</strong> is most accurate — two doses each of standard and unknown let you test parallelism (validity) and compute the potency ratio with confidence limits.<div class=\"sr-note\">💎 <strong>Practical Pearl:</strong> If the standard and unknown lines are parallel, the horizontal gap between them is the log potency ratio.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Interpolation is only valid over the linear (≈20–80%) portion of the log dose–response curve.</div>"}, {"id": "exp:fc:6", "deck": "Experimental & Clinical", "dk": "exp", "type": "flashcard", "front": "Which physiological salt solution and temperature do you use for the rat uterus, and what pre-treatment does the animal need?", "back": "<strong>De Jalon solution at 32 °C</strong>, aerated; the rat is <strong>oestrogen-primed</strong> to standardise uterine responsiveness. Agonists include acetylcholine, oxytocin and 5-HT.<div class=\"sr-note\">💎 <strong>Practical Pearl:</strong> De Jalon is low in calcium to keep spontaneous activity quiet so drug responses stand out.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Don't default to 37 °C — the uterus prep runs cooler (32 °C) than the guinea-pig ileum (37 °C).</div>"}, {"id": "exp:fc:7", "deck": "Experimental & Clinical", "dk": "exp", "type": "flashcard", "front": "Why must Krebs solution be aerated with carbogen (95% O₂/5% CO₂) rather than plain air?", "back": "Krebs is a <strong>bicarbonate-buffered</strong> solution; its pH 7.4 is held only by an equilibrium with dissolved CO₂. Bubbling carbogen supplies both oxygen for the tissue <em>and</em> the CO₂ needed to keep the bicarbonate buffer at pH 7.4. Plain air lacks enough CO₂ and the pH drifts alkaline.<div class=\"sr-note\">💎 <strong>Practical Pearl:</strong> Tyrode (also bicarbonate-buffered) behaves similarly; Ringer for frog tissue is simpler and aerated with air at room temperature.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> A drifting baseline or failing tissue is often a buffering/aeration problem, not a drug effect.</div>"}, {"id": "exp:fc:8", "deck": "Experimental & Clinical", "dk": "exp", "type": "flashcard", "front": "On a frontal writing lever, the tissue arm is 1 cm and the writing arm is 10 cm. A muscle shortens 1.5 mm — how big is the trace, and what is the magnification?", "back": "Magnification = writing arm ÷ tissue arm = 10 ÷ 1 = <strong>10×</strong>; a 1.5 mm contraction is drawn as a <strong>15 mm</strong> deflection.<div class=\"sr-note\">💎 <strong>Practical Pearl:</strong> Levers magnify tiny movements onto a smoked kymograph drum; modern labs use force transducers + chart/software instead.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Excessive magnification or lever weight distorts the response — the lever must be light and friction-free.</div>"}, {"id": "exp:fc:9", "deck": "Experimental & Clinical", "dk": "exp", "type": "flashcard", "front": "Which agonist and receptor are used in the guinea-pig ileum and frog rectus abdominis preparations?", "back": "<strong>Guinea-pig ileum:</strong> histamine (H₁) and acetylcholine (muscarinic M₃). <strong>Frog rectus abdominis:</strong> acetylcholine acting on <strong>nicotinic (N<sub>M</sub>)</strong> receptors — a depolarising, slow contraction.<div class=\"sr-note\">💎 <strong>Practical Pearl:</strong> The frog rectus is the classic prep to demonstrate depolarising (nicotinic) versus the smooth-muscle muscarinic response of the ileum.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> ACh acts on muscarinic receptors in the ileum but nicotinic receptors in the rectus — same agonist, different receptor and response.</div>"}, {"id": "exp:fc:10", "deck": "Experimental & Clinical", "dk": "exp", "type": "flashcard", "front": "How does HPLC separate a drug from plasma components, and what does the detector peak area tell you?", "back": "HPLC pumps the sample at high pressure through a column; components separate by how strongly each partitions between mobile and stationary phases. The detector (UV/MS) records each as a peak whose <strong>area is proportional to the amount</strong> of that component — read off a calibration curve.<div class=\"sr-note\">💎 <strong>Practical Pearl:</strong> HPLC is the workhorse for measuring drug levels in PK studies and TDM.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Strongly retained compounds elute <em>later</em> (longer retention time), not earlier.</div>"}, {"id": "exp:fc:11", "deck": "Experimental & Clinical", "dk": "exp", "type": "flashcard", "front": "State the Beer–Lambert law and how a spectrophotometer turns absorbance into a concentration.", "back": "<strong>A = ε·c·l</strong> (absorbance = molar absorptivity × concentration × path length). Absorbance rises linearly with concentration, so you build a <strong>calibration curve</strong> from known standards and read the unknown's absorbance back to a concentration.<div class=\"sr-note\">💎 <strong>Practical Pearl:</strong> Keep readings in the linear (low-absorbance) range; dilute samples that read above the top standard.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> At high concentrations Beer–Lambert deviates (non-linear) — an out-of-range sample reads falsely low.</div>"}, {"id": "exp:fc:12", "deck": "Experimental & Clinical", "dk": "exp", "type": "flashcard", "front": "A new anticonvulsant is positive in the MES test but negative in the PTZ test. What does this predict clinically?", "back": "<strong>MES</strong> (maximal electroshock) models <strong>generalised tonic–clonic (grand-mal)</strong> seizures; a positive MES with negative PTZ predicts efficacy in grand-mal but probably <strong>not in absence (petit-mal)</strong> seizures — a phenytoin/carbamazepine-like profile.<div class=\"sr-note\">💎 <strong>Practical Pearl:</strong> PTZ models absence/myoclonic seizures (ethosuximide positive). A drug positive in <em>both</em> (e.g., valproate) is broad-spectrum.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> MES = abolish tonic extension; PTZ = raise seizure <em>threshold</em> — don't swap which models which seizure type.</div>"}, {"id": "exp:fc:13", "deck": "Experimental & Clinical", "dk": "exp", "type": "flashcard", "front": "Which model screens for muscle relaxants, and which distinguishes central from peripheral analgesia?", "back": "<strong>Rotarod</strong> (fall-off time) screens muscle relaxants/sedatives. <strong>Hot-plate &amp; tail-flick</strong> test <strong>central</strong> (opioid) analgesia; <strong>acetic-acid writhing</strong> tests <strong>peripheral</strong> (NSAID-type) analgesia.<div class=\"sr-note\">💎 <strong>Practical Pearl:</strong> Actophotometer counts locomotion → distinguishes CNS stimulants (↑) from depressants (↓).</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> A drug that simply impairs coordination (rotarod) can masquerade as analgesia in motor-based tests — use a sensory endpoint to be sure.</div>"}, {"id": "exp:fc:14", "deck": "Experimental & Clinical", "dk": "exp", "type": "flashcard", "front": "Name the inducing agent for: carrageenan paw model, isoproterenol model, DOCA-salt model, and TNBS model.", "back": "<strong>Carrageenan</strong> → acute paw oedema (NSAID screen). <strong>Isoproterenol</strong> → myocardial infarction. <strong>DOCA + salt</strong> → hypertension. <strong>TNBS (intrarectal)</strong> → colitis (IBD model).<div class=\"sr-note\">💎 <strong>Practical Pearl:</strong> Paw oedema is quantified with a plethysmometer; cotton-pellet granuloma (dry weight) screens <em>chronic</em> anti-inflammatories.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Carrageenan oedema is biphasic — early (histamine/serotonin/bradykinin) and late (prostaglandin) phases; NSAIDs act mainly on the late phase.</div>"}, {"id": "exp:fc:15", "deck": "Experimental & Clinical", "dk": "exp", "type": "flashcard", "front": "Define LD₅₀ and explain why a steep dose–mortality curve matters.", "back": "<strong>LD₅₀</strong> = the dose that kills 50% of test animals, read off the dose–mortality (quantal) curve. A <strong>steep</strong> curve means a uniform population (small dose increase tips many over); a shallow curve means wide variation in sensitivity.<div class=\"sr-note\">💎 <strong>Practical Pearl:</strong> Therapeutic index = LD₅₀/ED₅₀; a steep, low LD₅₀ near the ED₅₀ signals danger.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> LD₅₀ varies with species, strain, sex, age and route — a poor stand-alone safety figure, now replaced by humane OECD methods.</div>"}, {"id": "exp:fc:16", "deck": "Experimental & Clinical", "dk": "exp", "type": "flashcard", "front": "Put the toxicity studies in order of duration and state what the sub-chronic study primarily defines.", "back": "Order: <strong>acute → sub-acute (~14–28 d) → sub-chronic (~90 d) → chronic (months–2 y)</strong>. The sub-chronic study primarily defines target-organ toxicity and the <strong>NOAEL</strong> (no-observed-adverse-effect level).<div class=\"sr-note\">💎 <strong>Practical Pearl:</strong> Special toxicology adds reproductive (Segments I–III), genotoxicity (Ames) and carcinogenicity (2-year rodent) studies.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Acute toxicity needs ≥2 species, at least one non-rodent.</div>"}, {"id": "exp:fc:17", "deck": "Experimental & Clinical", "dk": "exp", "type": "flashcard", "front": "What does the Ames test detect, and how does it work?", "back": "It detects <strong>mutagenicity</strong> (an early signal of carcinogenic potential) using histidine-dependent <em>Salmonella</em>: if the test chemical mutates their DNA back to a functional gene, colonies grow on histidine-free plates — more colonies = more mutagenic.<div class=\"sr-note\">💎 <strong>Practical Pearl:</strong> Adding liver S9 fraction lets the test catch pro-mutagens that need metabolic activation.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> A positive Ames flags <em>mutagenicity</em>, not proven carcinogenicity — confirm with rodent bioassays.</div>"}, {"id": "exp:fc:18", "deck": "Experimental & Clinical", "dk": "exp", "type": "flashcard", "front": "A batch of IV fluid is sterile but a patient spikes a fever after infusion. What was likely present, and how is it detected?", "back": "<strong>Pyrogen — bacterial endotoxin (lipopolysaccharide)</strong>, which is heat-stable and survives autoclaving even though the bacteria are killed. Detected by the <strong>rabbit pyrogen test</strong> (temperature rise after IV injection) or the <strong>LAL / bacterial endotoxin test</strong> (endotoxin clots horseshoe-crab amoebocyte lysate).<div class=\"sr-note\">💎 <strong>Practical Pearl:</strong> Depyrogenation needs dry heat (~250 °C) or removal steps — sterilisation alone is insufficient.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> \"Sterile\" ≠ \"pyrogen-free\"; the LAL test is faster, more sensitive and animal-free, so it has largely replaced the rabbit test.</div>"}, {"id": "exp:fc:19", "deck": "Experimental & Clinical", "dk": "exp", "type": "flashcard", "front": "What does the MTT assay measure, and what does a darker well indicate?", "back": "Cell <strong>viability/cytotoxicity</strong>: metabolically active (living) cells reduce yellow MTT to purple <strong>formazan</strong>. Absorbance ∝ number of viable cells, so a <strong>darker well = more living cells</strong>; a cytotoxic drug lightens the well.<div class=\"sr-note\">💎 <strong>Practical Pearl:</strong> IC₅₀ (concentration cutting viability by 50%) is read from the MTT dose–response curve.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> MTT reports metabolic activity, not cell number directly — agents that alter metabolism without killing can confound it.</div>"}, {"id": "exp:fc:20", "deck": "Experimental & Clinical", "dk": "exp", "type": "flashcard", "front": "Three groups (control, standard, test) are compared on a continuous, normally-distributed outcome. Which test, and why not three t-tests?", "back": "<strong>One-way ANOVA</strong> (with a post-hoc test). Running three separate t-tests inflates the false-positive rate — each carries a 5% risk, so three ≈ 14% overall. ANOVA tests all groups together and post-hoc correction controls the error.<div class=\"sr-note\">💎 <strong>Practical Pearl:</strong> If the data are skewed/ordinal, use the non-parametric <strong>Kruskal–Wallis</strong> instead.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Repeated measurements on the <em>same</em> animals need repeated-measures ANOVA (or Friedman), not one-way ANOVA.</div>"}, {"id": "exp:fc:21", "deck": "Experimental & Clinical", "dk": "exp", "type": "flashcard", "front": "What does p &lt; 0.05 mean, and how do Type I and Type II errors differ?", "back": "p &lt; 0.05 = if the null hypothesis (no effect) were true, a difference this large would arise by chance &lt;5% of the time. <strong>Type I (α)</strong> = false positive (claiming an effect that isn't real); <strong>Type II (β)</strong> = false negative (missing a real effect). <strong>Power = 1 − β</strong>.<div class=\"sr-note\">💎 <strong>Practical Pearl:</strong> Increase sample size to lower β (raise power) without changing α.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> p is NOT the probability the drug works, and a non-significant result doesn't prove \"no effect\" — it may be underpowered.</div>"}, {"id": "exp:fc:22", "deck": "Experimental & Clinical", "dk": "exp", "type": "flashcard", "front": "Two test (numerical) variables are related but the data are skewed. Which correlation do you use?", "back": "<strong>Spearman rank correlation</strong> (the non-parametric counterpart of Pearson). It works on ranks, so it tolerates non-normality and ordinal data.<div class=\"sr-note\">💎 <strong>Practical Pearl:</strong> Correlation ≠ causation, and a correlation coefficient says nothing about the slope's clinical size.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Pearson assumes a linear relationship and normal data; a strong non-linear relationship can give a near-zero Pearson r.</div>"}, {"id": "exp:fc:23", "deck": "Experimental & Clinical", "dk": "exp", "type": "flashcard", "front": "On a plasma concentration–time curve, what do C<sub>max</sub>, T<sub>max</sub>, AUC and the terminal slope each represent?", "back": "<strong>C<sub>max</sub></strong> = peak concentration; <strong>T<sub>max</sub></strong> = time to peak (both describe absorption rate/extent); <strong>AUC</strong> = total systemic exposure (trapezoidal rule); <strong>terminal slope</strong> on a log scale gives the elimination rate constant k, hence t½ = 0.693/k.<div class=\"sr-note\">💎 <strong>Practical Pearl:</strong> Oral bioavailability F = AUC<sub>oral</sub>/AUC<sub>IV</sub>; bioequivalence compares AUC and C<sub>max</sub>.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Two formulations can share AUC yet differ in C<sub>max</sub>/T<sub>max</sub> — relevant where onset speed matters.</div>"}, {"id": "exp:fc:24", "deck": "Experimental & Clinical", "dk": "exp", "type": "flashcard", "front": "Name four drugs that classically require therapeutic drug monitoring and the single feature they share.", "back": "<strong>Digoxin, lithium, phenytoin, aminoglycosides</strong> (also theophylline, vancomycin, cyclosporine). Shared feature: a <strong>narrow therapeutic index</strong> where plasma level predicts effect/toxicity better than the dose.<div class=\"sr-note\">💎 <strong>Practical Pearl:</strong> Phenytoin needs TDM because its zero-order kinetics make small dose changes cause large level changes.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> A TDM level is only meaningful with correct timing — steady state reached and the right (usually trough) sample.</div>"}, {"id": "exp:fc:25", "deck": "Experimental & Clinical", "dk": "exp", "type": "flashcard", "front": "In the eye experiments, contrast the pupil effect of tropicamide, pilocarpine and hyoscine.", "back": "<strong>Tropicamide</strong> (antimuscarinic) → mydriasis + cycloplegia. <strong>Hyoscine</strong> (antimuscarinic) → mydriasis, reduced salivation, ↑HR. <strong>Pilocarpine</strong> (muscarinic agonist) → miosis (and lowers intra-ocular pressure).<div class=\"sr-note\">💎 <strong>Practical Pearl:</strong> Antimuscarinics dilate (block the sphincter); muscarinic agonists constrict (contract the sphincter).</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Mydriatic antimuscarinics can precipitate <em>angle-closure glaucoma</em> in susceptible eyes — a real safety caution in the practical.</div>"}, {"id": "exp:fc:26", "deck": "Experimental & Clinical", "dk": "exp", "type": "flashcard", "front": "What is microdosing / Phase 0, and why is it valuable?", "back": "Administering a <strong>sub-pharmacological dose (≈1%)</strong> to humans early, using ultra-sensitive assays (e.g., AMS) to read PK, before a full Phase I. It lets a candidate with hopeless human pharmacokinetics be dropped <strong>cheaply and with almost no subject risk</strong>.<div class=\"sr-note\">💎 <strong>Practical Pearl:</strong> Part of the \"fail early, fail cheap\" philosophy alongside in-silico docking and QSAR.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> A microdose reveals PK, not efficacy or safety at therapeutic doses — kinetics need not be linear from a microdose up to the full dose.</div>"}, {"id": "exp:fc:27", "deck": "Experimental & Clinical", "dk": "exp", "type": "flashcard", "front": "Match the biomedical-waste bin colours (India, 2016) to: a used needle, an expired drug, a soiled IV set, and a broken glass ampoule.", "back": "Used needle → <strong>White</strong> (puncture-proof sharps). Expired drug → <strong>Yellow</strong>. Soiled IV set (contaminated plastic) → <strong>Red</strong>. Broken glass ampoule → <strong>Blue</strong>.<div class=\"sr-note\">💎 <strong>Practical Pearl:</strong> Yellow = incineration/deep burial; Red = autoclave→recycle; White = autoclave→shred; Blue = disinfect→recycle.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Segregate at the <em>point of generation</em>; never put sharps into the red plastics bin.</div>"}, {"id": "exp:q:0", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Which species is preferred for the histamine-sensitive ileum bioassay?", "back": "Guinea pig."}, {"id": "exp:q:1", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Which animal is standard for the pyrogen test?", "back": "Rabbit."}, {"id": "exp:q:2", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Which frog preparation demonstrates nicotinic acetylcholine action?", "back": "Rectus abdominis muscle."}, {"id": "exp:q:3", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Typical body-weight range of a laboratory rat?", "back": "About 150–250 g."}, {"id": "exp:q:4", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Which animal is used for the mydriatic/miotic eye experiments?", "back": "Rabbit."}, {"id": "exp:q:5", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Why are mice and rats preferred for general screening?", "back": "Small, inexpensive, well-characterised genetics, easy to house in numbers."}, {"id": "exp:q:6", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Which species provides the isolated perfused heart and rectus prep?", "back": "Frog."}, {"id": "exp:q:7", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "On what physical feature does sex determination in rodents mainly rely?", "back": "Anogenital distance (greater in males)."}, {"id": "exp:q:8", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Guinea pig is especially used to model which hypersensitivity reaction?", "back": "Anaphylaxis (and airway/tracheal responses)."}, {"id": "exp:q:9", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Which route gives 100% bioavailability instantly?", "back": "Intravenous (IV)."}, {"id": "exp:q:10", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Approximate maximum intraperitoneal volume in a mouse?", "back": "About 1 mL."}, {"id": "exp:q:11", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Which oral technique delivers a measured volume to the stomach?", "back": "Oral gavage (curved needle/cannula)."}, {"id": "exp:q:12", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Name two survival blood-collection sites in a rodent.", "back": "Tail vein and retro-orbital (or saphenous) vein."}, {"id": "exp:q:13", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Which terminal method yields a large blood volume?", "back": "Cardiac puncture (non-survival)."}, {"id": "exp:q:14", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Name two zoonotic diseases relevant to animal handlers.", "back": "Leptospirosis and rat-bite fever (also LCMV, salmonellosis)."}, {"id": "exp:q:15", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Preferred humane inhalational euthanasia agent for rodents?", "back": "Carbon dioxide, by gradual fill."}, {"id": "exp:q:16", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Why gradual rather than sudden high CO₂?", "back": "Less distress/aversion — more humane."}, {"id": "exp:q:17", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "What is acclimatisation and why is it done?", "back": "Settling animals in the facility before experiments to reduce stress-related artefacts."}, {"id": "exp:q:18", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Which committee approves protocols at the institution?", "back": "The IAEC (Institutional Animal Ethics Committee)."}, {"id": "exp:q:19", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Which body regulates animal experiments nationally in India?", "back": "CPCSEA."}, {"id": "exp:q:20", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Expand the 3Rs.", "back": "Replacement, Reduction, Refinement."}, {"id": "exp:q:21", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Which R does a correct sample-size calculation serve?", "back": "Reduction."}, {"id": "exp:q:22", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Which R do analgesia and gentle handling serve?", "back": "Refinement."}, {"id": "exp:q:23", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Which R does using cell culture instead of animals serve?", "back": "Replacement."}, {"id": "exp:q:24", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Order routes by speed of onset, fastest first.", "back": "IV &gt; IP &gt; IM/SC &gt; oral."}, {"id": "exp:q:25", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Why is IP bioavailability less predictable than IV?", "back": "Peritoneal absorption drains via the portal vein → hepatic first-pass."}, {"id": "exp:q:26", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Approximate maximum IV volume in a mouse?", "back": "About 0.2 mL."}, {"id": "exp:q:27", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Why must IV injectables be aqueous and non-irritant?", "back": "They enter the bloodstream directly; oily/irritant solutions cause embolism or phlebitis."}, {"id": "exp:q:28", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Which route forms a depot for slow release?", "back": "Subcutaneous (SC)."}, {"id": "exp:q:29", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Why is the IM volume tiny in a mouse?", "back": "Very small muscle mass."}, {"id": "exp:q:30", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "What two things cap the maximum injection volume?", "back": "Body weight and the route (to avoid pain, dilution, injury)."}, {"id": "exp:q:31", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Define bioavailability.", "back": "The fraction of an administered dose reaching the systemic circulation unchanged."}, {"id": "exp:q:32", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Why is oral absorption the most variable?", "back": "GI transit, first-pass metabolism, food and formulation all vary."}, {"id": "exp:q:33", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "What must precede any experimental procedure?", "back": "Ethics (IAEC) approval."}, {"id": "exp:q:34", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "State one humane-endpoint principle.", "back": "Euthanise before severe suffering, using predefined criteria."}, {"id": "exp:q:35", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Refinement of handling aims to reduce what?", "back": "Pain and distress."}, {"id": "exp:q:36", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Why may animals be segregated by sex?", "back": "Hormonal differences alter drug responses and add variability."}, {"id": "exp:q:37", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "What is a \"naïve\" animal?", "back": "One not previously used or exposed to drugs."}, {"id": "exp:q:38", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Why must needle size and volume suit the species?", "back": "To avoid tissue injury and dosing artefacts."}, {"id": "exp:q:39", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Which document lists the planned procedures for approval?", "back": "The research/experimental protocol."}, {"id": "exp:q:40", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Doses scale across species with what, rather than weight?", "back": "Body surface area."}, {"id": "exp:q:41", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Define the K<sub>m</sub> factor.", "back": "Body weight (kg) ÷ body surface area (m²)."}, {"id": "exp:q:42", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "K<sub>m</sub> values for mouse and human?", "back": "Mouse 3; human 37."}, {"id": "exp:q:43", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Write the Human Equivalent Dose equation.", "back": "HED = animal dose × (K<sub>m</sub> animal ÷ K<sub>m</sub> human)."}, {"id": "exp:q:44", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Convert a 50 mg/kg mouse dose to an HED.", "back": "50 × (3/37) ≈ 4.05 mg/kg."}, {"id": "exp:q:45", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Why does a mouse need a higher mg/kg dose than a human?", "back": "Higher surface-area-to-mass ratio → faster metabolism and clearance."}, {"id": "exp:q:46", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Approximate allometric exponent for metabolic rate?", "back": "≈ 0.75 (surface area ≈ 0.67)."}, {"id": "exp:q:47", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "K<sub>m</sub> for the rat?", "back": "6."}, {"id": "exp:q:48", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "K<sub>m</sub> for the dog?", "back": "20."}, {"id": "exp:q:49", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "After computing HED, what is applied before the first human dose?", "back": "A safety factor (commonly ÷10)."}, {"id": "exp:q:50", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Name the tabulated alternative to K<sub>m</sub> for dose conversion.", "back": "The Paget &amp; Barnes conversion table."}, {"id": "exp:q:51", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Why is linear mg/kg scaling from rodent to human dangerous?", "back": "It over-estimates the human dose."}, {"id": "exp:q:52", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Total HED for a 60 kg adult from 4.05 mg/kg?", "back": "≈ 243 mg."}, {"id": "exp:q:53", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "First-in-human dose after a ÷10 safety factor on 243 mg?", "back": "≈ 24 mg."}, {"id": "exp:q:54", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Reference adult human weight in K<sub>m</sub> tables?", "back": "≈ 60 kg."}, {"id": "exp:q:55", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Reference mouse weight?", "back": "≈ 0.02 kg."}, {"id": "exp:q:56", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Why is surface area linked to metabolic rate?", "back": "Heat loss and metabolism scale with surface area."}, {"id": "exp:q:57", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "What is the NOAEL used for?", "back": "As a basis for the safe human starting dose (with safety factors)."}, {"id": "exp:q:58", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "K<sub>m</sub> for the rabbit?", "back": "12."}, {"id": "exp:q:59", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Does the K<sub>m</sub> method correct for weight or surface area?", "back": "Surface area (K<sub>m</sub> packages the surface-area correction)."}, {"id": "exp:q:60", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Define a bioassay.", "back": "Estimating the potency/concentration of a substance by the biological response it evokes, versus a standard."}, {"id": "exp:q:61", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "The unknown must be compared with what?", "back": "A standard of the same substance, on the same tissue, under identical conditions."}, {"id": "exp:q:62", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Name the five matching methods.", "back": "Matching, bracketing, interpolation, three-point, four-point."}, {"id": "exp:q:63", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Which method is most accurate and why?", "back": "Four-point — it tests parallelism (validity) and gives the potency ratio with statistics."}, {"id": "exp:q:64", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "In interpolation, what is plotted on the axes?", "back": "Response (y) vs log dose of the standard (x)."}, {"id": "exp:q:65", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Over what part of the curve is interpolation valid?", "back": "The linear ≈20–80% portion."}, {"id": "exp:q:66", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "What does bracketing achieve?", "back": "Traps the unknown between a clearly larger and a clearly smaller standard response."}, {"id": "exp:q:67", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "When is the matching method used?", "back": "For a quick, crude estimate (e.g., teaching/bedside)."}, {"id": "exp:q:68", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "What does parallelism of log dose–response lines indicate?", "back": "Same mechanism (valid assay); the horizontal gap is the log potency ratio."}, {"id": "exp:q:69", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Advantage of bioassay over chemical assay?", "back": "It measures biological activity, and works when the active principle is unknown or impure."}, {"id": "exp:q:70", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Main source of error in a bioassay?", "back": "Biological variation."}, {"id": "exp:q:71", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "How is biological variation controlled?", "back": "Randomisation, replication, and using the tissue as its own control."}, {"id": "exp:q:72", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "What is a standard preparation?", "back": "A reference of known potency used for comparison."}, {"id": "exp:q:73", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Give an example of a tissue bioassay.", "back": "Histamine assayed on guinea-pig ileum."}, {"id": "exp:q:74", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Why must conditions be identical for standard and unknown?", "back": "To keep the comparison (and the potency estimate) valid."}, {"id": "exp:q:75", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "The three-point assay uses how many doses, of what?", "back": "Two standard doses + one unknown, in geometric progression."}, {"id": "exp:q:76", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Describe the four-point assay design.", "back": "Two doses each of standard and unknown (2 + 2)."}, {"id": "exp:q:77", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "What does the four-point design let you check?", "back": "Assay validity through parallelism of the two lines."}, {"id": "exp:q:78", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Which historically un-assayable agents were measured by bioassay?", "back": "Hormones, cytokines and toxins."}, {"id": "exp:q:79", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Why plot dose on a log scale?", "back": "It linearises the central portion of the sigmoid dose–response curve."}, {"id": "exp:q:80", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Define a graded response.", "back": "A continuous, dose-dependent response in a single preparation."}, {"id": "exp:q:81", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Define a quantal response.", "back": "An all-or-none response scored per subject across a population."}, {"id": "exp:q:82", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Example of a graded response.", "back": "Height of an ileum or uterus contraction."}, {"id": "exp:q:83", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Example of a quantal response.", "back": "Death or convulsion (present/absent)."}, {"id": "exp:q:84", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "What does a quantal dose–response curve yield?", "back": "ED₅₀ / LD₅₀ (via probit analysis)."}, {"id": "exp:q:85", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Define ED₅₀.", "back": "The dose producing the defined effect in 50% of the population."}, {"id": "exp:q:86", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Define therapeutic index.", "back": "LD₅₀ ÷ ED₅₀."}, {"id": "exp:q:87", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "What does an antagonist bioassay quantify?", "back": "Antagonist potency, expressed as pA₂."}, {"id": "exp:q:88", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Define pA₂.", "back": "The negative log of the antagonist concentration that requires the agonist dose to be doubled (dose ratio = 2)."}, {"id": "exp:q:89", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "What does a competitive antagonist do to the agonist curve?", "back": "Parallel rightward shift with Emax preserved (surmountable)."}, {"id": "exp:q:90", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "What does an irreversible antagonist do to Emax?", "back": "Reduces it (non-surmountable)."}, {"id": "exp:q:91", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "A Schild plot slope of ~1 indicates what?", "back": "Simple competitive antagonism."}, {"id": "exp:q:92", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "What is a dose ratio (DR)?", "back": "The factor by which agonist dose must rise to restore the response in the antagonist's presence."}, {"id": "exp:q:93", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Why use the middle of the dose–response curve for readings?", "back": "It is the most linear and most sensitive region."}, {"id": "exp:q:94", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "The probit transformation converts what to what?", "back": "A sigmoid % response into a straight line."}, {"id": "exp:q:95", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Why is one tissue often used as its own control?", "back": "To minimise between-animal variability."}, {"id": "exp:q:96", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "What confirms a tissue is still viable before calling a drug inactive?", "back": "A normal response to a standard agonist dose."}, {"id": "exp:q:97", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Which property does EC₅₀ reflect?", "back": "Potency."}, {"id": "exp:q:98", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Which property does Emax reflect?", "back": "Efficacy."}, {"id": "exp:q:99", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "A surmountable antagonist is overcome by what?", "back": "Increasing the agonist concentration."}, {"id": "exp:q:100", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "What keeps an isolated tissue alive in the organ bath?", "back": "Warmed, aerated physiological salt solution (PSS)."}, {"id": "exp:q:101", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "PSS for the guinea-pig ileum?", "back": "Tyrode solution."}, {"id": "exp:q:102", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "PSS for most mammalian smooth and cardiac muscle?", "back": "Krebs (–Henseleit) solution."}, {"id": "exp:q:103", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "PSS and temperature for the rat uterus?", "back": "De Jalon solution at 32 °C."}, {"id": "exp:q:104", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "PSS for frog tissues?", "back": "Ringer solution."}, {"id": "exp:q:105", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "PSS for the isolated rabbit/mammalian heart?", "back": "Locke solution."}, {"id": "exp:q:106", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Why does Krebs need carbogen rather than air?", "back": "Its bicarbonate buffer needs CO₂ to hold pH 7.4, plus O₂ for the tissue."}, {"id": "exp:q:107", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Composition of carbogen?", "back": "95% O₂ and 5% CO₂."}, {"id": "exp:q:108", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Standard temperature for mammalian gut preparations?", "back": "37 °C."}, {"id": "exp:q:109", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Temperature for frog-tissue preparations?", "back": "Room temperature."}, {"id": "exp:q:110", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Function of the water jacket around the bath?", "back": "Maintains the PSS at a constant temperature."}, {"id": "exp:q:111", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Two reasons to aerate the bath continuously?", "back": "Supply oxygen and (for bicarbonate buffers) maintain pH."}, {"id": "exp:q:112", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Describe the dose cycle.", "back": "Add dose → record peak → wash → rest → next dose, kept constant."}, {"id": "exp:q:113", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Why keep contact time constant?", "back": "To obtain comparable, valid responses."}, {"id": "exp:q:114", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "What does washing between doses achieve?", "back": "Removes drug and lets the tissue recover."}, {"id": "exp:q:115", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "De Jalon is low in which ion, and why?", "back": "Calcium — to suppress spontaneous activity."}, {"id": "exp:q:116", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Why is the rat oestrogen-primed for uterus work?", "back": "To standardise uterine responsiveness."}, {"id": "exp:q:117", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Why might a flat trace mean a dead prep, not an inactive drug?", "back": "Wrong PSS, temperature or aeration, or tissue fatigue."}, {"id": "exp:q:118", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "What confirms the preparation is healthy at the start?", "back": "A brisk response to a standard agonist dose."}, {"id": "exp:q:119", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Modern replacement for the smoked-drum lever?", "back": "A force transducer with chart recorder/software."}, {"id": "exp:q:120", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Guinea-pig ileum: histamine acts on which receptor?", "back": "H₁."}, {"id": "exp:q:121", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Guinea-pig ileum: acetylcholine acts on which receptor?", "back": "Muscarinic M₃."}, {"id": "exp:q:122", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "The rat fundus strip detects which agonist?", "back": "5-HT (serotonin)."}, {"id": "exp:q:123", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Name three agonists used on the rat uterus.", "back": "Acetylcholine, oxytocin, 5-HT."}, {"id": "exp:q:124", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Guinea-pig atria: agonist and receptor?", "back": "Adrenaline acting on β₁ receptors."}, {"id": "exp:q:125", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Frog rectus abdominis: agonist and receptor?", "back": "Acetylcholine on nicotinic (N<sub>M</sub>) receptors."}, {"id": "exp:q:126", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "ACh acts on which receptor in ileum vs rectus?", "back": "Muscarinic in ileum; nicotinic in the rectus."}, {"id": "exp:q:127", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "What does the frog rectus classically demonstrate?", "back": "A depolarising (nicotinic) contraction."}, {"id": "exp:q:128", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "The guinea-pig tracheal chain tests which drugs?", "back": "Bronchoconstrictors/dilators (H₁ / β₂)."}, {"id": "exp:q:129", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Define lever magnification.", "back": "Writing-arm length ÷ tissue-arm length."}, {"id": "exp:q:130", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "A lever ratio of 8 cm : 1 cm gives what magnification?", "back": "8×."}, {"id": "exp:q:131", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "A 2 mm contraction at 10× magnification draws how big?", "back": "20 mm."}, {"id": "exp:q:132", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Why must the lever be light and friction-free?", "back": "To avoid distorting the recorded response."}, {"id": "exp:q:133", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "What traditionally records the lever trace?", "back": "A smoked kymograph drum."}, {"id": "exp:q:134", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Which receptor mediates adrenaline's effect on atrial rate?", "back": "β₁-adrenergic."}, {"id": "exp:q:135", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Classic prep to show atropine antagonism of ACh?", "back": "Guinea-pig ileum (or rat tissue)."}, {"id": "exp:q:136", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "What is a frontal writing lever?", "back": "A lever whose point writes on the front of a vertical drum."}, {"id": "exp:q:137", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Why oestrogen-prime before a uterine oxytocin assay?", "back": "To get reproducible contractile responses."}, {"id": "exp:q:138", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Which preparation bioassays oxytocin?", "back": "The rat uterus."}, {"id": "exp:q:139", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Which preparation bioassays histamine?", "back": "The guinea-pig ileum."}, {"id": "exp:q:140", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "What are the two jobs of most analytical methods?", "back": "Separate, then detect/quantify."}, {"id": "exp:q:141", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Chromatography separates by what?", "back": "Differential partition between mobile and stationary phases."}, {"id": "exp:q:142", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "HPLC is used to measure what?", "back": "Drug concentration in plasma/urine (PK and TDM)."}, {"id": "exp:q:143", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "In HPLC, which compounds elute later?", "back": "Those more strongly retained by the stationary phase."}, {"id": "exp:q:144", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Peak area in a chromatogram is proportional to what?", "back": "The amount of that compound."}, {"id": "exp:q:145", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "State the Beer–Lambert law.", "back": "A = ε·c·l."}, {"id": "exp:q:146", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "How does a spectrophotometer yield a concentration?", "back": "By reading absorbance off a calibration curve."}, {"id": "exp:q:147", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Why keep absorbance in the linear range?", "back": "Beer–Lambert deviates at high concentrations."}, {"id": "exp:q:148", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "What does ELISA measure, and how?", "back": "Proteins/hormones/antibodies via an enzyme-linked colour change."}, {"id": "exp:q:149", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "What does PCR do?", "back": "Amplifies (and can quantify) specific DNA/RNA."}, {"id": "exp:q:150", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Electrophoresis separates molecules by what?", "back": "Size and charge in a gel under an electric field."}, {"id": "exp:q:151", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "A centrifuge separates by what?", "back": "Density (under g-force)."}, {"id": "exp:q:152", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "What value does TLC give for identity?", "back": "The Rf value."}, {"id": "exp:q:153", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Gas chromatography suits which compounds?", "back": "Volatile compounds."}, {"id": "exp:q:154", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "What is GC-MS used for?", "back": "Separation plus identification (e.g., toxicology)."}, {"id": "exp:q:155", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Why choose ELISA over HPLC for a picogram-level hormone?", "back": "Greater sensitivity/specificity for that antigen."}, {"id": "exp:q:156", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "What provides the calibration (standard) curve?", "back": "Known standards run alongside the unknowns."}, {"id": "exp:q:157", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Reading an unknown above the top standard gives what error?", "back": "A falsely low result (out of linear range)."}, {"id": "exp:q:158", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Which phase carries the sample along — mobile or stationary?", "back": "The mobile phase."}, {"id": "exp:q:159", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Name a common HPLC detector.", "back": "UV detector (or mass spectrometer)."}, {"id": "exp:q:160", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Rotarod tests what, and screens which drugs?", "back": "Motor coordination; muscle relaxants and sedatives."}, {"id": "exp:q:161", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "What does the actophotometer measure?", "back": "Locomotor activity (movement counts)."}, {"id": "exp:q:162", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "MES models which seizure type?", "back": "Generalised tonic–clonic (grand mal)."}, {"id": "exp:q:163", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "PTZ models which seizure type?", "back": "Absence/myoclonic (petit mal)."}, {"id": "exp:q:164", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Standard drug positive in MES?", "back": "Phenytoin (also carbamazepine)."}, {"id": "exp:q:165", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Standard drug positive in PTZ?", "back": "Ethosuximide."}, {"id": "exp:q:166", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "A drug positive in both MES and PTZ suggests what?", "back": "A broad-spectrum anticonvulsant (e.g., valproate)."}, {"id": "exp:q:167", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Hot-plate and tail-flick test which analgesia?", "back": "Central (opioid) analgesia."}, {"id": "exp:q:168", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Acetic-acid writhing tests which analgesia?", "back": "Peripheral (NSAID-type) analgesia."}, {"id": "exp:q:169", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "The Straub tail reaction is induced by what?", "back": "Morphine (opioids)."}, {"id": "exp:q:170", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Haloperidol catalepsy models what?", "back": "Extrapyramidal/antipsychotic-related motor effects."}, {"id": "exp:q:171", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "The Morris water maze tests what?", "back": "Spatial learning and memory."}, {"id": "exp:q:172", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "The elevated plus maze tests what?", "back": "Anxiety."}, {"id": "exp:q:173", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "MES endpoint indicating protection?", "back": "Abolition of tonic hind-limb extension."}, {"id": "exp:q:174", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "PTZ endpoint indicating protection?", "back": "Raised seizure threshold (no clonus)."}, {"id": "exp:q:175", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "The pentobarbital righting-reflex test demonstrates what?", "back": "Hypnosis/sleep (loss of righting reflex)."}, {"id": "exp:q:176", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Why can rotarod falsely suggest analgesia?", "back": "It detects motor impairment, not pain relief."}, {"id": "exp:q:177", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Diazepam on rotarod shows what effect?", "back": "Muscle relaxation (reduced fall-off time)."}, {"id": "exp:q:178", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Which maze uses an escape platform to test memory?", "back": "The Morris water maze."}, {"id": "exp:q:179", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Phenytoin protects against which seizure screen?", "back": "MES (grand-mal)."}, {"id": "exp:q:180", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Isoproterenol induces which cardiac condition?", "back": "Myocardial infarction."}, {"id": "exp:q:181", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "DOCA + salt induces what?", "back": "Hypertension."}, {"id": "exp:q:182", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "FeCl₃ applied to a vessel induces what?", "back": "Arterial thrombosis."}, {"id": "exp:q:183", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "The pylorus-ligation (Shay) model studies what?", "back": "Gastric (acid) ulcer."}, {"id": "exp:q:184", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Name two other ulcer-inducing agents.", "back": "Ethanol and NSAIDs (also stress)."}, {"id": "exp:q:185", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "TNBS given intrarectally induces what?", "back": "Colitis (an IBD model)."}, {"id": "exp:q:186", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Cerulein induces what?", "back": "Acute pancreatitis."}, {"id": "exp:q:187", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Carrageenan in the paw induces what?", "back": "Acute paw oedema (inflammation)."}, {"id": "exp:q:188", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Which drug class does carrageenan paw oedema screen?", "back": "NSAIDs (acute anti-inflammatories)."}, {"id": "exp:q:189", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "How is paw oedema quantified?", "back": "By paw volume (plethysmometer)."}, {"id": "exp:q:190", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "The cotton-pellet granuloma screens what?", "back": "Chronic anti-inflammatory activity."}, {"id": "exp:q:191", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "How is the granuloma quantified?", "back": "By the dry weight of the pellet."}, {"id": "exp:q:192", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Early-phase mediators of carrageenan oedema?", "back": "Histamine, serotonin and bradykinin."}, {"id": "exp:q:193", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Late-phase mediator of carrageenan oedema?", "back": "Prostaglandins."}, {"id": "exp:q:194", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Which phase do NSAIDs mainly suppress?", "back": "The late (prostaglandin) phase."}, {"id": "exp:q:195", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Endpoint of the isoproterenol MI model?", "back": "Cardiac enzymes and histology."}, {"id": "exp:q:196", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Endpoint of the DOCA-salt model?", "back": "A sustained rise in blood pressure."}, {"id": "exp:q:197", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Endpoint of the FeCl₃ model?", "back": "Time to occlusive thrombus formation."}, {"id": "exp:q:198", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Endpoint of gastric-ulcer models?", "back": "Ulcer index and acid output."}, {"id": "exp:q:199", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Endpoint of TNBS colitis?", "back": "Colonic damage/inflammation score."}, {"id": "exp:q:200", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Order the toxicity ladder by duration.", "back": "Acute → sub-acute → sub-chronic → chronic."}, {"id": "exp:q:201", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Which key value comes from acute toxicity?", "back": "The LD₅₀."}, {"id": "exp:q:202", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Duration of an acute study?", "back": "Single dose / 24 hours."}, {"id": "exp:q:203", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Duration of a sub-acute study?", "back": "About 14–28 days."}, {"id": "exp:q:204", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Sub-chronic duration and main output?", "back": "~90 days; NOAEL and target-organ toxicity."}, {"id": "exp:q:205", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Duration of a chronic study?", "back": "6 months to 2 years."}, {"id": "exp:q:206", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Define LD₅₀.", "back": "The dose that kills 50% of test animals."}, {"id": "exp:q:207", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "LD₅₀ is which type of endpoint?", "back": "Quantal (all-or-none)."}, {"id": "exp:q:208", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "What does a steep dose–mortality curve indicate?", "back": "A uniform population sensitivity."}, {"id": "exp:q:209", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "How many species are needed for acute toxicity?", "back": "At least two, one of them non-rodent."}, {"id": "exp:q:210", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Define NOAEL.", "back": "The highest dose with no observed adverse effect."}, {"id": "exp:q:211", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Name the three special-toxicology domains.", "back": "Reproductive, genotoxicity, carcinogenicity."}, {"id": "exp:q:212", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "What does the Ames test detect?", "back": "Mutagenicity."}, {"id": "exp:q:213", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "How does the Ames test work?", "back": "His⁻ Salmonella regain growth on His-free plates if the chemical mutates their DNA."}, {"id": "exp:q:214", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "What does adding liver S9 to the Ames test reveal?", "back": "Pro-mutagens needing metabolic activation."}, {"id": "exp:q:215", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Carcinogenicity bioassay duration?", "back": "About 2 years (rodent lifetime)."}, {"id": "exp:q:216", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "What do reproductive Segments I–III cover?", "back": "Fertility; organogenesis/teratogenicity; peri/postnatal development."}, {"id": "exp:q:217", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Why is the classical LD₅₀ now largely replaced?", "back": "It needs many animals and varies; humane OECD methods (fixed-dose, up-and-down) are preferred."}, {"id": "exp:q:218", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Under what quality system is toxicology conducted?", "back": "Good Laboratory Practice (GLP)."}, {"id": "exp:q:219", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Define therapeutic index from toxicity data.", "back": "LD₅₀ ÷ ED₅₀."}, {"id": "exp:q:220", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "What is a pyrogen chemically (commonest)?", "back": "Bacterial endotoxin (lipopolysaccharide)."}, {"id": "exp:q:221", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Source of endotoxin?", "back": "The Gram-negative bacterial cell wall."}, {"id": "exp:q:222", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Endpoint of the rabbit pyrogen test?", "back": "Rise in body temperature after IV injection."}, {"id": "exp:q:223", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "What does the LAL test detect?", "back": "Endotoxin (it clots the lysate)."}, {"id": "exp:q:224", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Source of LAL reagent?", "back": "Horseshoe-crab amoebocyte lysate."}, {"id": "exp:q:225", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Why has LAL replaced the rabbit test?", "back": "Faster, more sensitive and animal-free."}, {"id": "exp:q:226", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Why does endotoxin survive autoclaving?", "back": "It is heat-stable."}, {"id": "exp:q:227", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Are \"sterile\" and \"pyrogen-free\" the same?", "back": "No — sterilisation can leave heat-stable endotoxin behind."}, {"id": "exp:q:228", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Method of depyrogenation?", "back": "Dry heat (~250 °C) or removal/filtration steps."}, {"id": "exp:q:229", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Primary vs continuous cell line?", "back": "Primary = fresh, finite lifespan; continuous = immortalised, indefinite."}, {"id": "exp:q:230", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "What does serum (FBS) provide in culture?", "back": "Growth factors and nutrients."}, {"id": "exp:q:231", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Why 5% CO₂ in the incubator?", "back": "To maintain medium pH (bicarbonate buffer)."}, {"id": "exp:q:232", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Standard cell-culture temperature?", "back": "37 °C."}, {"id": "exp:q:233", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Commonest cell-culture disaster?", "back": "Contamination (bacteria, fungi, mycoplasma)."}, {"id": "exp:q:234", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "How is contamination prevented?", "back": "Strict aseptic technique."}, {"id": "exp:q:235", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "What does the MTT assay measure?", "back": "Cell viability / cytotoxicity."}, {"id": "exp:q:236", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Living cells convert MTT to what coloured product?", "back": "Purple formazan."}, {"id": "exp:q:237", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "A darker MTT well indicates what?", "back": "More viable cells."}, {"id": "exp:q:238", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "What does IC₅₀ from an MTT assay mean?", "back": "The concentration reducing viability by 50%."}, {"id": "exp:q:239", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Why is endotoxin testing critical for injectables specifically?", "back": "They bypass barriers; IV endotoxin causes fever/shock."}, {"id": "exp:q:240", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Two broad types of data?", "back": "Qualitative (categorical) and quantitative (numerical)."}, {"id": "exp:q:241", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Subtypes of qualitative data?", "back": "Nominal and ordinal."}, {"id": "exp:q:242", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Subtypes of quantitative data?", "back": "Discrete and continuous."}, {"id": "exp:q:243", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Descriptive vs inferential statistics?", "back": "Summarise the sample vs generalise to the population."}, {"id": "exp:q:244", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Test for two independent normal groups?", "back": "Unpaired (Student's) t-test."}, {"id": "exp:q:245", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Test for two paired normal measurements?", "back": "Paired t-test."}, {"id": "exp:q:246", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Test for ≥3 independent normal groups?", "back": "One-way ANOVA."}, {"id": "exp:q:247", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Non-parametric equivalent of the unpaired t-test?", "back": "Mann–Whitney U."}, {"id": "exp:q:248", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Non-parametric equivalent of the paired t-test?", "back": "Wilcoxon signed-rank."}, {"id": "exp:q:249", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Non-parametric equivalent of one-way ANOVA?", "back": "Kruskal–Wallis."}, {"id": "exp:q:250", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Test for proportions/categories?", "back": "Chi-square (or Fisher's exact)."}, {"id": "exp:q:251", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "When use Fisher's exact over chi-square?", "back": "With small expected counts."}, {"id": "exp:q:252", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Parametric vs non-parametric correlation?", "back": "Pearson vs Spearman."}, {"id": "exp:q:253", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "What does p &lt; 0.05 mean?", "back": "&lt;5% probability of a difference this large if the null were true."}, {"id": "exp:q:254", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Define Type I error.", "back": "A false positive (α)."}, {"id": "exp:q:255", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Define Type II error.", "back": "A false negative (β)."}, {"id": "exp:q:256", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Define power.", "back": "1 − β."}, {"id": "exp:q:257", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "How do you raise power?", "back": "Increase the sample size (or the effect size)."}, {"id": "exp:q:258", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Why not run several t-tests instead of ANOVA?", "back": "It inflates the overall false-positive rate."}, {"id": "exp:q:259", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Why calculate sample size before the study?", "back": "To ensure adequate power and use the minimum ethical number of animals."}, {"id": "exp:q:260", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "What does C<sub>max</sub> represent?", "back": "The peak plasma concentration."}, {"id": "exp:q:261", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "What does T<sub>max</sub> represent?", "back": "The time to peak concentration."}, {"id": "exp:q:262", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "What does AUC represent?", "back": "Total systemic exposure."}, {"id": "exp:q:263", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "How is AUC computed from sampled points?", "back": "By the trapezoidal rule."}, {"id": "exp:q:264", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "How is t½ obtained from the curve?", "back": "From the terminal slope (log scale): k, then t½ = 0.693/k."}, {"id": "exp:q:265", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Formula for oral bioavailability?", "back": "F = AUC<sub>oral</sub>/AUC<sub>IV</sub>."}, {"id": "exp:q:266", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "What does bioequivalence compare?", "back": "AUC and C<sub>max</sub> (and T<sub>max</sub>)."}, {"id": "exp:q:267", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "One- vs two-compartment model?", "back": "Single exponential decay vs biexponential (distribution then elimination)."}, {"id": "exp:q:268", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "After how many half-lives is steady state reached?", "back": "About 4–5."}, {"id": "exp:q:269", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Define therapeutic drug monitoring.", "back": "Measuring plasma drug levels to guide dosing."}, {"id": "exp:q:270", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Why monitor phenytoin?", "back": "Zero-order kinetics — a small dose change causes a large level change."}, {"id": "exp:q:271", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Name four classic TDM drugs.", "back": "Digoxin, lithium, phenytoin, aminoglycosides."}, {"id": "exp:q:272", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Shared feature of TDM drugs?", "back": "A narrow therapeutic index."}, {"id": "exp:q:273", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Which sample guides aminoglycoside safety?", "back": "The trough level."}, {"id": "exp:q:274", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "The salbutamol-vs-placebo experiment measures what?", "back": "Peak expiratory flow rate (PEFR)."}, {"id": "exp:q:275", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "The frusemide volunteer experiment measures what?", "back": "Urine volume and Na⁺/K⁺ excretion."}, {"id": "exp:q:276", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Tropicamide's effect on the pupil?", "back": "Mydriasis (antimuscarinic)."}, {"id": "exp:q:277", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Pilocarpine's effect on the pupil?", "back": "Miosis (muscarinic agonist)."}, {"id": "exp:q:278", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Why can two formulations share AUC yet differ clinically?", "back": "They can differ in C<sub>max</sub>/T<sub>max</sub> (onset)."}, {"id": "exp:q:279", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Propranolol's effect on exercise BP and HR?", "back": "It blunts the exercise-induced rise in both."}, {"id": "exp:q:280", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "First section of a research protocol?", "back": "The title (followed by rationale/background)."}, {"id": "exp:q:281", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "What must a protocol justify about numbers?", "back": "The sample size."}, {"id": "exp:q:282", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "What approval must precede data collection?", "back": "IAEC/ethics approval."}, {"id": "exp:q:283", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Give two items for the yellow waste bin.", "back": "Anatomical waste and expired/discarded drugs (also soiled/chemical/micro waste)."}, {"id": "exp:q:284", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Give two items for the red waste bin.", "back": "Contaminated plastics — tubing and IV sets (also gloves, catheters)."}, {"id": "exp:q:285", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "What goes in the white (puncture-proof) bin?", "back": "Sharps — needles, syringes with needles, blades."}, {"id": "exp:q:286", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "What goes in the blue bin?", "back": "Broken/discarded glass and metallic implants."}, {"id": "exp:q:287", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Treatment for yellow waste?", "back": "Incineration or deep burial."}, {"id": "exp:q:288", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Treatment for sharps (white)?", "back": "Autoclave/dry heat, then shred."}, {"id": "exp:q:289", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Where must waste segregation happen?", "back": "At the point of generation."}, {"id": "exp:q:290", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Define impact factor.", "back": "A journal's average citations per recent article per year."}, {"id": "exp:q:291", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Does impact factor rate a paper or a journal?", "back": "A journal."}, {"id": "exp:q:292", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "What is molecular docking?", "back": "In-silico fitting of a molecule into a target's structure."}, {"id": "exp:q:293", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "What is QSAR?", "back": "Quantitative structure–activity relationship modelling."}, {"id": "exp:q:294", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Define translational medicine.", "back": "Bench-to-bedside (and back) research."}, {"id": "exp:q:295", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Define reverse pharmacology.", "back": "Starting from a clinical/traditional lead and working back to the mechanism."}, {"id": "exp:q:296", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "What is microdosing / Phase 0?", "back": "Giving a sub-pharmacological human dose to study early PK."}, {"id": "exp:q:297", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Why microdose?", "back": "To drop poor-pharmacokinetic candidates cheaply with minimal subject risk."}, {"id": "exp:q:298", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "What does analytical toxicology do?", "back": "Detects and quantifies poisons/drugs in body fluids."}, {"id": "exp:q:299", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Why critically appraise promotional product literature?", "back": "Marketing claims may overstate the underlying evidence."}, {"id": "neuro:fc:20", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "flashcard", "front": "A 30-year-old has a generalised tonic-clonic seizure lasting 8 minutes. Outline the stepwise drug management of status epilepticus.", "back": "Status epilepticus = seizure ≥5 min (or recurrent without recovery). (1) ABC, O₂, IV access, check/correct glucose. (2) First-line: IV <strong>lorazepam</strong> (or buccal midazolam / rectal diazepam) — enhances GABA<sub>A</sub>; may repeat once. (3) Second-line load: IV <strong>levetiracetam, valproate, or (fos)phenytoin</strong> infusion. (4) Refractory (&gt;40 min): general anaesthesia (propofol / midazolam infusion / thiopental) + intubation + EEG.<div class=\"sr-note\">💎 <strong>Pearl:</strong> Fosphenytoin (prodrug) infuses faster with less hypotension and no purple-glove syndrome vs IV phenytoin (give ≤50 mg/min with cardiac monitoring).</div><div class=\"sr-note\">⚠️ <strong>Trap:</strong> Don't keep redosing benzodiazepines beyond two doses — escalate to a second-line AED instead; repeated boluses cause respiratory depression without controlling refractory status.</div>"}, {"id": "neuro:fc:21", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "flashcard", "front": "Before starting carbamazepine in a Han Chinese patient, which gene is tested and why? Name two other characteristic carbamazepine effects.", "back": "Test <strong>HLA-B*1502</strong> — carriers (Han Chinese, Thai, SE Asian) have high risk of <strong>Stevens-Johnson syndrome / TEN</strong>. Other effects: <strong>hyponatraemia/SIADH</strong> (ADH-like action on collecting duct) and <strong>autoinduction</strong> (induces CYP3A4 including its own metabolism, so levels fall over weeks).<div class=\"sr-note\">💎 <strong>Pearl:</strong> Also causes idiosyncratic aplastic anaemia/agranulocytosis; potent enzyme inducer (lowers warfarin, OCP, other AED levels). Oxcarbazepine has less autoinduction but more hyponatraemia.</div><div class=\"sr-note\">⚠️ <strong>Trap:</strong> Carbamazepine worsens absence and myoclonic seizures — never use in idiopathic generalised epilepsy.</div>"}, {"id": "neuro:fc:22", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "flashcard", "front": "A woman on valproate is started on lamotrigine and develops a blistering mucosal rash. Explain the pharmacological basis.", "back": "Lamotrigine is cleared by <strong>glucuronidation (UGT)</strong>. <strong>Valproate inhibits glucuronidation</strong> → roughly doubles lamotrigine level/half-life → standard starting dose becomes toxic → sharply raised risk of <strong>Stevens-Johnson syndrome / TEN</strong>, especially with fast titration. Manage by halving the lamotrigine start dose and titrating very slowly.<div class=\"sr-note\">💎 <strong>Pearl:</strong> Lamotrigine is preferred in women of childbearing age (low teratogenicity), but oestrogen contraceptives induce its glucuronidation → levels fall ~50% when the pill is started.</div><div class=\"sr-note\">⚠️ <strong>Trap:</strong> Any rash in the first 8 weeks of lamotrigine → stop and assess for SJS/TEN/DRESS. Slow low titration is the key preventive measure.</div>"}, {"id": "neuro:fc:23", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "flashcard", "front": "A 7-year-old has frequent staring spells with 3-Hz spike-and-wave on EEG. First-line drug, its mechanism, and when to choose valproate instead?", "back": "<strong>Childhood absence epilepsy.</strong> First-line: <strong>ethosuximide</strong>, which blocks <strong>T-type Ca²⁺ channels</strong> in thalamic neurons that pace the 3-Hz thalamocortical rhythm. Preferred for pure absence (effective with fewer cognitive side effects than alternatives). Choose <strong>valproate</strong> instead when there are also generalised tonic-clonic or myoclonic seizures, since ethosuximide covers absence only.<div class=\"sr-note\">💎 <strong>Pearl:</strong> \"Ethosuximide = absence only\" — no significant role in other seizure types and no enzyme induction.</div><div class=\"sr-note\">⚠️ <strong>Trap:</strong> Carbamazepine, phenytoin, vigabatrin and gabapentin can all worsen absence seizures.</div>"}, {"id": "neuro:fc:24", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "flashcard", "front": "An infant with West syndrome improves on vigabatrin. What irreversible toxicity needs monitoring, and what is vigabatrin's mechanism?", "back": "Vigabatrin <strong>irreversibly inhibits GABA-transaminase</strong> (the GABA-degrading enzyme) → raises CNS GABA (\"vi-GABA\"). Defining toxicity: <strong>irreversible peripheral visual field constriction</strong> (tunnel vision), so regular visual field perimetry (and ERG in young children) is mandatory. Reserved for <strong>infantile spasms / West syndrome</strong> (first-line in tuberous sclerosis) and refractory focal seizures.<div class=\"sr-note\">💎 <strong>Pearl:</strong> West syndrome triad = infantile spasms + hypsarrhythmia + developmental regression; treated with vigabatrin or ACTH/corticosteroids.</div><div class=\"sr-note\">⚠️ <strong>Trap:</strong> Distinguish GABA drugs: vigabatrin inhibits GABA-transaminase (breakdown), tiagabine blocks GABA reuptake (GAT-1), benzodiazepines/barbiturates act at the GABA<sub>A</sub> receptor.</div>"}, {"id": "neuro:q:100", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "What are the three core mechanisms by which antiepileptic drugs work?", "back": "Block voltage-gated Na⁺ (or Ca²⁺) channels, enhance GABA-mediated inhibition, or modulate transmitter release (SV2A)."}, {"id": "neuro:q:101", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "How does use-dependent Na⁺-channel block selectively quiet a seizing neuron?", "back": "Drugs bind the inactivated channel state, which rapidly-firing neurons occupy far more than normal ones — so only over-active cells are suppressed."}, {"id": "neuro:q:102", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "First-line drug for absence seizures and its molecular target?", "back": "Ethosuximide — blocks T-type (low-threshold) Ca²⁺ channels in thalamic neurons."}, {"id": "neuro:q:103", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Which AEDs can worsen absence and myoclonic seizures?", "back": "Carbamazepine, phenytoin, vigabatrin, gabapentin (and tiagabine)."}, {"id": "neuro:q:104", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Why is valproate broad-spectrum?", "back": "It acts by several mechanisms at once — Na⁺-channel block, T-type Ca²⁺ block, and increased GABA."}, {"id": "neuro:q:105", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "What is the novel mechanism of levetiracetam?", "back": "It binds the synaptic vesicle protein SV2A, modulating neurotransmitter release."}, {"id": "neuro:q:106", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Recite the stepwise drug management of status epilepticus.", "back": "IV lorazepam (or buccal midazolam) first → load IV phenytoin/fosphenytoin, valproate, or levetiracetam → if refractory, general anaesthesia."}, {"id": "neuro:q:107", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Why can a small phenytoin dose increase cause toxicity?", "back": "Phenytoin follows zero-order (saturable) kinetics — once the enzyme is saturated, plasma levels rise disproportionately to dose."}, {"id": "neuro:q:108", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Benzodiazepines vs barbiturates at the GABA-A receptor?", "back": "Benzodiazepines increase frequency of Cl⁻ channel opening (ceiling, safer); barbiturates increase duration (no ceiling, lethal in overdose)."}, {"id": "neuro:q:109", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Which gene is tested before carbamazepine in Han Chinese/SE Asian patients, and why?", "back": "HLA-B*1502 — carriers have a high risk of Stevens-Johnson syndrome / TEN."}, {"id": "neuro:q:110", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Why start lamotrigine lower when added to valproate?", "back": "Valproate inhibits lamotrigine glucuronidation, roughly doubling its level and raising SJS risk — halve the start dose and titrate slowly."}, {"id": "neuro:q:111", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "What irreversible effect mandates visual field monitoring with vigabatrin, and its mechanism?", "back": "Irreversible peripheral visual field constriction; vigabatrin irreversibly inhibits GABA-transaminase, raising CNS GABA."}, {"id": "neuro:fc:25", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "flashcard", "front": "A migraine patient already on an SSRI is prescribed a triptan and a week later develops agitation, tremor, clonus and a temperature of 39°C. What is happening and how is it managed?", "back": "<strong>Serotonin syndrome</strong> from additive serotonergic activity (SSRI raises synaptic 5-HT; triptans are 5-HT₁ agonists). Triad: <strong>neuromuscular excitation</strong> (clonus, hyperreflexia, tremor — lower-limb predominant), <strong>autonomic instability</strong> (hyperthermia, tachycardia, diaphoresis), and <strong>altered mental state</strong> (agitation). Management: stop the serotonergic drugs, supportive cooling and IV fluids, benzodiazepines, and <strong>cyproheptadine</strong> (5-HT₂ antagonist) in severe cases.<div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Distinguish from NMS — serotonin syndrome has hyperreflexia and clonus with rapid onset (hours); NMS has lead-pipe rigidity, hyporeflexia and slower onset (days). Other potent triggers: SSRI/SNRI + MAOI, tramadol, pethidine, linezolid, methylene blue.</div>"}, {"id": "neuro:fc:26", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "flashcard", "front": "A young woman on an antipsychotic develops galactorrhoea and amenorrhoea. Which dopamine pathway explains this, and which agent would minimise it?", "back": "Blockade of the <strong>tuberoinfundibular</strong> dopamine pathway — dopamine normally <em>inhibits</em> prolactin release, so D2 blockade disinhibits prolactin → <strong>hyperprolactinaemia</strong> (galactorrhoea, amenorrhoea, gynaecomastia, sexual dysfunction). Risperidone and typical antipsychotics raise prolactin most; switching to a <strong>prolactin-sparing agent (aripiprazole — a D2 partial agonist, or quetiapine)</strong> minimises it.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Aripiprazole's partial agonism actually <em>lowers</em> prolactin and is sometimes added specifically to treat antipsychotic-induced hyperprolactinaemia.</div>"}, {"id": "neuro:fc:27", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "flashcard", "front": "A patient on chemotherapy is given ondansetron for nausea. What receptor does it block, and where?", "back": "Ondansetron blocks <strong>5-HT₃ receptors</strong> — ligand-gated cation channels — at two sites: <strong>peripheral vagal afferents in the gut</strong> (chemotherapy/radiation release serotonin from enterochromaffin cells) and <strong>centrally at the chemoreceptor trigger zone</strong>. This dual action makes it highly effective for chemotherapy-induced and post-operative nausea.<div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> 5-HT₃ antagonists prolong the <strong>QT interval</strong> (especially IV) and cause constipation and headache. They do nothing for motion sickness (that's a vestibular/muscarinic-histaminergic problem — use hyoscine or antihistamines).</div>"}, {"id": "neuro:fc:28", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "flashcard", "front": "Why is the NMDA receptor described as a \"coincidence detector\", and what protects it from firing inappropriately?", "back": "The NMDA receptor opens only when <strong>three conditions coincide</strong>: glutamate binds, the co-agonist <strong>glycine</strong> binds, <em>and</em> the membrane is already depolarised enough to expel the <strong>Mg²⁺ ion</strong> plugging its pore. Only then does Ca²⁺ enter. Requiring simultaneous presynaptic release (glutamate) and postsynaptic activity (depolarisation) makes it a detector of coincident activity — the molecular basis of synaptic plasticity and learning (LTP).<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Over-activation floods neurons with Ca²⁺ → <strong>excitotoxicity</strong> (stroke, status epilepticus, traumatic brain injury). Memantine and ketamine are therapeutic NMDA blockers; alcohol also inhibits NMDA.</div>"}, {"id": "neuro:fc:29", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "flashcard", "front": "A patient with severe spasticity from multiple sclerosis is started on baclofen. What receptor does it act on, and what is the danger of stopping it abruptly?", "back": "Baclofen is a <strong>GABA<sub>B</sub> receptor agonist</strong> (a Gi-coupled GPCR) — it reduces excitatory transmission in the spinal cord, relieving spasticity. <strong>Abrupt withdrawal</strong> (especially of intrathecal baclofen) can precipitate a severe syndrome of rebound spasticity, hyperthermia, autonomic instability, seizures and even death — taper rather than stop suddenly.<div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Don't confuse the GABA receptors: GABA<sub>A</sub> is an ionotropic Cl⁻ channel (benzodiazepines, barbiturates, alcohol, propofol); GABA<sub>B</sub> is a metabotropic GPCR (baclofen). Different structure, different drugs.</div>"}, {"id": "neuro:fc:30", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "flashcard", "front": "Why can dopamine not be used to treat Parkinson's disease, while levodopa can — and what does carbidopa add?", "back": "Dopamine is too polar to cross the <strong>blood-brain barrier</strong>. Its precursor <strong>levodopa</strong> resembles an amino acid and is carried across by the <strong>LAT1 transporter</strong>, then decarboxylated to dopamine in the brain. <strong>Carbidopa</strong> inhibits peripheral DOPA decarboxylase but cannot itself cross the BBB — so it blocks wasteful peripheral conversion (reducing nausea and hypotension) and lets more levodopa reach the CNS.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> The four requirements to cross the BBB: small, lipophilic, un-ionised, and not a P-glycoprotein substrate. Levodopa breaks the \"small lipophilic\" rule but gets in by hijacking an amino-acid carrier.</div>"}, {"id": "neuro:fc:31", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "flashcard", "front": "A patient on loperamide for chronic diarrhoea takes a large dose hoping for a \"high\" but feels nothing centrally. Why?", "back": "Loperamide is an opioid agonist that acts on gut μ-receptors to slow motility, but it is a <strong>P-glycoprotein substrate</strong> — the efflux pump at the blood-brain barrier ejects it back into the blood, so it never reaches central reward circuits. Hence it relieves diarrhoea without euphoria or dependence at normal doses.<div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Massive overdose (or co-ingestion of a P-gp inhibitor) can overwhelm the pump and cause CNS opioid effects — and loperamide also blocks cardiac channels, causing <strong>QT prolongation and fatal arrhythmias</strong> in abuse.</div>"}, {"id": "neuro:fc:32", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "flashcard", "front": "A patient newly started on an SSRI for depression reports no improvement after 5 days and asks if it has failed. How do you respond and why?", "back": "Reassure: antidepressants take <strong>2–4 weeks</strong> to lift mood. The reuptake block raises synaptic serotonin immediately, but this initially activates inhibitory <strong>5-HT₁A autoreceptors</strong> that suppress firing. Benefit appears only after these autoreceptors <strong>desensitise</strong> and downstream neuroplasticity (BDNF) develops. Continue at the same dose and review at 2–4 weeks before judging response.<div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> In the first weeks, energy and drive can return before mood does, transiently <strong>increasing suicide risk</strong> (especially in young people) — review early and counsel the patient/family.</div>"}, {"id": "neuro:fc:33", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "flashcard", "front": "A patient on phenelzine eats a mature cheese platter and develops a severe throbbing headache with BP 220/120. Mechanism and treatment?", "back": "The <strong>tyramine (\"cheese\") reaction</strong>. Phenelzine irreversibly inhibits MAO, so dietary <strong>tyramine</strong> escapes gut/hepatic first-pass metabolism, enters nerve terminals via NET, and displaces stored noradrenaline → massive sympathetic surge → <strong>hypertensive crisis</strong>. Treatment: IV <strong>phentolamine</strong> (α-blocker) or sodium nitroprusside.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Moclobemide (reversible MAO-A inhibitor, RIMA) is displaced by tyramine, so dietary restriction is far less strict; low-dose selegiline (selective MAO-B) doesn't require tyramine restriction either.</div>"}, {"id": "neuro:fc:34", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "flashcard", "front": "A young man started on haloperidol develops a sudden painful upward deviation of both eyes and neck twisting 6 hours after the first dose. Name it and treat it.", "back": "<strong>Acute dystonia</strong> (oculogyric crisis + torticollis) — an early extrapyramidal effect of D2 blockade, leaving striatal acetylcholine unopposed. Treat with an <strong>anticholinergic</strong>: IV/IM <strong>procyclidine</strong> or benztropine (or IV diphenhydramine). It resolves rapidly.<div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Do <em>not</em> treat with dopamine — that would worsen psychosis. The EPS timeline: acute dystonia (hours–days) → akathisia (days) → parkinsonism (weeks) → tardive dyskinesia (months–years, often irreversible).</div>"}, {"id": "neuro:fc:35", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "flashcard", "front": "A 62-year-old man with Parkinson's on ropinirole has lost his savings gambling online and his wife reports compulsive shopping. What is the cause?", "back": "<strong>Impulse-control disorder</strong> caused by the <strong>dopamine agonist</strong> — direct stimulation of mesolimbic D3 receptors in the reward circuit produces pathological gambling, hypersexuality, compulsive shopping and binge eating. It is dose-related and reversible: reduce or switch off the agonist (and screen for it proactively, as patients rarely volunteer it).<div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Always ask specifically about gambling, hypersexuality, shopping and eating when prescribing dopamine agonists — patients feel ashamed and won't report it spontaneously. Sudden agonist withdrawal can cause a dopamine-agonist withdrawal syndrome.</div>"}, {"id": "neuro:fc:36", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "flashcard", "front": "Why is memantine, a receptor <em>blocker</em>, useful in Alzheimer's when the disease involves <em>loss</em> of acetylcholine?", "back": "Memantine targets a <em>different</em> problem: chronic low-level <strong>glutamate excitotoxicity</strong>. As an <strong>NMDA-receptor antagonist</strong>, it blocks the pathological background \"noise\" of excess glutamate (which damages neurons and degrades the signal-to-noise ratio of memory) while still permitting the larger, physiological signals needed for learning. So a blocker improves cognition by filtering noise, not by raising acetylcholine — it's used in <strong>moderate–severe</strong> AD and can be combined with an AChE inhibitor.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> AChE inhibitors (donepezil etc.) suit mild–moderate AD and provide modest symptomatic benefit; none halt progression. Newer anti-amyloid antibodies (lecanemab) slow decline modestly but risk ARIA (cerebral oedema/microhaemorrhage).</div>"}, {"id": "neuro:fc:37", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "flashcard", "front": "An elderly patient with insomnia and mild liver impairment needs a short course of a benzodiazepine. Which agents are preferred and why?", "back": "Prefer <strong>Lorazepam, Oxazepam or Temazepam (\"LOT\")</strong> — they are cleared by <strong>glucuronidation</strong> rather than hepatic oxidation and have <strong>no active metabolites</strong>, so they don't accumulate in liver disease or the elderly (more predictable, less risk of prolonged sedation and falls).<div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Benzodiazepines and Z-drugs markedly increase falls, fractures and confusion in the elderly (Beers list) — use the lowest dose for the shortest time. Long-acting oxidised agents (diazepam, chlordiazepoxide) accumulate dangerously in this group.</div>"}, {"id": "neuro:fc:38", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "flashcard", "front": "A patient takes an overdose of 50 phenobarbital tablets and stops breathing, whereas a similar number of diazepam tablets would likely only cause deep sleep. Explain the difference.", "back": "Both enhance GABA<sub>A</sub>, but differently. <strong>Benzodiazepines increase the frequency</strong> of channel opening and <em>require endogenous GABA</em> — once GABA's effect is maximised there is a <strong>ceiling</strong>, so overdose alone rarely kills. <strong>Barbiturates increase the duration</strong> of opening and, at high concentration, <strong>open the channel directly without GABA</strong> — there is no ceiling, so the brainstem respiratory centres can be silenced completely.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Flumazenil reverses benzodiazepines but not barbiturates. The real danger of benzodiazepines is co-ingestion with alcohol/opioids — the ceiling no longer protects when respiratory depression becomes additive.</div>"}, {"id": "neuro:fc:39", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "flashcard", "front": "A patient is found unresponsive with a respiratory rate of 5 and pinpoint pupils. After naloxone he wakes, but 30 minutes later becomes drowsy again. Explain.", "back": "Opioid overdose (the triad: <strong>coma, pinpoint pupils, respiratory depression</strong>). Naloxone, a competitive μ-antagonist, reversed it — but its <strong>half-life is shorter than most opioids</strong>, so as it wears off the opioid re-occupies the receptor and re-sedation occurs. Manage with <strong>repeat doses or a naloxone infusion</strong> and prolonged observation, especially with long-acting opioids (methadone) or fentanyl.<div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Tolerance develops to analgesia, euphoria and respiratory depression but <em>never</em> to miosis or constipation — pinpoint pupils stay diagnostic even in chronic users, and laxatives must be co-prescribed from day one.</div>"}, {"id": "neuro:fc:40", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "flashcard", "front": "A breastfeeding mother is given codeine for post-caesarean pain; her infant becomes lethargic and apnoeic. What is the mechanism?", "back": "Codeine is a prodrug converted to morphine by <strong>CYP2D6</strong>. If the mother is an <strong>ultra-rapid metaboliser</strong>, she produces excessive morphine that passes into breast milk, causing opioid toxicity (sedation, respiratory depression) in the infant. For this reason codeine is <strong>contraindicated in breastfeeding and in children</strong> — use a safer analgesic.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> CYP2D6 activity varies widely: poor metabolisers get no analgesia from codeine/tramadol; ultra-rapid metabolisers risk toxicity. The same genetics affect tramadol.</div>"}, {"id": "neuro:fc:41", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "flashcard", "front": "During general anaesthesia with sevoflurane and suxamethonium, the patient's end-tidal CO₂ rises sharply, with masseter spasm and a rising temperature. Diagnosis and treatment?", "back": "<strong>Malignant hyperthermia</strong> — a genetic (RYR1) susceptibility triggered by <strong>volatile anaesthetics and suxamethonium</strong>, causing uncontrolled sarcoplasmic-reticulum Ca²⁺ release → sustained muscle contraction, heat, and CO₂ production. Earliest sign is often <strong>rising end-tidal CO₂</strong>. Treat immediately: stop the trigger, 100% O₂, <strong>IV dantrolene</strong> (blocks SR Ca²⁺ release), active cooling, and treat hyperkalaemia/acidosis/arrhythmias.<div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Dantrolene is the specific antidote (it also treats neuroleptic malignant syndrome). Etomidate causes adrenal suppression; propofol can cause propofol-infusion syndrome — don't confuse these with MH.</div>"}, {"id": "neuro:fc:42", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "flashcard", "front": "A hypotensive trauma patient with active bronchospasm needs rapid anaesthetic induction. Which IV agent is preferred and why?", "back": "<strong>Ketamine</strong> — an NMDA-receptor antagonist producing \"dissociative\" anaesthesia. Unlike propofol/thiopental (which drop blood pressure), ketamine <strong>stimulates the sympathetic nervous system</strong>, maintaining blood pressure and heart rate, and is a <strong>bronchodilator</strong> — ideal in shock and asthma. It also preserves airway reflexes.<div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Ketamine raises secretions (consider an antisialagogue) and causes emergence phenomena/hallucinations (mitigate with a benzodiazepine). Avoid where a rise in blood pressure or intracranial/intraocular pressure is hazardous.</div>"}, {"id": "neuro:fc:43", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "flashcard", "front": "A dentist injects lidocaine into an inflamed, abscessed tooth but achieves poor anaesthesia. Why does infection reduce efficacy?", "back": "Local anaesthetics must be <strong>un-ionised to cross the nerve membrane</strong>, then ionised inside to block the Na⁺ channel. Infected tissue is <strong>acidic</strong>, which shifts the weak-base drug toward its <strong>ionised form</strong> that cannot cross the membrane (<strong>ion trapping</strong>) — so little reaches the intracellular site and the block is weak.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Adding adrenaline causes vasoconstriction → prolongs action, reduces bleeding and systemic toxicity — but never in end-arteries (fingers, toes, nose, penis). This is the same pH-partitioning principle as aspirin absorption.</div>"}, {"id": "neuro:fc:44", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "flashcard", "front": "During a regional block, a patient develops perioral tingling and tinnitus, then a seizure and cardiac arrest. Which agent is most implicated and what is the specific treatment?", "back": "<strong>Local-anaesthetic systemic toxicity (LAST)</strong> from inadvertent intravascular injection. The sequence is <strong>CNS first</strong> (circumoral numbness, metallic taste, tinnitus, agitation, seizures) <strong>then cardiac</strong> (arrhythmia, arrest). <strong>Bupivacaine</strong> is the most cardiotoxic (avidly binds cardiac Na⁺ channels, hard to resuscitate). Specific treatment: stop injection, ABC, benzodiazepine for seizures, and <strong>IV 20% lipid emulsion (\"lipid rescue\")</strong>.<div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Always know the maximum safe mg/kg dose before injecting. Prilocaine and benzocaine instead cause <strong>methaemoglobinaemia</strong> (treat with methylene blue) — a different toxicity.</div>"}, {"id": "neuro:fc:45", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "flashcard", "front": "Which cannabinoid receptor mediates the \"high\" and appetite stimulation, and how does THC differ from CBD?", "back": "<strong>CB1</strong> (mainly CNS, presynaptic) mediates euphoria, appetite (\"the munchies\"), memory impairment, analgesia and antiemesis. <strong>THC</strong> is the psychoactive <em>partial CB1 agonist</em>; <strong>CBD</strong> is <em>non-intoxicating</em> with anticonvulsant and anxiolytic properties. CB2 (immune cells) handles anti-inflammatory/immunomodulatory effects with little psychoactivity.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Endocannabinoids (anandamide, 2-AG) are retrograde messengers — released by the postsynaptic neuron to dampen presynaptic transmitter release.</div>"}, {"id": "neuro:fc:46", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "flashcard", "front": "A child with Dravet syndrome has seizures refractory to standard drugs. Which cannabinoid is licensed for this?", "back": "<strong>Cannabidiol (CBD)</strong> is licensed as an adjunct for the severe childhood epilepsies <strong>Dravet syndrome and Lennox-Gastaut syndrome</strong> (and seizures in tuberous sclerosis). It is non-psychoactive.<div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> CBD inhibits CYP enzymes and raises levels of clobazam's active metabolite — watch for sedation when co-prescribed. Don't confuse the antiepileptic CBD with psychoactive THC.</div>"}, {"id": "neuro:fc:47", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "flashcard", "front": "A long-term heavy cannabis user has recurrent severe vomiting relieved only by very hot showers. What is this?", "back": "<strong>Cannabinoid hyperemesis syndrome</strong> — paradoxical cyclical nausea and vomiting in chronic heavy users, classically relieved by hot bathing/showers. The only definitive treatment is <strong>cannabis cessation</strong>; topical capsaicin and supportive antiemetics/fluids help acutely.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> It is easily mistaken for cyclical vomiting syndrome — the hot-shower relief and chronic cannabis history are the diagnostic clues.</div>"}, {"id": "neuro:fc:48", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "flashcard", "front": "Why are synthetic cannabinoids (\"spice\") far more dangerous than herbal cannabis?", "back": "Synthetic cannabinoids are <strong>full CB1 agonists</strong> (and often far more potent), whereas THC is only a <em>partial</em> agonist. Full agonism produces much more intense and unpredictable effects — severe agitation, psychosis, seizures, tachyarrhythmias and acute kidney injury.<div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Heavy, early, high-potency cannabis use is associated with increased risk of later <strong>psychotic illness</strong> in susceptible individuals.</div>"}, {"id": "neuro:fc:49", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "flashcard", "front": "A patient on disulfiram for alcohol dependence drinks a beer and develops flushing, throbbing headache, vomiting and palpitations. Explain the mechanism.", "back": "Disulfiram <strong>inhibits aldehyde dehydrogenase (ALDH)</strong>, so ethanol metabolism stalls at <strong>acetaldehyde</strong>, which accumulates and causes a deliberately aversive reaction: flushing, throbbing headache, nausea/vomiting, tachycardia and hypotension. The unpleasantness is the therapeutic principle (deterrence).<div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> The same disulfiram-like reaction occurs with <strong>metronidazole</strong>, some cephalosporins and chlorpropamide — warn patients to avoid alcohol with these drugs.</div>"}, {"id": "neuro:fc:50", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "flashcard", "front": "A chronic alcohol user is admitted; 36 hours after his last drink he has a tonic-clonic seizure, then becomes tremulous, sweaty and hallucinating. What is happening and how is it treated?", "back": "<strong>Alcohol withdrawal progressing toward delirium tremens.</strong> Chronic alcohol down-regulates GABA<sub>A</sub> and up-regulates NMDA; removing the alcohol unmasks <strong>CNS hyperexcitability</strong> → tremor/anxiety (6–12 h), seizures (24–48 h), delirium tremens (48–72 h, with mortality). Treat with <strong>long-acting benzodiazepines</strong> (chlordiazepoxide or diazepam) to restore GABA tone, plus <strong>thiamine</strong> and supportive care.<div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Give <strong>thiamine before any glucose</strong> — a glucose load in a thiamine-deficient patient can precipitate Wernicke's encephalopathy (ophthalmoplegia, ataxia, confusion), which may progress to irreversible Korsakoff's psychosis.</div>"}, {"id": "neuro:fc:51", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "flashcard", "front": "Why does a person's blood alcohol fall by roughly the same amount each hour regardless of how much they drank?", "back": "Because <strong>alcohol dehydrogenase is saturated</strong> at ordinary drinking concentrations, it works at a constant maximal rate — so ethanol is eliminated by <strong>zero-order kinetics</strong> (a fixed amount per unit time, ~one unit/hour), not proportionally to concentration.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Phenytoin and high-dose aspirin share this saturable, zero-order behaviour — small dose increases can cause disproportionate rises in plasma level.</div>"}, {"id": "neuro:fc:52", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "flashcard", "front": "A patient on long-term opioid therapy wants to stop. They are started on buprenorphine but immediately develop sweating, agitation and abdominal cramps. Why?", "back": "Buprenorphine is a <strong>partial μ-agonist with very high receptor affinity</strong>. Given while a full agonist still occupies the receptor, it <strong>displaces the full agonist</strong> and, because its intrinsic activity is lower, the net opioid effect <em>drops</em> — <strong>precipitating acute withdrawal</strong>. It must be started only once the patient is already in early withdrawal.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Buprenorphine's partial agonism gives a ceiling on respiratory depression, making it safer than methadone (a full agonist) in overdose.</div>"}, {"id": "neuro:fc:53", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "flashcard", "front": "What single neural pathway is common to addiction to heroin, alcohol and nicotine, and how does this shape treatment?", "back": "All converge on the <strong>mesolimbic dopamine reward pathway</strong> (ventral tegmental area → nucleus accumbens) — each drug, by its own receptor route, raises dopamine there. But pharmacological treatment is <strong>substance-specific</strong>: opioids → methadone/buprenorphine/naltrexone; alcohol → naltrexone/acamprosate/disulfiram; nicotine → NRT/varenicline/bupropion.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Partial agonists (buprenorphine for opioids, varenicline for nicotine) ease craving while capping the high, then block the full agonist — an elegant common strategy.</div>"}, {"id": "neuro:fc:54", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "flashcard", "front": "A patient wants to quit smoking and is offered varenicline. What is its mechanism and a key monitoring point?", "back": "Varenicline is a <strong>partial agonist at the α4β2 nicotinic receptor</strong>: it relieves craving and withdrawal (partial stimulation) while <strong>blocking nicotine's reinforcing effect</strong> if the patient smokes. Monitor for <strong>neuropsychiatric symptoms / mood changes</strong> and unusual dreams; nausea is the commonest side effect.<div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Bupropion is an alternative cessation aid (and antidepressant) that lowers the seizure threshold — avoid in epilepsy, eating disorders and alcohol withdrawal.</div>"}, {"id": "neuro:q:112", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "From which amino acid is serotonin synthesised?", "back": "Tryptophan (→ 5-HTP → 5-HT)."}, {"id": "neuro:q:113", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Which 5-HT receptor do triptans target, and for what?", "back": "5-HT₁B/₁D agonism for acute migraine (cranial vasoconstriction + ↓CGRP release)."}, {"id": "neuro:q:114", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Which 5-HT receptor type is a ligand-gated ion channel, and which drugs block it?", "back": "5-HT₃ — blocked by the \"-setron\" antiemetics (ondansetron)."}, {"id": "neuro:q:115", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Name the four dopamine pathways.", "back": "Nigrostriatal, mesolimbic, mesocortical, tuberoinfundibular."}, {"id": "neuro:q:116", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Which pathway, when blocked, causes extrapyramidal side effects?", "back": "Nigrostriatal."}, {"id": "neuro:q:117", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Why does D2 blockade cause hyperprolactinaemia?", "back": "Dopamine normally inhibits prolactin via the tuberoinfundibular pathway; blocking it disinhibits prolactin release."}, {"id": "neuro:q:118", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Antipsychotic potency correlates with affinity for which receptor?", "back": "The D2 dopamine receptor."}, {"id": "neuro:q:119", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Buspirone acts at which receptor?", "back": "5-HT₁A partial agonist (non-sedating anxiolytic)."}, {"id": "neuro:q:120", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Give the triad of serotonin syndrome.", "back": "Neuromuscular excitation (clonus/hyperreflexia), autonomic instability (hyperthermia), and altered mental state."}, {"id": "neuro:q:121", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "How is serotonin syndrome distinguished from NMS?", "back": "Serotonin syndrome: hyperreflexia/clonus, rapid onset; NMS: lead-pipe rigidity, hyporeflexia, slower onset."}, {"id": "neuro:q:122", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Main excitatory and inhibitory CNS transmitters?", "back": "Glutamate (excitatory), GABA (inhibitory)."}, {"id": "neuro:q:123", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Which ion does the NMDA receptor preferentially conduct, and what blocks its pore at rest?", "back": "Ca²⁺; a magnesium (Mg²⁺) ion blocks the pore at rest."}, {"id": "neuro:q:124", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "What co-agonist (besides glutamate) does the NMDA receptor require?", "back": "Glycine (or D-serine)."}, {"id": "neuro:q:125", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Name two drugs that act as NMDA-receptor antagonists.", "back": "Ketamine and memantine (alcohol also inhibits NMDA)."}, {"id": "neuro:q:126", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "What ion does the GABA<sub>A</sub> receptor conduct?", "back": "Chloride (Cl⁻)."}, {"id": "neuro:q:127", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "GABA<sub>B</sub> receptor type and its agonist drug?", "back": "Gi GPCR; agonist is baclofen."}, {"id": "neuro:q:128", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "What is excitotoxicity?", "back": "Excess glutamate → NMDA-mediated Ca²⁺ influx → neuronal death (e.g. in stroke, status epilepticus)."}, {"id": "neuro:q:129", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Main inhibitory transmitter of the spinal cord, and the toxin that blocks it?", "back": "Glycine; blocked by strychnine (impaired by tetanus toxin)."}, {"id": "neuro:q:130", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Why do barbiturates lack the safety ceiling that benzodiazepines have?", "back": "At high dose barbiturates open the GABA<sub>A</sub> channel directly without needing GABA, so there is no ceiling."}, {"id": "neuro:q:131", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Does flumazenil reverse alcohol or barbiturate intoxication?", "back": "No — only benzodiazepines (different binding mechanism)."}, {"id": "neuro:q:132", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "What structural feature seals the BBB endothelium?", "back": "Tight junctions (no fenestrations)."}, {"id": "neuro:q:133", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "List the properties a drug needs to cross the BBB passively.", "back": "Small, lipophilic, un-ionised, and not a P-glycoprotein substrate."}, {"id": "neuro:q:134", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Which efflux pump throws drugs back into the blood?", "back": "P-glycoprotein (P-gp / MDR1)."}, {"id": "neuro:q:135", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Why give levodopa rather than dopamine for Parkinson's?", "back": "Dopamine can't cross the BBB; levodopa enters via the LAT1 amino-acid transporter and is converted centrally."}, {"id": "neuro:q:136", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "How does carbidopa help if it cannot enter the brain?", "back": "It blocks peripheral DOPA decarboxylase, so more levodopa survives to reach the brain (and fewer peripheral side effects)."}, {"id": "neuro:q:137", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Why is loperamide non-addictive despite being an opioid?", "back": "It is a P-glycoprotein substrate, kept out of the CNS."}, {"id": "neuro:q:138", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Why does penicillin penetrate better in meningitis?", "back": "Inflammation increases BBB permeability."}, {"id": "neuro:q:139", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Where is the BBB naturally deficient, allowing central antiemetic action?", "back": "The circumventricular organs — chemoreceptor trigger zone / area postrema."}, {"id": "neuro:q:140", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Effect of a P-gp inhibitor (e.g. verapamil) on CNS drug levels?", "back": "It can let normally-excluded drugs into the CNS, risking central toxicity."}, {"id": "neuro:q:141", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Why are neonates at risk of kernicterus?", "back": "An immature BBB lets bilirubin cross into the brain."}, {"id": "neuro:q:142", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "First-line antidepressant class and why?", "back": "SSRIs — effective, well tolerated, and safest in overdose."}, {"id": "neuro:q:143", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Why do antidepressants take 2–4 weeks to work?", "back": "Benefit depends on autoreceptor desensitisation and neuroplasticity, not the immediate reuptake block."}, {"id": "neuro:q:144", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Major danger of TCA overdose and its antidote?", "back": "Cardiotoxicity (Na⁺-channel block → wide QRS); treat with IV sodium bicarbonate."}, {"id": "neuro:q:145", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Dietary danger with MAO inhibitors?", "back": "Tyramine-rich foods → hypertensive (\"cheese\") crisis."}, {"id": "neuro:q:146", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Washout period between an irreversible MAOI and a serotonergic drug?", "back": "At least 14 days."}, {"id": "neuro:q:147", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Why is the washout 5 weeks after fluoxetine before starting an MAOI?", "back": "Fluoxetine's active metabolite norfluoxetine has a very long half-life."}, {"id": "neuro:q:148", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Mechanism of mirtazapine and a useful side effect?", "back": "α2 + 5-HT₂/₃ antagonist; sedation and appetite stimulation (used to advantage)."}, {"id": "neuro:q:149", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Which antidepressant lacks sexual dysfunction but lowers seizure threshold?", "back": "Bupropion (an NDRI)."}, {"id": "neuro:q:150", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "First-line drug therapy for generalised anxiety disorder?", "back": "An SSRI or SNRI (benzodiazepines only short-term)."}, {"id": "neuro:q:151", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Which SSRI/SNRI cause the worst discontinuation syndrome?", "back": "Short-half-life agents — paroxetine and venlafaxine."}, {"id": "neuro:q:152", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Primary receptor blocked by all antipsychotics?", "back": "D2 dopamine receptor."}, {"id": "neuro:q:153", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "What additional receptor do atypicals block, reducing EPS?", "back": "5-HT₂A."}, {"id": "neuro:q:154", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Give the EPS timeline from earliest to latest.", "back": "Acute dystonia → akathisia → parkinsonism → tardive dyskinesia."}, {"id": "neuro:q:155", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Treatment of acute dystonia, and why not dopamine?", "back": "An anticholinergic (procyclidine) — restoring dopamine would worsen psychosis."}, {"id": "neuro:q:156", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Which antipsychotic is most effective in resistant schizophrenia, and its key toxicity?", "back": "Clozapine — agranulocytosis (needs FBC monitoring)."}, {"id": "neuro:q:157", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Defining metabolic adverse effects of atypicals?", "back": "Weight gain, diabetes, dyslipidaemia (metabolic syndrome)."}, {"id": "neuro:q:158", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Tetrad of neuroleptic malignant syndrome?", "back": "Hyperthermia, lead-pipe rigidity, altered consciousness, autonomic instability (with raised CK)."}, {"id": "neuro:q:159", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Therapeutic range for lithium?", "back": "0.6–1.0 mmol/L (narrow)."}, {"id": "neuro:q:160", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Name three precipitants of lithium toxicity.", "back": "Dehydration, NSAIDs, thiazide diuretics (also ACE inhibitors/ARBs)."}, {"id": "neuro:q:161", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Why avoid antidepressant monotherapy in bipolar disorder?", "back": "Risk of precipitating a manic switch."}, {"id": "neuro:q:162", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Cornerstone of Parkinson's therapy?", "back": "Levodopa combined with carbidopa."}, {"id": "neuro:q:163", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Two long-term motor complications of levodopa?", "back": "Wearing-off and peak-dose dyskinesias (and on-off fluctuations)."}, {"id": "neuro:q:164", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Characteristic adverse effect of dopamine agonists?", "back": "Impulse-control disorders (gambling, hypersexuality) and sleep attacks."}, {"id": "neuro:q:165", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "What do COMT and MAO-B inhibitors achieve in Parkinson's?", "back": "They block dopamine breakdown, smoothing \"wearing off\"."}, {"id": "neuro:q:166", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Drug for levodopa-induced dyskinesia?", "back": "Amantadine."}, {"id": "neuro:q:167", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Which Alzheimer's drug class suits mild–moderate disease?", "back": "Acetylcholinesterase inhibitors (donepezil, rivastigmine, galantamine)."}, {"id": "neuro:q:168", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Mechanism and stage of memantine?", "back": "NMDA-receptor antagonist; moderate–severe Alzheimer's."}, {"id": "neuro:q:169", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Why take levodopa away from high-protein meals?", "back": "Dietary amino acids compete with levodopa for the LAT1 gut transporter, delaying absorption."}, {"id": "neuro:q:170", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Why must levodopa/agonists never be stopped abruptly?", "back": "Risk of parkinsonism-hyperpyrexia syndrome (NMS-like)."}, {"id": "neuro:q:171", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Do current Alzheimer's drugs stop disease progression?", "back": "No — they are symptomatic only."}, {"id": "neuro:q:172", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "How do benzodiazepines modify the GABA<sub>A</sub> channel?", "back": "They increase the frequency of chloride channel opening (need GABA present)."}, {"id": "neuro:q:173", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "How do barbiturates differ?", "back": "They increase the duration of opening and, at high dose, open the channel directly — no ceiling."}, {"id": "neuro:q:174", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Which benzodiazepines avoid oxidative metabolism (safer in liver disease/elderly)?", "back": "Lorazepam, Oxazepam, Temazepam (\"LOT\")."}, {"id": "neuro:q:175", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "What are the Z-drugs and their use?", "back": "Zolpidem, zopiclone, zaleplon — insomnia (selective benzodiazepine-site agonists)."}, {"id": "neuro:q:176", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Antidote for benzodiazepine overdose?", "back": "Flumazenil."}, {"id": "neuro:q:177", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Why is flumazenil used cautiously in chronic users?", "back": "It can precipitate seizures/acute withdrawal."}, {"id": "neuro:q:178", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Why is benzodiazepine overdose rarely fatal alone?", "back": "The ceiling effect (they require endogenous GABA to act)."}, {"id": "neuro:q:179", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "What makes benzodiazepines dangerous in overdose in practice?", "back": "Co-ingestion with other CNS depressants (alcohol, opioids) — additive respiratory depression."}, {"id": "neuro:q:180", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "How should chronic benzodiazepines be stopped?", "back": "By slow taper (abrupt withdrawal → rebound anxiety, insomnia, seizures)."}, {"id": "neuro:q:181", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Two further barbiturate hazards besides overdose?", "back": "Potent CYP enzyme induction and precipitation of acute porphyria."}, {"id": "neuro:q:182", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Receptor mediating opioid analgesia and its G-protein?", "back": "μ (mu) receptor, coupled to Gi."}, {"id": "neuro:q:183", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Classic opioid overdose triad?", "back": "Coma, pinpoint pupils, respiratory depression."}, {"id": "neuro:q:184", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Opioid antidote and a pitfall of its use?", "back": "Naloxone — short half-life, so re-sedation can occur (re-dose/infuse)."}, {"id": "neuro:q:185", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Two opioid effects to which tolerance does NOT develop?", "back": "Miosis and constipation."}, {"id": "neuro:q:186", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Which enzyme activates codeine, and why does it matter?", "back": "CYP2D6 — ultra-rapid metabolisers risk toxicity, poor metabolisers get no analgesia."}, {"id": "neuro:q:187", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Why is codeine contraindicated in breastfeeding/children?", "back": "Ultra-rapid CYP2D6 metabolism can produce dangerous morphine levels."}, {"id": "neuro:q:188", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Why is buprenorphine relatively safer in overdose?", "back": "It is a partial μ-agonist with a ceiling on respiratory depression."}, {"id": "neuro:q:189", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Two extra hazards of pethidine?", "back": "Norpethidine accumulation → seizures (renal impairment); with MAOIs → serotonin syndrome."}, {"id": "neuro:q:190", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Why does tramadol carry a serotonin-syndrome and seizure risk?", "back": "It also inhibits 5-HT/noradrenaline reuptake and lowers seizure threshold."}, {"id": "neuro:q:191", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Why must constipation be managed prophylactically?", "back": "Tolerance never develops to it — laxatives are co-prescribed from the start."}, {"id": "neuro:q:192", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "What does MAC measure, and does low MAC mean more or less potent?", "back": "Minimum alveolar concentration preventing movement in 50%; low MAC = more potent."}, {"id": "neuro:q:193", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "What property determines speed of onset/recovery of an inhaled agent?", "back": "The blood:gas partition coefficient — low solubility = faster on/off."}, {"id": "neuro:q:194", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Main molecular target of most general anaesthetics?", "back": "GABA<sub>A</sub> enhancement (ketamine instead blocks NMDA)."}, {"id": "neuro:q:195", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Induction agent of choice in a shocked/asthmatic trauma patient, and why?", "back": "Ketamine — maintains blood pressure and airway tone (sympathomimetic, bronchodilator)."}, {"id": "neuro:q:196", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Which IV agent causes adrenal suppression?", "back": "Etomidate."}, {"id": "neuro:q:197", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Triggers of malignant hyperthermia?", "back": "Volatile anaesthetics and suxamethonium (RYR1 susceptibility)."}, {"id": "neuro:q:198", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Earliest sign and treatment of malignant hyperthermia?", "back": "Rising end-tidal CO₂ (± masseter spasm); treat with IV dantrolene + cooling."}, {"id": "neuro:q:199", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "What is propofol-infusion syndrome?", "back": "Prolonged high-dose propofol → metabolic acidosis, rhabdomyolysis, cardiac failure."}, {"id": "neuro:q:200", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Which inhaled agent is a weak anaesthetic but good analgesic?", "back": "Nitrous oxide (high MAC)."}, {"id": "neuro:q:201", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "What is balanced anaesthesia?", "back": "Combining agents (induction + volatile + opioid + muscle relaxant + antiemetic), each doing one job."}, {"id": "neuro:q:202", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Molecular mechanism of local anaesthetics?", "back": "Block voltage-gated Na⁺ channels from inside the axon (use-dependent)."}, {"id": "neuro:q:203", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Which form crosses the membrane and which form binds the channel?", "back": "Un-ionised crosses; ionised binds the channel from inside."}, {"id": "neuro:q:204", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Sort: lidocaine, procaine, bupivacaine, tetracaine into esters/amides.", "back": "Amides: lidocaine, bupivacaine. Esters: procaine, tetracaine. (Amides have two \"i\"s.)"}, {"id": "neuro:q:205", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Which class causes more allergy and why?", "back": "Esters — metabolite PABA is allergenic."}, {"id": "neuro:q:206", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Why do local anaesthetics fail in infected tissue?", "back": "Acidic pH keeps the drug ionised so less crosses the membrane (ion trapping)."}, {"id": "neuro:q:207", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Why add adrenaline, and where is it forbidden?", "back": "Vasoconstriction prolongs action and reduces toxicity; avoid in end-arteries (fingers, toes, nose, penis)."}, {"id": "neuro:q:208", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Give the sequence of local-anaesthetic systemic toxicity.", "back": "CNS first (perioral tingling, tinnitus, seizures) then cardiac (arrhythmia, arrest)."}, {"id": "neuro:q:209", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Which local anaesthetic is most cardiotoxic?", "back": "Bupivacaine."}, {"id": "neuro:q:210", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Treatment of severe LA systemic toxicity?", "back": "Supportive care plus IV 20% lipid emulsion (\"lipid rescue\")."}, {"id": "neuro:q:211", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Which agents cause methaemoglobinaemia, and its antidote?", "back": "Prilocaine and benzocaine; treat with methylene blue."}, {"id": "neuro:q:212", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Which cannabinoid receptor is mainly in the CNS?", "back": "CB1."}, {"id": "neuro:q:213", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Which receptor is mainly on immune cells?", "back": "CB2."}, {"id": "neuro:q:214", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Which constituent is psychoactive, and its receptor action?", "back": "THC — a partial CB1 agonist."}, {"id": "neuro:q:215", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Is CBD intoxicating?", "back": "No — non-psychoactive (anticonvulsant, anxiolytic)."}, {"id": "neuro:q:216", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Name the two main endocannabinoids.", "back": "Anandamide and 2-AG (made on demand)."}, {"id": "neuro:q:217", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "How do endocannabinoids signal relative to the synapse?", "back": "Retrogradely — from postsynaptic neuron back to presynaptic CB1, reducing transmitter release."}, {"id": "neuro:q:218", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Licensed cannabinoid for chemotherapy nausea/appetite?", "back": "Nabilone or dronabinol."}, {"id": "neuro:q:219", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Cannabinoid licensed for specific epilepsies (Dravet/Lennox-Gastaut)?", "back": "Cannabidiol (CBD)."}, {"id": "neuro:q:220", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "What is cannabinoid hyperemesis syndrome?", "back": "Paradoxical cyclical vomiting in heavy users, classically relieved by hot showers."}, {"id": "neuro:q:221", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Why are synthetic cannabinoids (\"spice\") more dangerous than THC?", "back": "They are full CB1 agonists (THC is only partial)."}, {"id": "neuro:q:222", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Two molecular actions of ethanol in the CNS?", "back": "Enhances GABA<sub>A</sub> and inhibits NMDA."}, {"id": "neuro:q:223", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "What kinetic order describes ethanol elimination, and why?", "back": "Zero-order — alcohol dehydrogenase is saturated at usual levels."}, {"id": "neuro:q:224", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Give the metabolic pathway of ethanol.", "back": "Ethanol → (ADH) acetaldehyde → (ALDH) acetate."}, {"id": "neuro:q:225", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "How does disulfiram work?", "back": "Inhibits aldehyde dehydrogenase → acetaldehyde accumulates → aversive flushing reaction."}, {"id": "neuro:q:226", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Name a drug causing a disulfiram-like reaction.", "back": "Metronidazole (also some cephalosporins, chlorpropamide)."}, {"id": "neuro:q:227", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Why does abrupt alcohol cessation cause seizures?", "back": "Chronic use down-regulates GABA<sub>A</sub> and up-regulates NMDA; removal unmasks CNS hyperexcitability."}, {"id": "neuro:q:228", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "First-line treatment of alcohol withdrawal?", "back": "Long-acting benzodiazepines (chlordiazepoxide/diazepam) plus thiamine."}, {"id": "neuro:q:229", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Why give thiamine before glucose?", "back": "Glucose without thiamine can precipitate Wernicke's encephalopathy."}, {"id": "neuro:q:230", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Triad of Wernicke's encephalopathy?", "back": "Ophthalmoplegia, ataxia, confusion."}, {"id": "neuro:q:231", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Two relapse-prevention drugs besides disulfiram?", "back": "Naltrexone and acamprosate."}, {"id": "neuro:q:232", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Which brain pathway underlies addiction/reward?", "back": "The mesolimbic dopamine pathway (VTA → nucleus accumbens)."}, {"id": "neuro:q:233", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "What do nearly all drugs of abuse have in common functionally?", "back": "They raise dopamine in the nucleus accumbens."}, {"id": "neuro:q:234", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Define tolerance.", "back": "Needing more drug to achieve the same effect."}, {"id": "neuro:q:235", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Two substitution treatments for opioid use disorder?", "back": "Methadone (full agonist) and buprenorphine (partial agonist)."}, {"id": "neuro:q:236", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Why is buprenorphine safer than methadone?", "back": "Partial agonism gives a ceiling on respiratory depression."}, {"id": "neuro:q:237", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "When can buprenorphine precipitate withdrawal?", "back": "If given while a full agonist still occupies the receptor (give in early withdrawal)."}, {"id": "neuro:q:238", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Relapse-prevention drugs for alcohol use disorder?", "back": "Naltrexone, acamprosate, disulfiram."}, {"id": "neuro:q:239", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Partial nicotinic agonist for smoking cessation?", "back": "Varenicline (α4β2 partial agonist)."}, {"id": "neuro:q:240", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "A non-nicotine, non-varenicline aid to smoking cessation?", "back": "Bupropion."}, {"id": "neuro:q:241", "deck": "Neuropharmacology & ANS", "dk": "neuro", "type": "quiz", "front": "Cardiac caution with methadone?", "back": "QT-interval prolongation (plus long, variable half-life → accumulation)."}, {"id": "endo:fc:20", "deck": "Endocrine", "dk": "endo", "type": "flashcard", "front": "Immediately after delivery a woman has heavy uterine bleeding with a boggy, poorly contracted uterus. BP 110/70. What is first-line drug management and its mechanism?", "back": "Uterine atony — the leading cause of <strong>postpartum haemorrhage (PPH)</strong>. First-line drug: <strong>oxytocin</strong> (IV/IM), which acts on Gq-coupled oxytocin receptors → ↑IP₃ → ↑intracellular Ca²⁺ → myometrial contraction that mechanically compresses the bleeding spiral arteries. Escalate to <strong>ergometrine</strong> (sustained tetanic contraction) and then <strong>carboprost (PGF₂α)</strong> or misoprostol (PGE₁) if bleeding continues, alongside uterine massage and fluid resuscitation.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> \"Syntometrine\" = oxytocin + ergometrine combined, giving oxytocin's fast onset plus ergometrine's sustained action. Avoid bolus oxytocin in haemodynamically unstable women — it causes vasodilation and hypotension; give a slow infusion.</div>"}, {"id": "endo:fc:21", "deck": "Endocrine", "dk": "endo", "type": "flashcard", "front": "A woman with severe pre-eclampsia (BP 170/115) has postpartum haemorrhage. Which uterotonic must be avoided and why?", "back": "<strong>Ergometrine / methylergometrine must be avoided</strong> — it causes generalised vasoconstriction and can precipitate a dangerous further rise in blood pressure, even a hypertensive crisis or stroke, in a woman who is already severely hypertensive. Use <strong>oxytocin</strong> (and prostaglandins if needed) instead.<div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Conversely, <strong>carboprost (PGF₂α) is contraindicated in asthma</strong> (bronchospasm). So in an asthmatic <em>and</em> hypertensive woman with PPH, oxytocin is the safe backbone and the others must be chosen with these contraindications in mind.</div>"}, {"id": "endo:fc:22", "deck": "Endocrine", "dk": "endo", "type": "flashcard", "front": "Why is ergometrine excellent for postpartum haemorrhage but never used to induce labour?", "back": "Ergometrine produces a <strong>powerful, sustained, tetanic uterine contraction</strong> rather than the rhythmic contractions of physiological labour. After delivery this is exactly what's needed — a clamped-down uterus stops bleeding. <em>Before</em> delivery, a sustained spasm would compress the placental vessels continuously and <strong>asphyxiate the fetus</strong> (and risk uterine rupture), so it is never used for induction. Induction uses titratable <strong>oxytocin</strong> (± prostaglandins for cervical ripening).<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> The frog rectus / isolated-uterus preparations classically demonstrate this \"spasmogenic\" action — ergometrine and oxytocin contract, β₂-agonists relax (the spasmogenic/spasmolytic bioassay link).</div>"}, {"id": "endo:fc:23", "deck": "Endocrine", "dk": "endo", "type": "flashcard", "front": "A woman in threatened preterm labour at 29 weeks is given a tocolytic. What is the single most important purpose of the ~48-hour delay it provides?", "back": "The delay buys time to administer <strong>antenatal corticosteroids</strong> (e.g. betamethasone/dexamethasone) for <strong>fetal lung maturation</strong> — reducing neonatal respiratory distress syndrome, intraventricular haemorrhage and mortality — and to arrange in-utero transfer to a unit with neonatal intensive care. Tocolytics do <em>not</em> meaningfully prolong pregnancy or improve outcomes beyond this window.<div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> The benefit of tocolysis is the steroid window, not stopping labour itself. Magnesium sulphate is given in very preterm labour additionally for <strong>fetal neuroprotection</strong> (reduces cerebral palsy), independent of any tocolytic effect.</div>"}, {"id": "endo:fc:24", "deck": "Endocrine", "dk": "endo", "type": "flashcard", "front": "A 31-week pregnant woman is started on intravenous ritodrine for preterm labour and develops dyspnoea, tachycardia and crackles at the lung bases. What is happening?", "back": "<strong>β₂-agonist tocolytic adverse effects</strong> — ritodrine/salbutamol/terbutaline cause maternal <strong>tachycardia, and pulmonary oedema</strong> (fluid overload, especially with concurrent corticosteroids and IV fluids), plus <strong>hyperglycaemia</strong> and hypokalaemia. This is why β₂-agonists have largely been superseded by <strong>nifedipine</strong> or <strong>atosiban</strong>, which have better maternal/fetal safety profiles.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Mechanism of relaxation: β₂ stimulation → ↑cAMP → ↓intracellular Ca²⁺ → myometrial relaxation. The same Gs/cAMP pathway that relaxes bronchi relaxes the uterus.</div>"}, {"id": "endo:fc:25", "deck": "Endocrine", "dk": "endo", "type": "flashcard", "front": "Compare the mechanisms of nifedipine and atosiban as tocolytics.", "back": "<strong>Nifedipine</strong> is a dihydropyridine <strong>calcium-channel blocker</strong> — it blocks Ca²⁺ influx into myometrial cells, lowering intracellular calcium and relaxing the uterus (oral, cheap, effective; watch for maternal hypotension). <strong>Atosiban</strong> is a competitive <strong>oxytocin-receptor antagonist</strong> — it blocks oxytocin (and vasopressin) receptors, preventing the Gq → IP₃ → Ca²⁺ contraction signal (IV, very well tolerated, expensive). Both are first-choice modern tocolytics.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> The APOSTEL 8 trial found no superiority of atosiban over nifedipine — choice is often driven by route, cost and local protocol.</div>"}, {"id": "endo:fc:26", "deck": "Endocrine", "dk": "endo", "type": "flashcard", "front": "Indomethacin is used as a tocolytic but is avoided after about 32 weeks' gestation. Why?", "back": "Indomethacin is a <strong>COX inhibitor</strong> that reduces prostaglandin synthesis (prostaglandins drive uterine contraction). However, prostaglandins also keep the fetal <strong>ductus arteriosus</strong> patent — so indomethacin can cause <strong>premature closure/constriction of the ductus arteriosus</strong> (and oligohydramnios from reduced fetal renal perfusion), risks that rise with later gestation. It is therefore generally limited to earlier preterm labour and short courses.<div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> The same prostaglandin biology is used therapeutically elsewhere: a PGE₁ infusion (alprostadil) keeps the ductus <em>open</em> in duct-dependent congenital heart disease, while indomethacin/ibuprofen <em>close</em> a patent ductus arteriosus in neonates.</div>"}, {"id": "endo:fc:27", "deck": "Endocrine", "dk": "endo", "type": "flashcard", "front": "A woman receiving a high-volume oxytocin infusion for labour augmentation becomes confused with a serum sodium of 122 mmol/L. Explain.", "back": "<strong>Water intoxication / dilutional hyponatraemia.</strong> Oxytocin is structurally similar to <strong>vasopressin (ADH)</strong> and has intrinsic antidiuretic activity. Given in large doses with large volumes of electrolyte-free fluid over a prolonged labour, it promotes free-water retention → <strong>hyponatraemia</strong>, which can cause confusion, seizures and coma. Management: stop/reduce oxytocin, restrict fluids, careful correction of sodium.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Use the lowest effective oxytocin infusion rate in an isotonic, controlled-volume carrier, and monitor fluid balance in prolonged inductions to avoid this complication.</div>"}, {"id": "endo:q:165", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "What single intracellular signal determines whether the myometrium contracts or relaxes?", "back": "Intracellular calcium — high Ca²⁺ contracts (via MLCK), low Ca²⁺ relaxes."}, {"id": "endo:q:166", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Receptor and signalling pathway of oxytocin on the uterus?", "back": "Gq-coupled oxytocin receptor → IP₃ → ↑intracellular Ca²⁺ → contraction."}, {"id": "endo:q:167", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "First-line drug for prevention/treatment of postpartum haemorrhage?", "back": "Oxytocin."}, {"id": "endo:q:168", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Why is ergometrine never used to induce labour?", "back": "It causes a sustained tetanic contraction that would asphyxiate the fetus (and risk rupture)."}, {"id": "endo:q:169", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "In which condition is ergometrine contraindicated, and why?", "back": "Hypertension/pre-eclampsia — it causes vasoconstriction and can precipitate a crisis."}, {"id": "endo:q:170", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Which prostaglandin is used for cervical ripening?", "back": "PGE₂ (dinoprostone)."}, {"id": "endo:q:171", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Which uterotonic is contraindicated in asthma?", "back": "Carboprost (PGF₂α) — risk of bronchospasm."}, {"id": "endo:q:172", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Misoprostol (PGE₁) uses in obstetrics?", "back": "Induction of labour, PPH, and medical abortion (with mifepristone)."}, {"id": "endo:q:173", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Define a tocolytic and the typical duration of delay it provides.", "back": "A uterine relaxant that delays preterm labour by about 48 hours."}, {"id": "endo:q:174", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "What is the single most important purpose of that 48-hour delay?", "back": "To give antenatal corticosteroids for fetal lung maturation (and arrange transfer)."}, {"id": "endo:q:175", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Mechanism of β₂-agonist tocolytics (e.g. ritodrine)?", "back": "↑cAMP → ↓intracellular Ca²⁺ → myometrial relaxation."}, {"id": "endo:q:176", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Two serious maternal risks of β₂-agonist tocolytics?", "back": "Pulmonary oedema and tachycardia (also hyperglycaemia/hypokalaemia)."}, {"id": "endo:q:177", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Mechanism of atosiban?", "back": "Competitive oxytocin-receptor antagonist."}, {"id": "endo:q:178", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Besides tocolysis, why is magnesium sulphate given in very preterm labour?", "back": "Fetal neuroprotection (reduces cerebral palsy)."}, {"id": "endo:q:179", "deck": "Endocrine", "dk": "endo", "type": "quiz", "front": "Why is indomethacin avoided as a tocolytic in later gestation?", "back": "It can cause premature closure of the fetal ductus arteriosus (and oligohydramnios)."}, {"id": "gen:fc:20", "deck": "General Pharmacology", "dk": "gen", "type": "flashcard", "front": "A researcher wants to quantify how much of a target gene's messenger RNA is present in treated vs untreated cells. Which technique, and what extra step does it need vs ordinary PCR?", "back": "<strong>RT-qPCR</strong> (reverse-transcription quantitative PCR). Because PCR amplifies DNA, RNA must first be converted to <strong>complementary DNA (cDNA) by reverse transcriptase</strong> — the extra step ordinary PCR doesn't need — before real-time amplification quantifies expression.<div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> High mRNA does not guarantee functional protein (post-transcriptional/translational control) — confirm protein with a Western blot or ELISA.</div>"}, {"id": "gen:fc:21", "deck": "General Pharmacology", "dk": "gen", "type": "flashcard", "front": "Match the three classic blots to the molecule each detects, and give the mnemonic.", "back": "<strong>Southern = DNA, Northern = RNA, Western = protein</strong> (detected with antibodies). Mnemonic <strong>\"SNoW DRoP\"</strong>: <u>S</u>outhern–<u>D</u>NA, <u>N</u>orthern–<u>R</u>NA, <u>W</u>estern–<u>P</u>rotein.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> They line up along the central dogma — DNA → (transcription) → RNA → (translation) → protein.</div>"}, {"id": "gen:fc:22", "deck": "General Pharmacology", "dk": "gen", "type": "flashcard", "front": "Contrast monoclonal and polyclonal antibodies for a research assay.", "back": "<strong>Monoclonal</strong> — from a single B-cell clone (hybridoma), recognises one epitope; highly specific and reproducible, ideal for standardised assays and as therapeutics (\"-mab\"). <strong>Polyclonal</strong> — a mixture recognising many epitopes; cheaper, often more sensitive/avid, but batch-variable.<div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Monoclonal ≠ more sensitive; it is more <em>specific/reproducible</em>. Polyclonals are frequently more sensitive because they bind multiple epitopes.</div>"}, {"id": "gen:fc:23", "deck": "General Pharmacology", "dk": "gen", "type": "flashcard", "front": "How would you prove a candidate gene actually mediates a drug's effect rather than just being associated with it?", "back": "Silence or delete the gene and show the drug response disappears: <strong>antisense oligonucleotides or RNAi (siRNA)</strong> to knock down the mRNA, or a <strong>gene-knockout animal / CRISPR</strong> to remove it. Loss of effect on removal is causal evidence, unlike mere expression correlation.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Antisense/RNAi are also drugs themselves (e.g. nusinersen for SMA; patisiran siRNA).</div>"}, {"id": "gen:fc:24", "deck": "General Pharmacology", "dk": "gen", "type": "flashcard", "front": "Which technique quantifies a receptor's number and affinity, and what two parameters does it yield?", "back": "A <strong>radioligand binding assay</strong> yields <strong>B<sub>max</sub></strong> (maximum binding sites → receptor density) and <strong>K<sub>d</sub></strong> (dissociation constant → affinity; lower K<sub>d</sub> = higher affinity). Proteomics (2-D gels, mass spectrometry) maps the broader protein complement.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> B<sub>max</sub> tracks with receptor up/down-regulation (e.g. β-receptor changes in heart failure).</div>"}, {"id": "gen:fc:25", "deck": "General Pharmacology", "dk": "gen", "type": "flashcard", "front": "A company must guarantee every batch of a herbal extract is equivalent. What three steps achieve standardisation?", "back": "(1) <strong>Extraction</strong> (maceration or percolation) to pull out constituents; (2) <strong>HPTLC fingerprinting</strong> — a chromatographic \"barcode\" confirming identity and consistency; (3) assay of a <strong>marker compound</strong> to fix potency. Together these convert a variable botanical into a reproducible medicine.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Tracking the marker compound in blood/urine allows pharmacokinetic and quality monitoring of the herbal product.</div>"}, {"id": "gen:fc:26", "deck": "General Pharmacology", "dk": "gen", "type": "flashcard", "front": "Give the active-constituent class for morphine, digoxin and quinine.", "back": "<strong>Morphine — alkaloid</strong> (nitrogen-containing, basic). <strong>Digoxin — (cardiac) glycoside</strong> (sugar + aglycone). <strong>Quinine — alkaloid</strong>. Other classes: flavonoids/tannins (polyphenols), terpenoids/volatile oils, saponins, resins.<div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Glycosides yield a sugar plus an aglycone on hydrolysis; the aglycone usually carries the activity (e.g. digoxigenin).</div>"}, {"id": "gen:fc:27", "deck": "General Pharmacology", "dk": "gen", "type": "flashcard", "front": "Distinguish maceration from percolation as extraction methods.", "back": "<strong>Maceration</strong> — the drug is soaked in a fixed volume of solvent and left standing (static); simple, gentle, good for readily soluble or thermolabile constituents but less exhaustive. <strong>Percolation</strong> — solvent flows continuously through a packed bed of drug; more exhaustive extraction and the basis of tinctures.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Choose percolation when you need to extract nearly all of the active constituent; maceration when simplicity or heat-sensitivity matters.</div>"}, {"id": "gen:fc:28", "deck": "General Pharmacology", "dk": "gen", "type": "flashcard", "front": "What is \"reverse pharmacology\" and how does it differ from the classic discovery pipeline?", "back": "<strong>Reverse pharmacology</strong> starts from a plant/preparation already used in humans (traditional medicine) with observed clinical effect and works <em>backwards</em> to isolate the active molecule and define its mechanism. The classic (forward) pipeline starts from a molecular target and moves forward to a drug. Both must still pass the same preclinical and clinical evaluation.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Artemisinin (from Artemisia annua, traditional Chinese medicine) is a landmark reverse-pharmacology success.</div>"}, {"id": "gen:fc:29", "deck": "General Pharmacology", "dk": "gen", "type": "flashcard", "front": "Why is \"natural\" not the same as \"safe\" for a herbal product?", "back": "Herbals carry real risks: <strong>adulteration, heavy-metal contamination, batch variability, and herb–drug interactions</strong>. A classic example is <strong>St John's Wort</strong>, a potent CYP3A4 and P-glycoprotein inducer that lowers plasma levels of many drugs (ciclosporin, oral contraceptives, warfarin, some antiretrovirals).<div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Standardisation and pharmacovigilance apply to herbal medicines too — being plant-derived does not exempt a product from quality control or ADR reporting.</div>"}, {"id": "gen:fc:30", "deck": "General Pharmacology", "dk": "gen", "type": "flashcard", "front": "A new drug adds quality-adjusted survival at ten times the cost of the standard. Which pharmacoeconomic analysis judges it, and what metric?", "back": "<strong>Cost–utility analysis</strong>, using the <strong>QALY</strong> (quality-adjusted life-year). The <strong>ICER</strong> = Δcost ÷ Δeffect (cost per QALY gained) compares it with the standard against a willingness-to-pay threshold.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> QALY = years of life × quality weight (0 = death, 1 = perfect health), so it captures both length and quality of life on one scale.</div>"}, {"id": "gen:fc:31", "deck": "General Pharmacology", "dk": "gen", "type": "flashcard", "front": "Distinguish cost-minimisation, cost-effectiveness, cost–utility and cost–benefit analyses.", "back": "They differ only in how the <em>outcome</em> is measured: <strong>cost-minimisation</strong> — outcomes assumed equal, compare cost only; <strong>cost-effectiveness</strong> — natural units (cost per life-year, per mmHg); <strong>cost–utility</strong> — cost per QALY; <strong>cost–benefit</strong> — outcomes valued in money (net monetary benefit).<div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Cost-effectiveness uses natural units; only cost–<em>utility</em> uses QALYs — a very common MCQ distractor.</div>"}, {"id": "gen:fc:32", "deck": "General Pharmacology", "dk": "gen", "type": "flashcard", "front": "Which Indian Act regulates the manufacture and sale of drugs, and what do Schedules H, X and M cover?", "back": "The <strong>Drugs &amp; Cosmetics Act 1940</strong> (with Rules 1945). <strong>Schedule H/H1</strong> — prescription-only drugs (H1 for certain antibiotics/psychotropics needing extra record-keeping); <strong>Schedule X</strong> — narcotic/psychotropic drugs with stricter controls; <strong>Schedule M</strong> — Good Manufacturing Practices.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> The central regulator is CDSCO/DCGI; clinical trials and approvals run under the New Drugs &amp; Clinical Trials Rules 2019.</div>"}, {"id": "gen:fc:33", "deck": "General Pharmacology", "dk": "gen", "type": "flashcard", "front": "What are the NLEM and DPCO, and how are they linked?", "back": "The <strong>NLEM (National List of Essential Medicines)</strong> lists medicines meeting priority healthcare needs, chosen on efficacy, safety and cost-effectiveness. The <strong>DPCO (Drug Price Control Order)</strong>, enforced by the <strong>NPPA</strong>, caps the prices of scheduled medicines drawn from the NLEM — so essential drugs stay affordable.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> The NLEM mirrors the WHO Essential Medicines List concept; selection is scientific, price control is the economic tool applied to it.</div>"}, {"id": "gen:fc:34", "deck": "General Pharmacology", "dk": "gen", "type": "flashcard", "front": "Define rational prescribing in the WHO sense.", "back": "Prescribing the <strong>right drug, at the right dose, for the right duration, at the lowest cost</strong> to the patient and community — matched to the clinical need, with adequate information and follow-up. Drug-utilisation studies measure how prescribing compares with this standard.<div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Rational prescribing is simultaneously a clinical goal (safety/efficacy) and an economic one (avoiding waste and irrational polypharmacy).</div>"}, {"id": "gen:fc:35", "deck": "General Pharmacology", "dk": "gen", "type": "flashcard", "front": "Name the four sections of a scientific paper (IMRaD) and what each contains.", "back": "<strong>I</strong>ntroduction (the question/rationale), <strong>M</strong>ethods (how the study was done — reproducibly), <strong>R</strong>esults (what was found, without interpretation), <strong>D</strong>iscussion (what it means, limitations, implications) — framed by title, abstract and references.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> IMRaD is an \"hourglass\" — broad context → narrow specifics → broad meaning.</div>"}, {"id": "gen:fc:36", "deck": "General Pharmacology", "dk": "gen", "type": "flashcard", "front": "What is microteaching and why is it used in MD training?", "back": "A short (~5–10 minute) focused teaching episode to a small group practising <strong>one</strong> teaching skill (e.g. explaining, questioning), followed by structured feedback and <strong>re-teaching</strong>. Isolating a single skill in a brief, low-stakes loop makes improvement fast and targeted — useful for viva and teaching preparation.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> The cycle is plan → teach → feedback → re-teach.</div>"}, {"id": "gen:fc:37", "deck": "General Pharmacology", "dk": "gen", "type": "flashcard", "front": "What is the \"see one, do one, teach one\" model of a practical demonstration?", "back": "An apprenticeship approach to teaching a skill: <strong>demonstrate</strong> it (show), <strong>explain</strong> the steps, <strong>let the learner perform</strong> it, then <strong>give feedback</strong> — progressing to the learner teaching it themselves, which consolidates mastery.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Effective demonstrations pair clear learning objectives with immediate, specific feedback.</div>"}, {"id": "gen:fc:38", "deck": "General Pharmacology", "dk": "gen", "type": "flashcard", "front": "Why is accurate record-keeping an ethical requirement in pharmacology research?", "back": "Complete, contemporaneous records underpin <strong>reproducibility</strong> and are mandated by GLP/GCP; they protect against error and allow audit. Fabrication, falsification and plagiarism are serious research misconduct, and authorship must reflect genuine contribution (ICMJE criteria).<div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Poor record-keeping is not just untidy — it undermines data integrity and can invalidate a study or trigger misconduct proceedings.</div>"}, {"id": "gen:fc:39", "deck": "General Pharmacology", "dk": "gen", "type": "flashcard", "front": "What are the two main formats for presenting research at a conference, and how do they differ?", "back": "An <strong>oral presentation</strong> — a focused, time-limited talk with slides, ending in question handling — and a <strong>poster</strong> — a concise visual summary (aims, methods, key results, conclusion) discussed one-to-one at a poster session. Oral suits a clear headline message; posters suit detailed data and networking.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Both demand ruthless prioritisation of the key message — the same discipline as writing a good abstract.</div>"}, {"id": "gen:q:200", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "What does PCR do, and which enzyme drives it?", "back": "Exponentially amplifies a target DNA sequence; driven by a thermostable DNA polymerase (Taq)."}, {"id": "gen:q:201", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "What extra step does RT-PCR require versus ordinary PCR, and why?", "back": "Reverse transcription of RNA to cDNA first — because PCR amplifies DNA, not RNA."}, {"id": "gen:q:202", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "What is qPCR used to measure?", "back": "Gene expression — the quantity of a specific transcript (real-time amplification)."}, {"id": "gen:q:203", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Southern, Northern and Western blots detect what, respectively?", "back": "DNA, RNA, and protein (\"SNoW DRoP\")."}, {"id": "gen:q:204", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "How are proteins detected on a Western blot?", "back": "With specific antibodies."}, {"id": "gen:q:205", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Monoclonal vs polyclonal antibody — key difference?", "back": "Monoclonal recognises one epitope (specific, reproducible); polyclonal recognises many epitopes (often more sensitive, but variable)."}, {"id": "gen:q:206", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Name two ways to silence a specific gene's product.", "back": "Antisense oligonucleotides and RNA interference (siRNA)."}, {"id": "gen:q:207", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "How does a knockout animal help validate a drug target?", "back": "Deleting the gene should abolish the drug's effect — causal, not just correlational, evidence."}, {"id": "gen:q:208", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "What two parameters does a radioligand binding assay yield?", "back": "B<sub>max</sub> (receptor number) and K<sub>d</sub> (affinity)."}, {"id": "gen:q:209", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Give one technique used in proteomics.", "back": "Two-dimensional gel electrophoresis or mass spectrometry."}, {"id": "gen:q:210", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Name a therapeutic antisense/RNAi drug.", "back": "Nusinersen (antisense, SMA) or patisiran (siRNA)."}, {"id": "gen:q:211", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Why doesn't high mRNA guarantee active protein?", "back": "Post-transcriptional and post-translational control can alter protein amount and activity."}, {"id": "gen:q:212", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Why do herbal drugs specifically need \"standardisation\"?", "back": "They are complex, variable mixtures — standardisation ensures consistent identity, purity and potency."}, {"id": "gen:q:213", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Constituent class of morphine and quinine?", "back": "Alkaloids (nitrogen-containing, basic)."}, {"id": "gen:q:214", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Constituent class of digoxin?", "back": "A (cardiac) glycoside — sugar + aglycone."}, {"id": "gen:q:215", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Maceration vs percolation?", "back": "Maceration = static soaking in solvent; percolation = continuous solvent flow through the drug bed (more exhaustive)."}, {"id": "gen:q:216", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "What does HPTLC fingerprinting provide?", "back": "A characteristic chromatographic \"barcode\" confirming identity/consistency of an extract."}, {"id": "gen:q:217", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "What is a marker compound used for?", "back": "Assaying it fixes/standardises the extract's potency (and tracks PK in fluids)."}, {"id": "gen:q:218", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Define reverse pharmacology.", "back": "Starting from a traditionally-used plant with known human effect and working back to the active molecule and mechanism."}, {"id": "gen:q:219", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Give a landmark reverse-pharmacology drug.", "back": "Artemisinin (from Artemisia annua)."}, {"id": "gen:q:220", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Name a herb–drug interaction of major clinical importance.", "back": "St John's Wort induces CYP3A4/P-gp → lowers levels of many drugs (ciclosporin, OCPs, warfarin)."}, {"id": "gen:q:221", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Two safety hazards of herbal products besides interactions?", "back": "Adulteration and heavy-metal contamination (plus batch variability)."}, {"id": "gen:q:222", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Which Act regulates manufacture and sale of drugs in India?", "back": "The Drugs &amp; Cosmetics Act 1940 (with Rules 1945)."}, {"id": "gen:q:223", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "What does Schedule H (H1) cover?", "back": "Prescription-only drugs (H1 adds extra record-keeping for certain antibiotics/psychotropics)."}, {"id": "gen:q:224", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "What does Schedule M specify?", "back": "Good Manufacturing Practices."}, {"id": "gen:q:225", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Which body is the central drug regulator?", "back": "CDSCO, headed by the DCGI."}, {"id": "gen:q:226", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "What does the DPCO do, and who enforces it?", "back": "Caps prices of scheduled essential medicines; enforced by the NPPA."}, {"id": "gen:q:227", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "What is the NLEM?", "back": "National List of Essential Medicines — priority medicines chosen on efficacy, safety and cost-effectiveness."}, {"id": "gen:q:228", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Define a QALY.", "back": "Quality-adjusted life-year = life-years × quality weight (0 = death, 1 = perfect health)."}, {"id": "gen:q:229", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Which analysis uses cost per QALY?", "back": "Cost–utility analysis."}, {"id": "gen:q:230", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Which analysis uses natural units (e.g. cost per life-year)?", "back": "Cost-effectiveness analysis."}, {"id": "gen:q:231", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "What does the ICER measure?", "back": "Incremental cost-effectiveness ratio = Δcost ÷ Δeffect (extra cost per extra unit of benefit)."}, {"id": "gen:q:232", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Cost–benefit analysis expresses outcomes in what unit?", "back": "Money."}, {"id": "gen:q:233", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Define rational prescribing (WHO).", "back": "Right drug, right dose, right duration, lowest cost — matched to clinical need."}, {"id": "gen:q:234", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "What does IMRaD stand for?", "back": "Introduction, Methods, Results, and Discussion."}, {"id": "gen:q:235", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Which IMRaD section states the study question/rationale?", "back": "The Introduction."}, {"id": "gen:q:236", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Which section must allow the study to be reproduced?", "back": "The Methods."}, {"id": "gen:q:237", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Where is interpretation of findings placed?", "back": "The Discussion (Results report findings without interpretation)."}, {"id": "gen:q:238", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Why is IMRaD called an \"hourglass\"?", "back": "It moves from broad context → narrow specifics → broad meaning."}, {"id": "gen:q:239", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "What is microteaching?", "back": "A short (~5–10 min) focused episode practising one teaching skill, with feedback and re-teaching."}, {"id": "gen:q:240", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "State the microteaching cycle.", "back": "Plan → teach → feedback → re-teach."}, {"id": "gen:q:241", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Summarise the practical-demonstration model.", "back": "\"See one, do one, teach one\" — demonstrate, explain, let the learner do, give feedback."}, {"id": "gen:q:242", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Name the two main conference presentation formats.", "back": "Oral presentation and poster."}, {"id": "gen:q:243", "deck": "General Pharmacology", "dk": "gen", "type": "quiz", "front": "Why is accurate record-keeping an ethical requirement?", "back": "It underpins reproducibility and data integrity (GLP/GCP); guards against misconduct."}, {"id": "special:fc:20", "deck": "Special Systems", "dk": "special", "type": "flashcard", "front": "A patient with chronic cholestatic liver disease develops easy bruising and a prolonged prothrombin time that corrects with parenteral vitamin K. Explain.", "back": "<strong>Vitamin K deficiency from fat malabsorption.</strong> Vitamin K is fat-soluble and needs bile for absorption; cholestasis impairs this → deficiency of the vitamin-K-dependent clotting factors <strong>II, VII, IX, X</strong> → prolonged PT/INR and bleeding. Because the defect is substrate deficiency (not liver synthetic failure), parenteral vitamin K corrects it.<div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> If the PT does NOT correct with vitamin K, the problem is hepatocellular synthetic failure, not simple deficiency. The other fat-soluble vitamins (A, D, E) are also depleted in fat malabsorption.</div>"}, {"id": "special:fc:21", "deck": "Special Systems", "dk": "special", "type": "flashcard", "front": "Why must folic acid never be given alone to a patient with an unexplained megaloblastic anaemia?", "back": "If the cause is <strong>vitamin B12 deficiency</strong>, folate will correct the anaemia (masking it) but the <strong>neurological damage — subacute combined degeneration of the cord — progresses unchecked</strong> and may become irreversible. Always check B12 and folate together and replace B12 first (or both).<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> B12 deficiency causes neuro signs (dorsal column/pyramidal); folate deficiency causes neural-tube defects in pregnancy but not SCD.</div>"}, {"id": "special:fc:22", "deck": "Special Systems", "dk": "special", "type": "flashcard", "front": "An obese patient with type 2 diabetes is started on semaglutide and loses substantial weight. What is the mechanism and a key contraindication?", "back": "Semaglutide is a <strong>GLP-1 receptor agonist</strong>: it stimulates glucose-dependent insulin secretion, <strong>slows gastric emptying</strong>, and acts centrally to <strong>suppress appetite</strong> — together reducing intake and body weight. Contraindicated with a personal/family history of <strong>medullary thyroid carcinoma or MEN2</strong> (rodent C-cell tumour signal); also caution re pancreatitis.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Tirzepatide adds GIP agonism for even greater weight loss; GI upset is the commonest adverse effect of this class.</div>"}, {"id": "special:fc:23", "deck": "Special Systems", "dk": "special", "type": "flashcard", "front": "A patient on orlistat for obesity develops night blindness and a prolonged INR. Why?", "back": "Orlistat inhibits <strong>intestinal/pancreatic lipase</strong>, blocking dietary fat absorption — and with it the absorption of the <strong>fat-soluble vitamins A, D, E and K</strong>. Vitamin A deficiency → night blindness; vitamin K deficiency → reduced clotting factors → prolonged INR. Supplement fat-soluble vitamins, taken separated from the drug.<div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Orlistat's hallmark side effect is steatorrhoea (oily, fatty stools) from unabsorbed fat.</div>"}, {"id": "special:fc:24", "deck": "Special Systems", "dk": "special", "type": "flashcard", "front": "An alcoholic patient is brought in confused; the intern is about to start IV dextrose. What must be given first and why?", "back": "<strong>Thiamine (vitamin B1) before glucose.</strong> A glucose load in a thiamine-deficient patient consumes the last thiamine (a cofactor for glucose metabolism) and can precipitate <strong>Wernicke encephalopathy</strong> (ophthalmoplegia, ataxia, confusion), which may progress to irreversible Korsakoff psychosis.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Thiamine deficiency also causes beriberi — \"wet\" (high-output cardiac failure) and \"dry\" (peripheral neuropathy).</div>"}, {"id": "special:fc:25", "deck": "Special Systems", "dk": "special", "type": "flashcard", "front": "A neonate given chloramphenicol develops abdominal distension, cyanosis and cardiovascular collapse. Name the syndrome and its mechanism.", "back": "<strong>Grey-baby syndrome.</strong> Neonates have <strong>immature hepatic glucuronidation</strong> (and reduced renal excretion), so chloramphenicol accumulates to toxic levels → circulatory collapse, grey discolouration, hypotension. It illustrates how immature metabolism makes a normal weight-scaled dose dangerous.<div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Also avoid sulfonamides in neonates — they displace bilirubin from albumin and, with an immature blood-brain barrier, risk kernicterus.</div>"}, {"id": "special:fc:26", "deck": "Special Systems", "dk": "special", "type": "flashcard", "front": "An 82-year-old on multiple medications keeps falling. Which drug classes named in the Beers criteria should you review first?", "back": "The <strong>Beers criteria</strong> flag potentially inappropriate medicines in older adults: <strong>long-acting benzodiazepines</strong> and Z-drugs (sedation, falls), <strong>strong anticholinergics</strong> (confusion, retention), and <strong>NSAIDs</strong> (GI bleeding, renal/CV risk). Reduced clearance and increased sensitivity mean \"start low, go slow\" and regular deprescribing review.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Increased body fat raises the volume of distribution of lipophilic drugs (e.g. diazepam), prolonging their effect in the elderly.</div>"}, {"id": "special:fc:27", "deck": "Special Systems", "dk": "special", "type": "flashcard", "front": "A woman planning pregnancy is on several drugs. Which classic teratogens must be switched, and give one harm of each?", "back": "Switch the classic teratogens: <strong>warfarin</strong> (nasal/skeletal defects), <strong>ACE inhibitors/ARBs</strong> (renal dysgenesis, oligohydramnios in 2nd/3rd trimester), <strong>valproate</strong> (neural tube defects, neurodevelopmental harm), <strong>isotretinoin</strong> (severe craniofacial/cardiac/CNS defects), <strong>tetracyclines</strong> (teeth/bone), <strong>methotrexate</strong> and <strong>thalidomide</strong> (phocomelia).<div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> ACE inhibitor fetopathy is a 2nd/3rd-trimester effect — the drug must be stopped as soon as pregnancy is planned/confirmed.</div>"}, {"id": "special:fc:28", "deck": "Special Systems", "dk": "special", "type": "flashcard", "front": "A patient with eGFR 25 needs an aminoglycoside. How do you adjust dosing and why?", "back": "Aminoglycosides are <strong>renally excreted and nephrotoxic</strong>. In renal impairment, <strong>reduce the dose and/or extend the dosing interval</strong> guided by eGFR/CrCl and therapeutic drug monitoring (trough levels), and avoid other nephrotoxins. The goal is effective peak concentrations without accumulation.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> eGFR is preferred over serum creatinine alone because creatinine varies with muscle mass, age and sex.</div>"}, {"id": "special:fc:29", "deck": "Special Systems", "dk": "special", "type": "flashcard", "front": "Before starting azathioprine, a clinician checks an enzyme level. Which enzyme, and why does it matter?", "back": "<strong>TPMT (thiopurine methyltransferase).</strong> Patients with low/absent TPMT activity cannot inactivate azathioprine/6-mercaptopurine → drug accumulates → severe, potentially fatal <strong>myelosuppression</strong>. Genotyping/phenotyping guides dose reduction or avoidance — a classic pharmacogenomic example.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Other genotype-guided drugs: HLA-B*57:01 (abacavir), HLA-B*15:02 (carbamazepine SJS), CYP2C19 (clopidogrel).</div>"}, {"id": "special:fc:30", "deck": "Special Systems", "dk": "special", "type": "flashcard", "front": "A farmer arrives drowsy, sweating, with pinpoint pupils, copious secretions and muscle fasciculations. Diagnosis, antidotes, and the atropine end-point?", "back": "<strong>Organophosphate poisoning</strong> (cholinergic toxidrome — DUMBELS/SLUDGE). Antidotes: <strong>atropine</strong> (blocks muscarinic effects) titrated to <strong>drying of bronchial secretions</strong> (the key end-point, not pupils or heart rate) + <strong>pralidoxime</strong> to reactivate acetylcholinesterase before \"ageing\". Add airway protection, decontamination, and benzodiazepines for seizures.<div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Pralidoxime must be given early — once the phosphorylated enzyme \"ages\" it can no longer be reactivated.</div>"}, {"id": "special:fc:31", "deck": "Special Systems", "dk": "special", "type": "flashcard", "front": "An unconscious patient with respiratory depression and pinpoint pupils wakes after naloxone but re-sedates 30 minutes later. Why, and what do you do?", "back": "Opioid overdose (the triad: coma, pinpoint pupils, respiratory depression). Naloxone reversed it, but its <strong>half-life is shorter than most opioids</strong>, so as it wears off the opioid re-occupies the μ-receptor → re-sedation. Manage with <strong>repeat naloxone doses or a continuous infusion</strong> and prolonged observation (especially long-acting opioids/fentanyl).<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> The same short-half-life caveat applies to flumazenil for benzodiazepines.</div>"}, {"id": "special:fc:32", "deck": "Special Systems", "dk": "special", "type": "flashcard", "front": "A patient takes a large paracetamol overdose. Which antidote, how does it work, and why does timing matter?", "back": "<strong>N-acetylcysteine (NAC)</strong> — it <strong>replenishes hepatic glutathione</strong>, which neutralises the toxic metabolite NAPQI formed when the normal conjugation pathways saturate. It is most effective when given early (within ~8 hours), but is still given late in significant ingestions; the treatment nomogram guides the decision.<div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Activated charcoal helps only if given early after ingestion; it does not replace NAC.</div>"}, {"id": "special:fc:33", "deck": "Special Systems", "dk": "special", "type": "flashcard", "front": "Which poisonings are effectively treated with haemodialysis, and what physicochemical properties allow it?", "back": "Dialysable toxins are <strong>small, water-soluble, low protein-bound, and have a low volume of distribution</strong>: <strong>salicylate, lithium, methanol, ethylene glycol, valproate, metformin, theophylline</strong>. A large volume of distribution or high protein binding (e.g. digoxin, TCAs) makes dialysis ineffective because most drug sits in tissue, not plasma.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Urinary alkalinisation (bicarbonate) enhances renal elimination of weak acids such as salicylate and phenobarbital via ion trapping.</div>"}, {"id": "special:fc:34", "deck": "Special Systems", "dk": "special", "type": "flashcard", "front": "Which common poisons are NOT adsorbed by activated charcoal?", "back": "Activated charcoal does <strong>not bind metals, alcohols, hydrocarbons, caustics, lithium or iron</strong>. It is most useful given early for many drug overdoses; multiple-dose charcoal additionally interrupts enterohepatic recycling (theophylline, carbamazepine, dapsone, phenobarbital, quinine).<div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Charcoal is contraindicated/ineffective for caustic ingestion and where the airway is unprotected in a drowsy patient (aspiration risk).</div>"}, {"id": "special:fc:35", "deck": "Special Systems", "dk": "special", "type": "flashcard", "front": "Whose frog-heart experiment proved chemical neurotransmission, and what was \"Vagusstoff\"?", "back": "<strong>Otto Loewi</strong> (with Henry Dale, Nobel 1936). Stimulating the vagus of one frog heart released a substance (\"<strong>Vagusstoff</strong>\") that slowed a second heart when the perfusate was transferred — proving nerves signal chemically. Vagusstoff was later identified as <strong>acetylcholine</strong>, founding autonomic pharmacology.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Dale's classification of cholinergic vs adrenergic transmission underlies the entire ANS drug map.</div>"}, {"id": "special:fc:36", "deck": "Special Systems", "dk": "special", "type": "flashcard", "front": "Which two landmark drugs did James Black design, and why is his work called \"rational drug design\"?", "back": "<strong>Propranolol</strong> (the first β-adrenergic blocker) and <strong>cimetidine</strong> (the first H₂-receptor antagonist). Rather than screening by chance, Black started from a defined receptor and <strong>engineered molecules to block it</strong> — the birth of rational, receptor-based drug design (Nobel 1988).<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Both drugs founded whole therapeutic classes (β-blockers in cardiology; H₂-blockers in peptic ulcer disease).</div>"}, {"id": "special:fc:37", "deck": "Special Systems", "dk": "special", "type": "flashcard", "front": "Who discovered cyclic AMP, who discovered G-proteins, and why do these matter for pharmacology?", "back": "<strong>Earl Sutherland</strong> discovered cyclic AMP as a second messenger (Nobel 1971); <strong>Alfred Gilman and Martin Rodbell</strong> discovered G-proteins (Nobel 1994). Together they explained the intracellular machinery that receptors switch on — the basis of <strong>GPCR pharmacology</strong>, the largest single class of drug targets.<div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Don't swap them — cAMP = Sutherland; G-proteins = Gilman &amp; Rodbell.</div>"}, {"id": "special:fc:38", "deck": "Special Systems", "dk": "special", "type": "flashcard", "front": "Who developed the radioimmunoassay, and why was it transformative?", "back": "<strong>Rosalyn Yalow</strong> (Nobel 1977, with the work done alongside Solomon Berson, who had died). The <strong>radioimmunoassay (RIA)</strong> used antibody binding with a radiolabelled tracer to measure hormones, drugs and other molecules at <strong>extremely low concentrations</strong> — revolutionising endocrinology and therapeutic drug monitoring.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> RIA is the conceptual ancestor of ELISA and modern immunoassays.</div>"}, {"id": "special:fc:39", "deck": "Special Systems", "dk": "special", "type": "flashcard", "front": "Which discovery by Allison and Honjo reshaped oncology, and name the \"father of Indian pharmacology\".", "back": "James <strong>Allison</strong> and Tasuku <strong>Honjo</strong> discovered <strong>immune checkpoint inhibition</strong> (CTLA-4 and PD-1 respectively; Nobel 2018) → checkpoint-inhibitor drugs (ipilimumab, nivolumab, pembrolizumab) that release the immune system against cancer. The \"father of Indian pharmacology\" is <strong>Colonel Sir Ram Nath Chopra</strong>.<div class=\"sr-note\">💎 <strong>Clinical Pearl:</strong> Checkpoint inhibitors cause characteristic immune-related adverse events (colitis, thyroiditis, pneumonitis, hepatitis).</div>"}, {"id": "special:q:45", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "Name the four fat-soluble vitamins and state why toxicity is a particular concern for them.", "back": "<strong>A, D, E, K.</strong> They are stored in liver and adipose tissue rather than excreted, so excess accumulates and can cause toxicity."}, {"id": "special:q:46", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "Why do fat-soluble vitamin deficiencies cluster with fat malabsorption?", "back": "They require dietary fat for absorption, so any cause of fat malabsorption (cholestasis, coeliac disease, cystic fibrosis, orlistat) reduces their uptake."}, {"id": "special:q:47", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "Deficiency and a toxicity of vitamin A.", "back": "Deficiency: night blindness/xerophthalmia. Toxicity: teratogenicity, raised intracranial pressure, hepatotoxicity."}, {"id": "special:q:48", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "Which clotting factors depend on vitamin K?", "back": "Factors II, VII, IX, X (and proteins C and S)."}, {"id": "special:q:49", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "What triad characterises pellagra and which vitamin is deficient?", "back": "Dermatitis, diarrhoea, dementia (the 3 Ds); niacin (vitamin B3) deficiency."}, {"id": "special:q:50", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "Why must folate not be given alone in an unexplained megaloblastic anaemia?", "back": "If B12 deficiency is the cause, folate corrects the anaemia but the neurological damage (subacute combined degeneration) progresses unchecked."}, {"id": "special:q:51", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "Which vitamin is a cofactor for collagen hydroxylation, and what is its deficiency?", "back": "Vitamin C; deficiency causes scurvy (bleeding gums, perifollicular haemorrhage, poor wound healing)."}, {"id": "special:q:52", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "State the three weight-relevant actions of GLP-1 receptor agonists.", "back": "Glucose-dependent insulin secretion, slowed gastric emptying, and central appetite suppression."}, {"id": "special:q:53", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "Name a weekly GLP-1 agonist and the dual GIP/GLP-1 agonist used for obesity.", "back": "Semaglutide (weekly GLP-1); tirzepatide (dual GIP + GLP-1)."}, {"id": "special:q:54", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "Key contraindication to GLP-1/GIP agonists?", "back": "Personal or family history of medullary thyroid carcinoma or MEN2 (also caution re pancreatitis)."}, {"id": "special:q:55", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "Mechanism and main side effect of orlistat, and what must be supplemented?", "back": "Inhibits intestinal/pancreatic lipase → blocks fat absorption; causes steatorrhoea; supplement fat-soluble vitamins A, D, E, K."}, {"id": "special:q:56", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "Why give thiamine before glucose in an alcoholic patient?", "back": "A glucose load consumes remaining thiamine and can precipitate Wernicke encephalopathy."}, {"id": "special:q:57", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "What is the single most useful question when dosing any special population?", "back": "Which ADME step (absorption, distribution, metabolism, excretion) is altered — then adjust dose, interval or drug choice accordingly."}, {"id": "special:q:58", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "Why does chloramphenicol cause grey-baby syndrome in neonates?", "back": "Immature hepatic glucuronidation (and renal excretion) → drug accumulates → circulatory collapse."}, {"id": "special:q:59", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "Why are sulfonamides avoided in neonates?", "back": "They displace bilirubin from albumin → risk of kernicterus (immature BBB)."}, {"id": "special:q:60", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "What do the Beers criteria describe?", "back": "Potentially inappropriate medications to avoid in older adults (e.g. long-acting benzodiazepines, strong anticholinergics, NSAIDs)."}, {"id": "special:q:61", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "Why do lipophilic drugs like diazepam have a prolonged effect in the elderly?", "back": "Increased body fat raises their volume of distribution and, with reduced clearance, prolongs half-life."}, {"id": "special:q:62", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "Name five drugs contraindicated in pregnancy.", "back": "Warfarin, ACE inhibitors/ARBs, valproate, isotretinoin, tetracyclines (also methotrexate, thalidomide)."}, {"id": "special:q:63", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "Which teratogen causes renal dysgenesis and oligohydramnios in the 2nd/3rd trimester?", "back": "ACE inhibitors (and ARBs)."}, {"id": "special:q:64", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "Which score grades severity of hepatic impairment for dosing?", "back": "The Child-Pugh score (classes A/B/C)."}, {"id": "special:q:65", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "How is a renally-cleared drug adjusted in a patient with eGFR 25?", "back": "Reduce the dose and/or lengthen the dosing interval based on eGFR/CrCl, and avoid nephrotoxins."}, {"id": "special:q:66", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "Why hold metformin when eGFR is low or around iodinated contrast?", "back": "Reduced renal clearance risks metformin accumulation and lactic acidosis."}, {"id": "special:q:67", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "Give two genotype-guided prescribing examples.", "back": "TPMT before azathioprine/6-MP; HLA-B*57:01 before abacavir (also CYP2C19–clopidogrel, HLA-B*15:02–carbamazepine)."}, {"id": "special:q:68", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "Why is eGFR preferred over serum creatinine alone for dose adjustment?", "back": "Creatinine varies with muscle mass/age/sex; eGFR estimates actual filtration, better reflecting drug clearance capacity."}, {"id": "special:q:69", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "State the five-step approach to the poisoned patient in order.", "back": "Resuscitate (ABC) → identify (toxidrome/tests) → decontaminate → specific antidote if available → enhance elimination — all with supportive care."}, {"id": "special:q:70", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "Which classes of toxin does activated charcoal NOT bind?", "back": "Metals, alcohols, hydrocarbons, caustics, lithium and iron."}, {"id": "special:q:71", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "Antidote and mechanism for paracetamol poisoning.", "back": "N-acetylcysteine — replenishes glutathione to neutralise NAPQI."}, {"id": "special:q:72", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "Two-drug antidote for organophosphate poisoning and what each does.", "back": "Atropine (blocks muscarinic effects) + pralidoxime (reactivates AChE before ageing)."}, {"id": "special:q:73", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "What is the atropine end-point in organophosphate poisoning?", "back": "Drying of bronchial/oral secretions (not pupil size or heart rate)."}, {"id": "special:q:74", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "Antidote for methanol/ethylene glycol and its mechanism.", "back": "Fomepizole (or ethanol) — inhibits alcohol dehydrogenase, blocking toxic metabolite formation."}, {"id": "special:q:75", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "Describe the opioid toxidrome and its antidote's pitfall.", "back": "Coma, pinpoint pupils, respiratory depression; naloxone works but is short-acting → re-sedation, re-dose/infuse."}, {"id": "special:q:76", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "Why is flumazenil used cautiously?", "back": "It can precipitate seizures in chronic benzodiazepine users or mixed (e.g. TCA) overdose."}, {"id": "special:q:77", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "Which toxins are effectively removed by haemodialysis, and what properties allow it?", "back": "Salicylate, lithium, methanol, ethylene glycol, valproate, metformin, theophylline — small, water-soluble, low protein-binding, low Vd."}, {"id": "special:q:78", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "Why is a drug with a large volume of distribution poorly dialysed?", "back": "Most of it sits in tissues, not plasma, so little is accessible to the dialyser."}, {"id": "special:q:79", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "Antidote for digoxin toxicity and for iron overdose.", "back": "Digoxin-specific Fab fragments; deferoxamine (chelation) for iron."}, {"id": "special:q:80", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "Antidote for cyanide poisoning.", "back": "Hydroxocobalamin (also sodium thiosulfate/nitrite)."}, {"id": "special:q:81", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "Describe the anticholinergic toxidrome.", "back": "Hot (hyperthermia), dry skin, flushed, mydriasis/blind, urinary retention, delirium (\"mad\"), tachycardia."}, {"id": "special:q:82", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "Which enhanced-elimination method suits salicylate, and why?", "back": "Urinary alkalinisation with bicarbonate — ion-trapping of the weak acid increases renal excretion."}, {"id": "special:q:83", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "Name three duties of a poison information centre.", "back": "24-hour advice on poisoning management, maintaining a toxicology database, and toxicovigilance/public education (plus supporting analytical toxicology)."}, {"id": "special:q:84", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "Who demonstrated chemical neurotransmission, and with what famous experiment?", "back": "Otto Loewi (with Henry Dale) — the frog-heart \"Vagusstoff\" experiment identifying acetylcholine."}, {"id": "special:q:85", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "Which two landmark drugs did James Black design, and why is his work significant?", "back": "Propranolol (β-blocker) and cimetidine (H₂-blocker) — the birth of rational, receptor-based drug design."}, {"id": "special:q:86", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "Who discovered cyclic AMP as a second messenger?", "back": "Earl Sutherland."}, {"id": "special:q:87", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "Who won the Nobel Prize for discovering G-proteins?", "back": "Alfred Gilman and Martin Rodbell."}, {"id": "special:q:88", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "Who developed the radioimmunoassay?", "back": "Rosalyn Yalow."}, {"id": "special:q:89", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "Which discovery by Allison and Honjo transformed oncology, and name a resulting drug class?", "back": "Immune checkpoint inhibition (CTLA-4, PD-1) → checkpoint inhibitors (ipilimumab, nivolumab, pembrolizumab)."}, {"id": "special:q:90", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "Who is regarded as the \"father of Indian pharmacology\"?", "back": "Colonel Sir Ram Nath Chopra."}, {"id": "special:q:91", "deck": "Special Systems", "dk": "special", "type": "quiz", "front": "Why did the discovery of G-proteins and second messengers matter for drug development?", "back": "It revealed the intracellular signalling machinery that receptors control — the basis of GPCR pharmacology, the largest class of drug targets."}, {"id": "exp:fc:28", "deck": "Experimental & Clinical", "dk": "exp", "type": "flashcard", "front": "You treat a cell line with a candidate drug and need to prove the cells die by apoptosis rather than necrosis. Which flow-cytometry assay, and how are the quadrants read?", "back": "An <strong>Annexin V / PI (or 7-AAD) apoptosis assay</strong>. <strong>Annexin V</strong> binds phosphatidylserine flipped to the outer membrane in <em>early</em> apoptosis; <strong>PI</strong> enters only once the membrane is compromised (<em>late</em> apoptosis/necrosis). Quadrants: Annexin⁻/PI⁻ = live; Annexin⁺/PI⁻ = early apoptotic; Annexin⁺/PI⁺ = late apoptotic; Annexin⁻/PI⁺ = necrotic.<div class=\"sr-note\">💎 <strong>Practical Pearl:</strong> Forward scatter = cell size, side scatter = granularity; fluorescent anti-CD antibodies identify cell type (immunophenotyping).</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Requires a single-cell suspension and fluorophore compensation + proper controls — poor gating invents populations.</div>"}, {"id": "exp:fc:29", "deck": "Experimental & Clinical", "dk": "exp", "type": "flashcard", "front": "In an RT-qPCR experiment, the treated sample has a lower Ct for the target gene than the control. What does that mean?", "back": "A <strong>lower Ct (cycle threshold) means MORE starting template</strong> — fluorescence crosses the threshold in fewer cycles because there was more of that mRNA to begin with. So the target gene is <strong>more highly expressed</strong> in the treated sample (after normalising to a housekeeping gene by the ΔΔCt method).<div class=\"sr-note\">💎 <strong>Practical Pearl:</strong> Workflow: extract RNA → reverse-transcribe to cDNA → amplify with a fluorescent reporter → read Ct.</div><div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Genomic-DNA contamination or an unstable housekeeping gene are the classic causes of false expression changes.</div>"}, {"id": "exp:fc:30", "deck": "Experimental & Clinical", "dk": "exp", "type": "flashcard", "front": "What do forward scatter and side scatter measure in flow cytometry, and how are specific cell types identified?", "back": "<strong>Forward scatter (FSC)</strong> ∝ cell <strong>size</strong>; <strong>side scatter (SSC)</strong> ∝ internal <strong>granularity/complexity</strong>. Specific cell types are identified by <strong>fluorophore-tagged antibodies against surface CD markers</strong> (immunophenotyping) — e.g. CD4 counts in HIV, leukaemia/lymphoma panels.<div class=\"sr-note\">💎 <strong>Practical Pearl:</strong> FACS additionally sorts and physically collects the cells of interest.</div>"}, {"id": "exp:fc:31", "deck": "Experimental & Clinical", "dk": "exp", "type": "flashcard", "front": "Which assay is used for a quick in-vitro readout of drug cytotoxicity/viability, and what is the principle?", "back": "The <strong>MTT (or MTS) assay</strong>. Metabolically active (living) cells reduce the tetrazolium dye to a coloured formazan product; the absorbance is proportional to the number of viable cells, so a fall in signal indicates cytotoxicity.<div class=\"sr-note\">💎 <strong>Practical Pearl:</strong> Other cell-based assays: proliferation (BrdU), reporter-gene, and receptor-binding assays — the front line of in-vitro screening.</div>"}, {"id": "exp:fc:32", "deck": "Experimental & Clinical", "dk": "exp", "type": "flashcard", "front": "Why must RT-qPCR expression results be normalised to a housekeeping gene?", "back": "The amount of total RNA captured and reverse-transcribed varies between samples. A <strong>housekeeping gene</strong> (e.g. GAPDH, β-actin) is assumed constant across conditions, so expressing the target relative to it (ΔΔCt) corrects for loading differences and isolates the true change in the target.<div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> If the housekeeping gene is itself affected by the treatment, the normalisation is invalid — validate reference genes for your system.</div>"}, {"id": "exp:fc:33", "deck": "Experimental & Clinical", "dk": "exp", "type": "flashcard", "front": "An exam tracing shows adrenaline raising BP; after a drug is given, adrenaline now lowers BP. Name the phenomenon and the drug class, and state what happens with noradrenaline.", "back": "<strong>Dale's vasomotor reversal</strong> after an <strong>α-blocker</strong>. Adrenaline acts on both α (vasoconstriction) and β₂ (vasodilation); normally α dominates (BP rises), but with α blocked the β₂ vasodilation is unmasked, so adrenaline now <em>lowers</em> BP. <strong>Noradrenaline is NOT reversed</strong> — it has negligible β₂ action, so α-blockade merely abolishes its pressor effect.<div class=\"sr-note\">💎 <strong>Practical Pearl:</strong> This is the classic demonstration that adrenaline is a mixed α/β agonist.</div>"}, {"id": "exp:fc:34", "deck": "Experimental & Clinical", "dk": "exp", "type": "flashcard", "front": "Describe the Langendorff preparation and what it is used to measure.", "back": "The <strong>Langendorff isolated heart</strong> is perfused <em>retrogradely</em> down the aorta, which closes the aortic valve and drives perfusate into the coronary arteries, keeping the heart beating <em>ex vivo</em>. It measures <strong>heart rate, contractile force and coronary flow</strong> free of systemic reflexes — used to screen inotropes/chronotropes and study ischaemia-reperfusion/cardioprotection.<div class=\"sr-note\">💎 <strong>Practical Pearl:</strong> Because it removes neural/hormonal confounders, effects seen are direct actions on the myocardium/coronaries.</div>"}, {"id": "exp:fc:35", "deck": "Experimental & Clinical", "dk": "exp", "type": "flashcard", "front": "Explain how a four-point (2+2) bioassay estimates the potency of an unknown, and the key validity requirement.", "back": "Two doses of the <strong>standard</strong> and two of the <strong>test</strong> are applied to a sensitive isolated tissue to construct two log dose–response lines. If the lines are <strong>parallel</strong> (same mechanism), the horizontal distance between them gives the <strong>potency ratio</strong>, from which the unknown's concentration is calculated.<div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Non-parallel lines invalidate the assay — they indicate the standard and test are not acting by the same mechanism.</div>"}, {"id": "exp:fc:36", "deck": "Experimental & Clinical", "dk": "exp", "type": "flashcard", "front": "Define pA₂ and what a higher pA₂ indicates, using atropine vs acetylcholine as the example.", "back": "<strong>pA₂</strong> is the negative logarithm of the molar concentration of a <strong>competitive antagonist</strong> that requires a <strong>doubling</strong> of the agonist dose to restore the original response (a dose-ratio of 2). A <strong>higher pA₂ = a more potent antagonist</strong>. For atropine antagonising acetylcholine on guinea-pig ileum, the pA₂ quantifies atropine's affinity.<div class=\"sr-note\">💎 <strong>Practical Pearl:</strong> pA₂ is derived from a Schild plot; for a purely competitive antagonist the Schild slope ≈ 1.</div>"}, {"id": "exp:fc:37", "deck": "Experimental & Clinical", "dk": "exp", "type": "flashcard", "front": "At a PK station you must give a loading and maintenance regimen. State the two formulae and the parameters each needs.", "back": "<strong>Loading dose = V<sub>d</sub> × target plasma concentration ÷ bioavailability (F)</strong> — achieves the target level immediately (needs V<sub>d</sub>). <strong>Maintenance dosing rate = CL × target concentration ÷ F</strong> — replaces what is cleared (needs clearance). Half-life (t½ = 0.693 × V<sub>d</sub> ÷ CL) sets the dosing interval and time to steady state (~4–5 half-lives).<div class=\"sr-note\">⚠️ <strong>Exam Trap:</strong> Loading dose depends on V<sub>d</sub> (not clearance); maintenance rate depends on clearance (not V<sub>d</sub>) — mixing these up is the classic error.</div>"}, {"id": "exp:q:300", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "What do forward and side scatter measure in flow cytometry?", "back": "Forward scatter = cell size; side scatter = internal granularity/complexity."}, {"id": "exp:q:301", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "How are specific cell types identified in flow cytometry?", "back": "Fluorophore-tagged antibodies against surface CD markers (immunophenotyping)."}, {"id": "exp:q:302", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Which two stains define the apoptosis assay, and what does each mark?", "back": "Annexin V (early apoptosis — externalised phosphatidylserine) and PI/7-AAD (late apoptosis/necrosis — membrane compromise)."}, {"id": "exp:q:303", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "What is FACS?", "back": "Fluorescence-activated cell sorting — flow cytometry that also physically separates cells of interest."}, {"id": "exp:q:304", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Give the RT-qPCR workflow.", "back": "Extract RNA → reverse-transcribe to cDNA → amplify with a fluorescent reporter → read the Ct."}, {"id": "exp:q:305", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "What does a lower Ct value indicate?", "back": "More starting template — i.e. higher expression of that transcript."}, {"id": "exp:q:306", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Why normalise RT-qPCR data to a housekeeping gene?", "back": "To correct for differences in RNA input between samples (ΔΔCt method)."}, {"id": "exp:q:307", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Principle of the MTT/MTS viability assay?", "back": "Living cells reduce tetrazolium to coloured formazan; absorbance ∝ viable cell number."}, {"id": "exp:q:308", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Name two other cell-based assay types.", "back": "Proliferation (BrdU), reporter-gene or receptor-binding assays."}, {"id": "exp:q:309", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Why is fluorophore \"compensation\" needed?", "back": "To correct spectral overlap between fluorophores so signals aren't misattributed."}, {"id": "exp:q:310", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "What sample preparation does flow cytometry require?", "back": "A single-cell suspension."}, {"id": "exp:q:311", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Two classic causes of false RT-qPCR expression changes?", "back": "Genomic-DNA contamination and an unstable/inappropriate housekeeping gene."}, {"id": "exp:q:312", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "What is Dale's vasomotor reversal?", "back": "After α-blockade, adrenaline's pressor effect flips to a depressor effect (β₂ vasodilation unmasked)."}, {"id": "exp:q:313", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Why is noradrenaline not reversed by an α-blocker?", "back": "It has negligible β₂ activity, so α-blockade merely abolishes its pressor effect."}, {"id": "exp:q:314", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "How is the Langendorff heart perfused, and why?", "back": "Retrogradely down the aorta — this shuts the aortic valve and drives perfusate into the coronaries, keeping the heart beating ex vivo."}, {"id": "exp:q:315", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "What three parameters does the Langendorff preparation measure?", "back": "Heart rate, contractile force, and coronary flow."}, {"id": "exp:q:316", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Outline the four-point (2+2) bioassay.", "back": "Two doses each of standard and test on a sensitive tissue give parallel log dose–response lines; the horizontal gap gives the potency ratio."}, {"id": "exp:q:317", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "What is the key validity requirement of a bioassay?", "back": "The standard and test dose–response lines must be parallel (same mechanism)."}, {"id": "exp:q:318", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Define pA₂.", "back": "The negative log of the competitive-antagonist concentration requiring a doubling of agonist dose to restore the original response."}, {"id": "exp:q:319", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Does a higher pA₂ mean a stronger or weaker antagonist?", "back": "Stronger (more potent) antagonist."}, {"id": "exp:q:320", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Which tissues are used to bioassay ACh/histamine and 5-HT?", "back": "Guinea-pig ileum (ACh, histamine) and rat fundus (5-HT)."}, {"id": "exp:q:321", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "What does the rota-rod assess?", "back": "Motor coordination — screening muscle relaxants/sedatives."}, {"id": "exp:q:322", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "What does Eddy's hot plate test?", "back": "Central (opioid) analgesia."}, {"id": "exp:q:323", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Write the loading-dose formula.", "back": "Loading dose = V<sub>d</sub> × target concentration ÷ bioavailability."}, {"id": "exp:q:324", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Write the maintenance-rate formula.", "back": "Maintenance dosing rate = clearance × target concentration ÷ bioavailability."}, {"id": "exp:q:325", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Which parameter governs loading dose vs maintenance rate?", "back": "Loading dose depends on V<sub>d</sub>; maintenance rate depends on clearance."}, {"id": "exp:q:326", "deck": "Experimental & Clinical", "dk": "exp", "type": "quiz", "front": "Name three things to check when critically appraising a paper.", "back": "Study design/bias, internal &amp; external validity, and whether the conclusions follow from the data."}];
